UPDATE hadiths SET urdu = 'ہم کو عبدان نے حدیث بیان کی، انہیں عبداللہ بن مبارک نے خبر دی، ان کو یونس نے، انہوں نے زہری سے یہ حدیث سنی۔ (دوسری سند یہ ہے کہ) ہم سے بشر بن محمد نے یہ حدیث بیان کی۔ ان سے عبداللہ بن مبارک نے، ان سے یونس اور معمر دونوں نے، ان دونوں نے زہری سے روایت کی پہلی سند کے مطابق زہری سے عبیداللہ بن عبداللہ نے، انہوں نے ابن عباس رضی اللہ عنہما سے یہ روایت نقل کی کہ رسول اللہ صلی اللہ علیہ وسلم سب لوگوں سے زیادہ جواد ( سخی ) تھے اور رمضان میں ( دوسرے اوقات کے مقابلہ میں جب ) جبرائیل علیہ السلام آپ صلی اللہ علیہ وسلم سے ملتے بہت ہی زیادہ جود و کرم فرماتے۔ جبرائیل علیہ السلام رمضان کی ہر رات میں آپ صلی اللہ علیہ وسلم سے ملاقات کرتے اور آپ صلی اللہ علیہ وسلم کے ساتھ قرآن کا دورہ کرتے، غرض نبی کریم صلی اللہ علیہ وسلم لوگوں کو بھلائی پہنچانے میں بارش لانے والی ہوا سے بھی زیادہ جود و کرم فرمایا کرتے تھے۔' WHERE id = 7;
UPDATE hadiths SET urdu = 'ہمیں محمد بن مثنیٰ نے یہ حدیث بیان کی، ان کو عبدالوہاب ثقفی نے، ان کو ایوب نے، وہ ابوقلابہ سے روایت کرتے ہیں، وہ انس رضی اللہ عنہ سے ناقل ہیں وہ نبی کریم صلی اللہ علیہ وسلم سے آپ صلی اللہ علیہ وسلم نے فرمایا تین خصلتیں ایسی ہیں کہ جس میں یہ پیدا ہو جائیں اس نے ایمان کی مٹھاس کو پا لیا۔ اول یہ کہ اللہ اور اس کا رسول اس کے نزدیک سب سے زیادہ محبوب بن جائیں، دوسرے یہ کہ وہ کسی انسان سے محض اللہ کی رضا کے لیے محبت رکھے۔ تیسرے یہ کہ وہ کفر میں واپس لوٹنے کو ایسا برا جانے جیسا کہ آگ میں ڈالے جانے کو برا جانتا ہے۔' WHERE id = 17;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس اور موسیٰ بن اسماعیل دونوں نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعید نے بیان کیا، انہوں نے کہا ہم سے ابن شہاب نے بیان کیا، وہ سعید بن المسیب رضی اللہ عنہ سے روایت کرتے ہیں، وہ ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم سے دریافت کیا گیا کہ کون سا عمل سب سے افضل ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”اللہ اور اس کے رسول پر ایمان لانا“ کہا گیا، اس کے بعد کون سا؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ”اللہ کی راہ میں جہاد کرنا“ کہا گیا، پھر کیا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”حج مبرور“۔' WHERE id = 27;
UPDATE hadiths SET urdu = 'ہم سے حرمی بن حفص نے بیان کیا، ان سے عبدالواحد نے، ان سے عمارہ نے، ان سے ابوزرعہ بن عمرو بن جریر نے، وہ کہتے ہیں میں نے ابوہریرہ سے سنا، وہ رسول اللہ صلی اللہ علیہ وسلم سے نقل کرتے ہیں آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص اللہ کی راہ میں ( جہاد کے لیے ) نکلا، اللہ اس کا ضامن ہو گیا۔ ( اللہ تعالیٰ فرماتا ہے ) اس کو میری ذات پر یقین اور میرے پیغمبروں کی تصدیق نے ( اس سرفروشی کے لیے گھر سے ) نکالا ہے۔ ( میں اس بات کا ضامن ہوں ) کہ یا تو اس کو واپس کر دوں ثواب اور مال غنیمت کے ساتھ، یا ( شہید ہونے کے بعد ) جنت میں داخل کر دوں ( رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ) اور اگر میں اپنی امت پر ( اس کام کو ) دشوار نہ سمجھتا تو لشکر کا ساتھ نہ چھوڑتا اور میری خواہش ہے کہ اللہ کی راہ میں مارا جاؤں، پھر زندہ کیا جاؤں، پھر مارا جاؤں، پھر زندہ کیا جاؤں، پھر مارا جاؤں۔' WHERE id = 37;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا مجھ سے امام مالک رحمہ اللہ نے بیان کیا، انہوں نے اپنے چچا ابوسہیل بن مالک سے، انہوں نے اپنے باپ (مالک بن ابی عامر) سے، انہوں نے طلحہ بن عبیداللہ سے وہ کہتے تھے نجد والوں میں ایک شخص نبی کریم صلی اللہ علیہ وسلم کے پاس آیا، سر پریشان یعنی بال بکھرے ہوئے تھے، ہم اس کی آواز کی بھنبھناہٹ سنتے تھے اور ہم سمجھ نہیں پا رہے تھے کہ وہ کیا کہہ رہا ہے۔ یہاں تک کہ وہ نزدیک آن پہنچا، جب معلوم ہوا کہ وہ اسلام کے بارے میں پوچھ رہا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسلام دن رات میں پانچ نمازیں پڑھنا ہے، اس نے کہا بس اس کے سوا تو اور کوئی نماز مجھ پر نہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا نہیں مگر تو نفل پڑھے ( تو اور بات ہے ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا اور رمضان کے روزے رکھنا۔ اس نے کہا اور تو کوئی روزہ مجھ پر نہیں ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا نہیں مگر تو نفل روزے رکھے ( تو اور بات ہے ) طلحہ نے کہا اور نبی کریم صلی اللہ علیہ وسلم نے اس سے زکوٰۃ کا بیان کیا۔ وہ کہنے لگا کہ بس اور کوئی صدقہ مجھ پر نہیں ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا نہیں مگر یہ کہ تو نفل صدقہ دے ( تو اور بات ہے ) راوی نے کہا پھر وہ شخص پیٹھ موڑ کر چلا۔ یوں کہتا جاتا تھا، قسم اللہ کی میں نہ اس سے بڑھاؤں گا نہ گھٹاؤں گا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا اگر یہ سچا ہے تو اپنی مراد کو پہنچ گیا۔' WHERE id = 47;
UPDATE hadiths SET urdu = 'ہم سے حکم بن نافع نے بیان کیا، کہا ہم کو شعیب نے زہری سے خبر دی، انہوں نے کہا کہ مجھ سے عامر بن سعد نے سعد بن ابی وقاص سے بیان کیا، انہوں نے ان کو خبر دی کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا بیشک تو جو کچھ خرچ کرے اور اس سے تیری نیت اللہ کی رضا حاصل کرنی ہو تو تجھ کو اس کا ثواب ملے گا۔ یہاں تک کہ اس پر بھی جو تو اپنی بیوی کے منہ میں ڈالے۔' WHERE id = 57;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا ان سے مالک نے اسحاق بن عبداللہ بن ابی طلحہ کے واسطے سے ذکر کیا، بیشک ابومرہ مولیٰ عقیل بن ابی طالب نے انہیں ابوواقد اللیثی سے خبر دی کہ ( ایک مرتبہ ) رسول اللہ صلی اللہ علیہ وسلم مسجد میں تشریف فرما تھے اور لوگ آپ صلی اللہ علیہ وسلم کے اردگرد بیٹھے ہوئے تھے کہ تین آدمی وہاں آئے ( ان میں سے ) دو رسول اللہ صلی اللہ علیہ وسلم کے سامنے پہنچ گئے اور ایک واپس چلا گیا۔ ( راوی کہتے ہیں کہ ) پھر وہ دونوں رسول اللہ صلی اللہ علیہ وسلم کے سامنے کھڑے ہو گئے۔ اس کے بعد ان میں سے ایک نے ( جب ) مجلس میں ( ایک جگہ کچھ ) گنجائش دیکھی، تو وہاں بیٹھ گیا اور دوسرا اہل مجلس کے پیچھے بیٹھ گیا اور تیسرا جو تھا وہ لوٹ گیا۔ تو جب رسول اللہ صلی اللہ علیہ وسلم ( اپنی گفتگو سے ) فارغ ہوئے ( تو صحابہ رضی اللہ عنہم سے ) فرمایا کہ کیا میں تمہیں تین آدمیوں کے بارے میں نہ بتاؤں؟ تو ( سنو ) ان میں سے ایک نے اللہ سے پناہ چاہی اللہ نے اسے پناہ دی اور دوسرے کو شرم آئی تو اللہ بھی اس سے شرمایا ( کہ اسے بھی بخش دیا ) اور تیسرے شخص نے منہ موڑا، تو اللہ نے ( بھی ) اس سے منہ موڑ لیا۔' WHERE id = 67;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، ان سے مالک نے، ان سے ابن شہاب نے، ان سے عبیداللہ بن عبداللہ بن عتبہ نے، وہ عبداللہ بن عباس رضی اللہ عنہما سے روایت کرتے ہیں کہ میں ( ایک مرتبہ ) گدھی پر سوار ہو کر چلا، اس زمانے میں، میں بلوغ کے قریب تھا۔ رسول اللہ صلی اللہ علیہ وسلم منیٰ میں نماز پڑھ رہے تھے اور آپ کے سامنے دیوار ( کی آڑ ) نہ تھی، تو میں بعض صفوں کے سامنے سے گزرا اور گدھی کو چھوڑ دیا۔ وہ چرنے لگی، جب کہ میں صف میں شامل ہو گیا ( مگر ) کسی نے مجھے اس بات پر ٹوکا نہیں۔' WHERE id = 77;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، ان سے وہیب نے، ان سے ہشام نے فاطمہ کے واسطے سے نقل کیا، وہ اسماء سے روایت کرتی ہیں کہ میں عائشہ رضی اللہ عنہا کے پاس آئی، وہ نماز پڑھ رہی تھیں، میں نے کہا کہ لوگوں کا کیا حال ہے؟ تو انہوں نے آسمان کی طرف اشارہ کیا ( یعنی سورج کو گہن لگا ہے ) اتنے میں لوگ ( نماز کے لیے ) کھڑے ہو گئے۔ عائشہ رضی اللہ عنہا نے کہا، اللہ پاک ہے۔ میں نے کہا ( کیا یہ گہن ) کوئی ( خاص ) نشانی ہے؟ انہوں نے سر سے اشارہ کیا یعنی ہاں! پھر میں ( بھی نماز کے لیے ) کھڑی ہو گئی۔ حتیٰ کہ مجھے غش آنے لگا، تو میں اپنے سر پر پانی ڈالنے لگی۔ پھر ( نماز کے بعد ) رسول اللہ صلی اللہ علیہ وسلم نے اللہ تعالیٰ کی تعریف اور اس کی صفت بیان فرمائی، پھر فرمایا، جو چیز مجھے پہلے دکھلائی نہیں گئی تھی آج وہ سب اس جگہ میں نے دیکھ لی، یہاں تک کہ جنت اور دوزخ کو بھی دیکھ لیا اور مجھ پر یہ وحی کی گئی کہ تم اپنی قبروں میں آزمائے جاؤ گے، «مثل» یا «قرب» کا کون سا لفظ اسماء نے فرمایا، میں نہیں جانتی، فاطمہ کہتی ہیں ( یعنی ) فتنہ دجال کی طرح ( آزمائے جاؤ گے ) کہا جائے گا ( قبر کے اندر کہ ) تم اس آدمی کے بارے میں کیا جانتے ہو؟ تو جو صاحب ایمان یا صاحب یقین ہو گا، کون سا لفظ فرمایا اسماء رضی اللہ عنہا نے، مجھے یاد نہیں۔ وہ کہے گا وہ محمد اللہ کے رسول صلی اللہ علیہ وسلم ہیں، جو ہمارے پاس اللہ کی ہدایت اور دلیلیں لے کر آئے تو ہم نے ان کو قبول کر لیا اور ان کی پیروی کی وہ محمد صلی اللہ علیہ وسلم ہیں۔ تین بار ( اسی طرح کہے گا ) پھر ( اس سے ) کہہ دیا جائے گا کہ آرام سے سو جا بیشک ہم نے جان لیا کہ تو محمد صلی اللہ علیہ وسلم پر یقین رکھتا تھا۔ اور بہرحال منافق یا شکی آدمی، میں نہیں جانتی کہ ان میں سے کون سا لفظ اسماء رضی اللہ عنہا نے کہا۔ تو وہ ( منافق یا شکی آدمی ) کہے گا کہ جو لوگوں کو میں نے کہتے سنا میں نے ( بھی ) وہی کہہ دیا۔ ( باقی میں کچھ نہیں جانتا۔)' WHERE id = 87;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ان سے ابوعوانہ نے ابی بشر کے واسطے سے بیان کیا، وہ یوسف بن ماھک سے بیان کرتے ہیں، وہ عبداللہ بن عمرو رضی اللہ عنہما سے، وہ کہتے ہیں کہ ایک سفر میں رسول اللہ صلی اللہ علیہ وسلم ہم سے پیچھے رہ گئے۔ پھر آپ صلی اللہ علیہ وسلم ہمارے قریب پہنچے۔ تو عصر کی نماز کا وقت ہو چکا تھا یا تنگ ہو گیا تھا اور ہم وضو کر رہے تھے۔ ہم اپنے پیروں پر پانی کا ہاتھ پھیرنے لگے تو آپ صلی اللہ علیہ وسلم نے بلند آواز سے فرمایا کہ آگ کے عذاب سے ان ایڑیوں کی ( جو خشک رہ جائیں ) خرابی ہے۔ یہ دو مرتبہ فرمایا یا تین مرتبہ۔' WHERE id = 97;
UPDATE hadiths SET urdu = 'ہم سے علی بن جعد نے بیان کیا، انہیں شعبہ نے خبر دی، انہیں منصور نے، انہوں نے ربعی بن حراش سے سنا کہ میں نے علی رضی اللہ عنہ کو یہ فرماتے ہوئے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ مجھ پر جھوٹ مت بولو۔ کیونکہ جو مجھ پر جھوٹ باندھے وہ دوزخ میں داخل ہو۔' WHERE id = 107;
UPDATE hadiths SET urdu = 'سعید بن عفیر نے ہم سے بیان کیا، ان سے لیث نے بیان کیا، ان سے عبدالرحمٰن بن خالد بن مسافر نے ابن شہاب کے واسطے سے بیان کیا، انہوں نے سالم اور ابوبکر بن سلیمان بن ابی حثمہ سے روایت کیا کہ عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ آخر عمر میں ( ایک دفعہ ) رسول اللہ صلی اللہ علیہ وسلم نے ہمیں عشاء کی نماز پڑھائی۔ جب آپ صلی اللہ علیہ وسلم نے سلام پھیرا تو کھڑے ہو گئے اور فرمایا کہ تمہاری آج کی رات وہ ہے کہ اس رات سے سو برس کے آخر تک کوئی شخص جو زمین پر ہے وہ باقی نہیں رہے گا۔' WHERE id = 117;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے اسرائیل کے واسطے سے نقل کیا، انہوں نے ابواسحاق سے اسود کے واسطے سے بیان کیا، وہ کہتے ہیں کہ مجھ سے عبداللہ بن زبیر رضی اللہ عنہما نے بیان کیا کہ عائشہ رضی اللہ عنہا تم سے بہت باتیں چھپا کر کہتی تھیں، تو کیا تم سے کعبہ کے بارے میں بھی کچھ بیان کیا، میں نے کہا ( ہاں ) مجھ سے انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے ( ایک مرتبہ ) ارشاد فرمایا تھا کہ اے عائشہ! اگر تیری قوم ( دور جاہلیت کے ساتھ ) قریب نہ ہوتی ( بلکہ پرانی ہو گئی ہوتی ) ابن زبیر رضی اللہ عنہ نے کہا یعنی زمانہ کفر کے ساتھ ( قریب نہ ہوتی ) تو میں کعبہ کو توڑ دیتا اور اس کے لیے دو دروازے بنا دیتا۔ ایک دروازے سے لوگ داخل ہوتے اور دوسرے دروازے سے باہر نکلتے، ( بعد میں ) ابن زبیر نے یہ کام کیا۔' WHERE id = 127;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، ان سے لیث نے خالد کے واسطے سے نقل کیا، وہ سعید بن ابی ہلال سے نقل کرتے ہیں، وہ نعیم المجمر سے، وہ کہتے ہیں کہ میں ( ایک مرتبہ ) ابوہریرہ رضی اللہ عنہ کے ساتھ مسجد کی چھت پر چڑھا۔ تو آپ نے وضو کیا اور کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا تھا کہ آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ میری امت کے لوگ وضو کے نشانات کی وجہ سے قیامت کے دن سفید پیشانی اور سفید ہاتھ پاؤں والوں کی شکل میں بلائے جائیں گے۔ تو تم میں سے جو کوئی اپنی چمک بڑھانا چاہتا ہے تو وہ بڑھا لے ( یعنی وضو اچھی طرح کرے ) ۔' WHERE id = 137;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے ابن شہاب کے واسطے سے نقل کیا، وہ عروہ بن زبیر سے، وہ عائشہ رضی اللہ عنہا سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم کی بیویاں رات میں مناصع کی طرف قضاء حاجت کے لیے جاتیں اور مناصع ایک کھلا میدان ہے۔ تو عمر رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم سے کہا کرتے تھے کہ اپنی بیویوں کو پردہ کرائیے۔ مگر رسول اللہ صلی اللہ علیہ وسلم نے اس پر عمل نہیں کیا۔ ایک روز رات کو عشاء کے وقت سودہ بنت زمعہ رضی اللہ عنہا، رسول اللہ صلی اللہ علیہ وسلم کی اہلیہ جو دراز قد عورت تھیں، ( باہر ) گئیں۔ عمر رضی اللہ عنہ نے انہیں آواز دی ( اور کہا ) ہم نے تمہیں پہچان لیا اور ان کی خواہش یہ تھی کہ پردہ ( کا حکم ) نازل ہو جائے۔ چنانچہ ( اس کے بعد ) اللہ نے پردہ ( کا حکم ) نازل فرما دیا۔' WHERE id = 147;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے زہیر نے ابواسحاق کے واسطے سے نقل کیا، ابواسحاق کہتے ہیں کہ اس حدیث کو ابوعبیدہ نے ذکر نہیں کیا۔ لیکن عبدالرحمٰن بن الاسود نے اپنے باپ سے ذکر کیا، انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے سنا، وہ کہتے تھے کہ نبی کریم صلی اللہ علیہ وسلم رفع حاجت کے لیے گئے۔ تو آپ صلی اللہ علیہ وسلم نے مجھے فرمایا کہ میں تین پتھر تلاش کر کے آپ کے پاس لاؤں۔ لیکن مجھے دو پتھر ملے۔ تیسرا ڈھونڈا مگر مل نہ سکا۔ تو میں نے خشک گوبر اٹھا لیا۔ اس کو لے کر آپ صلی اللہ علیہ وسلم کے پاس آ گیا۔ آپ صلی اللہ علیہ وسلم نے پتھر ( تو ) لے لیے ( مگر ) گوبر پھینک دیا اور فرمایا یہ خود ناپاک ہے۔ ( اور یہ حدیث ) ابراہم بن یوسف نے اپنے باپ سے بیان کی۔ انہوں نے ابواسحاق سے سنا، ان سے عبدالرحمٰن نے بیان کیا۔' WHERE id = 157;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو مالک نے سعید المقبری کے واسطے سے خبر دی، وہ عبیداللہ بن جریج سے نقل کرتے ہیں کہ انہوں نے عبداللہ بن عمر سے کہا اے ابوعبدالرحمٰن! میں نے تمہیں چار ایسے کام کرتے ہوئے دیکھا ہے جنھیں تمہارے ساتھیوں کو کرتے ہوئے نہیں دیکھا۔ وہ کہنے لگے، اے ابن جریج! وہ کیا ہیں؟ ابن جریج نے کہا کہ میں نے طواف کے وقت آپ کو دیکھا کہ دو یمانی رکنوں کے سوا کسی اور رکن کو آپ نہیں چھوتے ہو۔ ( دوسرے ) میں نے آپ کو بستی جوتے پہنے ہوئے دیکھا اور ( تیسرے ) میں نے دیکھا کہ آپ زرد رنگ استعمال کرتے ہو اور ( چوتھی بات ) میں نے یہ دیکھی کہ جب آپ مکہ میں تھے، لوگ ( ذی الحجہ کا ) چاند دیکھ کر لبیک پکارنے لگتے ہیں۔ ( اور ) حج کا احرام باندھ لیتے ہیں اور آپ آٹھویں تاریخ تک احرام نہیں باندھتے۔ عبداللہ بن عمر رضی اللہ عنہما نے جواب دیا کہ ( دوسرے ) ارکان کو تو میں یوں نہیں چھوتا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو یمانی رکنوں کے علاوہ کسی اور رکن کو چھوتے ہوئے نہیں دیکھا اور رہے جوتے، تو میں نے رسول اللہ صلی اللہ علیہ وسلم کو ایسے جوتے پہنے ہوئے دیکھا کہ جن کے چمڑے پر بال نہیں تھے اور آپ انہیں کو پہنے پہنے وضو فرمایا کرتے تھے، تو میں بھی انہی کو پہننا پسند کرتا ہوں اور زرد رنگ کی بات یہ ہے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو زرد رنگ رنگتے ہوئے دیکھا ہے۔ تو میں بھی اسی رنگ سے رنگنا پسند کرتا ہوں اور احرام باندھنے کا معاملہ یہ ہے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو اس وقت تک احرام باندھتے ہوئے نہیں دیکھا جب تک آپ کی اونٹنی آپ کو لے کر نہ چل پڑتی۔' WHERE id = 167;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا ہم سے ابن ابی ذئب نے بیان کیا، انہوں نے کہا ہم سے سعید المقبری نے بیان کیا، وہ ابوہریرہ سے روایت کرتے ہیں، وہ کہتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ بندہ اس وقت تک نماز ہی میں رہتا ہے جب تک وہ مسجد میں نماز کا انتظار کرتا ہے۔ تاوقیتکہ وہ حدث نہ کرے۔ ایک عجمی آدمی نے پوچھا کہ اے ابوہریرہ! حدث کیا چیز ہے؟ انہوں نے فرمایا کہ ہوا جو پیچھے سے خارج ہو۔ ( جسے عرف عام میں گوز مارنا کہتے ہیں ) ۔' WHERE id = 177;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ نے بیان کیا، انہوں نے کہا ہم سے وہیب نے بیان کیا، انہوں نے عمرو سے، انہوں نے اپنے باپ (یحییٰ) سے خبر دی، انہوں نے کہا کہ میری موجودگی میں عمرو بن حسن نے عبداللہ بن زید رضی اللہ عنہ سے رسول اللہ صلی اللہ علیہ وسلم کے وضو کے بارے میں پوچھا تو انہوں نے پانی کا طشت منگوایا اور ان ( پوچھنے والوں ) کے لیے رسول اللہ صلی اللہ علیہ وسلم کا سا وضو کیا۔ ( پہلے طشت سے ) اپنے ہاتھوں پر پانی گرایا۔ پھر تین بار ہاتھ دھوئے، پھر اپنا ہاتھ طشت میں ڈالا ( اور پانی لیا ) پھر کلی کی، ناک میں پانی ڈالا، ناک صاف کی، تین چلوؤں سے، پھر اپنا ہاتھ طشت میں ڈالا اور تین مرتبہ منہ دھویا۔ پھر اپنے دونوں ہاتھ کہنیوں تک دو بار دھوئے۔ پھر اپنا ہاتھ طشت میں ڈالا اور سر کا مسح کیا۔ ( پہلے ) آگے لائے پھر پیچھے لے گئے، ایک بار۔ پھر ٹخنوں تک اپنے دونوں پاؤں دھوئے۔' WHERE id = 187;
UPDATE hadiths SET urdu = 'ہم سے محمد بن العلاء نے بیان کیا، انہوں نے کہا ہم سے ابواسامہ نے برید کے واسطے سے بیان کیا، وہ ابوبردہ سے، وہ ابوموسیٰ رضی اللہ عنہ سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک پیالہ منگایا جس میں پانی تھا۔ پھر اس میں آپ صلی اللہ علیہ وسلم نے اپنے دونوں ہاتھوں اور چہرے کو دھویا اور اسی میں کلی کی۔' WHERE id = 197;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے زکریا نے یحییٰ کے واسطے سے نقل کیا، وہ عامر سے وہ عروہ بن مغیرہ سے، وہ اپنے باپ (مغیرہ) سے روایت کرتے ہیں کہ میں ایک سفر میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھا، تو میں نے چاہا ( کہ وضو کرتے وقت ) آپ صلی اللہ علیہ وسلم کے موزے اتار ڈالوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ انہیں رہنے دو۔ چونکہ جب میں نے انہیں پہنا تھا تو میرے پاؤں پاک تھے۔ ( یعنی میں وضو سے تھا ) پس آپ صلی اللہ علیہ وسلم نے ان پر مسح کیا۔' WHERE id = 207;
UPDATE hadiths SET urdu = 'ہم سے عثمان نے بیان کیا، کہا ہم سے جریر نے منصور کے واسطے سے نقل کیا، وہ مجاہد سے وہ ابن عباس رضی اللہ عنہما سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم ایک دفعہ مدینہ یا مکے کے ایک باغ میں تشریف لے گئے۔ ( وہاں ) آپ صلی اللہ علیہ وسلم نے دو شخصوں کی آواز سنی جنھیں ان کی قبروں میں عذاب کیا جا رہا تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان پر عذاب ہو رہا ہے اور کسی بہت بڑے گناہ کی وجہ سے نہیں پھر آپ صلی اللہ علیہ وسلم نے فرمایا بات یہ ہے کہ ایک شخص ان میں سے پیشاب کے چھینٹوں سے بچنے کا اہتمام نہیں کرتا تھا اور دوسرا شخص چغل خوری کیا کرتا تھا۔ پھر آپ صلی اللہ علیہ وسلم نے ( کھجور کی ) ایک ڈالی منگوائی اور اس کو توڑ کر دو ٹکڑے کیا اور ان میں سے ( ایک ایک ٹکڑا ) ہر ایک کی قبر پر رکھ دیا۔ لوگوں نے آپ صلی اللہ علیہ وسلم سے پوچھا کہ یا رسول اللہ! یہ آپ صلی اللہ علیہ وسلم نے کیوں کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا اس لیے کہ جب تک یہ ڈالیاں خشک ہوں شاید اس وقت تک ان پر عذاب کم ہو جائے۔' WHERE id = 217;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عرعرہ نے بیان کیا، کہا ہم سے شعبہ نے منصور کے واسطے سے بیان کیا، وہ ابووائل سے نقل کرتے ہیں، وہ کہتے ہیں کہ ابوموسیٰ اشعری پیشاب ( کے بارہ ) میں سختی سے کام لیتے تھے اور کہتے تھے کہ بنی اسرائیل میں جب کسی کے کپڑے کو پیشاب لگ جاتا۔ تو اسے کاٹ ڈالتے۔ ابوحذیفہ کہتے ہیں کہ کاش! وہ اپنے اس تشدد سے رک جاتے ( کیونکہ ) رسول اللہ صلی اللہ علیہ وسلم کسی قوم کی کوڑی پر تشریف لائے اور آپ صلی اللہ علیہ وسلم نے وہاں کھڑے ہو کر پیشاب کیا۔' WHERE id = 227;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے معن نے، کہا ہم سے مالک نے ابن شہاب کے واسطے سے بیان کیا، وہ عبیداللہ ابن عبداللہ بن عتبہ بن مسعود سے، وہ ابن عباس رضی اللہ عنہما سے وہ میمونہ رضی اللہ عنہا سے نقل کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم سے چوہے کے بارے میں دریافت کیا گیا جو گھی میں گر گیا تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس چوہے کو اور اس کے آس پاس کے گھی کو نکال کر پھینک دو۔ معن کہتے ہیں کہ مالک نے اتنی بار کہ میں گن نہیں سکتا ( یہ حدیث ) ابن عباس سے اور انہوں نے میمونہ رضی اللہ عنہا سے روایت کی ہے۔' WHERE id = 237;
UPDATE hadiths SET urdu = 'عفان نے کہا کہ ہم سے صخر بن جویریہ نے نافع کے واسطے سے بیان کیا، وہ ابن عمر رضی اللہ عنہما سے نقل کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے دیکھا کہ ( خواب میں ) مسواک کر رہا ہوں تو میرے پاس دو آدمی آئے۔ ایک ان میں سے دوسرے سے بڑا تھا، تو میں نے چھوٹے کو مسواک دے دی پھر مجھ سے کہا گیا کہ بڑے کو دو۔ تب میں نے ان میں سے بڑے کو دی۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) کہتے ہیں کہ اس حدیث کو نعیم نے ابن المبارک سے، وہ اسامہ سے، وہ نافع سے، انہوں نے ابن عمر رضی اللہ عنہما سے مختصر طور پر روایت کیا ہے۔' WHERE id = 247;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم (فضل بن دکین) نے بیان کیا، کہا کہ ہم سے معمر بن یحییٰ بن سام نے روایت کیا، کہا کہ ہم سے ابوجعفر (محمد باقر) نے بیان کیا، انہوں نے کہا کہ ہم سے جابر نے بیان کیا کہ میرے پاس تمہارے چچا کے بیٹے ( ان کی مراد حسن بن محمد ابن حنفیہ سے تھی ) آئے۔ انہوں نے پوچھا کہ جنابت کے غسل کا کیا طریقہ ہے؟ میں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم تین چلو پانی لیتے اور ان کو اپنے سر پر بہاتے تھے۔ پھر اپنے تمام بدن پر پانی بہاتے تھے۔ حسن نے اس پر کہا کہ میں تو بہت بالوں والا آدمی ہوں۔ میں نے جواب دیا کہ نبی کریم صلی اللہ علیہ وسلم کے بال تم سے زیادہ تھے۔' WHERE id = 257;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے ابوعوانہ نے بیان کیا، انہوں نے کہا ہم سے اعمش نے سالم بن ابی الجعد کے واسطہ سے بیان کیا، وہ ابن عباس رضی اللہ عنہما کے مولیٰ کریب سے، انہوں نے ابن عباس رضی اللہ عنہما سے، انہوں نے میمونہ بنت حارث رضی اللہ عنہا سے، انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے لیے ( غسل کا ) پانی رکھا اور پردہ کر دیا، آپ نے ( پہلے غسل میں ) اپنے ہاتھ پر پانی ڈالا اور اسے ایک یا دو بار دھویا۔ سلیمان اعمش کہتے ہیں کہ مجھے یاد نہیں راوی ( سالم بن ابی الجعد ) نے تیسری بار کا بھی ذکر کیا یا نہیں۔ پھر داہنے ہاتھ سے بائیں پر پانی ڈالا۔ اور شرمگاہ دھوئی، پھر اپنے ہاتھ کو زمین پر یا دیوار پر رگڑا۔ پھر کلی کی اور ناک میں پانی ڈالا اور چہرے اور ہاتھوں کو دھویا۔ اور سر کو دھویا۔ پھر سارے بدن پر پانی بہایا۔ پھر ایک طرف سرک کر دونوں پاؤں دھوئے۔ بعد میں میں نے ایک کپڑا دیا تو آپ صلی اللہ علیہ وسلم نے اپنے ہاتھ سے اشارہ کیا اس طرح کہ اسے ہٹاؤ اور آپ نے اس کپڑے کا ارادہ نہیں فرمایا۔' WHERE id = 267;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نصر نے بیان کیا، انہوں نے کہا ہم سے عبدالرزاق نے بیان کیا، انہوں نے معمر سے، انہوں نے ہمام بن منبہ سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا بنی اسرائیل ننگے ہو کر اس طرح نہاتے تھے کہ ایک شخص دوسرے کو دیکھتا لیکن موسیٰ علیہ السلام تنہا پردہ سے غسل فرماتے۔ اس پر انہوں نے کہا کہ بخدا موسیٰ کو ہمارے ساتھ غسل کرنے میں صرف یہ چیز مانع ہے کہ آپ کے خصیے بڑھے ہوئے ہیں۔ ایک مرتبہ موسیٰ علیہ السلام غسل کرنے لگے اور آپ نے کپڑوں کو ایک پتھر پر رکھ دیا۔ اتنے میں پتھر کپڑوں کو لے کر بھاگا اور موسیٰ علیہ السلام بھی اس کے پیچھے بڑی تیزی سے دوڑے۔ آپ کہتے جاتے تھے۔ اے پتھر! میرا کپڑا دے۔ اے پتھر! میرا کپڑا دے۔ اس عرصہ میں بنی اسرائیل نے موسیٰ علیہ السلام کو ننگا دیکھ لیا اور کہنے لگے کہ بخدا موسیٰ کو کوئی بیماری نہیں اور موسیٰ علیہ السلام نے کپڑا لیا اور پتھر کو مارنے لگے۔ ابوہریرہ رضی اللہ عنہ نے کہا کہ بخدا اس پتھر پر چھ یا سات مار کے نشان باقی ہیں۔' WHERE id = 278;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، انہوں نے عبیداللہ بن ابی الجعد کے واسطے سے، انہوں نے محمد بن عبدالرحمٰن سے، انہوں نے عروہ سے، وہ عائشہ رضی اللہ عنہا سے، آپ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم جب جنابت کی حالت میں ہوتے اور سونے کا ارادہ کرتے تو شرمگاہ کو دھو لیتے اور نماز کی طرح وضو کرتے۔' WHERE id = 288;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے ہشام نے یحییٰ بن کثیر کے واسطہ سے بیان کیا، انہوں نے ابوسلمہ سے کہ زینب بنت ام سلمہ نے ان سے بیان کیا اور ان سے ام سلمہ رضی اللہ عنہا نے کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک چادر میں لیٹی ہوئی تھی، اتنے میں مجھے حیض آ گیا۔ اس لیے میں آہستہ سے باہر نکل آئی اور اپنے حیض کے کپڑے پہن لیے۔ نبی کریم صلی اللہ علیہ وسلم نے پوچھا کیا تمہیں نفاس آ گیا ہے؟ میں نے عرض کیا ہاں۔ پھر مجھے آپ صلی اللہ علیہ وسلم نے بلا لیا، اور میں چادر میں آپ صلی اللہ علیہ وسلم کے ساتھ لیٹ گئی۔' WHERE id = 298;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے معتمر بن سلیمان نے خالد کے واسطہ سے بیان کیا، وہ عکرمہ سے وہ عائشہ رضی اللہ عنہا سے کہ بعض امہات المؤمنین نے اعتکاف کیا حالانکہ وہ مستحاضہ تھیں۔ ( اوپر والی روایت میں ان ہی کا ذکر ہے ) ۔' WHERE id = 309;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے، کہا ہم سے قتادہ نے، کہا مجھ سے معاذہ بنت عبداللہ نے کہ ایک عورت نے عائشہ رضی اللہ عنہا سے پوچھا کہ جس زمانہ میں ہم پاک رہتے ہیں۔ ( حیض سے ) کیا ہمارے لیے اسی زمانہ کی نماز کافی ہے۔ اس پر عائشہ رضی اللہ عنہا نے فرمایا کہ کیا تم حروریہ ہو؟ ہم نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں حائضہ ہوتی تھیں اور آپ ہمیں نماز کا حکم نہیں دیتے تھے۔ یا عائشہ رضی اللہ عنہا نے یہ فرمایا کہ ہم نماز نہیں پڑھتی تھیں۔' WHERE id = 319;
UPDATE hadiths SET urdu = 'ہم سے حسن بن مدرک نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن حماد نے بیان کیا، انہوں نے کہا ہمیں ابوعوانہ وضاح نے اپنی کتاب سے دیکھ کر خبر دی۔ انہوں نے کہا کہ ہمیں خبر دی سلیمان شیبانی نے عبداللہ بن شداد سے، انہوں نے کہا میں نے اپنی خالہ میمونہ رضی اللہ عنہا سے جو نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ تھیں سنا کہ میں حائضہ ہوتی تو نماز نہیں پڑھتی تھی اور یہ کہ آپ رسول اللہ صلی اللہ علیہ وسلم کے ( گھر میں ) نماز پڑھنے کی جگہ کے قریب لیٹی ہوتی تھی۔ آپ صلی اللہ علیہ وسلم نماز اپنی چٹائی پر پڑھتے۔ جب آپ صلی اللہ علیہ وسلم سجدہ کرتے تو آپ صلی اللہ علیہ وسلم کے کپڑے کا کوئی حصہ مجھ سے لگ جاتا تھا۔' WHERE id = 330;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے، کہا کہ ہم سے شعبہ نے حکم کے واسطے سے، انہوں نے ذر بن عبداللہ سے، انہوں نے ابن عبدالرحمٰن بن ابزی سے، انہوں نے اپنے والد سے کہ عمار نے بیان کیا پس نبی کریم صلی اللہ علیہ وسلم نے اپنے ہاتھوں کو زمین پر مارا اور اس سے اپنے چہرے اور پہنچوں کا مسح کیا' WHERE id = 340;
UPDATE hadiths SET urdu = 'ہم سے ابومصعب بن عبداللہ مطرف نے بیان کیا، انہوں نے کہا ہم سے عبدالرحمٰن بن ابی الموالی نے بیان کیا، انہوں نے محمد بن منکدر سے، انہوں نے کہا کہ میں نے جابر رضی اللہ عنہ کو ایک کپڑے میں نماز پڑھتے دیکھا اور انہوں نے بتلایا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو بھی ایک ہی کپڑے میں نماز پڑھتے دیکھا تھا۔' WHERE id = 350;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ نے بیان کیا، کہا ہم سے ابومعاویہ نے اعمش کے واسطہ سے، انہوں نے مسلم بن صبیح سے، انہوں نے مسروق بن اجدع سے، انہوں نے مغیرہ بن شعبہ سے، آپ نے فرمایا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک سفر ( غزوہ تبوک ) میں تھا۔ آپ نے ایک موقع پر فرمایا۔ مغیرہ! پانی کی چھاگل اٹھا لے۔ میں نے اسے اٹھا لیا۔ پھر رسول اللہ صلی اللہ علیہ وسلم چلے اور میری نظروں سے چھپ گئے۔ آپ نے قضائے حاجت کی۔ اس وقت آپ شامی جبہ پہنے ہوئے تھے۔ آپ ہاتھ کھولنے کے لیے آستین اوپر چڑھانی چاہتے تھے لیکن وہ تنگ تھی اس لیے آستین کے اندر سے ہاتھ باہر نکالا۔ میں نے آپ کے ہاتھوں پر پانی ڈالا۔ آپ صلی اللہ علیہ وسلم نے نماز کے وضو کی طرح وضو کیا اور اپنے خفین پر مسح کیا۔ پھر نماز پڑھی۔' WHERE id = 360;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا کہ ہمیں ابراہیم بن سعد نے خبر دی، انہوں نے کہا کہ ہم سے ابن شہاب نے بیان کیا، انہوں نے عروہ سے، انہوں نے ام المؤمنین عائشہ رضی اللہ عنہا سے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک چادر میں نماز پڑھی۔ جس میں نقش و نگار تھے۔ آپ صلی اللہ علیہ وسلم نے انہیں ایک مرتبہ دیکھا۔ پھر جب نماز سے فارغ ہوئے تو فرمایا کہ میری یہ چادر ابوجہم ( عامر بن حذیفہ ) کے پاس لے جاؤ اور ان کی انبجانیہ والی چادر لے آؤ، کیونکہ اس چادر نے ابھی نماز سے مجھ کو غافل کر دیا۔ اور ہشام بن عروہ نے اپنے والد سے روایت کی، انہوں نے عائشہ رضی اللہ عنہا سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا میں نماز میں اس کے نقش و نگار دیکھ رہا تھا، پس میں ڈرا کہ کہیں یہ مجھے غافل نہ کر دے۔' WHERE id = 370;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے عقیل سے، انہوں نے ابن شہاب سے، ان کو عروہ نے خبر دی کہ عائشہ رضی اللہ عنہا نے انہیں بتایا کہ رسول اللہ صلی اللہ علیہ وسلم اپنے گھر کے بچھونے پر نماز پڑھتے اور عائشہ رضی اللہ عنہا آپ صلی اللہ علیہ وسلم کے اور قبلہ کے درمیان اس طرح لیٹی ہوتیں جیسے ( نماز کے لیے ) جنازہ رکھا جاتا ہے۔' WHERE id = 380;
UPDATE hadiths SET urdu = 'ابن ابی مریم نے کہا، ہمیں یحییٰ بن ایوب نے خبر دی، انہوں نے کہا ہم سے حمید نے حدیث بیان کیا، انہوں نے کہا ہم سے انس بن مالک رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے نقل کر کے حدیث بیان کی۔ علی بن عبداللہ بن مدینی نے فرمایا کہ ہم سے خالد بن حارث نے بیان کیا، انہوں نے کہا ہم سے حمید طویل نے بیان کیا، انہوں نے کہا کہ میمون بن سیاہ نے انس بن مالک رضی اللہ عنہ سے پوچھا کہ اے ابوحمزہ! آدمی کی جان اور مال پر زیادتی کو کیا چیزیں حرام کرتی ہیں؟ تو انہوں نے فرمایا کہ جس نے گواہی دی کہ اللہ کے سوا کوئی معبود نہیں اور ہمارے قبلہ کی طرف منہ کیا اور ہماری نماز کی طرح نماز پڑھی اور ہمارے ذبیحہ کو کھایا تو وہ مسلمان ہے۔ پھر اس کے وہی حقوق ہیں جو عام مسلمانوں کے ہیں اور اس کی وہی ذمہ داریاں ہیں جو عام مسلمانوں پر ہیں۔' WHERE id = 390;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا کہ کہا ہم سے اسماعیل بن جعفر نے حمید کے واسطہ سے، انہوں نے انس بن مالک رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے قبلہ کی طرف ( دیوار پر ) بلغم دیکھا، جو آپ صلی اللہ علیہ وسلم کو ناگوار گزرا اور یہ ناگواری آپ صلی اللہ علیہ وسلم کے چہرہ مبارک پر دکھائی دینے لگی۔ پھر آپ صلی اللہ علیہ وسلم اٹھے اور خود اپنے ہاتھ سے اسے کھرچ ڈالا اور فرمایا کہ جب کوئی شخص نماز کے لیے کھڑا ہوتا ہے تو گویا وہ اپنے رب کے ساتھ سرگوشی کرتا ہے، یا یوں فرمایا کہ اس کا رب اس کے اور قبلہ کے درمیان ہوتا ہے۔ اس لیے کوئی شخص ( نماز میں اپنے ) قبلہ کی طرف نہ تھوکے۔ البتہ بائیں طرف یا اپنے قدموں کے نیچے تھوک سکتا ہے۔ پھر آپ نے اپنی چادر کا کنارہ لیا، اس پر تھوکا پھر اس کو الٹ پلٹ کیا اور فرمایا، یا اس طرح کر لیا کرو۔' WHERE id = 402;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن صالح نے بیان کیا، انہوں نے کہا ہم سے فلیح بن سلیمان نے ہلال بن علی سے، انہوں نے انس بن مالک رضی اللہ عنہ سے، وہ کہتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں ایک مرتبہ نماز پڑھائی، پھر آپ صلی اللہ علیہ وسلم منبر پر چڑھے، پھر نماز کے باب میں اور رکوع کے باب میں فرمایا میں تمہیں پیچھے سے بھی اسی طرح دیکھتا رہتا ہوں جیسے اب سامنے سے دیکھ رہا ہوں۔' WHERE id = 414;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے ابوالتیاح کے واسطے سے، انہوں نے انس بن مالک رضی اللہ عنہ سے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم بکریوں کے باڑوں میں نماز پڑھتے تھے، ابوالتیاح یا شعبہ نے کہا، پھر میں نے انس کو یہ کہتے ہوئے سنا کہ نبی کریم صلی اللہ علیہ وسلم بکریوں کے باڑہ میں مسجد کی تعمیر سے پہلے نماز پڑھا کرتے تھے۔' WHERE id = 424;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی حازم نے بیان کیا، انہوں نے اپنے باپ ابوحازم سہل بن دینار سے، انہوں نے سہل بن سعد رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم فاطمہ رضی اللہ عنہا کے گھر تشریف لائے دیکھا کہ علی رضی اللہ عنہ گھر میں موجود نہیں ہیں۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ تمہارے چچا کے بیٹے کہاں ہیں؟ انہوں نے بتایا کہ میرے اور ان کے درمیان کچھ ناگواری پیش آ گئی اور وہ مجھ پر خفا ہو کر کہیں باہر چلے گئے ہیں اور میرے یہاں قیلولہ بھی نہیں کیا ہے۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم نے ایک شخص سے کہا کہ علی رضی اللہ عنہ کو تلاش کرو کہ کہاں ہیں؟ وہ آئے اور بتایا کہ مسجد میں سوئے ہوئے ہیں۔ پھر نبی کریم صلی اللہ علیہ وسلم تشریف لائے۔ علی رضی اللہ عنہ لیٹے ہوئے تھے، چادر آپ صلی اللہ علیہ وسلم کے پہلو سے گر گئی تھی اور جسم پر مٹی لگ گئی تھی۔ رسول اللہ صلی اللہ علیہ وسلم جسم سے دھول جھاڑ رہے تھے اور فرما رہے تھے اٹھو ابوتراب اٹھو۔' WHERE id = 435;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے، انہوں نے کہا کہ میں نے عمرو بن دینار سے پوچھا کیا تم نے جابر بن عبداللہ سے یہ حدیث سنی ہے کہ ایک شخص مسجد نبوی میں آیا اور وہ تیر لیے ہوئے تھا، رسول اللہ صلی اللہ علیہ وسلم نے اس سے فرمایا کہ ان کی نوکیں تھامے رکھو۔' WHERE id = 445;
UPDATE hadiths SET urdu = 'ہم سے زکریا بن یحییٰ نے بیان کیا کہ کہا ہم سے عبداللہ بن نمیر نے کہ کہا ہم سے ہشام بن عروہ نے اپنے باپ عروہ بن زبیر کے واسطہ سے بیان کیا، انہوں نے عائشہ رضی اللہ عنہا سے آپ نے فرمایا کہ غزوہ خندق میں سعد ( رضی اللہ عنہ ) کے بازو کی ایک رگ ( اکحل ) میں زخم آیا تھا۔ ان کے لیے نبی کریم صلی اللہ علیہ وسلم نے مسجد میں ایک خیمہ نصب کرا دیا تاکہ آپ قریب رہ کر ان کی دیکھ بھال کیا کریں۔ مسجد ہی میں بنی غفار کے لوگوں کا بھی ایک خیمہ تھا۔ سعد رضی اللہ عنہ کے زخم کا خون ( جو رگ سے بکثرت نکل رہا تھا ) بہہ کر جب ان کے خیمہ تک پہنچا تو وہ ڈر گئے۔ انہوں نے کہا کہ اے خیمہ والو! تمہاری طرف سے یہ کیسا خون ہمارے خیمہ تک آ رہا ہے۔ پھر انہیں معلوم ہوا کہ یہ خون سعد رضی اللہ عنہ کے زخم سے بہہ رہا ہے۔ سعد رضی اللہ عنہ کا اسی زخم کی وجہ سے انتقال ہو گیا۔' WHERE id = 456;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان محمد بن فضل نے بیان کیا کہ کہا ہم سے حماد بن زید نے، انہوں نے ایوب سختیانی سے، انہوں نے ابن عمر رضی اللہ عنہما سے کہ ایک شخص نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ آپ صلی اللہ علیہ وسلم اس وقت خطبہ دے رہے تھے آنے والے نے پوچھا کہ رات کی نماز کس طرح پڑھی جائے؟ آپ صلی اللہ علیہ وسلم نے فرمایا دو دو رکعت پھر جب طلوع صبح صادق کا اندیشہ ہو تو ایک رکعت وتر کی پڑھ لے تاکہ تو نے جو نماز پڑھی ہے اسے یہ رکعت طاق بنا دے اور امام بخاری رحمہ اللہ نے فرمایا کہ ولید بن کثیر نے کہا کہ مجھ سے عبیداللہ بن عبداللہ عمری نے بیان کیا، عبداللہ بن عمر رضی اللہ عنہما نے ان سے بیان کیا کہ ایک شخص نے نبی کریم صلی اللہ علیہ وسلم کو آواز دی جب کہ آپ صلی اللہ علیہ وسلم مسجد میں تشریف فرما تھے۔' WHERE id = 466;
UPDATE hadiths SET urdu = 'اور عبداللہ بن عمر رضی اللہ عنہما نے نافع سے یہ بھی بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اس جگہ نماز پڑھی جہاں اب شرف روحاء کی مسجد کے قریب ایک چھوٹی مسجد ہے، عبداللہ بن عمر رضی اللہ عنہما اس جگہ کی نشاندہی کرتے تھے جہاں نبی کریم صلی اللہ علیہ وسلم نے نماز پڑھی تھی۔ کہتے تھے کہ یہاں تمہارے دائیں طرف جب تم مسجد میں ( قبلہ رو ہو کر ) نماز پڑھنے کے لیے کھڑے ہوتے ہو۔ جب تم ( مدینہ سے ) مکہ جاؤ تو یہ چھوٹی سی مسجد راستے کے دائیں جانب پڑتی ہے۔ اس کے اور بڑی مسجد کے درمیان ایک پتھر کی مار کا فاصلہ ہے یا اس سے کچھ کم زیادہ۔' WHERE id = 477;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا عون بن ابی حجیفہ سے، کہا میں نے اپنے باپ (وہب بن عبداللہ) سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے لوگوں کو بطحاء میں نماز پڑھائی۔ آپ صلی اللہ علیہ وسلم کے سامنے عنزہ ( ڈنڈا جس کے نیچے پھل لگا ہوا ہو ) گاڑ دیا گیا تھا۔ ( چونکہ آپ صلی اللہ علیہ وسلم مسافر تھے اس لیے ) ظہر کی دو رکعت اور عصر کی دو رکعت ادا کیں۔ آپ صلی اللہ علیہ وسلم کے سامنے سے عورتیں اور گدھے گزر رہے تھے۔' WHERE id = 487;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہمیں امام مالک بن انس نے خبر دی نافع سے، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے کہ نبی کریم صلی اللہ علیہ وسلم کعبہ کے اندر تشریف لے گئے اور اسامہ بن زید، بلال اور عثمان بن طلحہ حجبی بھی آپ صلی اللہ علیہ وسلم کے ساتھ تھے۔ پھر عثمان رضی اللہ عنہ نے کعبہ کا دروازہ بند کر دیا۔ اور آپ صلی اللہ علیہ وسلم اس میں ٹھہرے رہے۔ جب آپ صلی اللہ علیہ وسلم باہر نکلے تو میں نے بلال رضی اللہ عنہ سے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم نے اندر کیا کیا؟ انہوں نے کہا کہ آپ نے ایک ستون کو تو بائیں طرف چھوڑا اور ایک کو دائیں طرف اور تین کو پیچھے اور اس زمانہ میں خانہ کعبہ میں چھ ستون تھے۔ پھر آپ صلی اللہ علیہ وسلم نے نماز پڑھی۔ امام بخاری رحمہ اللہ نے کہا کہ ہم سے اسماعیل بن ابی ادریس نے کہا، وہ کہتے ہیں کہ مجھ سے امام مالک نے یہ حدیث یوں بیان کی کہ آپ صلی اللہ علیہ وسلم نے اپنے دائیں طرف دو ستون چھوڑے تھے۔' WHERE id = 497;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، کہا کہ ہمیں یعقوب بن ابراہیم نے خبر دی، کہا کہ مجھ سے میرے بھتیجے ابن شہاب نے بیان کیا، انہوں نے اپنے چچا سے پوچھا کہ کیا نماز کو کوئی چیز توڑ دیتی ہے؟ تو انہوں نے فرمایا کہ نہیں، اسے کوئی چیز نہیں توڑتی۔ کیونکہ مجھے عروہ بن زبیر رضی اللہ عنہ نے خبر دی ہے کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم کھڑے ہو کر رات کو نماز پڑھتے اور میں آپ صلی اللہ علیہ وسلم کے سامنے آپ صلی اللہ علیہ وسلم کے اور قبلہ کے درمیان عرض میں بستر پر لیٹی رہتی تھی۔' WHERE id = 507;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، کہا ہم سے شعبہ نے، انہوں نے کہا کہ مجھے ولید بن عیزار کوفی نے خبر دی، کہا کہ میں نے ابوعمر و شیبانی سے سنا، وہ کہتے تھے کہ میں نے اس گھر کے مالک سے سنا، (آپ عبداللہ بن مسعود رضی اللہ عنہ کے گھر کی طرف اشارہ کر رہے تھے) انہوں نے فرمایا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا کہ اللہ تعالیٰ کی بارگاہ میں کون سا عمل زیادہ محبوب ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنے وقت پر نماز پڑھنا، پھر پوچھا، اس کے بعد، فرمایا والدین کے ساتھ نیک معاملہ رکھنا۔ پوچھا اس کے بعد، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کی راہ میں جہاد کرنا۔ ابن مسعود رضی اللہ عنہ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے مجھے یہ تفصیل بتائی اور اگر میں اور سوالات کرتا تو آپ صلی اللہ علیہ وسلم اور زیادہ بھی بتلاتے۔ ( لیکن میں نے بطور ادب خاموشی اختیار کی ) ۔' WHERE id = 518;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہ ہم سے شعبہ نے بیان کیا ابوالمنہال کی روایت سے، انہوں نے ابوبرزہ (فضلہ بن عبید رضی اللہ عنہ) سے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم صبح کی نماز اس وقت پڑھتے تھے جب ہم اپنے پاس بیٹھے ہوئے شخص کو پہچان لیتے تھے۔ صبح کی نماز میں نبی کریم صلی اللہ علیہ وسلم ساٹھ سے سو تک آیتیں پڑھتے۔ اور آپ صلی اللہ علیہ وسلم ظہر اس وقت پڑھتے جب سورج ڈھل جاتا۔ اور عصر کی نماز اس وقت کہ ہم مدینہ منورہ کی آخری حد تک ( نماز پڑھنے کے بعد ) جاتے لیکن سورج اب بھی تیز رہتا تھا۔ نماز مغرب کا انس رضی اللہ عنہ نے جو وقت بتایا تھا وہ مجھے یاد نہیں رہا۔ اور نبی کریم صلی اللہ علیہ وسلم عشاء کی نماز کو تہائی رات تک دیر کرنے میں کوئی حرج نہیں سمجھتے تھے، پھر ابوالمنہال نے کہا کہ آدھی رات تک ( مؤخر کرنے میں ) کوئی حرج نہیں سمجھتے تھے۔ اور معاذ نے کہا کہ شعبہ نے فرمایا کہ پھر میں دوبارہ ابوالمنہال سے ملا تو انہوں نے فرمایا ”یا تہائی رات تک“۔' WHERE id = 530;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہمیں امام مالک رحمہ اللہ علیہ نے ابن شہاب زہری کے واسطہ سے خبر دی، انہوں نے انس بن مالک رضی اللہ عنہ سے کہ آپ نے فرمایا ہم عصر کی نماز پڑھتے ( نبی کریم صلی اللہ علیہ وسلم کے ساتھ ) اس کے بعد کوئی شخص قباء جاتا اور جب وہاں پہنچ جاتا تو سورج ابھی بلند ہوتا تھا۔' WHERE id = 540;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے یزید بن ابی عبید نے بیان کیا سلمہ بن اکوع رضی اللہ عنہ سے، فرمایا کہ ہم نماز مغرب نبی کریم صلی اللہ علیہ وسلم کے ساتھ اس وقت پڑھتے تھے جب سورج پردے میں چھپ جاتا۔' WHERE id = 550;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے اسماعیل سے، کہا ہم سے قیس نے بیان کیا، کہا مجھ سے جریر بن عبداللہ نے بیان کیا، کہ ہم نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر تھے آپ صلی اللہ علیہ وسلم نے چاند کی طرف نظر اٹھائی جو چودھویں رات کا تھا۔ پھر فرمایا کہ تم لوگ بے ٹوک اپنے رب کو اسی طرح دیکھو گے جیسے اس چاند کو دیکھ رہے ہو ( اسے دیکھنے میں تم کو کسی قسم کی بھی مزاحمت نہ ہو گی ) یا یہ فرمایا کہ تمہیں اس کے دیدار میں مطلق شبہ نہ ہو گا اس لیے اگر تم سے سورج کے طلوع اور غروب سے پہلے ( فجر اور عصر ) کی نمازوں کے پڑھنے میں کوتاہی نہ ہو سکے تو ایسا ضرور کرو۔ ( کیونکہ ان ہی کے طفیل دیدار الٰہی نصیب ہو گا یا ان ہی وقتوں میں یہ رویت ملے گی ) پھر آپ صلی اللہ علیہ وسلم نے یہ آیت تلاوت فرمائی «فسبح بحمد ربك قبل طلوع الشمس وقبل غروبها» ”پس اپنے رب کے حمد کی تسبیح پڑھ سورج کے نکلنے اور اس کے غروب ہونے سے پہلے۔“ امام ابوعبداللہ بخاری رحمہ اللہ نے کہا کہ ابن شہاب نے اسماعیل کے واسطہ سے جو قیس سے بواسطہ جریر ( راوی ہیں ) یہ زیادتی نقل کی کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم اپنے رب کو صاف دیکھو گے“۔' WHERE id = 561;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہ کہا ہمیں امام مالک نے نافع سے خبر دی، انہوں نے ابن عمر رضی اللہ عنہما سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، کوئی تم میں سے انتظار میں نہ بیٹھا رہے کہ سورج طلوع ہوتے ہی نماز کے لیے کھڑا ہو جائے، اسی طرح سورج کے ڈوبنے کے انتظار میں بھی نہ رہنا چاہیے۔' WHERE id = 572;
UPDATE hadiths SET urdu = 'ہم سے عمران بن میسرہ نے روایت کیا، کہا ہم سے محمد بن فضیل نے بیان کیا، کہا کہ ہم سے حصین بن عبدالرحمٰن نے عبداللہ بن ابی قتادہ سے، انہوں نے اپنے باپ سے، کہا ہم ( خیبر سے لوٹ کر ) نبی کریم صلی اللہ علیہ وسلم کے ساتھ رات میں سفر کر رہے تھے۔ کسی نے کہا کہ یا رسول اللہ! آپ اب پڑاؤ ڈال دیتے تو بہتر ہوتا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ مجھے ڈر ہے کہ کہیں نماز کے وقت بھی تم سوتے نہ رہ جاؤ۔ اس پر بلال رضی اللہ عنہ بولے کہ میں آپ سب لوگوں کو جگا دوں گا۔ چنانچہ سب لوگ لیٹ گئے۔ اور بلال رضی اللہ عنہ نے بھی اپنی پیٹھ کجاوہ سے لگا لی۔ اور ان کی بھی آنکھ لگ گئی اور جب نبی کریم صلی اللہ علیہ وسلم بیدار ہوئے تو سورج کے اوپر کا حصہ نکل چکا تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا بلال! تو نے کیا کہا تھا۔ وہ بولے آج جیسی نیند مجھے کبھی نہیں آئی۔ پھر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ تمہاری ارواح کو جب چاہتا ہے قبض کر لیتا ہے اور جس وقت چاہتا ہے واپس کر دیتا ہے۔ اے بلال! اٹھ اور اذان دے۔ پھر آپ صلی اللہ علیہ وسلم نے وضو کیا اور جب سورج بلند ہو کر روشن ہو گیا تو آپ صلی اللہ علیہ وسلم کھڑے ہوئے اور نماز پڑھائی۔' WHERE id = 582;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا سماک بن عطیہ سے، انہوں نے ایوب سختیانی سے، انہوں نے ابوقلابہ سے، انہوں نے انس رضی اللہ عنہ سے کہ بلال رضی اللہ عنہ کو حکم دیا گیا کہ اذان کے کلمات دو دو مرتبہ کہیں اور سوا «قد قامت الصلوة» کے تکبیر کے کلمات ایک ایک دفعہ کہیں۔' WHERE id = 592;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا کہ ہمیں امام مالک نے سمی سے جو ابوبکر عبدالرحمٰن بن حارث کے غلام تھے خبر دی، انہوں نے ابوصالح ذکوان سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر لوگوں کو معلوم ہوتا کہ اذان کہنے اور نماز پہلی صف میں پڑھنے سے کتنا ثواب ملتا ہے۔ پھر ان کے لیے قرعہ ڈالنے کے سوائے اور کوئی چارہ نہ باقی رہتا، تو البتہ اس پر قرعہ اندازی ہی کرتے اور اگر لوگوں کو معلوم ہو جاتا کہ نماز کے لیے جلدی آنے میں کتنا ثواب ملتا ہے تو اس کے لیے دوسرے سے آگے بڑھنے کی کوشش کرتے۔ اور اگر لوگوں کو معلوم ہو جاتا کہ عشاء اور صبح کی نماز کا ثواب کتنا ملتا ہے، تو ضرور چوتڑوں کے بل گھسیٹتے ہوئے ان کے لیے آتے۔' WHERE id = 602;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یزید مقری نے بیان کیا، انہوں نے کہا کہ ہم سے کہمس بن حسن نے بیان کیا، انہوں نے عبداللہ بن بریدہ سے، انہوں نے عبداللہ بن مغفل رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہر دو اذانوں ( اذان و تکبیر ) کے بیچ میں نماز ہے۔ ہر دو اذانوں کے درمیان نماز ہے۔ پھر تیسری مرتبہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر کوئی پڑھنا چاہے۔' WHERE id = 613;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا کہ ہم سے ہشام دستوائی نے بیان کیا، کہا مجھے یحییٰ نے عبداللہ عبدالوہاب بن ابی قتادہ سے یہ حدیث لکھ کر بھیجی کہ وہ اپنے باپ (ابوقتادہ) سے بیان کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب نماز کے لیے تکبیر کہی جائے تو اس وقت تک نہ کھڑے ہو جب تک مجھے نکلتے ہوئے نہ دیکھ لو۔' WHERE id = 623;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالواحد نے بیان کیا، انہوں نے کہا کہ ہم سے اعمش نے بیان کیا، انہوں نے کہا کہ میں نے ابوصالح سے سنا، انہوں نے کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ آدمی کی جماعت کے ساتھ نماز گھر میں یا بازار میں پڑھنے سے پچیس درجہ زیادہ بہتر ہے۔ وجہ یہ ہے کہ جب ایک شخص وضو کرتا ہے اور اس کے تمام آداب کو ملحوظ رکھ کر اچھی طرح وضو کرتا ہے پھر مسجد کا راستہ پکڑتا ہے اور سوا نماز کے اور کوئی دوسرا ارادہ اس کا نہیں ہوتا، تو ہر قدم پر اس کا ایک درجہ بڑھتا ہے اور ایک گناہ معاف کیا جاتا ہے اور جب نماز سے فارغ ہو جاتا ہے تو فرشتے اس وقت تک اس کے لیے برابر دعائیں کرتے رہتے ہیں جب تک وہ اپنے مصلے پر بیٹھا رہے۔ کہتے ہیں «اللهم صل عليه،‏‏‏‏ اللهم ارحمه‏» اے اللہ! اس پر اپنی رحمتیں نازل فرما۔ اے اللہ! اس پر رحم کر اور جب تک تم نماز کا انتظار کرتے رہو گویا تم نماز ہی میں مشغول ہو۔' WHERE id = 633;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے عبیداللہ بن عمر عمری سے بیان کیا، کہا کہ مجھ سے خبیب بن عبدالرحمٰن نے بیان کیا حفص بن عاصم سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ سات طرح کے آدمی ہوں گے۔ جن کو اللہ اس دن اپنے سایہ میں جگہ دے گا۔ جس دن اس کے سایہ کے سوا اور کوئی سایہ نہ ہو گا۔ اول انصاف کرنے والا بادشاہ، دوسرے وہ نوجوان جو اپنے رب کی عبادت میں جوانی کی امنگ سے مصروف رہا، تیسرا ایسا شخص جس کا دل ہر وقت مسجد میں لگا رہتا ہے، چوتھے دو ایسے شخص جو اللہ کے لیے باہم محبت رکھتے ہیں اور ان کے ملنے اور جدا ہونے کی بنیاد یہی «للهى» ( اللہ کے لیے محبت ) محبت ہے، پانچواں وہ شخص جسے کسی باعزت اور حسین عورت نے ( برے ارادہ سے ) بلایا لیکن اس نے کہہ دیا کہ میں اللہ سے ڈرتا ہوں، چھٹا وہ شخص جس نے صدقہ کیا، مگر اتنے پوشیدہ طور پر کہ بائیں ہاتھ کو بھی خبر نہیں ہوئی کہ داہنے ہاتھ نے کیا خرچ کیا۔ ساتواں وہ شخص جس نے تنہائی میں اللہ کو یاد کیا اور ( بے ساختہ ) آنکھوں سے آنسو جاری ہو گئے۔' WHERE id = 643;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہم سے انس بن سیرین نے بیان کیا، کہا کہ میں نے انس رضی اللہ عنہ سے سنا کہ انصار میں سے ایک مرد نے عذر پیش کیا کہ میں آپ کے ساتھ نماز میں شریک نہیں ہو سکتا اور وہ موٹا آدمی تھا۔ اس نے نبی کریم صلی اللہ علیہ وسلم کے لیے کھانا تیار کیا اور آپ صلی اللہ علیہ وسلم کو اپنے گھر دعوت دی اور آپ صلی اللہ علیہ وسلم کے لیے ایک چٹائی بچھا دی اور اس کے ایک کنارہ کو ( صاف کر کے ) دھو دیا۔ نبی کریم صلی اللہ علیہ وسلم نے اس بوریے پر دو رکعتیں پڑھیں۔ آل جارود کے ایک شخص ( عبدالحمید ) نے انس رضی اللہ عنہ سے پوچھا کہ کیا نبی کریم صلی اللہ علیہ وسلم چاشت کی نماز پڑھتے تھے تو انہوں نے فرمایا کہ اس دن کے سوا اور کبھی میں نے آپ صلی اللہ علیہ وسلم کو پڑھتے نہیں دیکھا۔' WHERE id = 653;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے بیان کیا، کہا کہ ہمیں شعیب بن ابی حمزہ نے زہری سے خبر دی، کہا کہ مجھے انس بن مالک انصاری رضی اللہ عنہ نے خبر دی…. آپ نبی کریم صلی اللہ علیہ وسلم کی پیروی کرنے والے، آپ کے خادم اور صحابی تھے…. کہ نبی کریم صلی اللہ علیہ وسلم کے مرض الموت میں ابوبکر صدیق رضی اللہ عنہ نماز پڑھاتے تھے۔ پیر کے دن جب لوگ نماز میں صف باندھے کھڑے ہوئے تھے تو نبی کریم صلی اللہ علیہ وسلم حجرہ کا پردہ ہٹائے کھڑے ہوئے، ہماری طرف دیکھ رہے تھے۔ آپ صلی اللہ علیہ وسلم کا چہرہ مبارک ( حسن و جمال اور صفائی میں ) گویا مصحف کا ورق تھا۔ آپ صلی اللہ علیہ وسلم مسکرا کر ہنسنے لگے۔ ہمیں اتنی خوشی ہوئی کہ خطرہ ہو گیا کہ کہیں ہم سب آپ صلی اللہ علیہ وسلم کو دیکھنے ہی میں نہ مشغول ہو جائیں اور نماز توڑ دیں۔ ابوبکر رضی اللہ عنہ الٹے پاؤں پیچھے ہٹ کر صف کے ساتھ آ ملنا چاہتے تھے۔ انہوں نے سمجھا کہ نبی کریم صلی اللہ علیہ وسلم نماز کے لیے تشریف لا رہے ہیں، لیکن آپ صلی اللہ علیہ وسلم نے ہمیں اشارہ کیا کہ نماز پوری کر لو۔ پھر آپ صلی اللہ علیہ وسلم نے پردہ ڈال دیا۔ پس نبی کریم صلی اللہ علیہ وسلم کی وفات اسی دن ہو گئی۔ ( «اناللہ و انا الیہ راجعون»)' WHERE id = 663;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، انہوں نے کہا کہ ہم سے یحییٰ بن سعید نے سفیان سے بیان کیا، انہوں نے کہا کہ مجھ سے ابواسحاق نے بیان کیا، کہا کہ مجھ سے عبداللہ بن یزید نے بیان کیا، کہا کہ مجھ سے براء بن عازب رضی اللہ عنہ نے بیان کیا، وہ جھوٹے نہیں تھے۔ (بلکہ نہایت ہی سچے تھے) انہوں نے بتلایا کہ جب نبی کریم صلی اللہ علیہ وسلم «سمع الله لمن حمده‏» کہتے تو ہم میں سے کوئی بھی اس وقت تک نہ جھکتا جب تک نبی کریم صلی اللہ علیہ وسلم سجدہ میں نہ چلے جاتے پھر ہم لوگ سجدہ میں جاتے۔ ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان ثوری نے، انہوں نے ابواسحٰق سے جیسے اوپر گزرا۔' WHERE id = 673;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا کہ ہم سے شعبہ نے عمرو بن دینار سے بیان کیا، انہوں نے جابر بن عبداللہ سے کہ معاذ بن جبل رضی اللہ عنہ، نبی کریم صلی اللہ علیہ وسلم کے ساتھ نماز پڑھتے پھر واپس آ کر اپنی قوم کی امامت کیا کرتے تھے۔' WHERE id = 684;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہمیں محمد بن ابراہیم بن عدی نے سعید بن ابی عروبہ کے واسطہ سے خبر دی، انہوں نے قتادہ سے، انہوں نے انس بن مالک رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نماز کی نیت باندھتا ہوں، ارادہ یہ ہوتا ہے کہ نماز کو طویل کروں گا، لیکن بچے کے رونے کی آواز سن کر مختصر کر دیتا ہوں کیونکہ میں اس درد کو سمجھتا ہوں جو بچے کے رونے کی وجہ سے ماں کو ہو جاتا ہے۔ اور موسیٰ بن اسماعیل نے کہا ہم سے ابان بن یزید نے بیان کیا، کہا ہم سے قتادہ نے، کہا ہم سے انس نے نبی کریم صلی اللہ علیہ وسلم سے یہی حدیث بیان کی۔' WHERE id = 694;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا کہ ہم کو عبدالرزاق نے خبر دی، انہوں نے کہا کہ ہمیں معمر نے ہمام بن منبہ کے واسطہ سے خبر دی، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ امام اس لیے ہوتا ہے تاکہ اس کی پیروی کی جائے، اس لیے تم اس سے اختلاف نہ کرو۔ جب وہ رکوع کرے تو تم بھی رکوع کرو اور جب وہ «سمع الله لمن حمده‏» کہے تو تم «ربنا لك الحمد‏» کہو اور جب وہ سجدہ کرے تو تم بھی سجدہ کرو۔ اور جب وہ بیٹھ کر نماز پڑھے تو تم سب بھی بیٹھ کر پڑھو اور نماز میں صفیں برابر رکھو، کیونکہ نماز کا حسن صفوں کے برابر رکھنے میں ہے۔' WHERE id = 705;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے یہ بیان کیا، انہوں نے کہا کہ ہم سے شعیب نے زہری کے واسطہ سے بیان کیا، انہوں نے کہا کہ مجھے انس بن مالک انصاری رضی اللہ عنہ نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم ایک گھوڑے پر سوار ہوئے اور ( گر جانے کی وجہ سے ) آپ صلی اللہ علیہ وسلم کے دائیں پہلو میں زخم آ گئے۔ انس رضی اللہ عنہ نے بتلایا کہ اس دن ہمیں آپ صلی اللہ علیہ وسلم نے ایک نماز پڑھائی، چونکہ آپ صلی اللہ علیہ وسلم بیٹھے ہوئے تھے، اس لیے ہم نے بھی آپ صلی اللہ علیہ وسلم کے پیچھے بیٹھ کر نماز پڑھی۔ پھر سلام کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا کہ امام اس لیے ہے کہ اس کی پیروی کی جائے۔ اس لیے جب وہ کھڑے ہو کر نماز پڑھے تو تم بھی کھڑے ہو کر پڑھو اور جب وہ رکوع کرے تو تم بھی رکوع کرو اور جب وہ سر اٹھائے تو تم بھی اٹھاؤ اور جب وہ سجدہ کرے تو تم بھی کرو اور جب وہ «سمع الله لمن حمده‏» کہے تو تم «ربنا ولك الحمد» کہو۔' WHERE id = 715;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا کہ ہم سے غندر نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ میں نے قتادہ سے سنا، وہ انس بن مالک رضی اللہ عنہ سے بیان کرتے تھے اور وہ نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا رکوع اور سجود پوری طرح کیا کرو۔ اللہ کی قسم! میں تمہیں اپنے پیچھے سے بھی دیکھتا رہتا ہوں یا اس طرح کہا کہ پیٹھ پیچھے سے جب تم رکوع کرتے ہو اور سجدہ کرتے ہو ( تو میں تمہیں دیکھتا ہوں ) ۔' WHERE id = 725;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے زہری سے بیان کیا، انہوں نے عروہ سے، انہوں نے عائشہ رضی اللہ عنہا سے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک دھاری دار چادر میں نماز پڑھی۔ پھر فرمایا کہ اس کے نقش و نگار نے مجھے غافل کر دیا۔ اسے لے جا کر ابوجہم کو واپس کر دو اور ان سے ( بجائے اس کے ) سادی چادر مانگ لاؤ۔' WHERE id = 735;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، انہوں نے ہشام دستوائی سے، انہوں نے یحییٰ بن ابی کثیر سے، انہوں نے عبداللہ بن ابی قتادہ سے، انہوں نے اپنے باپ ابوقتادہ رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم ظہر اور عصر کی دو رکعات میں سورۃ فاتحہ اور ایک ایک سورۃ پڑھتے تھے۔ اور آپ صلی اللہ علیہ وسلم کبھی کبھی کوئی آیت ہمیں سنا بھی دیا کرتے۔' WHERE id = 745;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے اسماعیل بن ابراہیم نے بیان کیا، کہا کہ ہمیں عبدالملک ابن جریج نے خبر دی، کہا کہ مجھے عطاء بن ابی رباح نے خبر دی کہ انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، وہ فرماتے تھے کہ ہر نماز میں قرآن مجید کی تلاوت کی جائے گی۔ جن میں نبی کریم صلی اللہ علیہ وسلم نے ہمیں قرآن سنایا تھا ہم بھی تمہیں ان میں سنائیں گے اور جن نمازوں میں آپ صلی اللہ علیہ وسلم نے آہستہ قرآت کی ہم بھی ان میں آہستہ ہی قرآت کریں گے اور اگر سورۃ فاتحہ ہی پڑھو جب بھی کافی ہے، لیکن اگر زیادہ پڑھ لو تو اور بہتر ہے۔' WHERE id = 755;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، انہوں نے امام مالک رحمہ اللہ سے، انہوں نے ابوبکر بن عبدالرحمٰن کے غلام سمی سے، انہوں نے ابوصالح سمان سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب «غير المغضوب عليهم ولا الضالين‏» کہے تو تم بھی «آمين» کہو کیونکہ جس نے فرشتوں کے ساتھ «آمين» کہی اس کے پچھلے تمام گناہ معاف کر دیئے جاتے ہیں۔ سمی کے ساتھ اس حدیث کو محمد بن عمرو نے ابوسلمہ سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے روایت کیا۔ اور نعیم مجمر نے بھی ابوہریرہ رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 766;
UPDATE hadiths SET urdu = 'ہم سے بدل بن محبر نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا، انہوں نے کہا کہ مجھے حکم نے ابن ابی لیلیٰ سے خبر دی، انہوں نے براء بن عازب رضی اللہ عنہ سے، انہوں نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم کے رکوع و سجود، دونوں سجدوں کے درمیان کا وقفہ اور جب رکوع سے سر اٹھاتے تو تقریباً سب برابر تھے۔ سوا قیام اور تشہد کے قعود کے۔' WHERE id = 776;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا کہ ہم سے حماد بن زید نے بیان کیا، انہوں نے ایوب سختیانی سے، انہوں نے ابوقلابہ سے کہ مالک بن حویرث رضی اللہ عنہ ہمیں ( نماز پڑھ کر ) دکھلاتے کہ نبی کریم صلی اللہ علیہ وسلم کس طرح نماز پڑھتے تھے اور یہ نماز کا وقت نہیں تھا۔ چنانچہ آپ ( ایک مرتبہ ) کھڑے ہوئے اور پوری طرح کھڑے رہے۔ پھر جب رکوع کیا اور پوری طمانیت کے ساتھ سر اٹھایا تب بھی تھوڑی دیر سیدھے کھڑے رہے۔ ابوقلابہ نے بیان کیا کہ مالک رضی اللہ عنہ نے ہمارے اس شیخ ابویزید کی طرح نماز پڑھائی۔ ابویزید جب دوسرے سجدہ سے سر اٹھاتے تو پہلے اچھی طرح بیٹھ لیتے پھر کھڑے ہوتے۔' WHERE id = 786;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، انہوں نے کہا ہم سے وہیب بن خالد نے بیان کیا، انہوں نے عبداللہ بن طاؤس سے، انہوں نے اپنے باپ سے، انہوں نے ابن عباس رضی اللہ عنہما سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا مجھے سات اعضاء پر سجدہ کرنے کا حکم ہوا ہے۔ پیشانی پر اور اپنے ہاتھ سے ناک کی طرف اشارہ کیا اور دونوں ہاتھ اور دونوں گھٹنے اور دونوں پاؤں کی انگلیوں پر۔ اس طرح کہ ہم نہ کپڑے سمیٹیں نہ بال۔' WHERE id = 796;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، انہوں نے کہا کہ ہم سے وہیب نے بیان کیا، انہوں نے ایوب سختیانی سے، انہوں نے ابوقلابہ سے، انہوں نے بیان کیا کہ مالک بن حویرث رضی اللہ عنہ ہمارے یہاں تشریف لائے اور آپ نے ہماری اس مسجد میں نماز پڑھائی۔ آپ نے فرمایا کہ میں نماز پڑھا رہا ہوں لیکن میری نیت کسی فرض کی ادائیگی نہیں ہے بلکہ میں صرف تم کو یہ دکھانا چاہتا ہوں کہ نبی کریم کس طرح نماز پڑھا کرتے تھے۔ ایوب سختیانی نے بیان کیا کہ میں نے ابوقلابہ سے پوچھا کہ مالک رضی اللہ عنہ کس طرح نماز پڑھتے تھے؟ تو انہوں نے فرمایا کہ ہمارے شیخ عمرو بن سلمہ کی طرح۔ ایوب نے بیان کیا کہ شیخ تمام تکبیرات کہتے تھے اور جب دوسرے سجدہ سے سر اٹھاتے تو تھوڑی دیر بیٹھتے اور زمین کا سہارا لے کر پھر اٹھتے۔' WHERE id = 807;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا کہ ہم سے ہشام دستوائی نے یحییٰ بن ابی کثیر سے بیان کیا ان سے ابوسلمہ بن عبدالرحمٰن نے انہوں نے کہا کہ میں نے ابو سعید خدری رضی اللہ عنہ سے دریافت کیا تو آپ نے بتلایا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو کیچڑ میں سجدہ کرتے ہوئے دیکھا۔ مٹی کا اثر آپ صلی اللہ علیہ وسلم کی پیشانی پر صاف ظاہر تھا۔' WHERE id = 818;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن منیر نے بیان کیا، انہوں نے یزید بن ہارون سے سنا، انہیں حمید ذیلی نے خبر دی، اور انہیں انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک رات ( عشاء کی ) نماز میں دیر فرمائی تقریباً آدھی رات تک۔ پھر آخر حجرہ سے باہر تشریف لائے اور نماز کے بعد ہماری طرف منہ کیا اور فرمایا کہ دوسرے لوگ نماز پڑھ کر سو چکے لیکن تم لوگ جب تک نماز کا انتظار کرتے رہے گویا کہ نماز میں رہے ( یعنی تم کو نماز کا ثواب ملتا رہا ) ۔' WHERE id = 828;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہ کہا ہم سے سفیان بن عیینہ نے عمرو بن دینار سے بیان کیا، کہا کہ مجھے کریب نے خبر دی ابن عباس سے، انہوں نے بیان کیا کہ ایک رات میں اپنی خالہ میمونہ رضی اللہ عنہا کے یہاں سویا اور رسول اللہ صلی اللہ علیہ وسلم بھی وہاں سو گئے۔ پھر رات کا ایک حصہ جب گزر گیا آپ صلی اللہ علیہ وسلم کھڑے ہوئے اور ایک لٹکی ہوئی مشک سے ہلکا سا وضو کیا۔ عمرو ( راوی حدیث نے ) اس وضو کو بہت ہی ہلکا بتلایا ( یعنی اس میں آپ صلی اللہ علیہ وسلم نے بہت کم پانی استعمال فرمایا ) پھر آپ صلی اللہ علیہ وسلم نماز کے لیے کھڑے ہوئے اس کے بعد میں نے بھی اٹھ کر اسی طرح وضو کیا جیسے آپ صلی اللہ علیہ وسلم نے کیا تھا پھر میں آپ صلی اللہ علیہ وسلم کے بائیں طرف کھڑا ہو گیا۔ لیکن آپ صلی اللہ علیہ وسلم نے مجھے داہنی طرف پھیر دیا پھر اللہ تعالیٰ نے جتنا چاہا آپ صلی اللہ علیہ وسلم نے نماز پڑھی پھر آپ صلی اللہ علیہ وسلم لیٹ رہے پھر سو گئے۔ یہاں تک کہ آپ صلی اللہ علیہ وسلم خراٹے لینے لگے۔ آخر مؤذن نے آ کر آپ صلی اللہ علیہ وسلم کو نماز کی خبر دی اور آپ صلی اللہ علیہ وسلم اس کے ساتھ نماز کے لیے تشریف لے گئے اور نماز پڑھائی مگر ( نیا ) وضو نہیں کیا سفیان نے کہا۔ ہم نے عمرو بن دینار سے کہا کہ لوگ کہتے ہیں کہ ( سوتے وقت ) آپ صلی اللہ علیہ وسلم کی ( صرف ) آنکھیں سوتی تھیں لیکن دل نہیں سوتا تھا۔ عمرو بن دینار نے جواب دیا کہ میں نے عبید بن عمیر سے سنا وہ کہتے تھے کہ انبیاء کا خواب بھی وحی ہوتا ہے پھر عبید نے اس آیت کی تلاوت کی «إني أرى في المنام أني أذبحك‏» ( ترجمہ ) میں نے خواب دیکھا ہے کہ تمہیں ذبح کر رہا ہوں۔' WHERE id = 839;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا کہ ہمیں امام مالک رحمہ اللہ نے یحییٰ بن سعید سے خبر دی، ان سے عمرہ بنت عبدالرحمٰن نے، ان سے عائشہ رضی اللہ عنہا نے، انہوں نے فرمایا کہ آج عورتوں میں جو نئی باتیں پیدا ہو گئی ہیں اگر رسول اللہ صلی اللہ علیہ وسلم انہیں دیکھ لیتے تو ان کو مسجد میں آنے سے روک دیتے جس طرح بنی اسرائیل کی عورتوں کو روک دیا گیا تھا۔ میں نے پوچھا کہ کیا بنی اسرائیل کی عورتوں کو روک دیا گیا تھا؟ آپ نے فرمایا کہ ہاں۔' WHERE id = 849;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا کہ ہمیں امام مالک نے ابوبکر بن عبدالرحمٰن کے غلام سمی سے خبر دی، جنہیں ابوصالح سمان نے، انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص جمعہ کے دن غسل جنابت کر کے نماز پڑھنے جائے تو گویا اس نے ایک اونٹ کی قربانی دی ( اگر اول وقت مسجد میں پہنچا ) اور اگر بعد میں گیا تو گویا ایک گائے کی قربانی دی اور جو تیسرے نمبر پر گیا تو گویا اس نے ایک سینگ والے مینڈھے کی قربانی دی۔ اور جو کوئی چوتھے نمبر پر گیا تو اس نے گویا ایک مرغی کی قربانی دی اور جو کوئی پانچویں نمبر پر گیا اس نے گویا انڈا اللہ کی راہ میں دیا۔ لیکن جب امام خطبہ کے لیے باہر آ جاتا ہے تو فرشتے خطبہ سننے میں مشغول ہو جاتے ہیں۔' WHERE id = 861;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان ثوری نے سعد بن ابراہیم کے واسطے سے بیان کیا، ان سے عبدالرحمٰن بن ہرمز نے، ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم جمعہ کے دن فجر کی نماز میں «الم تنزيل‏» اور «هل أتى على الإنسان‏» پڑھا کرتے تھے۔' WHERE id = 871;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا، انہوں نے کہا کہ ہم سے عبداللہ بن وہب نے بیان کیا، انہوں نے کہا کہ مجھے عمرو بن حارث نے خبر دی، ان سے عبیداللہ بن ابی جعفر نے کہ محمد بن جعفر بن زبیر نے ان سے بیان کیا، ان سے عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ نے، آپ نے کہا کہ لوگ جمعہ کی نماز پڑھنے اپنے گھروں سے اور اطراف مدینہ گاؤں سے ( مسجد نبوی میں ) باری باری آیا کرتے تھے۔ لوگ گردوغبار میں چلے آتے، گرد میں اٹے ہوئے اور پسینہ میں شرابور۔ اس قدر پسینہ ہوتا کہ تھمتا ( رکتا ) نہیں تھا۔ اسی حالت میں ایک آدمی رسول اللہ صلی اللہ علیہ وسلم کے پاس آیا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم لوگ اس دن ( جمعہ میں ) غسل کر لیا کرتے تو بہتر ہوتا۔' WHERE id = 881;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، انہوں نے کہا کہ ہم سے ابن ابی ذئب نے زہری کے واسطے سے بیان کیا، ان سے سائب بن یزید نے کہ نبی کریم صلی اللہ علیہ وسلم اور ابوبکر اور عمر رضی اللہ عنہما کے زمانے میں جمعہ کی پہلی اذان اس وقت دی جاتی تھی جب امام منبر پر خطبہ کے لیے بیٹھتے لیکن عثمان رضی اللہ عنہ کے زمانہ میں جب مسلمانوں کی کثرت ہو گئی تو وہ مقام زوراء سے ایک اور اذان دلوانے لگے۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) فرماتے ہیں کہ زوراء مدینہ کے بازار میں ایک جگہ ہے۔' WHERE id = 891;
UPDATE hadiths SET urdu = 'اور محمود بن غیلان (امام بخاری رحمہ اللہ کے استاذ) نے کہا کہ ہم سے ابواسامہ نے بیان کیا کہ ہم سے ہشام بن عروہ نے بیان کیا، کہ مجھے فاطمہ بنت منذر نے خبر دی، ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے، انہوں نے کہا کہ میں عائشہ رضی اللہ عنہا کے پاس گئی۔ لوگ نماز پڑھ رہے تھے۔ میں نے ( اس بے وقت نماز پر تعجب سے پوچھا کہ ) یہ کیا ہے؟ عائشہ رضی اللہ عنہا نے سر سے آسمان کی طرف اشارہ کیا۔ میں نے پوچھا کیا کوئی نشانی ہے؟ انہوں نے سر کے اشارہ سے ہاں کہا ( کیونکہ سورج گہن ہو گیا تھا ) اسماء رضی اللہ عنہا نے کہا کہ نبی کریم صلی اللہ علیہ وسلم دیر تک نماز پڑھتے رہے۔ یہاں تک کہ مجھ کو غشی آنے لگی۔ قریب ہی ایک مشک میں پانی بھرا رکھا تھا۔ میں اسے کھول کر اپنے سر پر پانی ڈالنے لگی۔ پھر جب سورج صاف ہو گیا تو رسول اللہ صلی اللہ علیہ وسلم نے نماز ختم کر دی۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے خطبہ دیا۔ پہلے اللہ تعالیٰ کی اس کی شان کے مناسب تعریف بیان کی۔ اس کے بعد فرمایا «امابعد» ! اتنا فرمانا تھا کہ کچھ انصاری عورتیں شور کرنے لگیں۔ اس لیے میں ان کی طرف بڑھی کہ انہیں چپ کراؤں ( تاکہ رسول اللہ صلی اللہ علیہ وسلم کی بات اچھی طرح سن سکوں مگر میں آپ کا کلام نہ سن سکی ) تو پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم نے کیا فرمایا؟ انہوں نے بتایا کہ آپ نے فرمایا کہ بہت سی چیزیں جو میں نے اس سے پہلے نہیں دیکھی تھیں، آج اپنی اس جگہ سے میں نے انہیں دیکھ لیا۔ یہاں تک کہ جنت اور دوزخ تک میں نے آج دیکھی۔ مجھے وحی کے ذریعہ یہ بھی بتایا گیا کہ قبروں میں تمہاری ایسی آزمائش ہو گی جیسے کانے دجال کے سامنے یا اس کے قریب قریب۔ تم میں سے ہر ایک کے پاس فرشتہ آئے گا اور پوچھے گا کہ تو اس شخص کے بارے میں کیا اعتقاد رکھتا تھا؟ مومن یا یہ کہا کہ یقین والا ( ہشام کو شک تھا ) کہے گا کہ وہ محمد رسول اللہ صلی اللہ علیہ وسلم ہیں، ہمارے پاس ہدایت اور واضح دلائل لے کر آئے، اس لیے ہم ان پر ایمان لائے، ان کی دعوت قبول کی، ان کی اتباع کی اور ان کی تصدیق کی۔ اب اس سے کہا جائے گا کہ تو تو صالح ہے، آرام سے سو جا۔ ہم پہلے ہی جانتے تھے کہ تیرا ان پر ایمان ہے۔ ہشام نے شک کے اظہار کے ساتھ کہا کہ رہا منافق یا شک کرنے والا تو جب اس سے پوچھا جائے گا کہ تو اس شخص کے بارے میں کیا کہتا ہے تو وہ جواب دے گا کہ مجھے نہیں معلوم میں نے لوگوں کو ایک بات کہتے سنا اسی کے مطابق میں نے بھی کہا۔ ہشام نے بیان کیا کہ فاطمہ بنت منذر نے جو کچھ کہا تھا۔ میں نے وہ سب یاد رکھا۔ لیکن انہوں نے قبر میں منافقوں پر سخت عذاب کے بارے میں جو کچھ کہا وہ مجھے یاد نہیں رہا۔' WHERE id = 901;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے عبد العزیز بن انس نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے (دوسری سند) اور حماد بن یونس سے بھی روایت کی عبدالعزیز اور یونس دونوں نے ثابت سے، انہوں نے انس رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم جمعہ کا خطبہ دے رہے تھے کہ ایک شخص کھڑا ہو گیا اور عرض کیا یا رسول اللہ صلی اللہ علیہ وسلم مویشی اور بکریاں ہلاک ہو گئیں ( بارش نہ ہونے کی وجہ سے ) آپ دعا فرمائیں کہ اللہ تعالیٰ بارش برسائے۔ چنانچہ آپ صلی اللہ علیہ وسلم نے دونوں ہاتھ پھیلائے اور دعا کی۔' WHERE id = 911;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا کہ ہمیں شعیب نے زہری سے خبر دی، انہوں نے زہری سے پوچھا کیا نبی کریم صلی اللہ علیہ وسلم نے صلوۃ خوف پڑھی تھی؟ اس پر انہوں نے فرمایا کہ ہمیں سالم نے خبر دی کہ عبداللہ بن عمر رضی اللہ عنہما نے بتلایا کہ میں نجد کی طرف نبی کریم صلی اللہ علیہ وسلم کے ساتھ غزوہ ( ذات الرقاع ) میں شریک تھا۔ دشمن سے مقابلہ کے وقت ہم نے صفیں باندھیں۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم نے ہمیں خوف کی نماز پڑھائی ( تو ہم میں سے ) ایک جماعت آپ صلی اللہ علیہ وسلم کے ساتھ نماز پڑھنے میں شریک ہو گئی اور دوسرا گروہ دشمن کے مقابلہ میں کھڑا رہا۔ پھر رسول اللہ صلی اللہ علیہ وسلم نے اپنی اقتداء میں نماز پڑھنے والوں کے ساتھ ایک رکوع اور دو سجدے کئے۔ پھر یہ لوگ لوٹ کر اس جماعت کی جگہ آ گئے جس نے ابھی نماز نہیں پڑھی تھی۔ اب دوسری جماعت آئی۔ ان کے ساتھ بھی آپ صلی اللہ علیہ وسلم نے ایک رکوع اور دو سجدے کئے۔ پھر آپ صلی اللہ علیہ وسلم نے سلام پھیر دیا۔ اس گروہ میں سے ہر شخص کھڑا ہوا اور اس نے اکیلے اکیلے ایک رکوع اور دو سجدے ادا کئے۔' WHERE id = 921;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے اسماعیل بن علیہ نے ایوب سختیانی سے، انہوں نے محمد بن سیرین سے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص نماز سے پہلے قربانی کر دے اسے دوبارہ کرنی چاہیے۔ اس پر ایک شخص ( ابوبردہ ) نے کھڑے ہو کر کہا کہ یہ ایسا دن ہے جس میں گوشت کی خواہش زیادہ ہوتی ہے اور اس نے اپنے پڑوسیوں کی تنگی کا حال بیان کیا۔ نبی کریم صلی اللہ علیہ وسلم نے اس کو سچا سمجھا اس شخص نے کہا کہ میرے پاس ایک سال کی پٹھیا ہے جو گوشت کی دو بکریوں سے بھی مجھے زیادہ پیاری ہے۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر اسے اجازت دے دی کہ وہی قربانی کرے۔ اب مجھے معلوم نہیں کہ یہ اجازت دوسروں کے لیے بھی ہے یا نہیں۔' WHERE id = 932;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا کہ ہم سے شعبہ نے زبید سے بیان کیا، ان سے شعبی نے، ان سے براء بن عازب رضی اللہ عنہ نے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے قربانی کے دن خطبہ دیا اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس دن سب سے پہلے ہمیں نماز پڑھنی چاہیے پھر ( خطبہ کے بعد ) واپس آ کر قربانی کرنی چاہیے جس نے اس طرح کیا اس نے ہماری سنت کے مطابق کیا اور جس نے نماز سے پہلے ذبح کر دیا تو یہ ایک ایسا گوشت ہو گا جسے اس نے اپنے گھر والوں کے لیے جلدی سے تیار کر لیا ہے، یہ قربانی قطعاً نہیں۔ اس پر میرے ماموں ابوبردہ بن نیار نے کھڑے ہو کر کہا کہ یا رسول اللہ! میں نے تو نماز کے پڑھنے سے پہلے ہی ذبح کر دیا۔ البتہ میرے پاس ایک سال کی ایک پٹھیا ہے جو دانت نکلی بکری سے بھی زیادہ بہتر ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس کے بدلہ میں اسے سمجھ لو یا یہ فرمایا کہ اسے ذبح کر لو اور تمہارے بعد یہ ایک سال کی پٹھیا کسی کے لیے کافی نہیں ہو گی۔' WHERE id = 943;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم بن نصر نے بیان کیا، کہا کہ ہم سے عبدالرزاق نے بیان کیا، کہا کہ ہمیں ابن جریج نے خبر دی، کہا کہ مجھے عطاء نے خبر دی کہ جابر بن عبداللہ رضی اللہ عنہما کو میں نے یہ کہتے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے عیدالفطر کی نماز پڑھی۔ پہلے آپ صلی اللہ علیہ وسلم نے نماز پڑھی اس کے بعد خطبہ دیا۔ جب آپ صلی اللہ علیہ وسلم خطبہ سے فارغ ہو گئے تو اترے ( نبی کریم صلی اللہ علیہ وسلم عیدگاہ میں منبر نہیں لے کر جاتے تھے۔ تو اس اترے سے مراد بلند جگہ سے اترے ) اور عورتوں کی طرف آئے۔ پھر انہیں نصیحت فرمائی۔ آپ اس وقت بلال رضی اللہ عنہ کے ہاتھ کا سہارا لیے ہوئے تھے۔ بلال رضی اللہ عنہ نے اپنا کپڑا پھیلا رکھا تھا جس میں عورتیں صدقہ ڈال رہی تھیں۔ میں نے عطاء سے پوچھا کیا یہ صدقہ فطر دے رہی تھیں۔ انہوں نے فرمایا کہ نہیں بلکہ صدقہ کے طور پر دے رہی تھیں۔ اس وقت عورتیں اپنے چھلے ( وغیرہ ) برابر ڈال رہی تھیں۔ پھر میں نے عطاء سے پوچھا کہ کیا آپ اب بھی امام پر اس کا حق سمجھتے ہیں کہ وہ عورتوں کو نصیحت کرے؟ انہوں نے فرمایا ہاں ان پر یہ حق ہے اور کیا وجہ ہے کہ وہ ایسا نہیں کرتے۔' WHERE id = 953;
UPDATE hadiths SET urdu = 'ہم سے ابوولید نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ مجھے عدی بن ثابت نے خبر دی، انہوں نے کہا کہ میں نے سعید بن جبیر سے سنا، وہ ابن عباس رضی اللہ عنہما سے بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم عیدالفطر کے دن نکلے اور ( عیدگاہ ) میں دو رکعت نماز عید پڑھی۔ آپ صلی اللہ علیہ وسلم نے نہ اس سے پہلے نفل نماز پڑھی اور نہ اس کے بعد۔ آپ صلی اللہ علیہ وسلم کے ساتھ بلال رضی اللہ عنہ بھی تھے۔' WHERE id = 963;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا کہ ہم سے امام مالک نے بیان کیا، انہوں نے ابوبکر بن عمر بن عبدالرحمٰن بن عبداللہ بن عمر بن خطاب سے بیان کیا اور ان کو سعید بن یسار نے بتلایا کہ میں عبداللہ بن عمر رضی اللہ عنہما کے ساتھ مکہ کے راستے میں تھا۔ سعید نے کہا کہ جب راستے میں مجھے طلوع فجر کا خطرہ ہوا تو سواری سے اتر کر میں نے وتر پڑھ لیا اور پھر عبداللہ بن عمر رضی اللہ عنہما سے جا ملا۔ آپ نے پوچھا کہ کہاں رک گئے تھے؟ میں نے کہا کہ اب صبح کا وقت ہونے ہی والا تھا اس لیے میں سواری سے اتر کر وتر پڑھنے لگا۔ اس پر عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ کیا تمہارے لیے نبی کریم صلی اللہ علیہ وسلم کا عمل اچھا نمونہ نہیں ہے۔ میں نے عرض کیا کیوں نہیں بیشک ہے۔ آپ نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم تو اونٹ ہی پر وتر پڑھ لیا کرتے تھے۔' WHERE id = 973;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، انہوں نے کہا کہ ہم سے وہب بن جریر نے بیان کیا، انہوں نے کہا ہمیں شعبہ نے خبر دی، انہیں محمد بن ابی بکر نے، انہیں عباد بن تمیم نے، انہیں عبداللہ بن زید رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے دعا استسقاء کی تو اپنی چادر کو بھی الٹا۔' WHERE id = 984;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن ابی بکر نے بیان کیا، کہا کہ ہم سے معتمر بن سلیمان نے عبیداللہ عمری سے بیان کیا، ان سے ثابت نے، ان سے انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم جمعہ کے دن خطبہ دے رہے تھے کہ اتنے میں لوگوں نے کھڑے ہو کر غل مچایا، کہنے لگے کہ یا رسول اللہ! بارش کے نام بوند بھی نہیں درخت سرخ ہو چکے ( یعنی تمام پتے خشک ہو گئے ) اور جانور تباہ ہو رہے ہیں، آپ اللہ تعالیٰ سے دعا کیجئے کہ ہمیں سیراب کرے۔ آپ صلی اللہ علیہ وسلم نے دعا کی «اللهم اسقنا» اے اللہ! ہمیں سیراب کر۔ دو مرتبہ آپ صلی اللہ علیہ وسلم نے اس طرح کہا، قسم اللہ کی اس وقت آسمان پر بادل کہیں دور دور نظر نہیں آتا تھا لیکن دعا کے بعد اچانک ایک بادل آیا اور بارش شروع ہو گئی۔ آپ صلی اللہ علیہ وسلم منبر سے اتر ے اور نماز پڑھائی۔ جب آپ صلی اللہ علیہ وسلم نماز سے فارغ ہوئے تو بارش ہو رہی تھی اور دوسرے جمعہ تک بارش برابر ہوتی رہی پھر جب نبی کریم صلی اللہ علیہ وسلم دوسرے جمعہ میں خطبہ کے لیے کھڑے ہوئے تو لوگوں نے بتایا کہ مکانات منہدم ہو گئے اور راستے بند ہو گئے، اللہ سے دعا کیجئے کہ بارش بند کر دے۔ اس پر نبی کریم صلی اللہ علیہ وسلم مسکرائے اور دعا کی «االلهم حوالينا ولا علينا» اے اللہ! ہمارے اطراف میں اب بارش برسا، مدینہ میں اس کا سلسلہ بند کر۔ آپ صلی اللہ علیہ وسلم کی دعا سے مدینہ سے بادل چھٹ گئے اور بارش ہمارے ارد گرد ہونے لگی۔ اس شان سے کہ اب مدینہ میں ایک بوند بھی نہ پڑتی تھی میں نے مدینہ کو دیکھا ابر تاج کی طرح گردا گرد تھا اور مدینہ اس کے بیچ میں۔' WHERE id = 994;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا کہ ہم سے یحییٰ بن سعید قطان اور محمد بن ابراہیم بن عدی بن عروبہ نے بیان کیا، ان سے سعید نے، ان سے قتادہ اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم دعائے استسقاء کے سوا اور کسی دعا کے لیے ہاتھ ( زیادہ ) نہیں اٹھاتے تھے اور استسقاء میں ہاتھ اتنا اٹھاتے کہ بغلوں کی سفیدی نظر آ جاتی۔' WHERE id = 1004;
UPDATE hadiths SET urdu = 'ہم سے شہاب بن عباد نے بیان کیا، انہوں نے کہا کہ ہمیں ابراہیم بن حمید نے خبر دی، انہیں اسماعیل بن ابی خالد نے، انہیں قیس بن ابی حازم نے اور انہوں نے کہا کہ میں نے ابومسعود انصاری رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا سورج اور چاند میں گرہن کسی شخص کی موت سے نہیں لگتا۔ یہ دونوں تو اللہ تعالیٰ کی قدرت کی نشانیاں ہیں۔ اس لیے اسے دیکھتے ہی کھڑے ہو جاؤ اور نماز پڑھو۔' WHERE id = 1014;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک رحمہ اللہ نے خبر دی، انہیں ہشام بن عروہ نے، انہیں ان کی بیوی فاطمہ بنت منذر نے، انہیں اسماء بنت ابی بکر رضی اللہ عنہما نے، انہوں نے کہا کہ جب سورج کو گرہن لگا تو میں نبی کریم صلی اللہ علیہ وسلم کی بیوی عائشہ صدیقہ رضی اللہ عنہا کے گھر آئی۔ اچانک لوگ کھڑے ہوئے نماز پڑھ رہے تھے اور عائشہ رضی اللہ عنہا بھی نماز میں شریک تھی میں نے پوچھا کہ لوگوں کو بات کیا پیش آئی؟ اس پر آپ نے آسمان کی طرف اشارہ کر کے سبحان اللہ کہا۔ پھر میں نے پوچھا کیا کوئی نشانی ہے؟ اس کا آپ نے اشارہ سے ہاں میں جواب دیا۔ انہوں نے بیان کیا کہ پھر میں بھی کھڑی ہو گئی۔ لیکن مجھے چکر آ گیا اس لیے میں اپنے سر پر پانی ڈالنے لگی۔ جب رسول اللہ صلی اللہ علیہ وسلم نماز سے فارغ ہوئے تو اللہ تعالیٰ کی حمد و ثنا کے بعد فرمایا کہ وہ چیزیں جو کہ میں نے پہلے نہیں دیکھی تھیں اب انہیں میں نے اپنی اسی جگہ سے دیکھ لیا۔ جنت اور دوزخ تک میں نے دیکھی اور مجھے وحی کے ذریعہ بتایا گیا ہے کہ تم قبر میں دجال کے فتنہ کی طرح یا ( یہ کہا کہ ) دجال کے فتنہ کے قریب ایک فتنہ میں مبتلا ہو گے۔ مجھے یاد نہیں کہ اسماء رضی اللہ عنہا نے کیا کہا تھا آپ نے فرمایا کہ تمہیں لایا جائے گا اور پوچھا جائے گا کہ اس شخص ( مجھ صلی اللہ علیہ وسلم ) کے بارے میں تم کیا جانتے ہو۔ مومن یا یہ کہا کہ یقین کرنے والا ( مجھے یاد نہیں کہ ان دو باتوں میں سے اسماء رضی اللہ عنہا نے کون سی بات کہی تھی ) تو کہے گا یہ محمد صلی اللہ علیہ وسلم ہیں آپ صلی اللہ علیہ وسلم نے ہمارے سامنے صحیح راستہ اور اس کے دلائل پیش کئے اور ہم آپ صلی اللہ علیہ وسلم پر ایمان لائے تھے اور آپ صلی اللہ علیہ وسلم کی بات قبول کی اور آپ صلی اللہ علیہ وسلم کا اتباع کیا تھا۔ اس پر اس سے کہا جائے گا کہ تو مرد صالح ہے پس آرام سے سو جاؤ ہمیں تو پہلے ہی معلوم تھا کہ تو ایمان و یقین والا ہے۔ منافق یا شک کرنے والا ( مجھے معلوم نہیں کہ اسماء رضی اللہ عنہا نے کیا کہا تھا ) وہ یہ کہے گا کہ مجھے کچھ معلوم نہیں میں نے لوگوں سے ایک بات سنی تھی وہی میں نے بھی کہی ( آگے مجھ کو کچھ حقیقت معلوم نہیں ) ۔' WHERE id = 1025;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے غندر محمد بن جعفر نے بیان کیا کہا کہ ہم سے شعبہ نے بیان کیا اور ان سے ابواسحاق نے انہوں نے کہا کہ میں نے اسود سے سنا انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے کہ مکہ میں نبی کریم صلی اللہ علیہ وسلم نے سورۃ النجم کی تلاوت کی اور سجدہ تلاوت کیا آپ صلی اللہ علیہ وسلم کے پاس جتنے آدمی تھے ( مسلمان اور کافر ) ان سب نے بھی آپ صلی اللہ علیہ وسلم کے ساتھ سجدہ کیا البتہ ایک بوڑھا شخص ( امیہ بن خلف ) اپنے ہاتھ میں کنکری یا مٹی اٹھا کر اپنی پیشانی تک لے گیا اور کہا میرے لیے یہی کافی ہے میں نے دیکھا کہ بعد میں وہ بوڑھا حالت کفر میں ہی مارا گیا۔' WHERE id = 1037;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، انہوں نے کہا کہ ہمیں ہشام بن یوسف نے خبر دی اور انہیں ابن جریج نے خبر دی، انہوں نے کہا کہ مجھے ابوبکر بن ابی ملیکہ نے خبر دی، انہیں عثمان بن عبدالرحمٰن تیمی نے اور انہیں ربیعہ بن عبداللہ بن ہدیر تیمی نے کہا۔۔۔ ابوبکر بن ابی ملیکہ نے بیان کیا کہ ربیعہ بہت اچھے لوگوں میں سے تھے ربیعہ نے وہ حال بیان کیا جو عمر بن خطاب رضی اللہ عنہ کی مجلس میں انہوں نے دیکھا۔ عمر رضی اللہ عنہ نے جمعہ کے دن منبر پر سورۃ النحل پڑھی جب سجدہ کی آیت ( «‏‏‏‏ولله يسجد ما في السمٰوٰت» ‏‏‏‏ ) آخر تک پہنچے تو منبر پر سے اترے اور سجدہ کیا تو لوگوں نے بھی ان کے ساتھ سجدہ کیا۔ دوسرے جمعہ کو پھر یہی سورت پڑھی جب سجدہ کی آیت پر پہنچے تو کہنے لگے لوگو! ہم سجدہ کی آیت پڑھتے چلے جاتے ہیں پھر جو کوئی سجدہ کرے اس نے اچھا کیا اور جو کوئی نہ کرے تو اس پر کچھ گناہ نہیں اور عمر رضی اللہ عنہ نے سجدہ نہیں کیا اور نافع نے عبداللہ بن عمر رضی اللہ عنہما سے نقل کیا کہ اللہ تعالیٰ نے سجدہ تلاوت فرض نہیں کیا ہماری خوشی پر رکھا۔' WHERE id = 1047;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے، عبیداللہ عمری سے بیان کیا، انہوں نے کہا کہ ہمیں نافع نے خبر دی، انہیں ابن عمر رضی اللہ عنہما نے نبی کریم صلی اللہ علیہ وسلم سے خبر دی کہ آپ صلی اللہ علیہ وسلم نے فرمایا عورت تین دن کا سفر اس وقت تک نہ کرے جب تک اس کے ساتھ کوئی محرم رشتہ دار نہ ہو۔ اس روایت کی متابعت احمد نے ابن مبارک سے کی ان سے عبیداللہ عمری نے ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے نبی کریم صلی اللہ علیہ وسلم کے حوالہ سے۔' WHERE id = 1057;
UPDATE hadiths SET urdu = 'اور لیث بن سعد نے بیان کیا کہ مجھ سے یونس نے بیان کیا، انہوں نے ابن شہاب کے واسطہ سے بیان کیا انہوں نے کہا کہ سالم نے بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما سفر میں رات کے وقت اپنے جانور پر نماز پڑھتے کچھ پرواہ نہ کرتے کہ اس کا منہ کس طرف ہے۔ ابن عمر رضی اللہ عنہما نے کہا کہ نبی کریم صلی اللہ علیہ وسلم بھی اونٹنی پر نفل نماز پڑھا کرتے چاہے اس کا منہ کدھر ہی ہو اور وتر بھی سواری پر پڑھ لیتے تھے البتہ فرض اس پر نہیں پڑھتے تھے۔' WHERE id = 1067;
UPDATE hadiths SET urdu = 'اور ابن طہمان ہی نے بیان کیا کہ ان سے حسین نے، ان سے یحییٰ بن ابی کثیر نے، ان سے حفص بن عبیداللہ بن انس رضی اللہ عنہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سفر میں مغرب اور عشاء ایک ساتھ ملا کر پڑھتے تھے۔ اس روایت کی متابعت علی بن مبارک اور حرب نے یحییٰ سے کی ہے۔ یحییٰ، حفص سے اور حفص انس رضی اللہ عنہ سے روایت کرتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم نے ( مغرب اور عشاء ) ایک ساتھ ملا کر پڑھی تھیں۔' WHERE id = 1077;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک رحمہ اللہ نے خبر دی، انہیں ہشام بن عروہ نے، انہیں ان کے باپ عروہ بن زبیر نے اور انہیں ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے کہ آپ نے رسول اللہ صلی اللہ علیہ وسلم کو کبھی بیٹھ کر نماز پڑھتے نہیں دیکھا البتہ جب آپ ضعیف ہو گئے تو قرآت قرآن نماز میں بیٹھ کر کرتے تھے، پھر جب رکوع کا وقت آتا تو کھڑے ہو جاتے اور پھر تقریباً تیس یا چالیس آیتیں پڑھ کر رکوع کرتے۔' WHERE id = 1087;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے مسعر نے بیان کیا، ان سے زیاد بن علاقہ نے، انہوں نے بیان کیا کہ میں نے مغیرہ بن شعبہ رضی اللہ عنہ کو یہ کہتے سنا کہ نبی کریم صلی اللہ علیہ وسلم اتنی دیر تک کھڑے ہو کر نماز پڑھتے رہتے کہ آپ صلی اللہ علیہ وسلم کے قدم یا ( یہ کہا کہ ) پنڈلیوں پر ورم آ جاتا، جب آپ صلی اللہ علیہ وسلم سے اس کے متعلق کچھ عرض کیا جاتا تو فرماتے ”کیا میں اللہ کا شکر گزار بندہ نہ بنوں“۔' WHERE id = 1098;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، کہا کہ ہمیں حنظلہ بن ابی سفیان نے خبر دی، انہیں قاسم بن محمد نے اور انہیں عائشہ صدیقہ رضی اللہ عنہا نے، آپ نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم رات کو تیرہ رکعتیں پڑھتے تھے۔ وتر اور فجر کی دو سنت رکعتیں اسی میں ہوتیں۔' WHERE id = 1109;
UPDATE hadiths SET urdu = 'ہم سے ابو معمرعبداللہ بن عمرو نے بیان کیا، کہا کہ ہم سے عبدالوارث بن سعد نے بیان کیا، کہا کہ ہم سے عبدالعزیز بن صہیب نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم مسجد میں تشریف لے گئے۔ آپ صلی اللہ علیہ وسلم کی نظر ایک رسی پر پڑی جو دو ستونوں کے درمیان تنی ہوئی تھی۔ دریافت فرمایا کہ یہ رسی کیسی ہے؟ لوگوں نے عرض کی کہ یہ زینب رضی اللہ عنہا نے باندھی ہے جب وہ ( نماز میں کھڑی کھڑی ) تھک جاتی ہیں تو اس سے لٹکی رہتی ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں یہ رسی نہیں ہونی چاہیے اسے کھول ڈالو، تم میں ہر شخص کو چاہیے جب تک دل لگے نماز پڑھے، تھک جائے تو بیٹھ جائے۔' WHERE id = 1119;
UPDATE hadiths SET urdu = 'ہم سے بیان بن عمرو نے بیان کیا، انہوں نے کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا، انہوں نے کہا کہ ہم سے ابن جریج نے بیان کیا، ان سے عطاء نے بیان کیا، ان سے عبید بن عمیر نے، ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کسی نفل نماز کی فجر کی دو رکعتوں سے زیادہ پابندی نہیں کرتے تھے۔' WHERE id = 1130;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا کہ ہم سے ابن ابی ذئب نے بیان کیا، ان سے زہری نے بیان کیا، ان سے عروہ بن زبیر نے، ان سے عائشہ صدیقہ رضی اللہ عنہا نے کہ میں نے تو رسول اللہ صلی اللہ علیہ وسلم کو چاشت کی نماز پڑھتے نہیں دیکھا مگر میں خود پڑھتی ہوں۔' WHERE id = 1143;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے زید بن رباح اور عبیداللہ بن ابی عبداللہ اغر سے خبر دی، انہیں ابوعبدللہ اغر نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میری اس مسجد میں نماز مسجد الحرام کے سوا تمام مسجدوں میں نماز سے ایک ہزار درجہ زیادہ افضل ہے۔' WHERE id = 1154;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عیسیٰ نے بیان کیا، انہوں نے کہا کہ ہم سے ابوعبدالصمد العمی عبدالعزیز بن عبدالصمد نے بیان کیا، انہوں نے کہا ہم سے حصین بن عبدالرحمٰن نے بیان کیا، ان سے ابووائل نے بیان کیا، ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیاکہ ہم پہلے نماز میں یوں کہا کرتے تھے فلاں پر سلام اور نام لیتے تھے۔ اور آپس میں ایک شخص دوسرے کو سلام کر لیتا۔ نبی کریم صلی اللہ علیہ وسلم نے سن کر فرمایا اس طرح کہا کرو۔ «التحيات لله والصلوات والطيبات،‏‏‏‏ السلام عليك أيها النبي ورحمة الله وبركاته،‏‏‏‏ السلام علينا وعلى عباد الله الصالحين،‏‏‏‏ أشهد أن لا إله إلا الله وأشهد أن محمدا عبده ورسوله» ”یعنی ساری تحیات، بندگیاں اور کوششیں اور اچھی باتیں خاص اللہ ہی کے لیے ہیں اور اے نبی! آپ پر سلام ہو، اللہ کی رحمتیں اور اس کی برکتیں نازل ہوں۔ ہم پر سلام ہو اور اللہ کے سب نیک بندوں پر، میں گواہی دیتا ہوں کہ اللہ کے سوا کوئی معبود نہیں اور گواہی دیتا ہوں کہ محمد صلی اللہ علیہ وسلم اس کے بندے اور رسول ہیں۔“ اگر تم نے یہ پڑھ لیا تو گویا اللہ کے ان تمام صالح بندوں پر سلام پہنچا دیا جو آسمان اور زمین میں ہیں۔' WHERE id = 1166;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا کہ ہم کو عبداللہ بن مبارک نے خبر دی، کہا کہ ہم کو یونس نے خبر دی، انہیں زہری نے، ان سے عروہ نے بیان کیا کہ عائشہ رضی اللہ عنہا نے بتلایا کہ جب سورج گرہن لگا تو نبی کریم صلی اللہ علیہ وسلم ( نماز کے لیے ) کھڑے ہوئے اور ایک لمبی سورت پڑھی۔ پھر رکوع کیا اور بہت لمبا رکوع کیا۔ پھر سر اٹھایا اس کے بعد دوسری سورت شروع کر دی، پھر رکوع کیا اور رکوع پورا کر کے اس رکعت کو ختم کیا اور سجدے میں گئے۔ پھر دوسری رکعت میں بھی آپ صلی اللہ علیہ وسلم نے اسی طرح کیا، نماز سے فارغ ہو کر آپ صلی اللہ علیہ وسلم نے فرمایا کہ سورج اور چاند اللہ کی نشانیوں میں سے دو نشانیاں ہیں۔ اس لیے جب تم ان میں گرہن دیکھو تو نماز شروع کر دو جب تک کہ یہ صاف ہو جائے اور دیکھو میں نے اپنی اسی جگہ سے ان تمام چیزوں کو دیکھ لیا ہے جن کا مجھ سے وعدہ ہے۔ یہاں تک کہ میں نے یہ بھی دیکھا کہ میں جنت کا ایک خوشہ لینا چاہتا ہوں۔ ابھی تم لوگوں نے دیکھا ہو گا کہ میں آگے بڑھنے لگا تھا اور میں نے دوزخ بھی دیکھی ( اس حالت میں کہ ) بعض آگ بعض آگ کو کھائے جا رہی تھی۔ تم لوگوں نے دیکھا ہو گا کہ جہنم کے اس ہولناک منظر کو دیکھ کر میں پیچھے ہٹ گیا تھا۔ میں نے جہنم کے اندر عمرو بن لحیی کو دیکھا۔ یہ وہ شخص ہے جس نے سانڈ کی رسم عرب میں جاری کی تھی۔ ( نوٹ: سانڈ کی رسم سے مراد کہ اونٹنی کو غیر اللہ کے نام پر چھوڑ دینا حتیٰ کہ سواری اور دودھ بھی نہ دھونا۔)' WHERE id = 1176;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث نے، ان سے جعفر بن ربیعہ نے اور ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب نماز کے لیے اذان دی جاتی ہے تو شیطان پیٹھ موڑ کر ریاح خارج کرتا ہوا بھاگتا ہے تاکہ اذان نہ سن سکے۔ جب مؤذن چپ ہو جاتا ہے تو مردود پھر آ جاتا ہے اور جب جماعت کھڑی ہونے لگتی ہے ( اور تکبیر کہی جاتی ہے ) تو پھر بھاگ جاتا ہے۔ لیکن جب مؤذن چپ ہو جاتا ہے تو پھر آ جاتا ہے۔ اور آدمی کے دل میں وسواس پیدا کرتا رہتا ہے۔ کہتا ہے کہ ( فلاں فلاں بات ) یاد کر۔ کم بخت وہ باتیں یاد دلاتا ہے جو اس نمازی کے ذہن میں بھی نہ تھیں۔ اس طرح نمازی کو یہ بھی یاد نہیں رہتا کہ اس نے کتنی رکعتیں پڑھی ہیں۔ ابوسلمہ بن عبدالرحمٰن نے کہا کہ جب کوئی یہ بھول جائے ( کہ کتنی رکعتیں پڑھی ہیں ) تو بیٹھے بیٹھے ( سہو کے ) دو سجدے کر لے۔ ابوسلمہ نے یہ ابوہریرہ رضی اللہ عنہ سے سنا تھا۔' WHERE id = 1186;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہم کو امام مالک رحمہ اللہ نے خبر دی، انہیں ابن شہاب نے، انہیں ابوسلمہ بن عبدالرحمٰن نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ تم میں سے جب کوئی نماز پڑھنے کے لیے کھڑا ہوتا ہے تو شیطان آ کر اس کی نماز میں شبہ پیدا کر دیتا ہے پھر اسے یہ بھی یاد نہیں رہتا کہ کتنی رکعتیں پڑھیں۔ تم میں سے جب کسی کو ایسا اتفاق ہو تو بیٹھے بیٹھے دو سجدے کر لے۔' WHERE id = 1197;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا کہ ہم سے غندر نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا کہ میں نے محمد بن منکدر سے سنا، انہوں نے کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے کہا کہ جب میرے والد شہید کر دیئے گئے تو میں ان کے چہرے پر پڑا ہو کپڑا کھولتا اور روتا تھا۔ دوسرے لوگ تو مجھے اس سے روکتے تھے لیکن نبی کریم صلی اللہ علیہ وسلم کچھ نہیں کہہ رہے تھے۔ آخر میری چچی فاطمہ رضی اللہ عنہا بھی رونے لگیں تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم لوگ روؤ یا چپ رہو۔ جب تک تم لوگ میت کو اٹھاتے نہیں ملائکہ تو برابر اس پر اپنے پروں کا سایہ کئے ہوئے ہیں۔ اس روایت کی متابعت شعبہ کے ساتھ ابن جریج نے کی، انہیں ابن منکدر نے خبر دی اور انہوں نے جابر رضی اللہ عنہ سے سنا۔' WHERE id = 1208;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ نے بیان کیا، کہا کہ ہم سے وکیع نے بیان کیا، ان سے سفیان نے، ان سے خالد حذاء نے، ان سے حفصہ بنت سیرین نے اور ان سے ام عطیہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم کی صاحبزادی کو ہم غسل دے رہی تھیں۔ جب ہم نے غسل شروع کر دیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ غسل دائیں طرف سے اور اعضاء وضو سے شروع کرو۔' WHERE id = 1219;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ان سے حماد بن زید نے، ان سے عمرو اور ایوب نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ ایک شخص نبی کریم صلی اللہ علیہ وسلم کے ساتھ میدان عرفات میں کھڑا ہوا تھا، اچانک وہ اپنی سواری سے گر پڑا۔ ایوب نے کہا اونٹنی نے اس کی گردن توڑ ڈالی۔ اور عمرو نے یوں کہا کہ اونٹنی نے اس کو گرتے ہی مار ڈالا اور اس کا انتقال ہو گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسے پانی اور بیری کے پتوں سے غسل دو اور دو کپڑوں کا کفن دو اور خوشبو نہ لگاؤ نہ سر ڈھکو کیونکہ قیامت میں یہ اٹھایا جائے گا۔ ایوب نے کہا کہ ( یعنی ) تلبیہ کہتے ہوئے ( اٹھایا جائے گا ) اور عمرو نے ( اپنی روایت میں «ملبی» کے بجائے ) «ملبيا» کا لفظ نقل کیا۔ ( یعنی لبیک کہتا ہوا اٹھے گا ) ۔' WHERE id = 1230;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا ‘ انہوں نے کہا کہ ہم سے سفیان ثوری نے بیان کیا ‘ ان سے خالد حذاء نے ‘ ان سے ام ہذیل حفصہ بنت سیرین نے ‘ ان سے ام عطیہ رضی اللہ عنہا نے بیان کیا کہ ہمیں ( عورتوں کو ) جنازے کے ساتھ چلنے سے منع کیا گیا مگر تاکید سے منع نہیں ہوا۔' WHERE id = 1240;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ بن مدینی نے بیان کیا ‘ ان سے سفیان بن عیینہ نے بیان کیا ‘ کہا کہ ہم سے محمد بن منکدر نے بیان کیا ‘ کہا کہ میں نے جابر بن عبداللہ انصاری رضی اللہ عنہما سے سنا ‘ انہوں نے فرمایا کہ میرے والد کی لاش احد کے میدان سے لائی گئی۔ ( مشرکوں نے ) آپ کی صورت تک بگاڑ دی تھی۔ نعش رسول اللہ صلی اللہ علیہ وسلم کے سامنے رکھی گئی۔ اوپر سے ایک کپڑا ڈھکا ہوا تھا ‘ میں نے چاہا کہ کپڑے کو ہٹاؤں۔ لیکن میری قوم نے مجھے روکا۔ پھر دوبارہ کپڑا ہٹانے کی کوشش کی۔ اس مرتبہ بھی میری قوم نے مجھ کو روک دیا۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم کے حکم سے جنازہ اٹھایا گیا۔ اس وقت کسی زور زور سے رونے والے کی آواز سنائی دی تو رسول اللہ صلی اللہ علیہ وسلم نے پوچھا کہ یہ کون ہے؟ لوگوں نے کہا کہ یہ عمرو کی بیٹی یا ( یہ کہا کہ ) عمرو کی بہن ہیں۔ ( نام میں سفیان کو شک ہوا تھا ) آپ صلی اللہ علیہ وسلم نے فرمایا کہ روتی کیوں ہیں؟ یا یہ فرمایا کہ روؤ نہیں کہ ملائکہ برابر اپنے پروں کا سایہ کئے رہے ہیں جب تک اس کا جنازہ اٹھایا گیا۔' WHERE id = 1252;
UPDATE hadiths SET urdu = 'ہم سے حسن بن عبدالعزیز نے بیان کیا ‘ انہوں نے کہا کہ ہم سے یحییٰ بن حسان نے بیان کیا، انہوں نے کہا کہ ہم سے قریش نے جو حیان کے بیٹے ہیں، نے بیان کیا، ان سے ثابت نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کی کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ابوسیف لوہار کے یہاں گئے۔ یہ ابراہیم ( رسول اللہ صلی اللہ علیہ وسلم کے صاحبزادے رضی اللہ عنہ ) کو دودھ پلانے والی انا کے خاوند تھے۔ نبی کریم صلی اللہ علیہ وسلم نے ابراہیم رضی اللہ عنہ کو گود میں لیا اور پیار کیا اور سونگھا۔ پھر اس کے بعد ہم ان کے یہاں پھر گئے۔ دیکھا کہ اس وقت ابراہیم رضی اللہ عنہ دم توڑ رہے ہیں۔ رسول اللہ صلی اللہ علیہ وسلم کی آنکھیں آنسوؤں سے بھر آئیں۔ تو عبدالرحمٰن بن عوف رضی اللہ عنہ بول پڑے کہ یا رسول اللہ! اور آپ بھی لوگوں کی طرح بے صبری کرنے لگے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ‘ ابن عوف! یہ بے صبری نہیں یہ تو رحمت ہے۔ پھر آپ صلی اللہ علیہ وسلم دوبارہ روئے اور فرمایا۔ آنکھوں سے آنسو جاری ہیں اور دل غم سے نڈھال ہے پر زبان سے ہم کہیں گے وہی جو ہمارے پروردگار کو پسند ہے اور اے ابراہیم! ہم تمہاری جدائی سے غمگین ہیں۔ اسی حدیث کو موسیٰ بن اسماعیل نے سلیمان بن مغیرہ سے ‘ ان سے ثابت نے اور ان سے انس رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے روایت کیا ہے۔' WHERE id = 1262;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا ‘ کہا کہ ہم سے سفیان نے بیان کیا ‘ انہوں نے کہا کہ ہم نے زہری سے سن کر یہ حدیث یاد کی ‘ انہوں نے سعید بن مسیب سے اور انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جنازہ لے کر جلد چلا کرو کیونکہ اگر وہ نیک ہے تو تم اس کو بھلائی کی طرف نزدیک کر رہے ہو اور اگر اس کے سوا ہے تو ایک شر ہے جسے تم اپنی گردنوں سے اتارتے ہو۔' WHERE id = 1273;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا ‘ انہوں نے کہا ہم سے یحییٰ بن ابی بکیر نے ‘ انہوں نے کہا ہم سے زائدہ نے بیان کیا ‘ ان سے ابواسحاق شیبانی نے ‘ ان سے عامر نے ‘ ان سے ابن عباس رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم ایک قبر پر تشریف لائے۔ صحابہ نے عرض کیا کہ اس میت کو گزشتہ رات دفن کیا گیا ہے۔ ( صاحب قبر مرد تھا یا عورت تھی ) ابن عباس رضی اللہ عنہما نے کہا کہ پھر ہم نے آپ صلی اللہ علیہ وسلم کے پیچھے صف بندی کی اور آپ صلی اللہ علیہ وسلم نے نماز جنازہ پڑھائی۔' WHERE id = 1283;
UPDATE hadiths SET urdu = 'ہم سے عیاش بن ولید نے بیان کیا ‘ کہا کہ ہم سے عبدالاعلیٰ نے بیان کیا ‘ کہا کہ ہم سے سعید بن ابی عروبہ نے بیان کیا۔ (دوسری سند) امام بخاری رحمہ اللہ نے کہا کہ مجھ سے خلیفہ بن خیاط نے بیان کیا ‘ ان سے یزید بن زریع نے ‘ ان سے سعید بن ابی عروبہ نے ‘ ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ آدمی جب قبر میں رکھا جاتا ہے اور دفن کر کے اس کے لوگ پیٹھ موڑ کر رخصت ہوتے ہیں تو وہ ان کے جوتوں کی آواز سنتا ہے۔ پھر دو فرشتے آتے ہیں اسے بٹھاتے ہیں اور پوچھتے ہیں کہ اس شخص ( محمد صلی اللہ علیہ وسلم ) کے متعلق تمہارا کیا اعتقاد ہے؟ وہ جواب دیتا ہے کہ میں گواہی دیتا ہوں کہ وہ اللہ کے بندے اور اس کے رسول ہیں۔ اس جواب پر اس سے کہا جاتا ہے کہ یہ دیکھ جہنم کا اپنا ایک ٹھکانا لیکن اللہ تعالیٰ نے جنت میں تیرے لیے ایک مکان اس کے بدلے میں بنا دیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر اس بندہ مومن کو جنت اور جہنم دونوں دکھائی جاتی ہیں اور رہا کافر یا منافق تو اس کا جواب یہ ہوتا ہے کہ مجھے معلوم نہیں ‘ میں نے لوگوں کو ایک بات کہتے سنا تھا وہی میں بھی کہتا رہا۔ پھر اس سے کہا جاتا ہے کہ نہ تو نے کچھ سمجھا اور نہ ( اچھے لوگوں کی ) پیروی کی۔ اس کے بعد اسے ایک لوہے کے ہتھوڑے سے بڑے زور سے مارا جاتا ہے اور وہ اتنے بھیانک طریقہ سے چیختا ہے کہ انسان اور جن کے سوا اردگرد کی تمام مخلوق سنتی ہے۔' WHERE id = 1294;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا ‘ کہا کہ ہم سے سفیان نے بیان کیا ‘ عمرو نے کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا ‘ انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم تشریف لائے تو عبداللہ بن ابی ( منافق ) کو اس کی قبر میں ڈالا جا چکا تھا۔ لیکن آپ صلی اللہ علیہ وسلم کے ارشاد پر اسے قبر سے نکال لیا گیا۔ پھر آپ صلی اللہ علیہ وسلم نے اسے اپنے گھٹنوں پر رکھ کر لعاب دہن اس کے منہ میں ڈالا اور اپنا کرتہ اسے پہنایا۔ اب اللہ ہی بہتر جانتا ہے۔ ( غالباً مرنے کے بعد ایک منافق کے ساتھ اس احسان کی وجہ یہ تھی کہ ) انہوں نے عباس رضی اللہ عنہ کو ایک قمیص پہنائی تھی ( غزوہ بدر میں جب عباس رضی اللہ عنہ مسلمانوں کے قیدی بن کر آئے تھے ) سفیان نے بیان کیا کہ ابوہارون موسیٰ بن ابی عیسیٰ کہتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم کے استعمال میں دو کرتے تھے۔ عبداللہ کے لڑکے ( جو مومن مخلص تھے رضی اللہ عنہ ) نے کہا کہ یا رسول اللہ! میرے والد کو آپ وہ قمیص پہنا دیجئیے جو آپ صلی اللہ علیہ وسلم کے جسد اطہر کے قریب رہتی ہے۔ سفیان نے کہا لوگ سمجھتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم نے اپنا کرتہ اس کے کرتے کے بدل پہنا دیا جو اس نے عباس رضی اللہ عنہ کو پہنایا تھا۔' WHERE id = 1305;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن جعفر بیکندی نے بیان کیا، کہا کہ ہم سے ابومعاویہ نے بیان کیا، ان سے اعمش نے، ان سے مجاہد نے، ان سے طاؤس نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کا گزر ایسی دو قبروں پر ہوا جن میں عذاب ہو رہا تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان کو عذاب کسی بہت بڑی بات پر نہیں ہو رہا ہے صرف یہ کہ ان میں ایک شخص پیشاب سے نہیں بچتا تھا اور دوسرا شخص چغل خوری کیا کرتا تھا۔ پھر آپ صلی اللہ علیہ وسلم نے کھجور کی ایک ہری ڈالی لی اور اس کے دو ٹکڑے کر کے دونوں قبر پر ایک ایک ٹکڑا گاڑ دیا۔ لوگوں نے پوچھا کہ یا رسول اللہ! آپ نے ایسا کیوں کیا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ شاید اس وقت تک کے لیے ان پر عذاب کچھ ہلکا ہو جائے جب تک یہ خشک نہ ہوں۔' WHERE id = 1315;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، انہوں نے کہا، ہم سے عبداللہ بن وہب نے بیان کیا، انہوں نے کہا کہ مجھے یونس نے ابن شہاب سے خبر دی، انہوں نے کہا مجھے عروہ بن زبیر نے خبر دی، انہوں نے اسماء بنت ابی بکر رضی اللہ عنہا سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم خطبہ کے لیے کھڑے ہوئے تو آپ صلی اللہ علیہ وسلم نے قبر کے امتحان کا ذکر کیا جہاں انسان جانچا جاتا ہے۔ جب نبی کریم صلی اللہ علیہ وسلم اس کا ذکر کر رہے تھے تو مسلمانوں کی ہچکیاں بندھ گئیں۔' WHERE id = 1326;
UPDATE hadiths SET urdu = 'ہم سے حبان بن موسیٰ مروزی نے بیان کیا ‘ کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی ‘ کہا کہ ہمیں شعبہ نے خبر دی ‘ انہیں ابوبشر جعفر نے ‘ انہیں سعید بن جبیر نے ‘ ان کو ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم سے مشرکوں کے نابالغ بچوں کے بارے میں پوچھا گیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے جب انہیں پیدا کیا تھا اسی وقت وہ خوب جانتا تھا کہ یہ کیا عمل کریں گے۔' WHERE id = 1336;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا ‘ انہوں نے کہا ہم سے شعبہ نے بیان کیا ‘ ان سے اعمش نے بیان کیا ‘ ان سے مجاہد نے بیان کیا اور ان سے ام المؤمنین عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ‘ مردوں کو برا نہ کہو کیونکہ انہوں نے جیسا عمل کیا اس کا بدلہ پا لیا۔ اس روایت کی متابعت علی بن جعد ‘ محمد بن عرعرہ اور ابن ابی عدی نے شعبہ سے کی ہے۔ اور اس کی روایت عبداللہ بن عبدالقدوس نے اعمش سے اور محمد بن انس نے بھی اعمش سے کی ہے۔' WHERE id = 1348;
UPDATE hadiths SET urdu = 'ہم سے احمد بن شبیب بن سعید نے بیان کیا ‘ انہوں نے کہا ہم سے میرے والد شبیب نے بیان کیا ‘ انہوں نے کہا کہ ہم سے یونس نے بیان کیا ‘ ان سے ابن شہاب نے ‘ ان سے خالد بن اسلم نے ‘ انہوں نے بیان کیا کہ ہم عبداللہ بن عمر رضی اللہ عنہما کے ساتھ کہیں جا رہے تھے۔ ایک اعرابی نے آپ سے پوچھا کہ مجھے اللہ تعالیٰ کے اس فرمان کی تفسیر بتلائیے ”جو لوگ سونے اور چاندی کا خزانہ بنا کر رکھتے ہیں۔“ ابن عمر رضی اللہ عنہما نے اس کا جواب دیا کہ اگر کسی نے سونا چاندی جمع کیا اور اس کی زکوٰۃ نہ دی تو اس کے لیے «ويل» ( خرابی ) ہے۔ یہ حکم زکوٰۃ کے احکام نازل ہونے سے پہلے تھا لیکن جب اللہ تعالیٰ نے زکوٰۃ کا حکم نازل کر دیا تو اب وہی زکوٰۃ مال و دولت کو پاک کر دینے والی ہے۔' WHERE id = 1358;
UPDATE hadiths SET urdu = 'ہم سے سعید بن یحییٰ نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، کہا کہ ہم سے اعمش نے بیان کیا، ان سے شقیق نے اور ان سے ابومسعود انصاری رضی اللہ تعالیٰ عنہ نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے جب ہمیں صدقہ کرنے کا حکم دیا تو ہم میں سے بہت سے بازار جا کر بوجھ اٹھانے کی مزدوری کرتے اور اس طرح ایک مد ( غلہ یا کھجور وغیرہ ) حاصل کرتے۔ ( جسے صدقہ کر دیتے ) لیکن آج ہم میں سے بہت سوں کے پاس لاکھ لاکھ ( درہم یا دینار ) موجود ہیں۔' WHERE id = 1369;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا ‘ کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی ‘ انہیں یونس نے، انہیں زہری نے، انہوں نے کہا مجھے سعید بن مسیب نے خبر دی ‘ انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا بہترین خیرات وہ ہے جس کے دینے کے بعد آدمی مالدار رہے۔ پھر صدقہ پہلے انہیں دو جو تمہاری زیر پرورش ہیں۔' WHERE id = 1379;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا ‘ کہا کہ ہم سے ابواسامہ نے بیان کیا ‘ ان سے برید بن عبداللہ نے ‘ ان سے ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا «خازن» مسلمان امانتدار جو کچھ بھی خرچ کرتا ہے اور بعض دفعہ فرمایا وہ چیز پوری طرح دیتا ہے جس کا اسے سرمایہ کے مالک کی طرف سے حکم دیا گیا اور اس کا دل بھی اس سے خوش ہے اور اسی کو دیا ہے جسے دینے کے لیے مالک نے کہا تھا تو وہ دینے والا بھی صدقہ دینے والوں میں سے ایک ہے۔' WHERE id = 1390;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ نے بیان کیا۔ کہا کہ مجھ سے میرے والد عبداللہ بن مثنی نے بیان کیا۔ کہا کہ مجھ سے ثمامہ بن عبداللہ نے بیان کیا۔ ان سے انس رضی اللہ عنہ نے کہ ابوبکر صدیق رضی اللہ عنہ نے انہیں ( اپنے دور خلافت میں فرض زکوٰۃ سے متعلق ہدایت دیتے ہوئے ) اللہ اور رسول کے حکم کے مطابق یہ فرمان لکھا کہ جس کا صدقہ ”بنت مخاض“ تک پہنچ گیا ہو اور اس کے پاس ”بنت مخاض“ نہیں بلکہ ”بنت لبون“ ہے۔ تو اس سے وہی لے لیا جائے گا اور اس کے بدلہ میں صدقہ وصول کرنے والا بیس درہم یا دو بکریاں زائد دیدے گا اور اگر اس کے پاس ”بنت مخاض“ نہیں ہے بلکہ ”ابن لبون“ ہے تو یہ ”ابن لبون“ ہی لے لیا جائے گا اور اس صورت میں کچھ نہیں دیا جائے گا ‘ وہ مادہ یا نر اونٹ جو تیسرے سال میں لگا ہو۔' WHERE id = 1400;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا ‘ کہا کہ ہم سے میرے باپ نے بیان کیا ‘ کہا کہ ہم سے اعمش نے معرور بن سوید سے بیان کیا ‘ ان سے ابوذر رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کے قریب پہنچ گیا تھا اور آپ صلی اللہ علیہ وسلم فرما رہے تھے۔ اس ذات کی قسم جس کے ہاتھ میں میری جان ہے یا ( آپ صلی اللہ علیہ وسلم نے قسم اس طرح کھائی ) اس ذات کی قسم جس کے سوا کوئی معبود نہیں۔ یا جن الفاظ کے ساتھ بھی آپ نے قسم کھائی ہو ( اس تاکید کے بعد فرمایا ) کوئی بھی ایسا شخص جس کے پاس اونٹ گائے یا بکری ہو اور وہ اس کا حق ادا نہ کرتا ہو تو قیامت کے دن اسے لایا جائے گا۔ دنیا سے زیادہ بڑی اور موٹی تازہ کر کے۔ پھر وہ اپنے مالک کو اپنے کھروں سے روندے گی اور سینگ مارے گی۔ جب آخری جانور اس پر سے گزر جائے گا تو پہلا جانور پھر لوٹ کر آئے گا۔ ( اور اسے اپنے سینگ مارے گا اور کھروں سے روندے گا ) اس وقت تک ( یہ سلسلہ برابر قائم رہے گا ) جب تک لوگوں کا فیصلہ نہیں ہو جاتا۔ اس حدیث کو بکیر بن عبداللہ نے ابوصالح سے روایت کیا ہے ‘ انہوں نے ابوہریرہ رضی اللہ عنہ سے اور انہوں نبی کریم صلی اللہ علیہ وسلم سے۔ باب اپنے رشتہ داروں کو زکوٰۃ دینا اور نبی کریم صلی اللہ علیہ وسلم نے ( زینب کے حق میں فرمایا جو عبداللہ بن مسعود کی بیوی تھی ) اس کو دو گنا ثواب ملے گا ‘ ناطہٰ جوڑنے اور صدقے کا۔' WHERE id = 1411;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ کہا کہ ہمیں امام مالک رحمہ اللہ نے خبر دی ‘ انہیں ابوالزناد نے ‘ انہیں اعرج نے ‘ انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا اس ذات کی قسم جس کے ہاتھ میں میری جان ہے اگر کوئی شخص رسی سے لکڑیوں کا بوجھ باندھ کر اپنی پیٹھ پر جنگل سے اٹھا لائے ( پھر انہیں بازار میں بیچ کر اپنا رزق حاصل کرے ) تو وہ اس شخص سے بہتر ہے جو کسی کے پاس آ کر سوال کرے۔ پھر جس سے سوال کیا گیا ہے وہ اسے دے یا نہ دے۔' WHERE id = 1421;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ انہوں نے کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا ‘ انہوں نے کہا کہ ہم سے امام مالک رحمہ اللہ نے بیان کیا ‘ انہوں نے کہا کہ مجھ سے محمد بن عبداللہ بن عبدالرحمٰن بن ابی صعصعہ نے بیان کیا ‘ ان سے ان کے باپ نے بیان کیا اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا پانچ وسق سے کم میں زکوٰۃ نہیں ہے، اور پانچ مہار اونٹوں سے کم میں زکوٰۃ نہیں ہے۔ اور چاندی کے پانچ اوقیہ سے کم میں زکوٰۃ نہیں ہے۔' WHERE id = 1433;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا ‘ انہوں نے کہا کہ ہم سے یزید بن زریع نے بیان کیا ‘ انہوں نے کہا کہ ہم سے خالد حذاء نے بیان کیا ‘ ان سے حفصہ بنت سیرین نے اور ان سے ام عطیہ انصاریہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا کے یہاں تشریف لائے اور دریافت فرمایا کہ کیا تمہارے پاس کچھ ہے؟ عائشہ رضی اللہ عنہا نے جواب دیا کہ نہیں کوئی چیز نہیں۔ ہاں نسیبہ رضی اللہ عنہا کا بھیجا ہوا اس بکری کا گوشت ہے جو انہیں صدقہ کے طور پر ملی ہے۔ تو آپ صلی اللہ علیہ وسلم نے فرمایا لاؤ خیرات تو اپنے ٹھکانے پہنچ گئی۔' WHERE id = 1443;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ انہوں نے کہا کہ ہمیں امام مالک نے خبر دی ‘ انہیں نافع نے ‘ اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فطر کی زکوٰۃ آزاد یا غلام ‘ مرد یا عورت تمام مسلمانوں پر ایک صاع کھجور یا جَو فرض کی تھی۔' WHERE id = 1453;
UPDATE hadiths SET urdu = 'ہم سے احمد بن عیسیٰ نے بیان کیا، کہا کہ ہمیں عبداللہ بن وہب نے خبر دی، انہیں یونس نے، انہیں بن شہاب نے کہ سالم بن عبداللہ بن عمر رضی اللہ عنہما نے انہیں خبر دی، ان سے عبداللہ بن عمر نے فرمایا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو ذی الحلیفہ میں دیکھا کہ اپنی سواری پر چڑھ رہے ہیں۔ پھر جب وہ سیدھی کھڑی ہوئی تو آپ صلی اللہ علیہ وسلم نے لبیک کہا۔' WHERE id = 1463;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے وہیب نے بیان کیا، کہا کہ ہم سے عبداللہ بن طاؤس نے بیان کیا، ان سے ان کے باپ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے مدینہ والوں کے احرام کے لیے ذوالحلیفہ، شام والوں کے لیے حجفہ، نجد والوں کے قرن منزل، یمن والوں کے یلملم متعین کیا۔ یہاں سے ان مقامات والے بھی احرام باندھیں اور ان کے علاوہ وہ لوگ بھی جو ان راستوں سے آئیں اور حج یا عمرہ کا ارادہ رکھتے ہوں۔ لیکن جن کا قیام میقات اور مکہ کے درمیان ہے تو وہ احرام اسی جگہ سے باندھیں جہاں سے انہیں سفر شروع کرنا ہے۔ یہاں تک کہ مکہ کے لوگ مکہ ہی سے احرام باندھیں۔' WHERE id = 1473;
UPDATE hadiths SET urdu = 'ہم سے ابوبکر عبداللہ حمیدی نے بیان کیا، کہا کہ ہم سے ولید اور بشر بن بکر تنیسی نے بیان کیا، انہوں نے کہا کہ ہم سے امام اوزاعی نے بیان کیا، کہا کہ ہم سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے عکرمہ نے بیان کیا، انہوں نے عبداللہ بن عباس رضی اللہ عنہما سے سنا، وہ بیان کرتے تھے کہ میں نے عمر رضی اللہ عنہ سے سنا، ان کا بیان تھا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے وادی عقیق میں سنا۔ آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ رات میرے پاس میرے رب کا ایک فرشتہ آیا اور کہا کہ اس ”مبارک وادی“ میں نماز پڑھ اور اعلان کر کہ عمرہ حج میں شریک ہو گیا۔' WHERE id = 1483;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے ابوایوب نے، ان سے ابوقلابہ نے اور ان سے انس بن مالک نے کہ نبی کریم صلی اللہ علیہ وسلم نے نماز ظہر مدینہ منورہ میں چار رکعت پڑھی۔ لیکن نماز عصر ذوالحلیفہ میں دو رکعت پڑھی۔ میں نے خود سنا کہ لوگ بلند آواز سے حج اور عمرہ دونوں کے لیے لبیک کہہ رہے تھے۔' WHERE id = 1495;
UPDATE hadiths SET urdu = 'ہم سے حسن بن علی خلال ہذلی نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالصمد بن عبدالوارث نے بیان کیا، انہوں نے کہا کہ ہم سے سلیم بن حیان نے بیان کیا، انہوں نے کہا کہ میں نے مروان اصفر سے سنا اور ان سے انس بن مالک نے بیان کیا تھا کہ علی رضی اللہ عنہ یمن سے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے تو آپ صلی اللہ علیہ وسلم نے پوچھا کہ کس طرح کا احرام باندھا ہے؟ انہوں نے کہا کہ جس طرح کا نبی کریم صلی اللہ علیہ وسلم نے باندھا ہو۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر میرے ساتھ قربانی نہ ہوتی تو میں حلال ہو جاتا۔' WHERE id = 1505;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، ان سے ابوشہاب نے کہا کہ میں تمتع کی نیت سے عمرہ کا احرام باندھ کے یوم ترویہ سے تین دن پہلے مکہ پہنچا۔ اس پر مکہ کے کچھ لوگوں نے کہا اب تمہارا حج مکی ہو گا۔ میں عطاء بن ابی رباح کی خدمت میں حاضر ہوا۔ یہی پوچھنے کے لیے۔ انہوں نے فرمایا کہ مجھ سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ وہ حج کیا تھا جس میں آپ صلی اللہ علیہ وسلم اپنے ساتھ قربانی کے اونٹ لائے تھے ( یعنی حجتہ الوداع ) صحابہ نے صرف مفرد حج کا احرام باندھا تھا۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ ( عمرہ کا احرام باندھ لو اور ) بیت اللہ کے طواف اور صفا مروہ کی سعی کے بعد اپنے احرام کھول ڈالو اور بال ترشوا لو۔ یوم ترویہ تک برابر اسی طرح حلال رہو، پھر یوم ترویہ میں مکہ ہی سے حج کا احرام باندھو اور اس طرح اپنے حج مفرد کو جس کی تم نے پہلے نیت کی تھی، اب اسے تمتع بنا لو۔ صحابہ نے عرض کی کہ ہم اسے تمتع کیسے بنا سکتے ہیں؟ ہم تو حج کا احرام باندھ چکے ہیں۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس طرح میں کہہ رہا ہوں ویسے ہی کرو۔ اگر میرے ساتھ ہدی نہ ہوتی تو خود میں بھی اسی طرح کرتا جس طرح تم سے کہہ رہا ہوں۔ لیکن میں کیا کروں اب میرے لیے کوئی چیز اس وقت تک حلال نہیں ہو سکتی جب تک میرے قربانی کے جانوروں کی قربانی نہ ہو جائے۔ چنانچہ صحابہ نے آپ کے حکم کی تعمیل کی۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ ابوشہاب کی اس حدیث کے سوا اور کوئی مرفوع حدیث مروی نہیں ہے۔' WHERE id = 1515;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان مروزی نے بیان کیا، انہوں نے کہا کہ ہم سے ابواسامہ نے بیان کیا، انہوں نے کہا کہ ہم سے ہشام بن عروہ نے بیان کیا۔ ان سے ان کے والد عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم فتح مکہ کے موقع پر شہر میں کداء کی طرف سے داخل ہوئے اور کدیٰ کی طرف سے نکلے جو مکہ کے بلند جانب ہے۔' WHERE id = 1525;
UPDATE hadiths SET urdu = 'ہم سے اصبغ بن فرج نے بیان کیا، انہوں نے کہا کہ مجھے عبداللہ بن وہب نے خبر دی، انہیں یونس نے، انہیں ابن شہاب نے، انہیں علی بن حسین نے، انہیں عمرو بن عثمان نے اور انہیں اسامہ بن زید رضی اللہ عنہما نے کہ انہوں نے پوچھا یا رسول اللہ! آپ مکہ میں کیا اپنے گھر میں قیام فرمائیں گے۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ عقیل نے ہمارے لیے محلہ یا مکان چھوڑا ہی کب ہے۔ ( سب بیچ کھوچ کر برابر کر دئیے ) عقیل اور طالب، ابوطالب کے وارث ہوئے تھے۔ جعفر اور علی رضی اللہ عنہما کو وراثت میں کچھ نہیں ملا تھا، کیونکہ یہ دونوں مسلمان ہو گئے تھے اور عقیل رضی اللہ عنہ ( ابتداء میں ) اور طالب اسلام نہیں لائے تھے۔ اسی بنیاد پر عمر بن خطاب رضی اللہ عنہ فرمایا کرتے تھے کہ مسلمان کافر کا وارث نہیں ہوتا۔ ابن شہاب نے کہا کہ لوگ اللہ تعالیٰ کے اس ارشاد سے دلیل لیتے ہیں کہ ”جو لوگ ایمان لائے، ہجرت کی اور اپنے مال اور جان کے ساتھ اللہ کی راہ میں جہاد کیا اور وہ لوگ جنہوں نے پناہ دی اور مدد کی، وہی ایک دوسرے کے وارث ہوں گے۔“' WHERE id = 1535;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے لیث بن سعد نے بیان کیا، ان سے ابن شہاب نے، ان سے سالم نے اور ان سے ان کے باپ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم اور اسامہ بن زید اور بلال و عثمان بن ابی طلحہ رضی اللہ عنہم چاروں خانہ کعبہ کے اندر گئے اور اندر سے دروازہ بند کر لیا۔ پھر جب دروازہ کھولا تو میں پہلا شخص تھا جو اندر گیا۔ میری ملاقات بلال رضی اللہ عنہ سے ہوئی۔ میں نے پوچھا کہ کیا نبی کریم صلی اللہ علیہ وسلم نے ( اندر ) نماز پڑھی ہے؟ انہوں نے بتلایا کہ ”ہاں! دونوں یمنی ستونوں کے درمیان آپ صلی اللہ علیہ وسلم نے نماز پڑھی ہے۔“' WHERE id = 1545;
UPDATE hadiths SET urdu = 'اور محمد بن بکر نے کہا کہ ہمیں ابن جریج نے خبر دی، انہوں نے کہا مجھ کو عمرو بن دینار نے خبر دی کہ ابوالشعثاء نے کہا بیت اللہ کے کسی بھی حصہ سے بھلا کون پرہیز کر سکتا ہے۔ اور معاویہ رضی اللہ عنہ چاروں رکنوں کا استلام کرتے تھے، اس پر عبداللہ بن عباس رضی اللہ عنہما نے ان سے کہا کہ ہم ان دو ارکان شامی اور عراقی کا استلام نہیں کرتے تو معاویہ رضی اللہ عنہ نے فرمایا کہ بیت اللہ کا کوئی جزء ایسا نہیں جسے چھوڑ دیا جائے اور عبداللہ بن زبیر رضی اللہ عنہما بھی تمام ارکان کا استلام کرتے تھے۔' WHERE id = 1555;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا کہ ہم سے ہشام نے بیان کیا کہ ابن جریج نے انہیں خبر دی، کہا کہ مجھے سلیمان احول نے خبر دی، انہیں طاؤس نے خبر دی اور انہیں ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کعبہ کا طواف کرتے ہوئے ایک ایسے شخص کے پاس سے گزرے جس نے اپنا ہاتھ ایک دوسرے شخص کے ہاتھ سے تسمہ یا رسی یا کسی اور چیز سے باندھ رکھا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے اپنے ہاتھ سے اسے کاٹ دیا اور پھر فرمایا کہ ”اگر ساتھ ہی چلنا ہے تو ہاتھ پکڑ کے چلو۔“' WHERE id = 1566;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد بن ابی الاسود نے بیان کیا، انہوں نے کہا کہ ہم سے ابوضمرہ نے بیان کیا، انہوں نے کہا کہ ہم سے عبیداللہ عمری نے بیان کیا، ان سے نافع نے، ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ عباس بن عبدالمطلب رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم سے اپنے پانی ( زمزم کا حاجیوں کو ) پلانے کے لیے منیٰ کے دنوں میں مکہ ٹھہرنے کی اجازت چاہی تو آپ صلی اللہ علیہ وسلم نے ان کو اجازت دے دی۔' WHERE id = 1578;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے عمرو بن دینار سے بیان کہ ہم نے ابن عمر رضی اللہ عنہما سے ایک ایسے شخص کے متعلق پوچھا جو عمرہ میں بیت اللہ کا طواف تو کر لے لیکن صفا اور مروہ کی سعی نہیں کرتا، کیا وہ اپنی بیوی سے صحبت کر سکتا ہے۔ انہوں نے جواب دیا نبی کریم صلی اللہ علیہ وسلم ( مکہ ) تشریف لائے تو آپ نے بیت اللہ کا سات چکروں کے ساتھ طواف کیا اور مقام ابراہیم کے پیچھے دو رکعت نماز پڑھی۔ پھر صفا اور مروہ کی سات مرتبہ سعی کی اور تمہارے لیے رسول اللہ صلی اللہ علیہ وسلم کی زندگی بہترین نمونہ ہے۔' WHERE id = 1588;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے ابواسحاق ہمدانی سے بیان کیا اور ان سے حارثہ بن وہب خزاعی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے منیٰ میں ہمیں دو رکعات پڑھائیں، ہمارا شمار اس وقت سب سے زیادہ تھا اور ہم اتنے بے ڈر کسی وقت میں نہ تھے۔ ( اس کے باوجود ہم کو نماز قصر پڑھائی ) ۔' WHERE id = 1598;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، کہا ہم کو امام مالک نے ہشام بن عروہ سے خبر دی، ان سے ان کے والد نے بیان کیا کہ ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، کہا ہم کو امام مالک نے ہشام بن عروہ سے خبر دی، ان سے ان کے والد نے بیان کیا کہ' WHERE id = 1608;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، کہا کہ مجھے عبیداللہ بن ابی یزید نے خبر دی، انہوں نے ابن عباس رضی اللہ عنہما کو یہ کہتے سنا کہ میں ان لوگوں میں تھا جنہیں نبی کریم صلی اللہ علیہ وسلم نے اپنے گھر کے کمزور لوگوں کے ساتھ مزدلفہ کی رات ہی میں منیٰ بھیج دیا تھا۔' WHERE id = 1619;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا کہ ہم سے ہشام اور شعبہ نے بیان کیا، کہا کہ ہم سے قتادہ نے بیان کیا اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک شخص کو دیکھا کہ قربانی کا جانور لیے جا رہا ہے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس پر سوار ہو جا اس نے کہا کہ یہ تو قربانی کا جانور ہے آپ صلی اللہ علیہ وسلم نے فرمایا کہ سوا ر ہو جا اس نے پھر عرض کیا کہ یہ تو قربانی کا جانور ہے، لیکن آپ صلی اللہ علیہ وسلم نے تیسری مرتبہ پھر فرمایا کہ سوار ہو جا۔' WHERE id = 1630;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، ان سے عبدالواحد نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے ابراہیم نے، ان سے اسود نے اور ان سے عائشہ رضی اللہ عنہا نے کہ میں نبی کریم صلی اللہ علیہ وسلم کے قربانی کے جانوروں کے قلادہ خود بٹا کرتی تھی، نبی کریم صلی اللہ علیہ وسلم نے بکری کو بھی قلادہ پہنایا تھا اور آپ صلی اللہ علیہ وسلم خود اپنے گھر اس حال میں مقیم تھے کہ آپ صلی اللہ علیہ وسلم حلال تھے۔' WHERE id = 1641;
UPDATE hadiths SET urdu = 'ہم سے سہل بن بکار نے بیان کیا، انہوں نے کہا کہ ہم سے وہیب نے بیان کیا، ان سے ایوب نے، ان سے ابوقلابہ نے، ان سے انس بن مالک رضی اللہ عنہ نے اور انہوں نے مختصر حدیث بیان کی اور یہ بھی بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے سات اونٹ کھڑے کر کے اپنے ہاتھ سے نحر کئے اور مدینہ میں دو چتکبرے سینگ دار مینڈھوں کی قربانی کی۔' WHERE id = 1651;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم کو ابوبکر بن عیاش نے خبر دی، انہیں عبدالعزیز بن رفیع نے، انہیں عطا بن ابی رباح نے اور انہیں ابن عباس رضی اللہ عنہما نے کہ ایک آدمی نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا کہ یا رسول اللہ! رمی سے پہلے میں نے طواف زیارت کر لیا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کوئی حرج نہیں، پھر اس نے کہا اور یا رسول اللہ! قربانی کرنے سے پہلے میں نے سر منڈوا لیا، آپ صلی اللہ علیہ وسلم نے فرمایا کوئی حرج نہیں، پھر اس نے کہا اور قربانی کو رمی سے بھی پہلے کر لیا نبی کریم صلی اللہ علیہ وسلم نے پھر بھی یہی فرمایا کہ کوئی حرج نہیں۔ اور عبدالرحیم رازی نے ابن خشیم سے بیان کیا، کہا کہ عطاء نے خبر دی اور انہیں ابن عباس رضی اللہ عنہما نے نبی کریم صلی اللہ علیہ وسلم سے اور قاسم بن یحییٰ نے کہا کہ مجھ سے ابن خشیم نے بیان کیا، ان سے عطاء نے، ان سے ابن عباس رضی اللہ عنہما نے نبی کریم صلی اللہ علیہ وسلم سے۔ عفان بن مسلم صغار نے کہا کہ میرا خیال ہے کہ وہیب بن خالد سے روایت ہے کہ ابن خثیم نے بیان کیا، ان سے سعید بن جبیر نے، ان سے ابن عباس رضی اللہ عنہما نے نبی کریم صلی اللہ علیہ وسلم سے۔ اور حماد نے قیس بن سعد اور عباد بن منصور سے بیان کیا، ان سے عطاء نے اور ان سے جابر رضی اللہ عنہ نے انہوں نے نبی کریم صلی اللہ علیہ وسلم سے روایت کیا۔' WHERE id = 1661;
UPDATE hadiths SET urdu = 'اور ہم سے ابونعیم نے بیان کیا، ان سے سفیان نے بیان کیا، ان سے عبیداللہ نے، ان سے نافع نے کہ ابن عمر رضی اللہ عنہما نے صرف ایک طواف الزیارۃ کیا پھر سویرے سے منیٰ کو آئے، ان کی مراد دسویں تاریخ سے تھی، عبدالرزاق نے اس حدیث کا رفع ( رسول اللہ صلی اللہ علیہ وسلم تک ) بھی کیا ہے۔ انہیں عبیداللہ نے خبر دی۔' WHERE id = 1671;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنی نے بیان کیا، کہا ہم سے یزید بن ہارون نے بیان کیا، کہا ہم کو عاصم بن محمد بن زید نے خبر دی، انہیں ان کے باپ نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے منیٰ میں فرمایا کہ تم کو معلوم ہے! آج کون سا دن ہے؟ لوگوں نے کہا کہ اللہ اور اس کے رسول زیادہ جانتے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ حرمت کا دن ہے اور یہ بھی تم کو معلوم ہے کہ یہ کون سا شہر ہے؟ لوگوں نے کہا اللہ اور اس کے رسول زیادہ جانتے ہیں، آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ حرمت کا شہر ہے اور تم کو یہ بھی معلوم ہے کہ یہ کون سا مہینہ ہے، لوگوں نے کہا اللہ اور اس کے رسول زیادہ جانتے ہیں، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ حرمت کا مہینہ ہے پھر فرمایا کہ اللہ تعالیٰ نے تمہارا خون! تمہارا مال اور عزت ایک دوسرے پر ( ناحق ) اس طرح حرام کر دی ہیں جیسے اس دن کی حرمت اس مہینہ اور اس شہر میں ہے۔ ہشام بن غاز نے کہا کہ مجھے نافع نے ابن عمر رضی اللہ عنہما کے حوالے سے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم حجۃ الوداع میں دسویں تاریخ کو جمرات کے درمیان کھڑے ہوئے تھے اور فرمایا تھا کہ دیکھو! یہ ( «يوم النحر» ) حج اکبر کا دن ہے، پھر نبی کریم صلی اللہ علیہ وسلم یہ فرمانے لگے کہ اے اللہ! گواہ رہنا، نبی کریم صلی اللہ علیہ وسلم نے اس موقع پر چونکہ لوگوں کو رخصت کیا تھا۔ ( آپ سمجھ گئے کہ وفات کا زمانہ آن پہنچا ) جب سے لوگ اس حج کو حجۃ الوداع کہنے لگے۔' WHERE id = 1681;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، انہوں نے کہا کہ مجھ سے میرے بھائی (عبدالحمید) نے بیان کیا، ان سے سلیمان نے بیان کیا، ان سے یونس بن یزید نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے سالم بن عبداللہ نے بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما پہلے جمرہ کی رمی سات کنکریوں کے ساتھ کرتے اور ہر کنکری پر «الله اكبر» کہتے تھے، اس کے بعد آگے بڑھتے اور ایک نرم ہموار زمین پر قبلہ رخ کھڑے ہو جاتے، دعائیں کرتے رہتے اور دونوں ہاتھوں کو اٹھاتے پھر جمرہ وسطی کی رمی میں بھی اسی طرح کرتے اور بائیں طرف آگے بڑھ کر ایک نرم زمین پر قبلہ رخ کھڑے ہو جاتے، بہت دیر تک اسی طرح کھڑے ہو کر دعائیں کرتے رہتے، پھر جمرہ عقبہ کی رمی بطن وادی سے کرتے لیکن وہاں ٹھہرتے نہیں تھے، آپ فرماتے تھے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کی اسی طرح کرتے دیکھا ہے۔' WHERE id = 1691;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن عطاء بن ابی رباح نے بیان کیا اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ محصب میں اترنا حج کی کوئی عبادت نہیں ہے، یہ تو صرف رسول اللہ صلی اللہ علیہ وسلم کے قیام کی جگہ تھی۔' WHERE id = 1703;
UPDATE hadiths SET urdu = 'ہم سے ہدبہ بن خالد نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، اس روایت میں یوں ہے کہ جو عمرہ نبی کریم صلی اللہ علیہ وسلم نے اپنے حج کے ساتھ کیا تھا اس کے سوا تمام عمرے ذی قعدہ ہی میں کئے تھے۔ حدیبیہ کا عمرہ اور دوسرے سال اس کی قضاء کا عمرہ تھا۔ ( کیونکہ آپ صلی اللہ علیہ وسلم نے قران کیا تھا اور حجۃ الوداع سے متعلق ہے ) اور جعرانہ کا عمرہ جب آپ صلی اللہ علیہ وسلم نے جنگ حنین کی غنیمت تقسیم کی تھی۔ پھر ایک عمرہ اپنے حج کے ساتھ کیا تھا۔' WHERE id = 1715;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں ہشام بن عروہ نے، انہیں ان کے والد (عروہ بن زبیر) نے کہ میں نے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ صدیقہ رضی اللہ عنہا سے پوچھا جب کہ ابھی میں نوعمر تھا کہ اللہ تعالیٰ کا ارشاد ”صفا اور مروہ دونوں اللہ تعالیٰ کی نشانیاں ہیں اس لیے جو شخص بیت اللہ کا حج یا عمرہ کرے اس کے لیے ان کی سعی کرنے میں کوئی گناہ نہیں“ اس لیے میں سمجھتا ہوں کہ اگر کوئی ان کی سعی نہ کرے تو اس پر کوئی گناہ نہ ہو گا۔ یہ سن کر عائشہ صدیقہ رضی اللہ عنہا نے فرمایا کہ ہرگز نہیں۔ اگر مطلب یہ ہوتا جیسا کہ تم بتا رہے ہو پھر تو ان کی سعی نہ کرنے میں واقعی کوئی حرج نہیں تھا، لیکن یہ آیت تو انصار کے بارے میں نازل ہوئی ہے جو منات بت کے نام کا احرام باندھتے تھے جو قدید کے مقابل میں رکھا ہوا تھا وہ صفا اور مروہ کی سعی کو اچھا نہیں سمجھتے تھے، جب اسلام آیا تو انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے اس کے بارے میں پوچھا اور اس پر اللہ تعالیٰ نے یہ آیت نازل فرمائی کہ ”صفا اور مروہ دونوں اللہ کی نشانیاں ہیں اس لیے جو شخص بیت اللہ کا حج یا عمرہ کرے اس کے لیے ان کی سعی کرنے میں کوئی گناہ نہیں“ سفیان اور ابومعاویہ نے ہشام سے یہ زیادتی نکالی ہے کہ جو کوئی صفا مروہ کا پھیرا نہ کرے تو اللہ اس کا حج اور عمرہ پورا نہ کرے گا۔' WHERE id = 1725;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق نے کہ میں نے براء بن عازب رضی اللہ عنہ سے سنا، انہوں نے کہا کہ یہ آیت ہمارے بارے میں نازل ہوئی۔ انصار جب حج کے لیے آتے تو ( احرام کے بعد ) گھروں میں دروازوں سے نہیں جاتے بلکہ دیواروں سے کود کر ( گھر کے اندر ) داخل ہوا کرتے تھے پھر ( اسلام لانے کے بعد ) ایک انصاری شخص آیا اور دروازے سے گھر میں داخل ہو گیا اس پر لوگوں نے لعنت ملامت کی تو یہ وحی نازل ہوئی کہ ”یہ کوئی نیکی نہیں ہے کہ گھروں میں پیچھے سے ( دیواروں پر چڑھ کر ) آؤ بلکہ نیک وہ شخص ہے جو تقویٰ اختیار کرے اور گھروں میں ان کے دروازوں سے آیا کرو۔“' WHERE id = 1736;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے نافع نے بیان کیا کہ فتنہ کے زمانہ میں جب عبداللہ بن عمر رضی اللہ عنہما مکہ کے ارادے سے چلے تو فرمایا کہ اگر مجھے بیت اللہ تک پہنچے سے روک دیا گیا تو میں بھی وہی کام کروں گا جو ( حدیبیہ کے سال ) میں نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ کیا تھا۔ آپ نے عمرہ کا احرام باندھا کیونکہ رسول اللہ صلی اللہ علیہ وسلم نے بھی حدیبیہ کے سال عمرہ ہی کا احرام باندھا تھا۔ پھر آپ نے کچھ غور کر کے فرمایا کہ عمرہ اور حج تو ایک ہی ہے، اس کے بعد اپنے ساتھیوں سے بھی یہی فرمایا کہ یہ دونوں تو ایک ہی ہیں۔ میں تمہیں گواہ بناتا ہوں کہ عمرہ کے ساتھ اب حج بھی اپنے لیے میں نے واجب قرار دیے لیا ہے پھر ( مکہ پہنچ کر ) آپ نے دونوں کے لیے ایک ہی طواف کیا۔ آپ کا خیال تھا کہ یہ کافی ہے اور آپ قربانی کا جانور بھی ساتھ لے گئے تھے۔' WHERE id = 1746;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہ ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے صالح بن کیسان نے بیان کیا، ان سے ابومحمد نے، ان سے ابوقتادہ رضی اللہ عنہ کے غلام نافع نے، انہوں نے ابوقتادہ رضی اللہ عنہ سے سنا، آپ نے فرمایا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ مدینہ سے تین منزل دور مقام قاحہ میں تھے۔ ( دوسری سند امام بخاری رحمہ اللہ نے ) کہا کہ ہم سے علی بن عبداللہ نے بیان کیا، کہا کہ ہم سے سفیان نے بیان کیا کہا ہم سے صالح بن کیسان نے بیان کیا، ان سے ابومحمد نے اور ان سے ابوقتادہ رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ مقام قاحہ میں تھے، بعض تو ہم میں سے محرم تھے اور بعض غیر محرم۔ میں نے دیکھا کہ میرے ساتھی ایک دوسرے کو کچھ دکھا رہے ہیں، میں نے جو نظر اٹھائی تو ایک گورخر سامنے تھا، ان کی مراد یہ تھی کہ ان کا کوڑا گر گیا، ( اور اپنے ساتھیوں سے اسے اٹھانے کے لیے انہوں نے کہا ) ، لیکن ساتھیوں نے کہا کہ ہم تمہاری کچھ بھی مدد نہیں کر سکتے کیونکہ ہم محرم ہیں ) اس لیے میں نے وہ خود اٹھایا اس کے بعد میں اس گورخر کے نزدیک ایک ٹیلے کے پیچھے سے آیا اور اسے شکار کیا، پھر میں اسے اپنے ساتھیوں کے پاس لایا، بعض نے تو یہ کہا کہ ( ہمیں بھی ) کھا لینا چاہئے لیکن بعض نے کہا کہ نہیں کھانا چاہیے۔ پھر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں آیا۔ آپ ہم سے آگے تھے، میں نے آپ سے مسئلہ پوچھا تو آپ نے بتایا کہ کھا لو یہ حلال ہے۔ ہم سے عمرو بن دینار نے کہا کہ صالح بن کیسان کی خدمت میں حاضر ہو کر اس حدیث اور اس کے علاوہ کے متعلق پوچھ سکتے ہو اور وہ ہمارے پاس یہاں آئے تھے۔' WHERE id = 1756;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنی نے بیان کیا، کہا ہم سے عبدالوہاب نے بیان کیا، کہا ہم سے خالد نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اللہ تعالیٰ نے مکہ کو حرمت والا بنایا ہے مجھ سے پہلے بھی یہ کسی کے لیے حلال نہیں تھا اس لیے میرے بعد بھی وہ کسی کے لیے حلال نہیں ہو گا۔ میرے لیے صرف ایک دن گھڑی بھر حلال ہوا تھا اس لیے اس کی گھاس نہ اکھاڑی جائے اور اس کے درخت نہ کاٹے جائیں، اس کے شکار نہ بھڑکائے جائیں اور نہ وہاں کی گری ہوئی چیز اٹھائی جائے۔ ہاں اعلان کرنے والا اٹھا سکتا ہے۔ ( تاکہ اصل مالک تک پہنچا دے ) عباس رضی اللہ عنہ نے کہا کہ یا رسول اللہ! اذخر کی اجازت دیجئیے کیونکہ یہ ہمارے سناروں اور ہماری قبروں کے لیے کام آتی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اذخر کی اجازت ہے۔ خالد نے روایت کیا کہ عکرمہ رحمہ اللہ نے فرمایا کہ تم جانتے ہو کہ شکار کو نہ بھڑکانے سے کیا مراد ہے؟ اس کا مطلب یہ ہے کہ ( اگر کہیں کوئی جانور سایہ میں بیٹھا ہوا ہے تو ) اسے سایہ سے بھگا کر خود وہاں قیام نہ کرے۔' WHERE id = 1766;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا، ان سے جابر بن زید نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ہم کو میدان عرفات میں وعظ سنایا، اس میں آپ نے فرمایا کہ اگر کسی کو احرام کے لیے تہبند نہ ملے تو وہ پاجامہ پہن لے اور اگر کسی کو جوتے نہ ملیں تو وہ موزے پہن لے۔' WHERE id = 1776;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے ابن جریج سے بیان کیا، انہوں نے کہا ان سے ابن شہاب نے، ان سے سلیمان بن یسار نے، ان سے عبداللہ بن عباس رضی اللہ عنہما نے اور ان سے فضل بن عیاض رضی اللہ عنہم نے کہ ایک خاتون۔۔۔ ( حدیث نمبر 1854 دیکھیں)' WHERE id = 1786;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو یزید بن زریع نے خبر دی، کہا ہم کو حبیب معلم نے خبر دی، انہیں عطاء بن ابی رباح نے اور ان سے ابن عباس رضی اللہ عنہما نے فرمایا کہ جب رسول اللہ صلی اللہ علیہ وسلم حجۃ الوداع سے واپس ہوئے تو آپ صلی اللہ علیہ وسلم نے ام سنان انصاریہ عورت رضی اللہ عنہا سے دریافت فرمایا کہ تو حج کرنے نہیں گئی؟ انہوں نے عرض کی کہ فلاں کے باپ یعنی میرے خاوند کے پاس دو اونٹ پانی پلانے کے تھے ایک پر تو خود حج کو چلے گئے اور دوسرا ہماری زمین سیراب کرتا ہے۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ رمضان میں عمرہ کرنا میرے ساتھ حج کرنے کے برابر ہے، اس روایت کو ابن جریج نے عطاء سے سنا، کہا انہوں نے ابن عباس رضی اللہ عنہما سے سنا، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے، اور عبیداللہ نے عبدالکریم سے روایت کیا، ان سے عطاء نے ان سے جابر رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے۔' WHERE id = 1796;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہمیں امام مالک نے خبر دی، انہیں ابن شہاب زہری نے، انہیں سعید بن مسیب نے کہ ابوہریرہ رضی اللہ عنہ فرمایا کرتے تھے اگر میں مدینہ میں ہرن چرتے ہوئے دیکھوں تو انہیں کبھی نہ چھیڑوں کیونکہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ مدینہ کی زمین دونوں پتھریلے میدانوں کے بیچ میں حرم ہے۔' WHERE id = 1806;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عباس نے بیان کیا، کہا ہم سے عبدالرحمٰن نے بیان کیا، ان سے سفیان نے بیان کیا، ان سے محمد بن منکدر نے اور ان سے جابر رضی اللہ عنہ نے کہ ایک اعرابی نے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو کر اسلام پر بیعت کی، دوسرے دن آیا تو اسے بخار چڑھا ہوا تھا کہنے لگا کہ میری بیعت توڑ دیجئیے! تین بار اس نے یہی کہا آپ صلی اللہ علیہ وسلم نے انکار کیا پھر فرمایا کہ مدینہ کی مثال بھٹی کی سی ہے کہ میل کچیل کو دور کر کے خالص جوہر کو نکھار دیتی ہے۔' WHERE id = 1816;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، ان سے یزید بن ابی حبیب نے اور ان سے عراک بن مالک نے بیان کیا، انہیں عروہ نے خبر دی کہ ام المؤمنین عائشہ رضی اللہ عنہا نے فرمایا قریش زمانہ جاہلیت میں عاشورہ کا روزہ رکھتے تھے، پھر رسول اللہ صلی اللہ علیہ وسلم نے بھی اس دن روزہ کا حکم دیا یہاں تک کہ رمضان کے روزے فرض ہو گئے، پھر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جس کا جی چاہے یوم عاشورہ کا روزہ رکھے اور جس کا جی چاہے نہ رکھے۔' WHERE id = 1826;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے ابن ابی ذئب نے بیان کیا، ان سے سعید مقبری نے، ان سے ان کے والد کیسان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، اگر کوئی شخص جھوٹ بولنا اور دغا بازی کرنا ( روزے رکھ کر بھی ) نہ چھوڑے تو اللہ تعالیٰ کو اس کی کوئی ضرورت نہیں کہ وہ اپنا کھانا پینا چھوڑ دے۔' WHERE id = 1836;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے اسود بن قیس نے بیان کیا، ان سے سعید بن عمرو نے بیان کیا اور انہوں نے ابن عمر رضی اللہ عنہما سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، ہم ایک بے پڑھی لکھی قوم ہیں نہ لکھنا جانتے ہیں نہ حساب کرنا۔ مہینہ یوں ہے اور یوں ہے۔ آپ کی مراد ایک مرتبہ انتیس ( دنوں سے ) تھی اور ایک مرتبہ تیس سے۔ ( آپ صلی اللہ علیہ وسلم نے دسوں انگلیوں سے تین بار بتلایا ) ۔' WHERE id = 1846;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، ان سے شعبہ نے، ان سے حکم نے، ان سے ابراہیم نے ان سے اسود نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم روزہ سے ہوتے لیکن ( اپنی ازواج کے ساتھ ) «يقبل» ( بوسہ لینا ) و مباشرت ( اپنے جسم سے لگا لینا ) بھی کر لیتے تھے۔ نبی کریم صلی اللہ علیہ وسلم تم سب سے زیادہ اپنی خواہشات پر قابو رکھنے والے تھے، بیان کیا کہ ابن عباس رضی اللہ عنہما نے کہا کہ ( سورۃ طہٰ میں جو «مآرب‏» کا لفظ ہے وہ ) حاجت و ضرورت کے معنی میں ہے، طاؤس نے کہا کہ لفظ «أولي الإربة‏» ( جو سورۃ النور میں ہے ) اس احمق کو کہیں گے جسے عورتوں کی کوئی ضرورت نہ ہو۔' WHERE id = 1858;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر عبداللہ بن عمری نے بیان کیا، کہا ہم سے عبدالوارث بن سعید نے بیان کیا، ان سے ایوب سختیانی نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے روزہ کی حالت میں پچھنا لگوایا۔' WHERE id = 1869;
UPDATE hadiths SET urdu = 'ہم سے عیاش نے بیان کیا، ان سے عبدالاعلیٰ نے بیان کیا، ان سے عبیداللہ نے بیان کیا، ان سے نافع نے کہ عبداللہ بن عمر رضی اللہ عنہما نے ( آیت مذکور بالا ) «فديه طعام مسكين» پڑھی اور فرمایا یہ منسوخ ہے۔' WHERE id = 1879;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ مجھ سے یحییٰ قطان نے بیان کیا، ان سے شعبہ نے، کہا کہ مجھ سے قتادہ نے بیان کیا اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ( بلا سحر و افطار ) پے در پے روزے نہ رکھا کرو۔ صحابہ رضی اللہ عنہم نے عرض کی کہ آپ صلی اللہ علیہ وسلم تو وصال کرتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں تمہاری طرح نہیں ہوں۔ مجھے ( اللہ تعالیٰ کی طرف سے ) کھلایا اور پلایا جاتا ہے یا ( آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ ) میں اس طرح رات گزارتا ہوں کہ مجھے کھلایا اور پلایا جاتا رہتا ہے۔' WHERE id = 1891;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، ان سے ابوعوانہ نے بیان کیا، ان سے ابوبشر نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رمضان کے سوا نبی کریم صلی اللہ علیہ وسلم نے کبھی پورے مہینے کا روزہ نہیں رکھا۔ آپ صلی اللہ علیہ وسلم نفل روزہ رکھنے لگتے تو دیکھنے والا کہہ اٹھتا کہ بخدا، اب آپ بے روزہ نہیں رہیں گے اور اسی طرح جب نفل روزہ چھوڑ دیتے تو کہنے والا کہتا کہ واللہ! اب آپ صلی اللہ علیہ وسلم روزہ نہیں رکھیں گے۔' WHERE id = 1901;
UPDATE hadiths SET urdu = 'ہم سے معمر نے بیان کیا، ان سے عبدالوارث نے بیان کیا، ان سے ابوالتیاح نے بیان کیا، کہا کہ مجھ سے ابوعثمان نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ میرے خلیل صلی اللہ علیہ وسلم نے مجھے ہر مہینے کی تین تاریخوں میں روزہ رکھنے کی وصیت فرمائی تھی۔ اسی طرح چاشت کی دو رکعتوں کی بھی وصیت فرمائی تھی اور اس کی بھی کہ سونے سے پہلے ہی میں وتر پڑھ لیا کروں۔' WHERE id = 1911;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا کہ ہم کو ہشام نے خبر دی، ان سے ابن جریج نے بیان کیا کہ مجھے عمرو بن دینار نے خبر دی، انہوں نے عطاء بن میناء سے سنا، وہ ابوہریرہ رضی اللہ عنہ سے یہ حدیث نقل کرتے تھے کہ آپ نے فرمایا، نبی کریم صلی اللہ علیہ وسلم نے دو روزے اور دو قسم کی خرید و فروخت سے منع فرمایا ہے۔ عیدالفطر اور عید الاضحی کے روزے سے۔ اور ملامست اور منابذت کے ساتھ خرید و فروخت کرنے سے۔' WHERE id = 1922;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا کہ ہم سے ابواسامہ نے بیان کیا، ان سے ابوعمیس نے، ان سے قیس بن مسلم نے، ان سے طارق نے، ان سے ابن شہاب نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ عاشوراء کے دن کو یہودی عید کا دن سمجھتے تھے اس لیے رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ تم بھی اس دن روزہ رکھا کرو۔' WHERE id = 1933;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک رحمہ اللہ نے خبر دی، انہیں نافع نے، اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کے چند اصحاب کو شب قدر خواب میں ( رمضان کی ) سات آخری تاریخوں میں دکھائی گئی تھی۔ پھر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا میں دیکھ رہا ہوں کہ تمہارے سب کے خواب سات آخری تاریخوں پر متفق ہو گئے ہیں۔ اس لیے جسے اس کی تلاش ہو وہ اسی ہفتہ کی آخری ( طاق ) راتوں میں تلاش کرے۔' WHERE id = 1943;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، انہوں نے کہا کہ مجھ سے ابن وہب نے بیان کیا، انہوں نے کہا کہ مجھ سے یونس نے، انہیں نافع نے خبر دی، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم رمضان کے آخری عشرہ میں اعتکاف کرتے تھے۔' WHERE id = 1953;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا کہ ہم سے یزید بن زریع نے بیان کیا، ان سے خالد نے، ان سے عکرمہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ آپ کی بیویوں میں سے ایک خاتون ( ام سلمہ رضی اللہ عنہا ) نے جو مستحاضہ تھیں، اعتکاف کیا۔ وہ سرخی اور زردی ( یعنی استحاضہ کا خون ) دیکھتی تھیں۔ اکثر طشت ہم ان کے نیچے رکھ دیتے اور وہ نماز پڑھتی رہتیں۔' WHERE id = 1964;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، ان سے شعیب نے بیان کیا، ان سے زہری نے، کہا کہ مجھے سعید بن مسیب اور ابوسلمہ بن عبدالرحمٰن نے خبر دی کہ ابوہریرہ رضی اللہ عنہ نے کہا، تم لوگ کہتے ہو کہ ابوہریرہ ( رضی اللہ عنہ ) تو رسول اللہ صلی اللہ علیہ وسلم سے احادیث بہت زیادہ بیان کرتا ہے، اور یہ بھی کہتے ہو کہ مہاجرین و انصار ابوہریرہ ( رضی اللہ عنہ ) کی طرح کیوں حدیث نہیں بیان کرتے؟ اصل وجہ یہ ہے کہ میرے بھائی مہاجرین بازار کی خرید و فروخت میں مشغول رہا کرتے تھے۔ اور میں اپنا پیٹ بھرنے کے بعد پھر برابر رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر رہتا، اس لیے جب یہ بھائی غیر حاضر ہوتے تو میں اس وقت بھی حاضر رہتا اور میں ( وہ باتیں آپ سے سن کر ) یاد کر لیتا جسے ان حضرات کو ( اپنے کاروبار کی مشغولیت کی وجہ سے یا تو سننے کا موقعہ نہیں ملتا تھا یا ) وہ بھول جایا کرتے تھے۔ اسی طرح میرے بھائی انصار اپنے اموال ( کھیتوں اور باغوں ) میں مشغول رہتے، لیکن میں صفہ میں مقیم مسکینوں میں سے ایک مسکین آدمی تھا۔ جب یہ حضرات انصار بھولتے تو میں اسے یاد رکھتا۔ ایک مرتبہ رسول اللہ صلی اللہ علیہ وسلم نے ایک حدیث بیان کرتے ہوئے فرمایا تھا کہ جو کوئی اپنا کپڑا پھیلائے اور اس وقت تک پھیلائے رکھے جب تک اپنی یہ گفتگو نہ پوری کر لوں، پھر ( جب میری گفتگو پوری ہو جائے تو ) اس کپڑے کو سمیٹ لے تو وہ میری باتوں کو ( اپنے دل و دماغ میں ہمیشہ ) یاد رکھے گا، چنانچہ میں نے اپنا کمبل اپنے سامنے پھیلا دیا، پھر جب رسول اللہ صلی اللہ علیہ وسلم نے اپنا مقالہ مبارک ختم فرمایا، تو میں نے اسے سمیٹ کر اپنے سینے سے لگا لیا اور اس کے بعد پھر کبھی میں آپ کی کوئی حدیث نہیں بھولا۔' WHERE id = 1974;
UPDATE hadiths SET urdu = 'ہم سے احمد بن مقدام عجلی نے بیان کیا، انہوں نے کہا کہ ہم سے محمد بن عبدالرحمٰن طفاوی نے بیان کیا، انہوں نے کہا کہ ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد (عروہ بن زبیر) نے اور ان سے عائشہ رضی اللہ عنہا نے کہ کچھ لوگوں نے عرض کیا یا رسول اللہ! بہت سے لوگ ہمارے یہاں گوشت لاتے ہیں۔ ہمیں یہ معلوم نہیں کہ اللہ کا نام انہوں نے ذبح کے وقت لیا تھا یا نہیں؟ اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ تم بسم اللہ پڑھ کے اسے کھا لیا کرو۔' WHERE id = 1984;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا کہ ہم سے ہشام نے بیان کیا، ان سے قتادہ نے بیان کیا، ان سے انس رضی اللہ عنہ نے (دوسری سند) اور مجھ سے محمد بن عبداللہ بن حوشب نے بیان کیا، کہا کہ ہم سے اسباط ابوالیسع بصریٰ نے، کہا کہ ہم سے ہشام دستوائی نے، انہوں نے قتادہ سے، انہوں نے انس رضی اللہ عنہ سے کہ وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں جَو کی روٹی اور بدبودار چربی ( سالن کے طور پر ) لے گئے۔ نبی کریم صلی اللہ علیہ وسلم نے اس وقت اپنی زرہ مدینہ میں ایک یہودی کے یہاں گروی رکھی تھی اور اس سے اپنے گھر والوں کے لیے قرض لیا تھا۔ میں نے خود آپ کو یہ فرماتے سنا کہ محمد صلی اللہ علیہ وسلم کے گھرانے میں کوئی شام ایسی نہیں آئی جس میں ان کے پاس ایک صاع گیہوں یا ایک صاع کوئی غلہ موجود رہا ہو، حالانکہ آپ صلی اللہ علیہ وسلم کی گھر والیوں کی تعداد نو تھی۔' WHERE id = 1995;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے ان سے صالح ابوخلیل نے، ان سے عبیداللہ بن حارث نے، انہوں نے حکیم بن حزام رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، خریدنے اور بیچنے والوں کو اس وقت تک اختیار ( بیع ختم کر دینے کا ) ہے جب تک دونوں جدا نہ ہوں یا آپ صلی اللہ علیہ وسلم نے ( «ما لم يتفرقا» کے بجائے ) «حتى يتفرقا» فرمایا۔ ( نبی کریم صلی اللہ علیہ وسلم نے مزید ارشاد فرمایا ) پس اگر دونوں نے سچائی سے کام لیا اور ہر بات صاف صاف کھول دی تو ان کی خرید و فروخت میں برکت ہوتی ہے لیکن اگر کوئی بات چھپا رکھی یا جھوٹ کہی تو ان کی برکت ختم کر دی جاتی ہے۔' WHERE id = 2005;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، انہوں نے کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی، انہوں نے کہا کہ ہمیں یونس نے خبر دی، انہوں نے کہا کہ ہم سے ابن شہاب نے، انہوں نے کہا کہ ہمیں زین العابدین علی بن حسین رضی اللہ عنہ نے خبر دی، انہیں حسین بن علی رضی اللہ عنہ نے خبر دی کہ علی رضی اللہ عنہ نے فرمایا کہ غنیمت کے مال میں سے میرے حصے میں ایک اونٹ آیا تھا اور ایک دوسرا اونٹ مجھے نبی کریم صلی اللہ علیہ وسلم نے ”خمس“ میں سے دیا تھا۔ پھر جب میرا ارادہ رسول اللہ صلی اللہ علیہ وسلم کی صاحبزادی فاطمہ رضی اللہ عنہا کی رخصتی کرا کے لانے کا ہوا تو میں نے بنی قینقاع کے ایک سنار سے طے کیا کہ وہ میرے ساتھ چلے اور ہم دونوں مل کر اذخر گھاس ( جمع کر کے ) لائیں کیونکہ میرا ارادہ تھا کہ اسے سناروں کے ہاتھ بیچ کر اپنی شادی کے ولیمہ میں اس کی قیمت کو لگاؤں۔' WHERE id = 2015;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا کہ عمرو بن دینار نے کہا یہاں ( مکہ میں ) ایک شخص نواس نام کا تھا۔ اس کے پاس ایک بیمار اونٹ تھا۔ عبداللہ بن عمر رضی اللہ عنہما گئے اور اس کے شریک سے وہی اونٹ خرید لائے۔ وہ شخص آیا تو اس کے ساجھی نے کہا کہ ہم نے تو وہ اونٹ بیچ دیا۔ اس نے پوچھا کہ کسے بیچا؟ شریک نے کہا کہ ایک شیخ کے ہاتھوں جو اس طرح کے تھے۔ اس نے کہا افسوس! وہ تو عبداللہ بن عمر رضی اللہ عنہما تھے۔ چنانچہ وہ آپ کی خدمت میں حاضر ہوا اور عرض کیا کہ میرے ساتھی نے آپ کو مریض اونٹ بیچ دیا ہے اور آپ سے اس نے اس کے مرض کی وضاحت بھی نہیں کی۔ عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ پھر اسے واپس لے جاؤ۔ بیان کیا کہ جب وہ اس کو لے جانے لگا تو عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ اچھا رہنے دو ہم رسول اللہ صلی اللہ علیہ وسلم کے فیصلہ پر راضی ہیں ( آپ نے فرمایا تھا کہ ) «لا عدوى‏.‏» ( یعنی امراض چھوت والے نہیں ہوتے ) علی بن عبداللہ مدینی نے کہا کہ سفیان نے اس روایت کو عمرو سے سنا۔' WHERE id = 2025;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے بیان کیا، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، خریدنے والے اور بیچنے والے کو ( بیع توڑ دینے کا ) اس وقت تک اختیار ہے جب تک وہ جدا نہ ہو جائیں۔ یا دونوں میں سے کوئی ایک اپنے دوسرے فریق سے یہ نہ کہہ دے کہ پسند کر لو۔ کبھی یہ بھی کہا کہ ”یا اختیار کی شرط کے ساتھ بیع ہو۔“' WHERE id = 2035;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا کہ ہم سے جریر نے بیان کیا، ان سے اعمش نے، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، جماعت کے ساتھ کسی کی نماز بازار میں یا اپنے گھر میں نماز پڑھنے سے درجوں میں کچھ اوپر بیس درجے زیادہ فضیلت رکھتی ہے۔ کیونکہ جب ایک شخص اچھی طرح وضو کرتا ہے پھر مسجد میں صرف نماز کے ارادہ سے آتا ہے۔ نماز کے سوا اور کوئی چیز اسے لے جانے کا باعث نہیں بنتی تو جو بھی قدم وہ اٹھاتا ہے اس سے ایک درجہ اس کا بلند ہوتا ہے یا اس کی وجہ سے ایک گناہ اس کا معاف ہوتا ہے اور جب تک ایک شخص اپنے مصلے پر بیٹھا رہتا ہے جس پر اس نے نماز پڑھی ہے تو فرشتے برابر اس کے لیے رحمت کی دعائیں یوں کرتے رہتے ہیں «اللهم صل عليه،‏‏‏‏ ‏‏‏‏ اللهم ارحمه» ”اے اللہ! اس پر اپنی رحمتیں نازل فرما، اے اللہ اس پر رحم فرما۔“ یہ اس وقت تک ہوتا رہتا ہے جب تک وہ وضو توڑ کر فرشتوں کو تکلیف نہ پہنچائے جتنی دیر تک بھی آدمی نماز کی وجہ سے رکا رہتا ہے وہ سب نماز ہی میں شمار ہوتا ہے۔' WHERE id = 2045;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے وہیب نے بیان کیا، ان سے ابن طاؤس نے، ان سے ان کے باپ نے، ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے غلہ پر پوری طرح قبضہ سے پہلے اسے بیچنے سے منع فرمایا۔ طاؤس نے کہا کہ میں نے ابن عباس رضی اللہ عنہما سے پوچھا کہ ایسا کیوں ہے؟ تو انہوں نے فرمایا کہ یہ تو روپے کا روپوں کے بدلے بیچنا ہوا جب کہ ابھی غلہ تو میعاد ہی پر دیا جائے گا۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ «مرجئون» سے مراد «مؤخرون» یعنی مؤخر کرنا ہے۔' WHERE id = 2057;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہیں امام مالک نے خبر دی، انہیں نافع نے، اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے حمل کے حمل کی بیع سے منع فرمایا۔ اس بیع کا طریقہ جاہلیت میں رائج تھا۔ ایک شخص ایک اونٹ یا اونٹنی خریدتا اور قیمت دینے کی میعاد یہ مقرر کرتا کہ ایک اونٹنی جنے پھر اس کے پیٹ کی اونٹنی بڑی ہو کر جنے۔' WHERE id = 2068;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہمیں شعیب نے خبر دی، انہیں زہری نے، ان سے عروہ بن زبیر رضی اللہ عنہ نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم تشریف لائے تو میں نے آپ صلی اللہ علیہ وسلم سے ( بریرہ رضی اللہ عنہا کے خریدنے کا ) ذکر کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا تم خرید کر آزاد کر دو۔ ولاء تو اسی کی ہوتی ہے جو آزاد کرے۔ پھر آپ صلی اللہ علیہ وسلم منبر پر تشریف لائے اور فرمایا ”لوگوں کو کیا ہو گیا ہے کہ ( خرید و فروخت میں ) ایسی شرطیں لگاتے ہیں جن کی کوئی اصل کتاب اللہ میں نہیں ہے جو شخص بھی کوئی ایسی شرط لگائے گا جس کی اصل کتاب اللہ میں نہ ہو وہ شرط باطل ہو گی۔ خواہ سو شرطیں ہی کیوں نہ لگا لے کیونکہ اللہ ہی کی شرط حق اور مضبوط ہے ( اور اسی کا اعتبار ہے ) ۔“' WHERE id = 2079;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک رحمہ اللہ نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کوئی شخص کسی دوسرے کی بیع پر بیع نہ کرے اور جو مال باہر سے آ رہا ہو اس سے آگے جا کر نہ ملے جب تک وہ بازار میں نہ آئے۔' WHERE id = 2089;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں نافع نے اور انہیں ابو سعید خدری رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، سونا سونے کے بدلے اس وقت تک نہ بیچو جب تک دونوں طرف سے برابر برابر نہ ہو، دونوں طرف سے کسی کمی یا زیادتی کو روا نہ رکھو، اور چاندی کو چاندی کے بدلے میں اس وقت تک نہ بیچو جب تک دونوں طرف سے برابر برابر نہ ہو۔ دونوں طرف سے کسی کمی یا زیادتی کو روا نہ رکھو اور نہ ادھار کو نقد کے بدلے میں بیچو۔' WHERE id = 2100;
UPDATE hadiths SET urdu = 'لیث بن سعد نے ابوزناد عبداللہ بن ذکوان سے نقل کیا کہ عروہ بن زبیر، بنوحارثہ کے سہل بن ابی حثمہ انصاری رضی اللہ عنہ سے نقل کرتے تھے اور وہ زید بن ثابت رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں لوگ پھلوں کی خرید و فروخت ( درختوں پر پکنے سے پہلے ) کرتے تھے۔ پھر جب پھل توڑنے کا وقت آتا، اور مالک ( قیمت کا ) تقاضا کرنے آتے تو خریدار یہ عذر کرنے لگتے کہ پہلے ہی اس کا گابھا خراب اور کالا ہو گیا، اس کو بیماری ہو گئی، یہ تو ٹھٹھر گیا پھل بہت ہی کم آئے۔ اسی طرح مختلف آفتوں کو بیان کر کے مالکوں سے جھگڑتے ( تاکہ قیمت میں کمی کرا لیں ) جب رسول اللہ صلی اللہ علیہ وسلم کے پاس اس طرح کے مقدمات بکثرت آنے لگے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب اس طرح جھگڑے ختم نہیں ہو سکتے تو تم لوگ بھی میوہ کے پکنے سے پہلے ان کو نہ بیچا کرو۔ گویا مقدمات کی کثرت کی وجہ سے آپ صلی اللہ علیہ وسلم نے یہ بطور مشورہ فرمایا تھا۔ خارجہ بن زید بن ثابت رضی اللہ عنہ نے مجھے خبر دی کہ زید بن ثابت رضی اللہ عنہ اپنے باغ کے پھل اس وقت تک نہیں بیچتے جب تک ثریا نہ طلوع ہو جاتا اور زردی اور سرخی ظاہر نہ ہو جاتی۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ اس کی روایت علی بن بحر نے بھی کی ہے کہ ہم سے حکام بن سلم نے بیان کیا، ان سے عنبسہ نے بیان کیا، ان سے زکریا نے، ان سے ابوالزناد نے، ان سے عروہ نے اور ان سے سہل بن سعد نے اور ان سے زید بن ثابت نے۔' WHERE id = 2113;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا کہ ہم سے لیث نے بیان کیا، ان سے نافع نے، ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا، کہ نبی کریم صلی اللہ علیہ وسلم نے مزابنہ سے منع فرمایا۔ یعنی باغ کے پھلوں کو اگر وہ کھجور ہیں تو ٹوٹی ہوئی کھجور کے بدلے میں ناپ کر بیچا جائے۔ اور اگر انگور ہیں تو اسے خشک انگور کے بدلے ناپ کر بیچا جائے اور اگر وہ کھیتی ہے تو ناپ کر غلہ کے بدلے میں بیچا جائے۔ آپ صلی اللہ علیہ وسلم نے ان تمام قسموں کے لین دین سے منع فرمایا ہے۔' WHERE id = 2124;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا کہ ہم سے ابوعاصم نے بیان کیا کہا کہ ہم کو ابن جریج نے خبر دی، کہا کہ مجھے موسیٰ بن عقبہ نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا، تین شخص کہیں باہر جا رہے تھے کہ اچانک بارش ہونے لگی۔ انہوں نے ایک پہاڑ کے غار میں جا کر پناہ لی۔ اتفاق سے پہاڑ کی ایک چٹان اوپر سے لڑھکی ( اور اس غار کے منہ کو بند کر دیا جس میں یہ تینوں پناہ لیے ہوئے تھے ) اب ایک نے دوسرے سے کہا کہ اپنے سب سے اچھے عمل کا جو تم نے کبھی کیا ہو، نام لے کر اللہ تعالیٰ سے دعا کرو۔ اس پر ان میں سے ایک نے یہ دعا کی ”اے اللہ! میرے ماں باپ بہت ہی بوڑھے تھے۔ میں باہر لے جا کر اپنے مویشی چراتا تھا۔ پھر جب شام کو واپس آتا تو ان کا دودھ نکالتا اور برتن میں پہلے اپنے والدین کو پیش کرتا۔ جب میرے والدین پی چکتے تو پھر بچوں کو اور اپنی بیوی کو پلاتا۔ اتفاق سے ایک رات واپسی میں دیر ہو گئی اور جب میں گھر لوٹا تو والدین سو چکے تھے۔ اس نے کہا کہ پھر میں نے پسند نہیں کیا کہ انہیں جگاؤں بچے میرے قدموں میں بھوکے پڑے رو رہے تھے۔ میں برابر دودھ کا پیالہ لیے والدین کے سامنے اسی طرح کھڑا رہا یہاں تک کہ صبح ہو گئی۔ اے اللہ! اگر تیرے نزدیک بھی میں نے یہ کام صرف تیری رضا حاصل کرنے کے لیے کیا تھا، تو ہمارے لیے اس چٹان کو ہٹا کر اتنا راستہ تو بنا دے کہ ہم آسمان کو تو دیکھ سکیں“ نبی کریم صلی اللہ علیہ وسلم نے فرمایا۔ چنانچہ وہ پتھر کچھ ہٹ گیا۔ دوسرے شخص نے دعا کی ”اے اللہ! تو خوب جانتا ہے کہ مجھے اپنے چچا کی ایک لڑکی سے اتنی زیادہ محبت تھی جتنی ایک مرد کو کسی عورت سے ہو سکتی ہے۔ اس لڑکی نے کہا تم مجھ سے اپنی خواہش اس وقت تک پوری نہیں کر سکتے جب تک مجھے سو اشرفی نہ دے دو۔ میں نے ان کے حاصل کرنے کی کوشش کی، اور آخر اتنی اشرفی جمع کر لی۔ پھر جب میں اس کی دونوں رانوں کے درمیان بیٹھا۔ تو وہ بولی، اللہ سے ڈر، اور مہر کو ناجائز طریقے پر نہ توڑ۔ اس پر میں کھڑا ہو گیا اور میں نے اسے چھوڑ دیا۔ اب اگر تیرے نزدیک بھی میں نے یہ عمل تیری ہی رضا کے لیے کیا تھا تو ہمارے لیے ( نکلنے کا ) راستہ بنا دے“ نبی کریم صلی اللہ علیہ وسلم نے فرمایا۔ چنانچہ وہ پتھر دو تہائی ہٹ گیا۔ تیسرے شخص نے دعا کی ”اے اللہ! تو جانتا ہے کہ میں نے ایک مزدور سے ایک فرق جوار پر کام کرایا تھا۔ جب میں نے اس کی مزدوری اسے دے دی تو اس نے لینے سے انکار کر دیا۔ میں نے اس جوار کو لے کر بو دیا ( کھیتی جب کٹی تو اس میں اتنی جوار پیدا ہوئی کہ ) اس سے میں نے ایک بیل اور ایک چرواہا خرید لیا۔ کچھ عرصہ بعد پھر اس نے آ کر مزدوری مانگی کہ اللہ کے بندے مجھے میرا حق دیدے۔ میں نے کہا کہ اس بیل اور اس کے چرواہے کے پاس جاؤ کہ یہ تمہارے ہی ملک ہیں۔ اس نے کہا کہ مجھ سے مذاق کرتے ہو۔ میں نے کہا ”میں مذاق نہیں کرتا“ واقعی یہ تمہارے ہی ہیں۔ تو اے اللہ! اگر تیرے نزدیک یہ کام میں نے صرف تیری رضا حاصل کرنے کے لیے کیا تھا تو یہاں ہمارے لیے ( اس چٹان کو ہٹا کر ) راستہ بنا دے۔ چنانچہ وہ غار پورا کھل گیا اور وہ تینوں شخص باہر آ گئے۔' WHERE id = 2135;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، انہوں نے کہا کہ ہم سے یزید بن زریع نے بیان کیا، انہیں عوف بن ابی حمید نے خبر دی، انہیں سعید بن ابی حسن نے، کہا کہ میں ابن عباس رضی اللہ عنہما کی خدمت میں حاضر تھا کہ ایک شخص ان کے پاس آیا، اور کہا کہ اے ابوعباس! میں ان لوگوں میں سے ہوں، جن کی روزی اپنے ہاتھ کی صنعت پر موقوف ہے اور میں یہ مورتیں بناتا ہوں۔ ابن عباس رضی اللہ عنہما نے اس پر فرمایا کہ میں تمہیں صرف وہی بات بتلاؤں گا جو میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنی ہے۔ انہوں نے کہا کہ میں نے آپ کو یہ فرماتے ہوئے سنا تھا کہ جس نے بھی کوئی مورت بنائی تو اللہ تعالیٰ اسے اس وقت تک عذاب کرتا رہے گا جب تک وہ شخص اپنی مورت میں جان نہ ڈال دے اور وہ کبھی اس میں جان نہیں ڈال سکتا ( یہ سن کر ) اس شخص کا سانس چڑھ گیا اور چہرہ زرد پڑ گیا۔ ابن عباس رضی اللہ عنہما نے فرمایا کہ افسوس! اگر تم مورتیں بنانی ہی چاہتے ہو تو ان درختوں کی اور ہر اس چیز کی جس میں جان نہیں ہے مورتیں بنا سکتے ہو۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ سعید بن ابی عروبہ نے نضر بن انس سے صرف یہی ایک حدیث سنی ہے۔' WHERE id = 2145;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں ابی بکر بن عبدالرحمٰن نے اور انہیں ابومسعود انصاری رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے کتے کی قیمت، زانیہ کی اجرت اور کاہن کی اجرت سے منع فرمایا تھا۔' WHERE id = 2156;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالواحد نے بیان کیا، ان سے معمر نے بیان کیا، ان سے زہری نے بیان کیا، ان سے ابوسلمہ بن عبدالرحمٰن نے بیان کیا اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ہر اس چیز میں شفعہ کا حق دیا تھا جو ابھی تقسیم نہ ہوئی ہو۔ لیکن جب حدود مقرر ہو گئیں اور راستے بدل دیئے گئے تو پھر حق شفعہ باقی نہیں رہتا۔' WHERE id = 2174;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے عبداللہ بن عمر رضی اللہ عنہما کے غلام عبداللہ بن دینار نے بیان کیا، اور ان سے عبداللہ بن عمر بن خطاب رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ تمہاری اور یہود و نصاریٰ کی مثال ایسی ہے کہ ایک شخص نے چند مزدور کام پر لگائے اور کہا کہ ایک ایک قیراط پر آدھے دن تک میری مزدوری کون کرے گا؟ پس یہود نے ایک قیراط پر یہ مزدوری کی۔ پھر نصاریٰ نے بھی ایک قیراط پر کام کیا۔ پھر تم لوگوں نے عصر سے مغرب تک دو دو قیراط پر کام کیا۔ اس پر یہود و نصاریٰ غصہ ہو گئے کہ ہم نے تو زیادہ کام کیا اور مزدوری ہم کو کم ملی۔ اس پر اس شخص نے کہا کہ کیا میں نے تمہارا حق ذرہ برابر بھی مارا ہے؟ تو انہوں نے کہا کہ نہیں۔ پھر اس شخص نے کہا کہ یہ میرا فضل ہے جسے چاہوں زیادہ دیتا ہوں۔' WHERE id = 2185;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یزید بن زریع نے بیان کیا، ان سے خالد نے، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے پچھنا لگوایا اور پچھنا لگانے والے کو اجرت بھی دی، اگر اس میں کوئی کراہت ہوتی تو آپ صلی اللہ علیہ وسلم کا ہے کو دیتے۔' WHERE id = 2195;
UPDATE hadiths SET urdu = 'ابوعبداللہ (امام بخاری رحمہ اللہ) نے کہا کہ لیث نے بیان کیا، ان سے جعفر بن ربیعہ نے، ان سے عبدالرحمٰن بن ہرمز نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے بنی اسرائیل کے ایک شخص کا ذکر فرمایا کہ انہوں نے بنی اسرائیل کے ایک دوسرے آدمی سے ایک ہزار دینار قرض مانگے۔ انہوں نے کہا کہ پہلے ایسے گواہ لا جن کی گواہی پر مجھے اعتبار ہو۔ قرض مانگنے والا بولا کہ گواہ تو بس اللہ ہی کافی ہے پھر انہوں نے کہا کہ اچھا کوئی ضامن لا۔ قرض مانگنے والا بولا کہ ضامن بھی اللہ ہی کافی ہے۔ انہوں نے کہا کہ تو نے سچی بات کہی۔ چنانچہ اس نے ایک مقررہ مدت کے لیے اس کو قرض دے دیا۔ یہ صاحب قرض لے کر دریائی سفر پر روانہ ہوئے اور پھر اپنی ضرورت پوری کر کے کسی سواری ( کشتی وغیرہ ) کی تلاش کی تاکہ اس سے دریا پار کر کے اس مقررہ مدت تک قرض دینے والے کے پاس پہنچ سکے جو اس سے طے پائی تھی۔ ( اور اس کا قرض ادا کر دے ) لیکن کوئی سواری نہیں ملی۔ آخر ایک لکڑی لی اور اس میں سوراخ کیا۔ پھر ایک ہزار دینار اور ایک ( اس مضمون کا ) خط کہ اس کی طرف سے قرض دینے والے کی طرف ( یہ دینار بھیجے جا رہے ہیں ) اور اس کا منہ بند کر دیا۔ اور اسے دریا پر لے آئے، پھر کہا، اے اللہ! تو خوب جانتا ہے کہ میں نے فلاں شخص سے ایک ہزار دینار قرض لیے تھے۔ اس نے مجھ سے ضامن مانگا تو میں نے کہہ دیا تھا کہ میرا ضامن اللہ تعالیٰ کافی ہے اور وہ بھی تجھ پر راضی ہوا۔ اس نے مجھ سے گواہ مانگا تو اس کا بھی جواب میں نے یہی دیا کہ اللہ پاک گواہ کافی ہے تو وہ مجھ پر راضی ہو گیا اور ( تو جانتا ہے کہ ) میں نے بہت کوشش کی کہ کوئی سواری ملے جس کے ذریعہ میں اس کا قرض اس تک ( مدت مقررہ میں ) پہنچا سکوں۔ لیکن مجھے اس میں کامیابی نہیں ہوئی۔ اس لیے اب میں اس کو تیرے ہی حوالے کرتا ہوں ( کہ تو اس تک پہنچا دے ) چنانچہ اس نے وہ لکڑی جس میں رقم تھی دریا میں بہا دی۔ اب وہ دریا میں تھی اور وہ صاحب ( قرض دار ) واپس ہو چکے تھے۔ اگرچہ فکر اب بھی یہی تھا کہ کس طرح کوئی جہاز ملے۔ جس کے ذریعہ وہ اپنے شہر میں جا سکیں۔ دوسری طرف وہ صاحب جنہوں نے قرض دیا تھا اسی تلاش میں ( بندرگاہ ) آئے کہ ممکن ہے کوئی جہاز ان کا مال لے کر آیا ہو۔ لیکن وہاں انہیں ایک لکڑی ملی۔ وہی جس میں مال تھا۔ انہوں نے لکڑی اپنے گھر میں ایندھن کے لیے لے لی۔ لیکن جب اسے چیرا تو اس میں سے دینار نکلے اور ایک خط بھی نکلا۔ ( کچھ دنوں کے بعد جب وہ صاحب اپنے شہر آئے ) تو قرض خواہ کے گھر آئے۔ اور ( یہ خیال کر کے کہ شاید وہ لکڑی نہ مل سکی ہو دوبارہ ) ایک ہزار دینا ان کی خدمت میں پیش کر دیئے۔ اور کہا کہ قسم اللہ کی! میں تو برابر اسی کوشش میں رہا کہ کوئی جہاز ملے تو تمہارے پاس تمہارا مال لے کر پہنچوں لیکن اس دن سے پہلے جب کہ میں یہاں پہنچنے کے لیے سوار ہوا۔ مجھے اپنی کوششوں میں کامیابی نہیں ہوئی۔ پھر انہوں نے پوچھا اچھا یہ تو بتاؤ کہ کوئی چیز کبھی تم نے میرے نام بھیجی تھی؟ مقروض نے جواب دیا بتا تو رہا ہوں آپ کو کہ کوئی جہاز مجھے اس جہاز سے پہلے نہیں ملا جس سے میں آج پہنچا ہوں۔ اس پر قرض خواہ نے کہا کہ پھر اللہ نے بھی آپ کا وہ قرضا ادا کر دیا۔ جسے آپ نے لکڑی میں بھیجا تھا۔ چنانچہ وہ صاحب اپنا ہزار دینار لے کر خوش خوش واپس لوٹ گئے۔' WHERE id = 2206;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا کہ مجھ سے یوسف بن ماجشون نے بیان کیا، ان سے صالح بن ابراہیم بن عبدالرحمٰن بن عوف نے، ان سے ان کے باپ نے، اور ان سے صالح کے دادا عبدالرحمٰن بن عوف رضی اللہ عنہ نے بیان کیا کہ میں نے امیہ بن خلف سے یہ معاہدہ اپنے اور اس کے درمیان لکھوایا کہ وہ میرے بال بچوں یا میری جائیداد کی جو مکہ میں ہے، حفاظت کرے اور میں اس کی جائیداد کی جو مدینہ میں ہے حفاظت کروں۔ جب میں نے اپنا نام لکھتے وقت رحمان کا ذکر کیا تو اس نے کہا کہ میں رحمن کو کیا جانوں۔ تم اپنا وہی نام لکھواؤ جو زمانہ جاہلیت میں تھا۔ چنانچہ میں نے عبد عمرو لکھوایا۔ بدر کی لڑائی کے موقع پر میں ایک پہاڑ کی طرف گیا تاکہ لوگوں سے آنکھ بچا کر اس کی حفاظت کر سکوں، لیکن بلال رضی اللہ عنہ نے دیکھ لیا اور فوراً ہی انصار کی ایک مجلس میں آئے۔ انہوں نے مجلس والوں سے کہا کہ یہ دیکھو امیہ بن خلف ( کافر دشمن اسلام ) ادھر موجود ہے۔ اگر امیہ کافر بچ نکلا تو میری ناکامی ہو گی۔ چنانچہ ان کے ساتھ انصار کی ایک جماعت ہمارے پیچھے ہو لی۔ جب مجھے خوف ہوا کہ اب یہ لوگ ہمیں آ لیں گے تو میں نے اس کے لڑکے کو آگے کر دیا تاکہ اس کے ساتھ ( آنے والی جماعت ) مشغول رہے، لیکن لوگوں نے اسے قتل کر دیا اور پھر بھی وہ ہماری ہی طرف بڑھنے لگے۔ امیہ بہت بھاری جسم کا تھا۔ آخر جب جماعت انصار نے ہمیں آ لیا ا تو میں نے اس سے کہا کہ زمین پر لیٹ جا۔ جب وہ زمین پر لیٹ گیا تو میں نے اپنا جسم اس کے اوپر ڈال دیا۔ تاکہ لوگوں کو روک سکوں، لیکن لوگوں نے میرے جسم کے نیچے سے اس کے جسم پر تلوار کی ضربات لگائیں اور اسے قتل کر کے ہی چھوڑا۔ ایک صحابی نے اپنی تلوار سے میرے پاؤں کو بھی زخمی کر دیا تھا۔ عبدالرحمٰن بن عوف رضی اللہ عنہ اس کا نشان اپنے قدم کے اوپر ہمیں دکھایا کرتے تھے۔' WHERE id = 2216;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے عبداللہ بن ابی بکر بن حزم نے، انہیں عمرہ بنت عبدالرحمٰن نے خبر دی کہ عائشہ رضی اللہ عنہا نے بیان کیا، میں نے اپنے ہاتھوں سے نبی کریم صلی اللہ علیہ وسلم کے قربانی کے جانوروں کے قلادے بٹے تھے۔ پھر نبی کریم صلی اللہ علیہ وسلم نے ان جانوروں کو یہ قلادے اپنے ہاتھ سے پہنائے تھے۔ آپ صلی اللہ علیہ وسلم نے وہ جانور میرے والد کے ساتھ ( مکہ میں قربانی کے لیے ) بھیجے۔ ان کی قربانی کی گئی۔ لیکن ( اس بھیجنے کی وجہ سے ) آپ صلی اللہ علیہ وسلم پر کوئی ایسی چیز حرام نہیں ہوئی جسے اللہ تعالیٰ نے آپ صلی اللہ علیہ وسلم کے لیے حلال کیا تھا۔' WHERE id = 2229;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو یحییٰ بن سعید نے خبر دی، انہیں حنظلہ بن قیس انصاری نے، انہوں نے رافع بن خدیج رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ مدینہ میں ہمارے پاس کھیت دوسروں سے زیادہ تھے۔ ہم کھیتوں کو اس شرط کے ساتھ دوسروں کو جوتنے اور بونے کے لیے دیا کرتے تھے کہ کھیت کے ایک مقررہ حصے ( کی پیداوار ) مالک زمین لے گا۔ بعض دفعہ ایسا ہوتا کہ خاص اسی حصے کی پیداوار ماری جاتی اور سارا کھیت سلامت رہتا۔ اور بعض دفعہ سارے کھیت کی پیداوار ماری جاتی اور یہ خاص حصہ بچ جاتا۔ اس لیے ہمیں اس طرح کے معاملہ کرنے سے روک دیا گیا اور سونا اور چاندی کے بدلہ ٹھیکہ دینے کا تو اس وقت رواج ہی نہ تھا۔' WHERE id = 2239;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، کہا کہ ہمیں شعیب بن اسحاق نے خبر دی، ان سے امام اوزاعی نے بیان کیا کہ مجھ سے یحییٰ نے بیان کیا، ان سے عکرمہ نے، ان سے ابن عباس رضی اللہ عنہما نے، اور ان سے عمر رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا رات میرے پاس میرے رب کی طرف سے ایک آنے والا فرشتہ آیا۔ آپ صلی اللہ علیہ وسلم اس وقت وادی عقیق میں قیام کئے ہوئے تھے۔ ( اور اس نے یہ پیغام پہنچایا کہ ) اس مبارک وادی میں نماز پڑھ اور کہا کہ کہہ دیجئیے! عمرہ حج میں شریک ہو گیا۔' WHERE id = 2249;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں ابوالزناد نے، انہیں اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا بچے ہوئے پانی سے کسی کو اس لیے نہ روکا جائے کہ اس طرح جو ضرورت سے زیادہ گھاس ہو وہ بھی رکی رہے۔' WHERE id = 2262;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے غندر نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے محمد بن زیاد نے، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے۔ میں ( قیامت کے دن ) اپنے حوض سے کچھ لوگوں کو اس طرح ہانک دوں گا جیسے اجنبی اونٹ حوض سے ہانک دیئے جاتے ہیں۔' WHERE id = 2274;
UPDATE hadiths SET urdu = 'اور لیث نے یحییٰ بن سعید سے بیان کیا اور انہوں نے انس رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے انصار کو بلا کر بحرین میں انہیں قطعات اراضی بطور جاگیر دینے چاہے تو انہوں نے عرض کیا کہ اے اللہ کے رسول! اگر آپ کو ایسا کرنا ہی ہے تو ہمارے بھائی قریش ( مہاجرین ) کو بھی اسی طرح کی قطعات کی سند لکھ دیجئیے۔ لیکن نبی کریم صلی اللہ علیہ وسلم کے پاس اتنی زمین ہی نہ تھی اس لیے نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا ”میرے بعد تم دیکھو گے کہ دوسرے لوگوں کو تم پر مقدم کیا جائے گا۔ تو اس وقت تم مجھ سے ملنے تک صبر کئے رہنا۔“' WHERE id = 2284;
UPDATE hadiths SET urdu = 'ہم سے احمد بن شبیب بن سعید نے بیان کیا، کہا کہ ہم سے ہمارے والد نے بیان کیا، ان سے یونس نے کہ ابن شہاب نے بیان کیا، ان سے عبیداللہ بن عبداللہ بن عتبہ نے بیان کیا، اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، اگر میرے پاس احد پہاڑ کے برابر بھی سونا ہو تب بھی مجھے یہ پسند نہیں کہ تین دن گزر جائیں اور اس ( سونے ) کا کوئی حصہ میرے پاس رہ جائے۔ سوا اس کے جو میں کسی قرض کے دینے کے لیے رکھ چھوڑوں۔ اس کی روایت صالح اور عقیل نے زہری سے کی ہے۔' WHERE id = 2295;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا کہ ہم سے ابوعامر نے بیان کیا، ان سے فلیح نے بیان کیا، ان سے ہلال بن علی نے، ان سے عبدالرحمٰن بن ابی عمرہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، ہر مومن کا میں دنیا و آخرت میں سب سے زیادہ قریب ہوں۔ اگر تم چاہو تو یہ آیت پڑھ لو «النبي أولى بالمؤمنين من أنفسهم‏» ”نبی ( صلی اللہ علیہ وسلم ) مومنوں سے ان کی جان سے بھی زیادہ قریب ہیں۔“ اس لیے جو مومن بھی انتقال کر جائے اور مال چھوڑ جائے تو چاہئے کہ ورثاء اس کے مالک ہوں۔ وہ جو بھی ہوں اور جو شخص قرض چھوڑ جائے یا اولاد چھوڑ جائے تو وہ میرے پاس آ جائیں کہ ان کا ولی میں ہوں۔' WHERE id = 2305;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا، کہا کہ ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ابن شہاب نے، ان سے ابوسلمہ اور عبدالرحمٰن اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ دو شخصوں نے جن میں ایک مسلمان تھا اور دوسرا یہودی، ایک دوسرے کو برا بھلا کہا۔ مسلمان نے کہا، اس ذات کی قسم! جس نے محمد ( صلی اللہ علیہ وسلم ) کو تمام دنیا والوں پر بزرگی دی۔ اور یہودی نے کہا، اس ذات کی قسم جس نے موسیٰ ( علیہ السلام ) کو تمام دنیا والوں پر بزرگی دی۔ اس پر مسلمان نے ہاتھ اٹھا کر یہودی کے طمانچہ مارا۔ وہ یہودی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ اور مسلمان کے ساتھ اپنے واقعہ کو بیان کیا۔ پھر آپ صلی اللہ علیہ وسلم نے اس مسلمان کو بلایا اور اس سے واقعہ کے متعلق پوچھا۔ انہوں نے آپ صلی اللہ علیہ وسلم کو اس کی تفصیل بتا دی۔ آپ صلی اللہ علیہ وسلم نے اس کے بعد فرمایا، مجھے موسیٰ علیہ السلام پر ترجیح نہ دو۔ لوگ قیامت کے دن بیہوش کر دیئے جائیں گے۔ میں بھی بیہوش ہو جاؤں گا۔ بے ہوشی سے ہوش میں آنے والا سب سے پہلا شخص میں ہوں گا، لیکن موسیٰ علیہ السلام کو عرش الٰہی کا کنارہ پکڑے ہوئے پاؤں گا۔ اب مجھے معلوم نہیں کہ موسیٰ علیہ السلام بھی بیہوش ہونے والوں میں ہوں گے اور مجھ سے پہلے انہیں ہوش آ جائے گا۔ یا اللہ تعالیٰ نے ان کو ان لوگوں میں رکھا ہے جو بے ہوشی سے مستثنیٰ ہیں۔' WHERE id = 2316;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث نے بیان کیا، کہا کہ مجھ سے سعید بن ابی سعید نے بیان کیا، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، آپ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے سواروں کا ایک لشکر نجد کی طرف بھیجا جو بنو حنیفہ کے ایک شخص ثمامہ بن اثال کو پکڑ لائے۔ اور مسجد کے ایک ستون سے اس کو باندھ دیا۔' WHERE id = 2327;
UPDATE hadiths SET urdu = 'اور احمد بن سعد نے کہا، ان سے روح نے بیان کیا، ان سے زکریا نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، مکہ کے درخت نہ کاٹے جائیں، وہاں کے شکار نہ چھیڑے جائیں، اور وہاں کے لقطہٰ کو صرف وہی اٹھائے جو اعلان کرے، اور اس کی گھاس نہ کاٹی جائے۔ عباس رضی اللہ عنہ نے کہا کہ یا رسول اللہ! اذخر کی اجازت دے دیجئیے چنانچہ آپ صلی اللہ علیہ وسلم نے اذخر کی اجازت دے دی۔' WHERE id = 2337;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، انہوں نے کہا کہ ہم سے ہشیم نے بیان کیا، انہیں عبیداللہ بن ابی بکر بن انس اور حمید طویل نے خبر دی، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، اپنے بھائی کی مدد کرو وہ ظالم ہو یا مظلوم۔' WHERE id = 2348;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالوارث نے بیان کیا، ان سے حسین نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے کہ مجھ سے محمد بن ابراہیم نے بیان کیا، ان سے ابوسلمہ نے بیان کیا کہ ان کے اور بعض دوسرے لوگوں کے درمیان ( زمین کا ) جھگڑا تھا۔ اس کا ذکر انہوں نے عائشہ رضی اللہ عنہا سے کیا تو انہوں نے بتلایا، ابوسلمہ! زمین سے پرہیز کر نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اگر کسی شخص نے ایک بالشت بھر زمین بھی کسی دوسرے کی ظلم سے لے لی تو سات زمینوں کا طوق ( قیامت کے دن ) اس کے گردن میں ڈالا جائے گا۔' WHERE id = 2358;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے امام مالک رحمہ اللہ نے، ان سے ابن شہاب نے، ان سے اعرج نے، اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، کوئی شخص اپنے پڑوسی کو اپنی دیوار میں کھونٹی گاڑنے سے نہ روکے۔ پھر ابوہریرہ رضی اللہ عنہ کہا کرتے تھے، یہ کیا بات ہے کہ میں تمہیں اس سے منہ پھیرنے والا پاتا ہوں۔ قسم اللہ! اس کھونٹی کو تمہارے کندھوں کے درمیان گاڑ دوں گا۔' WHERE id = 2368;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے جریر بن حازم نے بیان کیا، ان سے زبیر بن خریت نے اور ان سے عکرمہ نے کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فیصلہ کیا تھا جب کہ راستے ( کی زمین ) کے بارے میں جھگڑا ہو تو سات ہاتھ راستہ چھوڑ دینا چاہئے۔' WHERE id = 2378;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں وہب بن کیسان نے اور انہیں جابر بن عبداللہ رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ( رجب 7 ھ میں ) ساحل بحر کی طرف ایک لشکر بھیجا۔ اور اس کا امیر ابوعبیدہ بن جراح رضی اللہ عنہ کو بنایا۔ فوجیوں کی تعداد تین سو تھی اور میں بھی ان میں شریک تھا۔ ہم نکلے اور ابھی راستے ہی میں تھے کہ توشہ ختم ہو گیا۔ ابوعبیدہ رضی اللہ عنہ نے حکم دیا کہ تمام فوجی اپنے توشے ( جو کچھ بھی باقی رہ گئے ہوں ) ایک جگہ جمع کر دیں۔ سب کچھ جمع کرنے کے بعد کھجوروں کے کل دو تھیلے ہو سکے اور روزانہ ہمیں اسی میں سے تھوڑی تھوڑی کھجور کھانے کے لیے ملنے لگی۔ جب اس کا بھی اکثر حصہ ختم ہو گیا تو ہمیں صرف ایک ایک کھجور ملتی رہی۔ میں ( وہب بن کیسان ) نے جابر رضی اللہ عنہ سے کہا بھلا ایک کھجور سے کیا ہوتا ہو گا؟ انہوں نے بتلایا کہ اس کی قدر ہمیں اس وقت معلوم ہوئی جب وہ بھی ختم ہو گئی تھی۔ انہوں نے بیان کیا کہ آخر ہم سمندر تک پہنچ گئے۔ اتفاق سے سمندر میں ہمیں ایک ایسی مچھلی مل گئی جو ( اپنے جسم میں ) پہاڑ کی طرح معلوم ہوتی تھی۔ سارا لشکر اس مچھلی کو اٹھارہ راتوں تک کھاتا رہا۔ پھر ابوعبیدہ رضی اللہ عنہ نے اس کی دونوں پسلیوں کو کھڑا کرنے کا حکم دیا۔ اس کے بعد اونٹوں کو ان کے تلے سے چلنے کا حکم دیا۔ اور وہ ان پسلیوں کے نیچے سے ہو کر گزرے، لیکن اونٹ نے ان کو چھوا تک نہیں۔' WHERE id = 2388;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہا کہ ہم سے زکریا نے، کہا میں نے عامر بن شعبہ سے سنا، انہوں نے بیان کیا کہ میں نے نعمان بن بشیر رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اللہ کی حدود پر قائم رہنے والے اور اس میں گھس جانے والے ( یعنی خلاف کرنے والے ) کی مثال ایسے لوگوں کی سی ہے جنہوں نے ایک کشتی کے سلسلے میں قرعہ ڈالا۔ جس کے نتیجہ میں بعض لوگوں کو کشتی کے اوپر کا حصہ اور بعض کو نیچے کا۔ پس جو لوگ نیچے والے تھے، انہیں ( دریا سے ) پانی لینے کے لیے اوپر والوں کے پاس سے گزرنا پڑتا۔ انہوں نے سوچا کہ کیوں نہ ہم اپنے ہی حصہ میں ایک سوراخ کر لیں تاکہ اوپر والوں کو ہم کوئی تکلیف نہ دیں۔ اب اگر اوپر والے بھی نیچے والوں کو من مانی کرنے دیں گے تو کشتی والے تمام ہلاک ہو جائیں گے اور اگر اوپر والے نیچے والوں کا ہاتھ پکڑ لیں تو یہ خود بھی بچیں گے اور ساری کشتی بھی بچ جائے گی۔' WHERE id = 2398;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے عبدالواحد بن زیاد نے بیان کیا، انہوں نے کہا کہ ہم سے اعمش نے بیان کیا کہ ہم نے ابراہیم نخعی رحمہ اللہ کے یہاں قرض میں رہن اور ضامن کا ذکر کیا تو انہوں نے کہا کہ ہم سے اسود نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک یہودی سے غلہ خریدا ایک مقررہ مدت کے قرض پر اور اپنی زرہ اس کے ہاں گروی رکھی تھی۔' WHERE id = 2411;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، ان سے سالم نے اور ان سے ان کے والد نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا دو ساجھیوں کے درمیان ساجھے کے غلام کو اگر کسی ایک ساجھی نے آزاد کیا، تو اگر آزاد کرنے والا مالدار ہے تو باقی حصوں کی قیمت کا اندازہ کیا جائے گا۔ پھر ( اسی کی طرف سے ) پورے غلام کو آزاد کر دیا جائے گا۔' WHERE id = 2422;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن سعید نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے اسماعیل نے بیان کیا، ان سے قیس نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ جب میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تھا تو آتے ہوئے راستے میں یہ شعر کہا تھا: ہے پیاری گو کٹھن ہے اور لمبی میری رات، پر دلائی اس نے دارالکفر سے مجھ کو نجات۔ انہوں نے بیان کیا کہ راستے میں میرا غلام مجھ سے بچھڑ گیا تھا۔ پھر جب میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو اسلام پر قائم رہنے کے لیے میں نے آپ صلی اللہ علیہ وسلم سے بیعت کر لی۔ میں ابھی آپ صلی اللہ علیہ وسلم کے پاس بیٹھا ہی ہوا تھا کہ وہ غلام دکھائی دیا۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، ابوہریرہ! یہ دیکھ تیرا غلام بھی آ گیا۔ میں نے کہا، یا رسول اللہ! وہ اللہ کے لیے آزاد ہے۔ پھر میں نے اسے آزاد کر دیا۔ امام بخاری رحمہ اللہ فرماتے ہیں کہ ابوکریب نے ( اپنی روایت میں ) ابواسامہ سے یہ لفظ نہیں روایت کیا کہ وہ آزاد ہے۔' WHERE id = 2432;
UPDATE hadiths SET urdu = 'ہم سے زہیر بن حرب نے بیان کیا، کہا کہ ہم سے جریر بن عبدالحمید نے بیان کیا، ان سے عمارہ بن قعقاع، ان سے ابوزرعہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہا کہ میں بنو تمیم سے ہمیشہ محبت کرتا رہا ہوں ( دوسری سند امام بخاری رحمہ اللہ نے کہا ) مجھ سے ابن سلام نے بیان کیا، کہا ہم کو جریر بن عبدالحمید نے خبر دی، انہیں مغیرہ نے، انہیں حارث نے، انہیں ابوزرعہ نے اور انہیں ابوہریرہ رضی اللہ عنہ نے، ( تیسری سند ) اور مغیرہ نے عمارہ سے روایت کی، انہوں نے ابوزرعہ سے کہ ابوہریرہ رضی اللہ عنہ نے فرمایا، تین باتوں کی وجہ سے جنہیں میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے۔ میں بنو تمیم سے ہمیشہ محبت کرتا ہوں۔ رسول اللہ صلی اللہ علیہ وسلم نے ان کے بارے میں فرمایا کہ یہ لوگ دجال کے مقابلے میں میری امت میں سب سے زیادہ سخت مخالف ثابت ہوں گے۔ انہوں نے بیان کیا کہ ( ایک مرتبہ ) بنو تمیم کے یہاں سے زکوٰۃ ( وصول ہو کر آئی ) تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا یہ ہماری قوم کی زکوٰۃ ہے۔ بنو تمیم کی ایک عورت قید ہو کر سیدہ عائشہ رضی اللہ عنہا کے پاس تھی تو آپ صلی اللہ علیہ وسلم نے ان سے فرمایا کہ اسے آزاد کر دے کہ یہ اسماعیل علیہ السلام کی اولاد میں سے ہے۔' WHERE id = 2443;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، انہوں نے کہا ہم سے جریر بن حازم نے بیان کیا، انہوں نے نافع سے، وہ عبداللہ بن عمر رضی اللہ عنہما سے روایت کرتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے غلام کا اپنا حصہ آزاد کر دیا، اور اس کے پاس اتنا مال بھی ہو جس سے غلام کی واجبی قیمت ادا کی جا سکے تو اسی کے مال سے پورا غلام آزاد کیا جائے گا ورنہ جتنا آزاد ہو گیا ہو گیا۔“' WHERE id = 2453;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے عبدالواحد بن ایمن نے بیان کیا کہ مجھ سے میرے باپ ایمن رضی اللہ عنہ نے بیان کیا کہ میں عائشہ رضی اللہ عنہا کی خدمت میں حاضر ہوا اور عرض کیا کہ میں پہلے عتبہ بن ابی لہب کا غلام تھا۔ ان کا جب انتقال ہوا تو ان کی اولاد میری وارث ہوئی۔ ان لوگوں نے مجھے عبداللہ ابن ابی عمرو کو بیچ دیا اور ابن ابی عمرو نے مجھے آزاد کر دیا۔ لیکن ( بیچتے وقت ) عتبہ کے وارثوں نے ولاء کی شرط اپنے لیے لگالی تھی ( تو کیا یہ شرط صحیح ہے؟ ) اس پر عائشہ رضی اللہ عنہا نے کہا کہ بریرہ رضی اللہ عنہا میرے یہاں آئی تھیں اور انہوں نے کتابت کا معاملہ کر لیا تھا۔ انہوں نے کہا کہ مجھے آپ خرید کر آزاد کر دیں۔ عائشہ رضی اللہ عنہا نے کہا کہ میں ایسا کر دوں گی ( لیکن مالکوں سے بات چیت کے بعد ) انہوں نے بتایا کہ وہ مجھے بیچنے پر صرف اس شرط کے ساتھ راضی ہیں کہ ولاء انہیں کے پاس رہے۔ عائشہ رضی اللہ عنہا نے کہا کہ پھر مجھے اس کی ضرورت بھی نہیں ہے۔ رسول اللہ صلی اللہ علیہ وسلم نے بھی اسے سنایا ( عائشہ رضی اللہ عنہا نے یہ کہا کہ ) آپ کو اس کی اطلاع ملی۔ اس لیے آپ صلی اللہ علیہ وسلم نے عائشہ رضی اللہ عنہا سے دریافت فرمایا، انہوں نے صورت حال کی آپ صلی اللہ علیہ وسلم کو خبر دی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ بریرہ کو خرید کر آزاد کر دے اور مالکوں کو جو بھی شرط چاہیں لگانے دو۔ چنانچہ عائشہ رضی اللہ عنہا نے انہیں خرید کر آزاد کر دیا۔ مالکوں نے چونکہ ولاء کی شرط رکھی تھی اس لیے نبی کریم صلی اللہ علیہ وسلم نے ( صحابہ کرام رضی اللہ عنہم کے ایک مجمع سے ) خطاب فرمایا، ولاء تو اسی کے ساتھ ہوتی ہے جو آزاد کرے۔ ( اور جو آزاد نہ کریں ) اگرچہ وہ سو شرطیں بھی لگا لیں ( ولاء پھر بھی ان کے ساتھ قائم نہیں ہو سکتی ) ۔' WHERE id = 2464;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے جعفر بن ایاس نے بیان کیا، کہا کہ میں نے سعید بن جبیر سے سنا کہ ابن عباس رضی اللہ عنہما نے بیان کیا کہ ان کی خالہ ام حفید رضی اللہ عنہا نے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں پنیر، گھی اور گوہ ( ساہنہ ) کے تحائف بھیجے۔ نبی کریم صلی اللہ علیہ وسلم نے پنیر اور گھی میں سے تو تناول فرمایا لیکن گوہ پسند نہ ہونے کی وجہ سے چھوڑ دی۔ ابن عباس رضی اللہ عنہما نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم کے ( اسی ) دستر خوان پر گوہ ( ساہنہ ) کو بھی کھایا گیا اور اگر وہ حرام ہوتی تو آپ صلی اللہ علیہ وسلم کے دستر خوان پر کیوں کھائی جاتی۔' WHERE id = 2474;
UPDATE hadiths SET urdu = 'ہم سے حامد بن عمر نے بیان کیا، انہوں نے کہا ہم سے ابوعوانہ نے بیان کیا حصین سے، وہ عامر سے کہ میں نے نعمان بن بشیر رضی اللہ عنہما سے سنا وہ منبر پر بیان کر رہے تھے کہ میرے باپ نے مجھے ایک عطیہ دیا، تو عمرہ بنت رواحہ رضی اللہ عنہا ( نعمان کی والدہ ) نے کہا کہ جب تک آپ رسول اللہ صلی اللہ علیہ وسلم کو اس پر گواہ نہ بنائیں میں راضی نہیں ہو سکتی۔ چنانچہ ( حاضر خدمت ہو کر ) انہوں نے عرض کیا کہ عمرہ بنت رواحہ سے اپنے بیٹے کو میں نے ایک عطیہ دیا تو انہوں نے کہا کہ پہلے میں آپ کو اس پر گواہ بنا لوں، آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ اسی جیسا عطیہ تم نے اپنی تمام اولاد کو دیا ہے؟ انہوں نے جواب دیا کہ نہیں، اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ سے ڈرو اور اپنی اولاد کے درمیان انصاف کو قائم رکھو۔ چنانچہ وہ واپس ہوئے اور ہدیہ واپس لے لیا۔' WHERE id = 2485;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، زہری سے، وہ عروہ بن زبیر سے، وہ ابو حمید ساعدی رضی اللہ عنہ سے کہ قبیلہ ازد کے ایک صحابی کو جنہیں ابن اتبیہ کہتے تھے، رسول اللہ صلی اللہ علیہ وسلم نے صدقہ وصول کرنے کے لیے عامل بنایا۔ پھر جب وہ واپس آئے تو کہا کہ یہ تم لوگوں کا ہے ( یعنی بیت المال کا ) اور یہ مجھے ہدیہ میں ملا ہے۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ وہ اپنے والد یا اپنی والدہ کے گھر میں کیوں نہ بیٹھا رہا۔ دیکھتا وہاں بھی انہیں ہدیہ ملتا ہے یا نہیں۔ اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے۔ اس ( مال زکوٰۃ ) میں سے اگر کوئی شخص کچھ بھی ( ناجائز ) لے لے گا تو قیامت کے دن اسے وہ اپنی گردن پر اٹھائے ہوئے آئے گا۔ اگر اونٹ ہے تو وہ اپنی آواز نکالتا ہوا آئے گا، گائے ہے تو وہ اپنی اور اگر بکری ہے تو وہ اپنی آواز نکالتی ہو گی۔ پھر آپ صلی اللہ علیہ وسلم نے اپنے ہاتھ اٹھائے یہاں تک کہ ہم نے آپ صلی اللہ علیہ وسلم کی بغل مبارک کی سفیدی بھی دیکھ لی ( اور فرمایا ) اے اللہ! کیا میں نے تیرا حکم پہنچا دیا۔ اے اللہ! کیا میں نے تیرا حکم پہنچا دیا۔ تین مرتبہ ( آپ صلی اللہ علیہ وسلم نے یہی فرمایا ) ۔' WHERE id = 2495;
UPDATE hadiths SET urdu = 'ہم سے ابن مقاتل نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی شعبہ سے، انہیں ابوسلمہ بن کہیل نے، انہیں ابوسلمہ نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک اونٹ بطور قرض لیا، قرض خواہ تقاضا کرنے آیا ( اور نازیبا گفتگو کی ) تو آپ صلی اللہ علیہ وسلم نے فرمایا ”حق والے کو کہنے کا حق ہوتا ہے۔“ پھر آپ صلی اللہ علیہ وسلم نے اس سے اچھی عمر کا اونٹ اسے دلا دیا اور فرمایا ”تم میں افضل وہ ہے جو ادا کرنے میں سب سے بہتر ہو۔“' WHERE id = 2506;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا ہشام سے، ان سے ان کے باپ نے اور ان سے اسماء بنت ابی بکر رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانے میں میری والدہ ( قتیلہ بنت عبدالعزیٰ ) جو مشرکہ تھیں، میرے یہاں آئیں۔ میں نے آپ صلی اللہ علیہ وسلم سے پوچھا، میں نے یہ بھی کہا کہ وہ ( مجھ سے ملاقات کی ) بہت خواہشمند ہیں، تو کیا میں اپنی والدہ کے ساتھ صلہ رحمی کر سکتی ہوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں اپنی والدہ کے ساتھ صلہ رحمی کر۔' WHERE id = 2516;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو ابن وہب نے خبر دی یونس سے، انہوں نے ابن شہاب سے، وہ انس بن مالک رضی اللہ عنہ سے کہ جب مہاجرین مکہ سے مدینہ آئے تو ان کے ساتھ کوئی بھی سامان نہ تھا۔ انصار زمین اور جائیداد والے تھے۔ انصار نے مہاجرین سے یہ معاملہ کر لیا کہ وہ اپنے باغات میں سے انہیں ہر سال پھل دیا کریں گے اور اس کے بدلے مہاجرین ان کے باغات میں کام کیا کریں۔ انس رضی اللہ عنہ کی والدہ ام سلیم جو عبداللہ بن ابی طلحہ رضی اللہ عنہما کی بھی والدہ تھیں، انہوں نے رسول اللہ صلی اللہ علیہ وسلم کو کھجور کا ایک باغ ہدیہ دے دیا تھا لیکن آپ صلی اللہ علیہ وسلم نے وہ باغ اپنی لونڈی ام ایمن رضی اللہ عنہا جو اسامہ بن زید رضی اللہ عنہما کی والدہ تھیں، عنایت فرما دیا۔ ابن شہاب نے بیان کیا کہ مجھے انس بن مالک رضی اللہ عنہ نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم جب خیبر کے یہودیوں کی جنگ سے فارغ ہوئے اور مدینہ تشریف لائے تو مہاجرین نے انصار کو ان کے تحائف واپس کر دئیے جو انہوں نے پھلوں کی صورت میں دے رکھے تھے۔ آپ صلی اللہ علیہ وسلم نے انس رضی اللہ عنہ کی والدہ کا باغ بھی واپس کر دیا اور ام ایمن رضی اللہ عنہا کو اس کے بجائے اپنے باغ میں سے ( کچھ درخت ) عنایت فرما دئیے۔ احمد بن شبیب نے بیان کیا، انہیں ان کے والد نے خبر دی اور انہیں یونس نے اسی طرح البتہ اپنی روایت میں بجائے «مكانهن من حائطه‏.‏» کے «مكانهن من خالصه‏.‏» مکانہن من خالصہ بیان کیا۔' WHERE id = 2526;
UPDATE hadiths SET urdu = 'ہم سے حبان نے بیان کیا، کہا کہ ہم کو عبداللہ نے خبر دی، کہا ہم کو عمر بن سعید بن ابی حسین نے خبر دی، کہا کہ مجھے عبداللہ بن ابی ملیکہ نے خبر دی اور انہیں عقبہ بن حارث رضی اللہ عنہ نے کہ انہوں نے ابواہاب بن عزیز کی لڑکی سے شادی کی تھی۔ ایک خاتون آئیں اور کہنے لگیں کہ عقبہ کو بھی میں نے دودھ پلایا ہے اور اسے بھی جس سے اس نے شادی کی ہے۔ عقبہ رضی اللہ عنہ نے کہا کہ مجھے تو معلوم نہیں کہ آپ نے مجھے دودھ پلایا ہے اور آپ نے مجھے پہلے اس سلسلے میں کچھ بتایا بھی نہیں تھا۔ پھر انہوں نے آل ابواہاب کے یہاں آدمی بھیجا کہ ان سے اس کے متعلق پوچھے۔ انہوں نے بھی یہی جواب دیا کہ ہمیں معلوم نہیں کہ انہوں نے دودھ پلایا ہے۔ عقبہ رضی اللہ عنہ اب رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں مدینہ حاضر ہوئے اور آپ صلی اللہ علیہ وسلم سے مسئلہ پوچھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا، اب کیا ہو سکتا ہے جب کہ کہا جا چکا۔ چنانچہ آپ صلی اللہ علیہ وسلم نے دونوں میں جدائی کرا دی اور اس کا نکاح دوسرے شخص سے کرا دیا۔' WHERE id = 2536;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو ابوحیان تیمی (یحییٰ بن سعید) نے، انہیں شعبی نے، اور ان سے نعمان بن بشیر رضی اللہ عنہما نے بیان کیا کہ میری ماں نے میرے باپ سے مجھے ایک چیز ہبہ دینے کے لیے کہا ( پہلے تو انہوں نے انکار کیا کیونکہ دوسری بیوی کے بھی اولاد تھی ) پھر راضی ہو گئے اور مجھے وہ چیز ہبہ کر دی۔ لیکن ماں نے کہا کہ جب تک آپ نبی کریم صلی اللہ علیہ وسلم کو اس معاملہ میں گواہ نہ بنائیں میں اس پر راضی نہ ہوں گی۔ چنانچہ والد میرا ہاتھ پکڑ کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ میں ابھی نوعمر تھا۔ انہوں نے عرض کیا کہ اس لڑکے کی ماں عمرہ بنت رواحہ رضی اللہ عنہا مجھ سے ایک چیز اسے ہبہ کرنے کے لیے کہہ رہی ہیں۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا اس کے علاوہ اور بھی تمہارے لڑکے ہیں؟ انہوں نے کہا ہاں، ہیں۔ نعمان رضی اللہ عنہ! نے بیان کیا، میرا خیال ہے کہ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا ”تو مجھ کو ظلم کی بات پر گواہ نہ بنا۔“ اور ابوحریز نے شعبی سے یہ نقل کیا کہ آپ صلی اللہ علیہ وسلم نے فرمایا ”میں ظلم کی بات پر گواہ نہیں بنتا۔“' WHERE id = 2546;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا عمر بن سعید سے، وہ ابن ابی ملیکہ سے، ان سے عقبہ بن حارث رضی اللہ عنہ نے بیان کیا کہ میں نے ایک عورت سے شادی کی تھی۔ پھر ایک عورت آئی اور کہنے لگی کہ میں نے تم دونوں کو دودھ پلایا تھا۔ اس لیے میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”جب تمہیں بتا دیا گیا ( کہ ایک ہی عورت تم دونوں کی دودھ کی ماں ہے ) تو پھر اب اور کیا صورت ہو سکتی ہے اپنی بیوی کو اپنے سے جدا کر دے۔“ یا اسی طرح کے الفاظ آپ صلی اللہ علیہ وسلم نے فرمائے۔' WHERE id = 2556;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے جریر بن عبدالحمید نے بیان کیا اعمش سے، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تین طرح کے لوگ ایسے ہیں کہ اللہ تعالیٰ ان سے بات بھی نہ کرے گا نہ ان کی طرف نظر اٹھا کر دیکھے گا اور نہ انہیں پاک کرے گا بلکہ انہیں سخت درد ناک عذاب ہو گا۔ ایک وہ شخص جو سفر میں ضرورت سے زیادہ پانی لے جا رہا ہے اور کسی مسافر کو ( جسے پانی کی ضرورت ہو ) نہ دے۔ دوسرا وہ شخص جو کسی ( خلیفۃ المسلمین ) سے بیعت کرے اور صرف دنیا کے لیے بیعت کرے کہ جس سے اس نے بیعت کی اگر وہ اس کا مقصد پورا کر دے تو یہ بھی وفاداری سے کام لے، ورنہ اس کے ساتھ بیعت و عہد کے خلاف کرے۔ تیسرا وہ شخص جو کسی سے عصر کے بعد کسی سامان کا بھاؤ کرے اور اللہ کی قسم کھا لے کہ اسے اس کا اتنا اتنا روپیہ مل رہا تھا اور خریدار اس سامان کو ( اس کی قسم کی وجہ سے ) لے لے۔ حالانکہ وہ جھوٹا ہے۔“' WHERE id = 2566;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا، کہا ہم کو سعید بن سلیمان نے خبر دی، ان سے مروان بن شجاع نے بیان کیا، ان سے سالم افطس نے اور ان سے سعید بن جبیر نے بیان کیا کہ حیرہ کے یہودی نے مجھ سے پوچھا، موسیٰ علیہ السلام نے ( اپنے مہر کے ادا کرنے میں ) کون سی مدت پوری کی تھی؟ ( یعنی آٹھ سال کی یا دس سال کی، جن کا قرآن میں ذکر ہے ) میں نے کہا کہ مجھے معلوم نہیں، ہاں! عرب کے بڑے عالم کی خدمت میں حاضر ہو کر پوچھ لوں ( تو پھر تمہیں بتا دوں گا ) چنانچہ میں نے ابن عباس رضی اللہ عنہما سے پوچھا تو انہوں نے بتایا کہ آپ نے بڑی مدت پوری کی ( دس سال کی ) جو دونوں مدتوں میں بہتر تھی۔ رسول اللہ صلی اللہ علیہ وسلم بھی جب کسی سے وعدہ کرتے تو پورا کرتے تھے۔' WHERE id = 2577;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا ہشام بن عروہ سے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے ( اللہ تعالیٰ کے اس فرمان کی تفسیر میں فرمایا ) «وإن امرأة خافت من بعلها نشوزا أو إعراضا‏» ”اگر کوئی عورت اپنے شوہر کی طرف سے بے توجہی دیکھے۔“ تو اس سے مراد ایسا شوہر ہے جو اپنی بیوی میں ایسی چیزیں پائے جو اسے پسند نہ ہوں، عمر کی زیادتی وغیرہ اور اس لیے اسے اپنے سے جدا کرنا چاہتا ہو اور عورت کہے کہ مجھے جدا نہ کرو ( نفقہ وغیرہ ) جس طرح تم چاہو دیتے رہنا، تو انہوں نے فرمایا کہ اگر دونوں اس پر راضی ہو جائیں تو کوئی حرج نہیں ہے۔' WHERE id = 2587;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے میرے بھائی عبدالحمید نے بیان کیا، ان سے سلیمان بن ہلال نے، ان سے یحییٰ بن سعید نے، ان سے ابوالرجال، محمد بن عبدالرحمٰن نے، ان سے ان کی والدہ عمرہ بنت عبدالرحمٰن نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا سے سنا، انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے دروازے پر دو جھگڑا کرنے والوں کی آواز سنی جو بلند ہو گئی تھی۔ واقعہ یہ تھا کہ ایک آدمی دوسرے سے قرض میں کچھ کمی کرنے اور تقاضے میں کچھ نرمی برتنے کے لیے کہہ رہا تھا اور دوسرا کہتا تھا کہ اللہ کی قسم! میں یہ نہیں کروں گا۔ آخر رسول اللہ صلی اللہ علیہ وسلم ان کے پاس گئے اور فرمایا کہ اس بات پر اللہ کی قسم کھانے والے صاحب کہاں ہیں؟ کہ وہ ایک اچھا کام نہیں کریں گے۔ ان صحابی نے عرض کیا، میں ہی ہوں یا رسول اللہ! اب میرا بھائی جو چاہتا ہے وہی مجھ کو بھی پسند ہے۔' WHERE id = 2597;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ نے اور انہیں عائشہ رضی اللہ عنہا نے خبر دی کہ بریرہ، عائشہ رضی اللہ عنہا کے یہاں اپنی مکاتبت کے بارے میں ان سے مدد لینے کے لیے آئیں، انہوں نے ابھی تک اس معاملے میں ( اپنے مالکوں کو ) کچھ دیا نہیں تھا۔ عائشہ رضی اللہ عنہا نے ان سے فرمایا کہ اپنے مالکوں کے یہاں جا کر ( ان سے دریافت کرو ) اگر وہ یہ صورت پسند کریں کہ تمہاری مکاتبت کی ساری رقم میں ادا کر دوں اور تمہاری ولاء میرے لیے ہو جائے تو میں ایسا کر سکتی ہوں۔ بریرہ نے اس کا تذکرہ جب اپنے مالکوں کے سامنے کیا تو انہوں نے انکار کیا اور کہا کہ وہ ( عائشہ رضی اللہ عنہا ) اگر چاہیں تو یہ کار ثواب تمہارے ساتھ کر سکتی ہیں لیکن ولاء تو ہمارے ہی رہے گی۔ عائشہ رضی اللہ عنہا نے اس کا ذکر رسول اللہ صلی اللہ علیہ وسلم سے کیا تو آپ صلی اللہ علیہ وسلم نے ان سے فرمایا کہ تم انہیں خرید کر آزاد کر دو، ولاء تو بہرحال اسی کی ہوتی ہے جو آزاد کر دے۔' WHERE id = 2608;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، انہوں نے ہشام بن عروہ سے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میرے پاس بریرہ رضی اللہ عنہا آئیں اور کہنے لگیں کہ میں نے اپنے مالک سے نو اوقیہ چاندی پر مکاتبت کر لی ہے، ہر سال ایک اوقیہ دینا ہو گا۔ آپ بھی میری مدد کیجئے۔ عائشہ رضی اللہ عنہا نے فرمایا کہ اگر تمہارے مالک چاہیں تو میں ایک دم انہیں اتنی قیمت ادا کر سکتی ہوں۔ لیکن تمہاری ولاء میری ہو گی۔ بریرہ رضی اللہ عنہا اپنے مالکوں کے یہاں گئیں اور ان سے اس صورت کا ذکر کیا لیکن انہوں نے ولاء کے لیے انکار کیا۔ جب وہ ان کے یہاں سے واپس ہوئیں تو رسول اللہ صلی اللہ علیہ وسلم بھی تشریف فرما تھے۔ انہوں نے کہا کہ میں نے اپنے مالکوں کے سامنے یہ صورت رکھی تھی، لیکن وہ کہتے تھے کہ ولاء انہیں کی ہو گی۔ نبی کریم صلی اللہ علیہ وسلم نے بھی یہ بات سنی اور عائشہ رضی اللہ عنہا نے آپ صلی اللہ علیہ وسلم کو صورت حال سے آگاہ کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تو انہیں خرید لے اور انہیں ولاء کی شرط لگانے دے۔ ولاء تو اسی کے ساتھ قائم ہو سکتی ہے جو آزاد کرے۔ چنانچہ عائشہ رضی اللہ عنہا نے ایسا ہی کیا پھر رسول اللہ صلی اللہ علیہ وسلم صحابہ میں گئے اور اللہ تعالیٰ کی حمد و ثناء کے بعد فرمایا کہ کچھ لوگوں کو کیا ہو گیا ہے کہ وہ ایسی شرطیں لگاتے ہیں جن کا کوئی پتہ ( سند، دلیل ) کتاب اللہ میں نہیں ہے ایسی کوئی بھی شرط جس کا پتہ ( سند، دلیل ) کتاب اللہ میں نہ ہو باطل ہے خواہ سو شرطیں کیوں نہ لگالی جائیں۔ اللہ کا فیصلہ ہی حق ہے اور اللہ کی شرطیں ہی پائیدار ہیں اور ولاء تو اسی کو ملے گی جو آزاد کرے گا۔' WHERE id = 2619;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا ‘ کہا ہم سے امام مالک نے بیان کیا ‘ کہا ہم سے طلحہ بن مصرف نے بیان کیا ‘ انہوں نے بیان کیا کہ میں نے عبداللہ بن ابی اوفی رضی اللہ عنہ سے سوال کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے کوئی وصیت کی تھی؟ انہوں نے کہا کہ نہیں۔ اس پر میں نے پوچھا کہ پھر وصیت کس طرح لوگوں پر فرض ہوئی؟ یا ( راوی نے اس طرح بیان کیا ) کہ لوگوں کو وصیت کا حکم کیوں کر دیا گیا؟ انہوں نے کہا کہ آپ صلی اللہ علیہ وسلم نے لوگوں کو کتاب اللہ پر عمل کرنے کی وصیت کی تھی ( اور کتاب اللہ میں وصیت کرنے کے لیے حکم موجود ہے ) ۔' WHERE id = 2629;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف بیکندی نے بیان کیا ‘ کہا ہم کو امام اوزاعی نے خبر دی ‘ انہوں نے زہری سے ‘ انہوں نے سعید بن مسیب اور عروہ بن زبیر سے کہ حکیم بن حزام رضی اللہ عنہ ( مشہور صحابی ) نے بیان کیا میں نے آپ صلی اللہ علیہ وسلم سے مانگا آپ نے مجھ کو دیا ‘ پھر مانگا پھر آپ نے دیا ‘ پھر فرمانے لگے حکیم یہ دنیا کا روپیہ پیسہ دیکھنے میں خوشنما اور مزے میں شیریں ہے لیکن جو کوئی اس کو سیر چشمی سے لے اس کو برکت ہوتی ہے اور جو کوئی جان لڑا کر حرص کے ساتھ اس کو لے اس کو برکت نہ ہو گی۔ اس کی مثال ایسی ہے جو کماتا ہے لیکن سیر نہیں ہوتا اوپر والا ( دینے والا ) ہاتھ نیچے والے ( لینے والے ) ہاتھ سے بہتر ہے۔ حکیم نے عرض کیا یا رسول اللہ! قسم اس کی جس نے آپ کو سچا پیغمبر کر کے بھیجا ہے میں تو آج سے آپ کے بعد کسی سے کوئی چیز کبھی نہیں لوں گا مرنے تک پھر ( حکیم کا یہ حال رہا ) کہ ابوبکر صدیق رضی اللہ عنہ ان کا سالانہ وظیفہ دینے کے لیے ان کو بلاتے ‘ وہ اس کے لینے سے انکار کرتے۔ پھر عمر رضی اللہ عنہ نے بھی اپنی خلافت میں ان کو بلایا ان کا وظیفہ دینے کے لیے لیکن انہوں نے انکار کیا۔ عمر رضی اللہ عنہ کہنے لگے مسلمانو! تم گواہ رہنا حکیم کو اس کا حق جو لوٹ کے مال میں اللہ نے رکھا ہے دیتا ہوں وہ نہیں لیتا۔ غرض حکیم نے آپ صلی اللہ علیہ وسلم کے بعد پھر کسی شخص سے کوئی چیز قبول نہیں کی ( اپنا وظیفہ بھی بیت المال میں نہ لیا ) یہاں تک کہ ان کی وفات ہو گئی۔ اللہ ان پر رحم کرے۔' WHERE id = 2639;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا ‘ کہا کہ مجھ سے امام مالک نے بیان کیا ‘ ان سے ہشام نے ‘ ان سے ان کے باپ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ایک صحابی ( سعد بن عبادہ ) نے رسول اللہ صلی اللہ علیہ وسلم سے کہا کہ میری والدہ کی موت اچانک واقع ہو گئی ‘ میرا خیال ہے کہ اگر انہیں گفتگو کا موقع ملتا تو وہ صدقہ کرتیں تو کیا میں ان کی طرف سے خیرات کر سکتا ہوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا ہاں ان کی طرف سے خیرات کر۔' WHERE id = 2649;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا ‘ کہا ہم کو روح بن عبادہ نے خبر دی ‘ کہا ہم کو زکریا بن اسحاق نے بیان کیا کہ مجھ سے عمرو بن دینار نے بیان کیا عکرمہ سے اور انہوں نے ابن عباس رضی اللہ عنہما سے کہ ایک صحابی سعد بن عبادہ نے رسول اللہ صلی ‌اللہ ‌علیہ ‌وسلم سے پوچھا کہ ان کی ماں کا انتقال ہو گیا ہے ۔ کیا اگر وہ ان کی طرف سے خیرات کریں تو انہیں اس کا فائدہ پہنچے گا ؟ آپ صلی ‌اللہ ‌علیہ ‌وسلم نے جواب دیا کہ ہاں ۔ اس پر ان صحابی نے کہا کہ میرا ایک پُر میوہ باغ ہے اور میں آپ کو گواہ بناتا ہوں کہ میں نے وہ ان کی طرف سے صدقہ کر دیا ۔' WHERE id = 2659;
UPDATE hadiths SET urdu = 'امام بخاری رحمہ اللہ نے کہا مجھ سے علی بن عبداللہ مدینی نے کہا ہم سے یحییٰ بن آدم نے ‘ کہا ہم سے ابن ابی زائدہ نے ‘ انہوں نے محمد بن ابی القاسم سے ‘ انہوں نے عبدالملک بن سعید بن جبیر سے ‘ انہوں نے اپنے باپ سے ‘ کہا ہم سے عبداللہ بن عباس رضی اللہ عنہما سے انہوں نے کہا بنی سہم کا ایک شخص تمیم داری اور عدی بن بداء کے ساتھ سفر کو نکلا ‘ وہ ایسے ملک میں جا کر مر گیا جہاں کوئی مسلمان نہ تھا۔ یہ دونوں شخص اس کا متروکہ مال لے کر مدینہ واپس آئے۔ اس کے اسباب میں چاندی کا ایک گلاس گم تھا۔ آپ صلی اللہ علیہ وسلم نے ان دونوں کو قسم کھانے کا حکم فرمایا ( انہوں نے قسم کھا لی ) پھر ایسا ہوا کہ وہ گلاس مکہ میں ملا، انہوں نے کہا ہم نے یہ گلاس تمیم اور عدی سے خریدا ہے۔ اس وقت میت کے دو عزیز ( عمرو بن العاص اور مطلب کھڑے ہوئے اور انہوں نے قسم کھائی کہ یہ ہماری گواہی تمیم اور عدی کی گواہی سے زیادہ معتبر ہے ‘ یہ گلاس میت ہی کا ہے۔ عبداللہ بن عباس رضی اللہ عنہما نے کہا ان ہی کے بارے میں یہ آیت نازل ہوئی «يا أيها الذين آمنوا شهادة بينكم‏» آخر آیت تک۔)' WHERE id = 2669;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا ‘ کہا ہم سے وہب بن خالد نے (فضل جہاد میں) بیان کیا ‘ کہا ہم سے حمید طویل نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ کے راستے میں گزرنے والی ایک صبح یا ایک شام دنیا سے اور جو کچھ دنیا میں ہے سب سے بہتر ہے۔“' WHERE id = 2680;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا ‘ کہا ہم سے لیث نے بیان کیا ‘ کہا کہ مجھ سے یونس نے بیان کیا ابن شہاب سے ‘ انہوں نے عبیداللہ بن عبداللہ سے انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی اور انہیں ابوسفیان رضی اللہ عنہ نے خبر دی کہ ہرقل نے ان سے کہا تھا میں نے تم سے پوچھا تھا کہ ان کے یعنی ( نبی کریم صلی اللہ علیہ وسلم ) کے ساتھ تمہاری لڑائیوں کا کیا انجام رہتا ہے تو تم نے بتایا کہ لڑائی ڈولوں کی طرح ہے ‘ کبھی ادھر کبھی ادھر یعنی کبھی لڑائی کا انجام ہمارے حق میں ہوتا ہے اور کبھی ان کے حق میں۔ انبیاء کا بھی یہی حال ہوتا ہے کہ ان کی آزمائش ہوتی رہتی ہے ( کبھی فتح اور کبھی ہار سے ) لیکن انجام انہیں کے حق میں اچھا ہوتا ہے۔' WHERE id = 2691;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا ‘ کہا ہم سے سفیان نے بیان کیا عمرو سے ‘ انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا ‘ آپ بیان کرتے تھے کہ کچھ صحابہ نے جنگ احد کے دن صبح کے وقت شراب پی ( راوی حدیث ) سے پوچھا گیا کیا اسی دن کے آخری حصے میں ( ان کی شہادت ہوئی ) تھی جس دن انہوں نے شراب پی تھی؟ تو انہوں نے جواب دیا کہ حدیث میں اس کا کوئی ذکر نہیں ہے۔' WHERE id = 2701;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی فلاس نے بیان کیا ‘ ہم سے یحییٰ قطان نے بیان کیا ‘ کہا ہم سے سفیان ثوری نے بیان کیا ‘ کہا کہ مجھ سے منصور نے بیان کیا مجاہد سے ‘ انہوں نے طاؤس سے اور انہوں نے ابن عباس رضی اللہ عنہما سے کہ نبی کریم صلی اللہ علیہ وسلم نے فتح مکہ کے دن فرمایا تھا مکہ فتح ہونے کے بعد ( اب مکہ سے مدینہ کے لیے ) ہجرت باقی نہیں ہے ‘ لیکن خلوص نیت کے ساتھ جہاد اب بھی باقی ہے اس لیے تمہیں جہاد کے لیے بلایا جائے تو نکل کھڑے ہو۔' WHERE id = 2711;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا ‘ کہا ہم سے عبدالوارث نے بیان کیا ‘ کہا ہم سے عبدالعزیز نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ( جب تمام عرب کے مدینہ منورہ پر حملہ کا خطرہ ہوا تو ) مدینہ کے اردگرد مہاجرین و انصار خندق کھودنے میں مشغول ہو گئے ‘ مٹی اپنی پشت پر لاد لاد کر اٹھاتے اور ( یہ رجز ) پڑھتے جاتے ”ہم وہ ہیں جنہوں نے محمد صلی اللہ علیہ وسلم کے ہاتھ پر اس وقت تک جہاد کے لیے بیعت کی ہے جب تک ہماری جان میں جان ہے۔“ نبی کریم صلی اللہ علیہ وسلم ان کے پاس رجز کے جواب میں یہ دعا فرماتے ”اے اللہ! آخرت کی خیر کے سوا اور کوئی خیر نہیں ‘ پس تو انصار اور مہاجرین کو برکت عطا فرما۔' WHERE id = 2721;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا ‘ کہا ہم سے خالد بن حارث نے بیان کیا ‘ کہا ہم سے ابن عون نے بیان کیا ‘ ان سے موسیٰ بن انس نے بیان کیا جنگ یمامہ کا وہ ذکر کر رہے تھے ‘ بیان کیا کہ انس بن مالک رضی اللہ عنہ ثابت بن قیس رضی اللہ عنہ کے یہاں گئے ‘ انہوں نے اپنی ران کھول رکھی تھی اور خوشبو لگا رہے تھے۔ انس رضی اللہ عنہ نے کہا چچا! اب تک آپ جنگ میں کیوں تشریف نہیں لائے؟ انہوں نے جواب دیا کہ بیٹے ابھی آتا ہوں اور وہ پھر خوشبو لگانے لگے پھر ( کفن پہن کر تشریف لائے اور بیٹھ گئے ) مراد صف میں شرکت سے ہے ) انس رضی اللہ عنہ نے گفتگو کرتے ہوئے مسلمانوں کی طرف سے کچھ کمزوری کے آثار کا ذکر کیا تو انہوں نے فرمایا کہ ہمارے سامنے سے ہٹ جاؤ تاکہ ہم کافروں سے دست بدست لڑیں ‘ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ہم ایسا کبھی نہیں کرتے تھے۔ ( یعنی پہلی صف کے لوگ ڈٹ کر لڑتے تھے کمزوری کا ہرگز مظاہرہ نہیں ہونے دیتے تھے ) تم نے اپنے دشمنوں کو بہت بری چیز کا عادی بنا دیا ہے ( تم جنگ کے موقع پر پیچھے ہٹ گئے ) وہ حملہ کرنے لگے۔ اس حدیث کو حماد نے ثابت سے اور انہوں نے انس رضی اللہ عنہ سے روایت کیا۔' WHERE id = 2731;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ بن جعفر نے بیان کیا، کہا ہم سے معن بن عیسیٰ نے بیان کیا، کہا ہم سے ابی بن عباس بن سہل نے بیان کیا، ان سے ان کے والد نے ان کے دادا (سہل بن سعد ساعدی رضی اللہ عنہ) سے بیان کیا کہ ہمارے باغ میں نبی کریم صلی اللہ علیہ وسلم کا ایک گھوڑا رہتا تھا جس کا نام لحیف تھا۔' WHERE id = 2741;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، ان سے ابواسامہ نے بیان کیا، ان سے عبیداللہ نے بیان کیا، ان سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے جب اپنا پائے مبارک «غرز» ( رکاب ) میں ڈالا اور اونٹنی آپ صلی اللہ علیہ وسلم کو لے کر سیدھی اٹھ گئی تو آپ صلی اللہ علیہ وسلم نے مسجد ذوالحلیفہ کے پاس لبیک کہا ( احرام باندھا ) ۔' WHERE id = 2751;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان ثوری نے خبر دی، انہیں معاویہ ابن اسحاق نے، انہیں عائشہ بنت طلحہ نے اور ان سے ام المؤمنین عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے جہاد کی اجازت چاہی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ تمہارا جہاد حج ہے۔ اور عبداللہ بن ولید نے بیان کیا کہ ہم سے سفیان ثوری نے بیان کیا اور ان سے معاویہ نے یہی حدیث نقل کی۔' WHERE id = 2761;
UPDATE hadiths SET urdu = 'اور عمرو ابن مرزوق نے ہم سے بڑھا کر بیان کیا، انہوں نے کہا ہم کو عبدالرحمٰن بن عبداللہ بن دینار نے خبر دی، انہوں نے اپنے باپ سے، انہوں نے ابوصالح سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے، آپ صلی اللہ علیہ وسلم نے فرمایا ”اشرفی کا بندہ اور روپے کا بندہ اور کمبل کا بندہ تباہ ہوا، اگر اس کو کچھ دیا جائے تب تو خوش جب نہ دیا جائے تو غصہ ہو جائے، ایسا شخص تباہ سرنگوں ہوا۔ اس کو کانٹا لگے تو اللہ کرے پھر نہ نکلے۔ مبارک کا مستحق ہے وہ بندہ جو اللہ کے راستے میں ( غزوہ کے موقع پر ) اپنے گھوڑے کی لگام تھامے ہوئے ہے، اس کے سر کے بال پراگندہ ہیں اور اس کے قدم گرد و غبار سے اٹے ہوئے ہیں، اگر اسے چوکی پہرے پر لگا دیا جائے تو وہ اپنے اس کام میں پوری تندہی سے لگا رہے اور اگر لشکر کے پیچھے ( دیکھ بھال کے لیے ) لگا دیا جائے تو اس میں بھی پوری تندہی اور فرض شناسی سے لگا رہے۔ ( اگرچہ زندگی میں غربت کی وجہ سے اس کی کوئی اہمیت بھی نہ ہو کہ ) اگر وہ کسی سے ملاقات کی اجازت چاہے تو اسے اجازت بھی نہ ملے اور اگر کسی کی سفارش کرے تو اس کی سفارش بھی قبول نہ کی جائے۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ اسرائیل اور محمد بن جحادہ نے ابوحصین سے یہ روایت مرفوعاً نہیں بیان کی ہے اور کہا کہ قرآن مجید میں جو لفظ «تعسا‏» آیا ہے گویا یوں کہنا چاہئے کہ «فأتعسهم الله‏.‏» ( اللہ انہیں گرائے ہلاک کرے ) «طوبى فعلى» کے وزن پر ہے ہر اچھی اور طیب چیز کے لیے۔ واو اصل میں یا تھا ( طیبیٰ ) پھر یا کو واو سے بدل دیا گیا اور یہ طیب سے نکلا ہے۔' WHERE id = 2772;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے حاتم بن اسماعیل نے بیان کیا، ان سے یزید بن ابی عبید نے بیان کیا، انہوں نے سلمہ بن اکوع رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کا قبیلہ بنو اسلم کے چند لوگوں پر گزر ہوا جو تیر اندازی کی مشق کر رہے تھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا: اسماعیل علیہ السلام کے بیٹو! تیر اندازی کرو کہ تمہارے بزرگ دادا اسماعیل علیہ السلام بھی تیرانداز تھے۔ ہاں! تیر اندازی کرو، میں بنی فلاں ( ابن الاورع رضی اللہ عنہ ) کی طرف ہوں۔ بیان کیا، جب آپ صلی اللہ علیہ وسلم ایک فریق کے ساتھ ہو گئے تو ( مقابلے میں حصہ لینے والے ) دوسرے ایک فریق نے ہاتھ روک لیے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کیا بات پیش آئی، تم لوگوں نے تیر اندازی بند کیوں کر دی؟ دوسرے فریق نے عرض کیا جب آپ صلی اللہ علیہ وسلم ایک فریق کے ساتھ ہو گئے تو بھلا ہم کس طرح مقابلہ کر سکتے ہیں۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا اچھا تیر اندازی جاری رکھو میں تم سب کے ساتھ ہوں۔' WHERE id = 2783;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی حازم نے بیان کیا، ان سے ان کے والد نے اور ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے کہ ان سے احد کی لڑائی میں نبی کریم صلی اللہ علیہ وسلم کے زخمی ہونے کے متعلق پوچھا گیا تو انہوں نے بتلایا آپ صلی اللہ علیہ وسلم کے چہرہ مبارک پر زخم آئے اور آپ صلی اللہ علیہ وسلم کے آگے کے دانت ٹوٹ گئے تھے اور خود آپ صلی اللہ علیہ وسلم کے سر مبارک پر ٹوٹ گئی تھی۔ ( جس سے سر پر زخم آئے تھے ) فاطمہ رضی اللہ عنہا خون دھو رہی تھیں اور علی رضی اللہ عنہ پانی ڈال رہے تھے۔ جب فاطمہ رضی اللہ عنہا نے دیکھا کہ خون برابر بڑھتا ہی جا رہا ہے تو انہوں نے ایک چٹائی جلائی اور اس کی راکھ کو آپ صلی اللہ علیہ وسلم کے زخموں پر لگا دیا جس سے خون بہنا بند ہو گیا۔' WHERE id = 2794;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے شعبہ نے، انہیں قتادہ نے خبر دی اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے عبدالرحمٰن بن عوف اور زبیر بن عوام رضی اللہ عنہما کو ریشمی کپڑے پہننے کی اجازت دے دی تھی۔' WHERE id = 2804;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو عیسیٰ نے خبر دی، کہا ہم سے ہشام نے بیان کیا، ان سے محمد نے، ان سے عبیدہ نے اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ غزوہ احزاب ( خندق ) کے موقع پر رسول اللہ صلی اللہ علیہ وسلم نے ( مشرکین کو ) یہ بددعا دی کہ اے اللہ! ان کے گھروں اور قبروں کو آگ سے بھر دے۔ انہوں نے ہم کو صلوٰۃ وسطیٰ ( عصر کی نماز ) نہیں پڑھنے دی ( یہ آپ صلی اللہ علیہ وسلم نے اس وقت فرمایا ) جب سورج غروب ہو چکا تھا اور عصر کی نماز قضاء ہو گئی تھی۔' WHERE id = 2814;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے معاویہ بن عمرو نے بیان کیا، کہا ہم سے ابواسحاق نے بیان کیا، ان سے حمید نے کہا کہ میں نے انس رضی اللہ عنہ سے سنا، آپ بیان کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم جب کسی قوم پر چڑھائی کرتے تو اس وقت تک کوئی اقدام نہ فرماتے جب تک صبح نہ ہو جاتی، جب صبح ہو جاتی اور اذان کی آواز سن لیتے تو رک جاتے اور اگر اذان کی آواز سنائی نہ دیتی تو صبح ہونے کے بعد حملہ کرتے۔ چنانچہ خیبر میں بھی ہم رات میں پہنچے تھے۔' WHERE id = 2825;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، کہا مجھ سے زہری نے بیان کیا، ان سے عبداللہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم ( فتح مکہ کے لیے مدینہ سے ) رمضان میں نکلے اور روزے سے تھے۔ جب آپ صلی اللہ علیہ وسلم مقام کدید پر پہنچے تو آپ صلی اللہ علیہ وسلم نے افطار کیا۔ سفیان نے کہا کہ زہری نے بیان کیا، انہیں عبداللہ نے خبر دی اور انہیں ابن عباس رضی اللہ عنہما نے پھر یہی حدیث بیان کی۔' WHERE id = 2835;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے شعبہ نے، ان سے قتادہ نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ مدینہ میں ایک دفعہ کچھ دہشت پھیل گئی تو رسول اللہ صلی اللہ علیہ وسلم ابوطلحہ رضی اللہ عنہ کے ایک گھوڑے پر سوار ہو کر ( حالات معلوم کرنے کے لیے سب سے آگے تھے ) پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہم نے تو کوئی بات نہیں دیکھی۔ البتہ اس گھوڑے کو ہم نے دوڑنے میں دریا کی روانی جیسا تیز پایا ہے ( باب اور حدیث میں مطابقت ظاہر ہے ) ۔' WHERE id = 2847;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا کہ مجھے عبیداللہ بن عبداللہ نے، انہیں ابن عباس رضی اللہ عنہما نے خبر دی اور انہیں ابوسفیان رضی اللہ عنہ نے خبر دی کہ ( آپ صلی اللہ علیہ وسلم کا نامہ مبارک جب شاہ روم ہرقل کو ملا تو ) اس نے اپنا آدمی انہیں تلاش کرنے کے لیے بھیجا۔ یہ لوگ اس وقت ایلیاء میں ٹھہرے ہوئے تھے۔ آخر ( طویل گفتگو کے بعد ) اس نے نبی کریم صلی اللہ علیہ وسلم کا نامہ مبارک منگوایا۔ جب وہ پڑھا جا چکا تو اس کے دربار میں ہنگامہ برپا ہو گیا ( چاروں طرف سے ) آواز بلند ہونے لگی۔ اور ہمیں باہر نکال دیا گیا۔ جب ہم باہر کر دئیے گئے تو میں نے اپنے ساتھیوں سے کہا کہ ابن ابی کبشہ ( مراد رسول اللہ صلی اللہ علیہ وسلم سے ہے ) کا معاملہ تو اب بہت آگے بڑھ چکا ہے۔ یہ ملک بنی اصفر ( قیصر روم ) بھی ان سے ڈرنے لگا ہے۔' WHERE id = 2857;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا کہ مجھ سے یونس نے بیان کیا، انہیں نافع نے خبر دی اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ فتح مکہ کے موقع پر رسول اللہ صلی اللہ علیہ وسلم مکہ کے بالائی علاقے سے اپنی سواری پر تشریف لائے۔ اسامہ رضی اللہ عنہ کو آپ صلی اللہ علیہ وسلم نے اپنی سواری پر پیچھے بٹھا دیا تھا اور آپ کے ساتھ بلال رضی اللہ عنہ بھی تھے۔ اور عثمان بن طلحہ رضی اللہ عنہ بھی جو کعبہ کے کلید بردار تھے۔ آپ صلی اللہ علیہ وسلم نے مسجد الحرام میں اپنی سواری بٹھا دی اور عثمان رضی اللہ عنہ سے کہا کہ بیت اللہ الحرام کی کنجی لائیں۔ انہوں نے کعبہ کا دروازہ کھول دیا اور رسول اللہ صلی اللہ علیہ وسلم اندر داخل ہو گئے۔ آپ صلی اللہ علیہ وسلم کے ساتھ اسامہ، بلال اور عثمان رضی اللہ عنہم بھی تھے۔ آپ صلی اللہ علیہ وسلم کافی دیر تک اندر ٹھہرے رہے۔ اور جب باہر تشریف لائے تو صحابہ نے ( اندر جانے کے لیے ) ایک دوسرے سے آگے ہونے کی کوشش کی سب سے پہلے اندر داخل ہونے والے عبداللہ بن عمر رضی اللہ عنہما تھے۔ انہوں نے بلال رضی اللہ عنہ کو دروازے کے پیچھے کھڑا پایا اور ان سے پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم نے نماز کہاں پڑھی ہے؟ انہوں نے اس جگہ کی طرف اشارہ کیا جہاں رسول اللہ صلی اللہ علیہ وسلم نے نماز پڑھی تھی۔ عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ مجھے یہ پوچھنا یاد نہیں رہا کہ رسول اللہ صلی اللہ علیہ وسلم نے کتنی رکعتیں پڑھی تھیں۔' WHERE id = 2867;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے عاصم بن محمد نے بیان کیا، کہا کہ مجھ سے میرے باپ نے بیان کیا، اور ان سے ابن عمر رضی اللہ عنہما نے کہ (دوسری سند) ہم سے ابونعیم نے بیان کیا، کہا ہم سے عاصم بن محمد بن زید بن عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا، ان سے ان کے والد نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جتنا میں جانتا ہوں، اگر لوگوں کو بھی اکیلے سفر ( کی برائیوں ) کے متعلق اتنا علم ہوتا تو کوئی سوار رات میں اکیلا سفر نہ کرتا۔“' WHERE id = 2877;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا ‘ کہا ہم سے ابن عیینہ نے بیان کیا ‘ ان سے عمرو بن دینار نے ‘ انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا ‘ انہوں نے بیان کیا کہ بدر کی لڑائی سے قیدی ( مشرکین مکہ ) لائے گئے۔ جن میں عباس ( رضی اللہ عنہ ) بھی تھے۔ ان کے بدن پر کوئی کپڑا نہیں تھا۔ نبی کریم صلی اللہ علیہ وسلم نے ان کے لیے قمیص تلاش کروائی۔ ( وہ لمبے قد کے تھے ) اس لیے عبداللہ بن ابی ( منافق ) کی قمیص ہی ان کے بدن پر آ سکی اور نبی کریم صلی اللہ علیہ وسلم نے انہیں وہ قمیص پہنا دی۔ نبی کریم صلی اللہ علیہ وسلم نے ( عبداللہ بن ابی کی موت کے بعد ) اپنی قمیص اتار کر اسے پہنائی تھی۔ ابن عیینہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم پر جو اس کا احسان تھا ‘ آپ صلی اللہ علیہ وسلم نے چاہا کہ اسے ادا کر دیں۔' WHERE id = 2887;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا ‘ کہا ہم سے وہیب بن خالد نے بیان کیا ‘ ان سے ایوب سختیانی نے ‘ ان سے ابوقلابہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ قبیلہ عکل کے آٹھ آدمیوں کی جماعت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ( اسلام قبول کرنے کو ) حاضر ہوئی لیکن مدینہ کی آب و ہوا انہیں موافق نہیں آئی ‘ انہوں نے عرض کیا: یا رسول اللہ! ہمارے لیے ( اونٹ کے ) دودھ کا انتظام کر دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں تمہارے لیے دودھ نہیں دے سکتا ‘ تم ( صدقہ کے ) اونٹوں میں چلے جاؤ۔ ان کا دودھ اور پیشاب پیو ‘ تاکہ تمہاری صحت ٹھیک ہو جائے۔ وہ لوگ وہاں سے چلے گئے اور ان کا دودھ اور پیشاب پی کر تندرست ہو گئے تو چرواہے کو قتل کر دیا ‘ اور اونٹوں کو اپنے ساتھ لے کر بھاگ نکلے اور اسلام لانے کے بعد کفر کیا ‘ ایک شخص نے اس کی خبر آپ صلی اللہ علیہ وسلم کو دی ‘ تو آپ صلی اللہ علیہ وسلم نے ان کی تلاش کے لیے سوار دوڑائے ‘ دوپہر سے پہلے ہی وہ پکڑ کر لائے گئے۔ ان کے ہاتھ پاؤں کاٹ دیئے گئے۔ پھر آپ کے حکم سے ان کی آنکھوں میں سلائی گرم کر کے پھیر دی گئی اور انہیں حرہ ( مدینہ کی پتھریلی زمین ) میں ڈال دیا گیا۔ وہ پانی مانگتے تھے لیکن انہیں نہیں دیا گیا۔ یہاں تک کہ وہ سب مر گئے۔ ( ایسا ہی انہوں نے اونٹوں کے چرانے والوں کے ساتھ کیا تھا ‘ جس کا بدلہ انہیں دیا گیا ) ابوقلابہ نے کہا کہ انہوں نے قتل کیا تھا ‘ چوری کی تھی ‘ اللہ اور اس کے رسول صلی اللہ علیہ وسلم کے ساتھ جنگ کی تھی اور زمین میں فساد برپا کرنے کی کوشش کی تھی۔' WHERE id = 2897;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ ان سے عمرو بن دینار نے اور ان سے جابر بن عبداللہ انصاری رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کعب بن اشرف کے لیے کون ہمت کرتا ہے؟“ محمد بن مسلمہ رضی اللہ عنہ نے کہا کیا میں اسے قتل کر دوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”ہاں!“ انہوں نے عرض کیا کہ پھر آپ مجھے اجازت دیں ( کہ میں جو چاہوں جھوٹ سچ کہوں ) آپ صلی اللہ علیہ وسلم نے فرمایا ”میری طرف سے اس کی اجازت ہے۔“' WHERE id = 2909;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابن شہاب نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم فتح مکہ کے دن جب شہر میں داخل ہوئے تو آپ صلی اللہ علیہ وسلم کے سر مبارک پر خود تھا۔ آپ صلی اللہ علیہ وسلم جب اسے اتار رہے تھے تو ایک شخص ( ابوبرزہ اسلمی ) نے آ کر آپ کو خبر دی کہ ابن خطل ( اسلام کا بدترین دشمن ) کعبہ کے پردے سے لٹکا ہوا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا اسے وہیں قتل کر دو۔' WHERE id = 2920;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا ‘ کہا ہم سے لیث بن سعد نے بیان کیا ‘ ان سے عقیل نے ‘ ان سے ابن شہاب نے ‘ ان سے سالم بن عبداللہ نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ عمر رضی اللہ عنہ نے دیکھا کہ بازار میں ایک ریشمی جوڑا فروخت ہو رہا ہے۔ پھر اسے وہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں لائے اور عرض کیا یا رسول اللہ! یہ جوڑا آپ خرید لیں اور عید اور وفود کی ملاقات پر اس سے اپنی زیبائش فرمایا کریں۔ آپ صلی اللہ علیہ وسلم نے فرمایا یہ ان لوگوں کا لباس ہے جن کا ( آخرت میں ) کوئی حصہ نہیں یا ( آپ نے یہ جملہ فرمایا ) اسے تو وہی لوگ پہن سکتے ہیں جن کا ( آخرت میں ) کوئی حصہ نہیں۔ پھر اللہ نے جتنے دنوں چاہا عمر رضی اللہ عنہ خاموش رہے۔ پھر جب ایک دن رسول اللہ صلی اللہ علیہ وسلم نے ان کے پاس ایک ریشمی جبہ بھیجا تو عمر رضی اللہ عنہ اسے لے کر خدمت نبوی میں حاضر ہوئے اور عرض کیا: یا رسول اللہ! آپ نے تو یہ فرمایا تھا کہ یہ ان کا لباس ہے جن کا ( آخرت میں ) کوئی حصہ نہیں ‘ یا ( عمر رضی اللہ عنہ نے آپ کی بات اس طرح دہرائی کہ ) اسے وہی لوگ پہن سکتے ہیں جن کا ( آخرت میں ) کوئی حصہ نہیں۔ اور پھر آپ نے یہی میرے پاس ارسال فرما دیا۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ( میرے بھیجنے کا مقصد یہ تھا کہ ) تم اسے بیچ لو ‘ یا ( فرمایا کہ ) اس سے اپنی کوئی ضرورت پوری کر سکو۔' WHERE id = 2930;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا ‘ کہا ہم سے روح بن عبادہ نے بیان کیا ‘ ان سے سعید نے بیان کیا ‘ ان سے قتادہ نے بیان کیا ‘ کہا کہ ہم سے انس بن مالک رضی اللہ عنہ نے ابوطلحہ رضی اللہ عنہ سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو جب کسی قوم پر فتح حاصل ہوتی، تو میدان جنگ میں تین رات قیام فرماتے۔ روح بن عبادہ کے ساتھ اس حدیث کو معاذ اور عبدالاعلیٰ نے بھی روایت کیا۔ دونوں نے کہا ہم سے سعید نے بیان کیا انہوں نے قتادہ سے ‘ انہوں نے انس سے ‘ انہوں نے ابوطلحہ سے انہوں نے آپ صلی اللہ علیہ وسلم سے۔' WHERE id = 2940;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ کہا ہم سے ابوعوانہ وضاح شکری نے بیان کیا ‘ ان سے سعید بن مسروق نے ‘ ان سے عبایہ بن رفاعہ نے اور ان سے ان کے دادا رافع بن خدیج رضی اللہ عنہ نے بیان کیا کہ مقام ذوالحلیفہ میں ہم نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ پڑاؤ کیا۔ لوگ بھوکے تھے۔ ادھر غنیمت میں ہمیں اونٹ اور بکریاں ملی تھیں۔ نبی کریم صلی اللہ علیہ وسلم لشکر کے پیچھے حصے میں تھے۔ لوگوں نے ( بھوک کے مارے ) جلدی کی ہانڈیاں چڑھا دیں۔ بعد میں نبی کریم صلی اللہ علیہ وسلم کے حکم سے ان ہانڈیوں کو اوندھا دیا گیا پھر آپ نے غنیمت کی تقسیم شروع کی دس بکریوں کو ایک اونٹ کے برابر رکھا اتفاق سے مال غنیمت کا ایک اونٹ بھاگ نکلا۔ لشکر میں گھوڑوں کی کمی تھی۔ لوگ اسے پکڑنے کے لیے دوڑے لیکن اونٹ نے سب کو تھکا دیا۔ آخر ایک صحابی ( خود رافع رضی اللہ عنہ ) نے اسے تیر مارا۔ اللہ تعالیٰ کے حکم سے اونٹ جہاں تھا وہیں رہ گیا۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان ( پالتو ) جانوروں میں بھی جنگلی جانوروں کی طرح بعض دفعہ وحشت ہو جاتی ہے۔ اس لیے اگر ان میں سے کوئی قابو میں نہ آئے تو اس کے ساتھ ایسا ہی کرو۔ عبایہ کہتے ہیں کہ میرے دادا ( رافع رضی اللہ عنہ ) نے خدمت نبوی میں عرض کیا ‘ کہ ہمیں امید ہے یا ( یہ کہا کہ ) خوف ہے کہ کل کہیں ہماری دشمن سے مڈبھیڑ نہ ہو جائے۔ ادھر ہمارے پاس چھری نہیں ہے۔ تو کیا ہم بانس کی کھپچیوں سے ذبح کر سکتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو چیز خون بہا دے اور ذبح کرتے وقت اس پر اللہ تعالیٰ کا نام بھی لیا گیا ہو ‘ تو اس کا گوشت کھانا حلال ہے۔ البتہ وہ چیز ( جس سے ذبح کیا گیا ہو ) دانت اور ناخن نہ ہونا چاہئے۔ تمہارے سامنے میں اس کی وجہ بھی بیان کرتا ہوں دانت تو اس لیے نہیں کہ وہ ہڈی ہے اور ناخن اس لیے نہیں کہ وہ حبشیوں کی چھری ہیں۔' WHERE id = 2950;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا ‘ انہوں نے کہا ہم سے شعبہ نے بیان کیا ‘ ان سے محارب بن دثار نے بیان کیا ‘ انہوں نے کہا کہ میں نے جابر بن عبداللہ انصاری رضی اللہ عنہما سے سنا ‘ انہوں نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک سفر میں تھا۔ جب ہم مدینہ پہنچے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ پہلے مسجد میں جا اور دو رکعت ( نفل ) نماز پڑھ۔' WHERE id = 2961;
UPDATE hadiths SET urdu = 'ہم سے حبان بن موسیٰ اور محمد بن مقاتل نے بیان کیا ‘ کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی ‘ کہا ہم کو معمر اور یونس نے خبر دی ‘ ان سے زہری نے بیان کیا ‘ انہیں عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ ( مرض الوفات میں ) جب نبی کریم صلی اللہ علیہ وسلم کا مرض بہت بڑھ گیا ‘ تو آپ صلی اللہ علیہ وسلم نے سب بیویوں سے اس کی اجازت چاہی کہ مرض کے دن آپ میرے گھر میں گزاریں۔ لہٰذا اس کی اجازت آپ صلی اللہ علیہ وسلم کو مل گئی تھی۔' WHERE id = 2972;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا ‘ ان سے ابوحمزہ نے ‘ ان سے عاصم نے ‘ ان سے ابن سیرین نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کا پانی پینے کا پیالہ ٹوٹ گیا تو آپ صلی اللہ علیہ وسلم نے ٹوٹی ہوئی جگہوں کو چاندی کی زنجیروں سے جٖڑوا لیا۔ عاصم کہتے ہیں کہ میں نے وہ پیالہ دیکھا ہے۔ اور اس میں میں نے پانی بھی پیا ہے۔' WHERE id = 2982;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا ہم سے خالد نے بیان کیا ‘ کہا ہم سے حصین نے بیان کیا ‘ ان سے عامر نے اور ان سے عروہ بارقی رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”گھوڑوں کی پیشانیوں سے قیامت تک خیر و برکت ( آخرت میں ) اور غنیمت ( دنیا میں ) بندھی ہوئی ہے۔“' WHERE id = 2992;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا ‘ کہا کہ میں نے ابواسامہ سے پوچھا ‘ کیا آپ لوگوں سے ہشام بن عروہ نے یہ حدیث اپنے والد سے بیان کی ہے کہ ان سے عبداللہ بن زبیر رضی اللہ عنہما نے کہا کہ جمل کی جنگ کے موقع پر جب زبیر رضی اللہ عنہ کھڑے ہوئے تو مجھے بلایا میں ان کے پہلو میں جا کر کھڑا ہو گیا ‘ انہوں نے کہا بیٹے! آج کی لڑائی میں ظالم مارا جائے گا یا مظلوم میں سمجھتا ہوں کہ آج میں مظلوم قتل کیا جاؤں گا اور مجھے سب سے زیادہ فکر اپنے قرضوں کی ہے۔ کیا تمہیں بھی کچھ اندازہ ہے کہ قرض ادا کرنے کے بعد ہمارا کچھ مال بچ سکے گا؟ پھر انہوں نے کہا بیٹے! ہمارا مال فروخت کر کے اس سے قرض ادا کر دینا۔ اس کے بعد انہوں نے ایک تہائی کی میرے لیے اور اس تہائی کے تیسرے حصہ کی وصیت میرے بچوں کے لیے کی ‘ یعنی عبداللہ بن زبیر رضی اللہ عنہ کے بچوں کے لیے۔ انہوں نے فرمایا تھا کہ اس تہائی کے تین حصے کر لینا اور اگر قرض کی ادائیگی کے بعد ہمارے اموال میں سے کچھ بچ جائے تو اس کا ایک تہائی تمہارے بچوں کے لیے ہو گا۔ ہشام راوی نے بیان کیا کہ عبداللہ رضی اللہ عنہ کے بعض لڑکے زبیر رضی اللہ عنہ کے لڑکوں کے ہم عمر تھے۔ جیسے خبیب اور عباد۔ اور زبیر رضی اللہ عنہ کے اس وقت نو لڑکے اور نو لڑکیاں تھیں۔ عبداللہ بن زبیر نے بیان کیا کہ پھر زبیر رضی اللہ عنہ مجھے اپنے قرض کے سلسلے میں وصیت کرنے لگے اور فرمانے لگے کہ بیٹا! اگر قرض ادا کرنے سے عاجز ہو جاؤ تو میرے مالک و مولا سے اس میں مدد چاہنا۔ عبداللہ نے بیان کیا کہ قسم اللہ کی! میں ان کی بات نہ سمجھ سکا ‘ میں نے پوچھا کہ بابا آپ کے مولا کون ہیں؟ انہوں نے فرمایا کہ اللہ پاک! عبداللہ نے بیان کیا ‘ قسم اللہ کی! قرض ادا کرنے میں جو بھی دشواری سامنے آئی تو میں نے اسی طرح دعا کی ‘ کہ اے زبیر کے مولا! ان کی طرف سے ان کا قرض ادا کرا دے اور ادائیگی کی صورت پیدا ہو جاتی تھی۔ چنانچہ جب زبیر رضی اللہ عنہ ( اسی موقع پر ) شہید ہو گئے تو انہوں نے ترکہ میں درہم و دینار نہیں چھوڑے بلکہ ان کا ترکہ کچھ تو اراضی کی صورت میں تھا اور اسی میں غابہ کی زمین بھی شامل تھی۔ گیارہ مکانات مدینہ میں تھے ‘ دو مکان بصرہ میں تھے ‘ ایک مکان کوفہ میں تھا اور ایک مصر میں تھا۔ عبداللہ نے بیان کیا کہ ان پر جو اتنا سارا قرض ہو گیا تھا اس کی صورت یہ ہوئی تھی کہ جب ان کے پاس کوئی شخص اپنا مال لے کر امانت رکھنے آتا تو آپ اسے کہتے کہ نہیں البتہ اس صورت میں رکھ سکتا ہوں کہ یہ میرے ذمے بطور قرض رہے۔ کیونکہ مجھے اس کے ضائع ہو جانے کا بھی خوف ہے۔ زبیر رضی اللہ عنہ کسی علاقے کے امیر کبھی نہیں بنے تھے۔ نہ وہ خراج وصول کرنے پر کبھی مقرر ہوئے اور نہ کوئی دوسرا عہدہ انہوں نے قبول کیا ‘ البتہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم کے سات' WHERE id = 3002;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یوسف بن ماجشون نے، ان سے صالح بن ابراہیم بن عبدالرحمٰن بن عوف نے، ان سے ان کے باپ نے اور ان سے صالح کے دادا (عبدالرحمٰن بن عوفص) نے بیان کے کہ بدر کی لڑائی میں، میں صف کے ساتھ کھڑا ہوا تھا۔ میں نے جو دائیں بائیں جانب دیکھا، تو میرے دونوں طرف قبیلہ انصار کے دو نوعمر لڑکے تھے۔ میں نے آرزو کی کاش! میں ان سے زبردست زیادہ عمر والوں کے بیچ میں ہوتا۔ ایک نے میری طرف اشارہ کیا، اور پوچھا چچا! آپ ابوجہل کو بھی پہچانتے ہیں؟ میں نے کہا کہ ہاں! لیکن بیٹے تم لوگوں کو اس سے کیا کام ہے؟ لڑکے نے جواب دیا مجھے معلوم ہوا ہے کہ وہ رسول اللہ صلی اللہ علیہ وسلم کو گالیاں دیتا ہے، اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے اگر مجھے وہ مل گیا تو اس وقت تک میں اس سے جدا نہ ہوں گا جب تک ہم میں سے کوئی جس کی قسمت میں پہلے مرنا ہو گا، مر نہ جائے، مجھے اس پر بڑی حیرت ہوئی۔ پھر دوسرے نے اشارہ کیا اور وہی باتیں اس نے بھی کہیں۔ ابھی چند منٹ ہی گزرے تھے کہ مجھے ابوجہل دکھائی دیا جو لوگوں میں ( کفار کے لشکر میں ) گھومتا پھر رہا تھا۔ میں نے ان لڑکوں سے کہا کہ جس کے متعلق تم لوگ مجھ سے پوچھ رہے تھے، وہ سامنے ( پھرتا ہوا نظر آ رہا ) ہے۔ دونوں نے اپنی تلواریں سنبھالیں اور اس پر جھپٹ پڑے اور حملہ کر کے اسے قتل کر ڈالا۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو کر آپ کو خبر دی، نبی کریم صلی اللہ علیہ وسلم نے پوچھا کہ تم دونوں میں سے کس نے اسے مارا ہے؟ دونوں نوجوانوں نے کہا کہ میں نے قتل کیا ہے۔ اس لیے آپ نے ان سے پوچھا کہ کیا اپنی تلواریں تم نے صاف کر لی ہیں؟ انہوں نے عرض کیا کہ نہیں۔ پھر نبی کریم صلی اللہ علیہ وسلم نے دونوں تلواروں کو دیکھا اور فرمایا کہ تم دونوں ہی نے اسے مارا ہے۔ اور اس کا سامان معاذ بن عمرو بن جموح کو ملے گا۔ وہ دونوں نوجوان معاذ بن عفراء اور معاذ بن عمرو بن جموع تھے۔ محمد نے کہا یوسف نے صالح سے سنا اور ابراہیم نے اپنے باپ سے سنا۔' WHERE id = 3013;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، کہا کہ مجھے میرے والد نے خبر دی، ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے زبیر رضی اللہ عنہ کو جو زمین عنایت فرمائی تھی، میں اس میں سے گٹھلیاں ( سوکھی کھجوریں ) اپنے سر پر لایا کرتی تھی۔ وہ جگہ میرے گھر سے دو میل فرسخ کی دو تہائی پر تھی۔ ابوضمرہ نے ہشام سے بیان کیا اور انہوں نے اپنے باپ سے ( مرسلاً ) بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے زبیر رضی اللہ عنہ کو بنی نضیر کی اراضی میں سے ایک زمین قطعہ کے طور پر دی تھی۔' WHERE id = 3023;
UPDATE hadiths SET urdu = 'ہم سے قیس بن حفص نے بیان کیا، انہوں نے کہا ہم سے عبدالواحد نے بیان کیا، انہوں نے کہا ہم سے حسن بن عمرو نے بیان کیا، انہوں نے کہا کہ ہم سے مجاہد نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے کسی ذمی کو ( ناحق ) قتل کیا وہ جنت کی خوشبو بھی نہ پا سکے گا۔ حالانکہ جنت کی خوشبو چالیس سال کی راہ سے سونگھی جا سکتی ہے۔“' WHERE id = 3035;
UPDATE hadiths SET urdu = 'مجھ سے حمیدی نے بیان کیا، کہا ہم سے ولید بن مسلم نے بیان کیا، کہا ہم سے عبداللہ بن علاء بن زبیر نے بیان کیا، انہوں نے بیان کیا کہ میں نے بسر بن عبیداللہ سے سنا، انہوں نے ابوادریس سے سنا، کہا کہ میں نے عوف بن مالک رضی اللہ عنہ سے سنا، آپ نے بیان کیا کہ میں غزوہ تبوک کے موقع پر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا، آپ اس وقت چمڑے کے ایک خیمے میں تشریف فرما تھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا، کہ قیامت کی چھ نشانیاں شمار کر لو، میری موت، پھر بیت المقدس کی فتح، پھر ایک وبا جو تم میں شدت سے پھیلے گی جیسے بکریوں میں طاعون پھیل جاتا ہے۔ پھر مال کی کثرت اس درجہ میں ہو گی کہ ایک شخص سو دینار بھی اگر کسی کو دے گا تو اس پر بھی وہ ناراض ہو گا۔ پھر فتنہ اتنا تباہ کن عام ہو گا کہ عرب کا کوئی گھر باقی نہ رہے گا جو اس کی لپیٹ میں نہ آ گیا ہو گا۔ پھر صلح جو تمہارے اور بنی الاصفر ( نصارائے روم ) کے درمیان ہو گی، لیکن وہ دغا کریں گے اور ایک عظیم لشکر کے ساتھ تم پر چڑھائی کریں گے۔ اس میں اسی جھنڈے ہوں گے اور ہر جھنڈے کے ماتحت بارہ ہزار فوج ہو گی ( یعنی نو لاکھ ساٹھ ہزار فوج سے وہ تم پر حملہ آور ہوں گے ) ۔' WHERE id = 3045;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد نے بیان کیا، ان سے ایوب نے، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا ”ہر دغا باز کے لیے قیامت کے دن ایک جھنڈا ہو گا جو اس کی دغا بازی کی علامت کے طور پر ( اس کے پیچھے ) گاڑ دیا جائے گا۔“' WHERE id = 3056;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے سعید بن زید بن عمرو بن نفیل رضی اللہ عنہ نے کہ ارویٰ بنت ابی اوس سے ان کا ایک ( زمین کے ) بارے میں جھگڑا ہوا۔ جس کے متعلق ارویٰ کہتی تھی کہ سعید نے میری زمین چھین لی۔ یہ مقدمہ مروان خلیفہ کے یہاں فیصلہ کے لیے گیا جو مدینہ کا حاکم تھا۔ سعید رضی اللہ عنہ نے کہا بھلا کیا میں ان کا حق دبا لوں گا، میں گواہی دیتا ہوں کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو یہ فرماتے سنا ہے کہ جس نے ایک بالشت زمین بھی ظلم سے کسی کی دبا لی تو قیامت کے دن ساتوں زمینوں کا طوق اس کی گردن میں ڈالا جائے گا۔ ابن ابی الزناد نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے بیان کیا، اور ان سے سعید بن زید رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں موجود تھے ( تب آپ صلی اللہ علیہ وسلم نے یہ حدیث بیان فرمائی تھی ) ۔' WHERE id = 3066;
UPDATE hadiths SET urdu = 'ہم سے حسن بن ربیع نے بیان کیا، کہا ہم سے ابوالاحوص نے، ان سے اعمش نے، ان سے زید بن وہب نے اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ ہم سے صادق المصدوق رسول اللہ صلی اللہ علیہ وسلم نے بیان فرمایا اور فرمایا کہ تمہاری پیدائش کی تیاری تمہاری ماں کے پیٹ میں چالیس دنوں تک ( نطفہ کی صورت ) میں کی جاتی ہے اتنی ہی دنوں تک پھر ایک بستہ خون کے صورت میں اختیار کئے رہتا ہے اور پھر وہ اتنے ہی دنوں تک ایک مضغہ گوشت رہتا ہے۔ اس کے بعد اللہ تعالیٰ ایک فرشتہ بھیجتا ہے اور اسے چار باتوں ( کے لکھنے ) کا حکم دیتا ہے۔ اس سے کہا جاتا ہے کہ اس کے عمل، اس کا رزق، اس کی مدت زندگی اور یہ کہ بد ہے یا نیک، لکھ لے۔ اب اس نطفہ میں روح ڈالی جاتی ہے ( یاد رکھ ) ایک شخص ( زندگی بھر نیک ) عمل کرتا رہتا ہے اور جب جنت اور اس کے درمیان صرف ایک ہاتھ کا فاصلہ رہ جاتا ہے تو اس کی تقدیر سامنے آ جاتی ہے اور دوزخ والوں کے عمل شروع کر دیتا ہے۔ اسی طرح ایک شخص ( زندگی بھر برے ) کام کرتا رہتا ہے اور جب دوزخ اور اس کے درمیان صرف ایک ہاتھ کا فاصلہ رہ جاتا ہے تو اس کی تقدیر غالب آ جاتی ہے اور جنت والوں کے کام شروع کر دیتا ہے۔' WHERE id = 3076;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے عمر بن ذر نے بیان کیا (دوسری سند) امام بخاری رحمہ اللہ نے کہا کہ مجھ سے یحییٰ بن جعفر نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، ان سے عمر بن ذر نے، ان سے ان کے والد نے، ان سے سعید بن جبیر نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے جبرائیل علیہ السلام سے ایک مرتبہ فرمایا ”ہم سے ملاقات کے لیے جتنی مرتبہ آپ آتے ہیں اس سے زیادہ کیوں نہیں آتے؟“ بیان کیا کہ اس پر یہ آیت نازل ہوئی «وما نتنزل إلا بأمر ربك له ما بين أيدينا وما خلفنا‏» ”اور ہم نہیں اترتے لیکن تیرے رب کے حکم سے، اسی کا ہے جو کچھ کہ ہمارے سامنے ہے اور جو کچھ ہمارے پیچھے ہے۔“ آخر آیت تک۔' WHERE id = 3086;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ادریس نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے سمی نے بیان کیا، ان سے ابوصالح نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب ( نماز میں ) امام کہے کہ «سمع الله لمن حمده» تو تم کہا کرو «اللهم ربنا لك الحمد» کیونکہ جس کا ذکر ملائکہ کے ساتھ موافق ہو جاتا ہے اس کے پچھلے گناہ معاف ہو جاتے ہیں۔“' WHERE id = 3096;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو لیث نے خبر دی، کہا کہ مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا کہ میں نے ابوسلمہ سے سنا، انہوں نے بیان کیا کہ مجھے جابر بن عبداللہ رضی اللہ عنہما نے خبر دی اور انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ نے فرمایا تھا کہ ( پہلے غار حراء میں جو جبرائیل علیہ السلام مجھ کو سورۃ اقراء پڑھا کر گئے تھے اس کے بعد ) مجھ پر وحی کا نزول ( تین سال ) بند رہا۔ ایک بار میں کہیں جا رہا تھا کہ میں نے آسمان میں سے ایک آواز سنی اور نظر آسمان کی طرف اٹھائی، میں نے دیکھا کہ وہی فرشتہ جو غار حرا میں میرے پاس آیا تھا ( یعنی جبرائیل علیہ السلام ) آسمان اور زمین کے درمیان ایک کرسی پر بیٹھا ہوا ہے۔ میں انہیں دیکھ کر اتنا ڈر گیا کہ زمین پر گر پڑا۔ پھر میں اپنے گھر آیا اور کہنے لگا کہ مجھے کچھ اوڑھا دو، مجھے کچھ اوڑھا دو۔ اس کے بعد اللہ تعالیٰ نے یہ آیت نازل فرمائی۔ «يا أيها المدثر‏» اللہ تعالیٰ کے ارشاد «فاهجر‏» تک۔ ابوسلمہ نے کہا کہ آیت میں «الرجز» سے بت مراد ہیں۔' WHERE id = 3106;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد جعفی نے بیان کیا، کہا ہم سے یونس بن محمد نے بیان کیا، ان سے شیبان نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں سندس ( ایک خاص قسم کا ریشم ) کا ایک جبہ تحفہ میں پیش کیا گیا۔ آپ صلی اللہ علیہ وسلم ( مردوں کے لیے ) ریشم کے استعمال سے پہلے ہی منع فرما چکے تھے۔ لوگوں نے اس جبے کو بہت ہی پسند کیا، تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ جنت میں سعد بن معاذ کے رومال اس سے بہتر ہوں گے۔' WHERE id = 3116;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا کہ ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہوں نے کہا کہ مجھ سے ابوسلمہ بن عبدالرحمٰن نے بیان کیا اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، آپ بیان کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جہنم نے اپنے رب کے حضور میں شکایت کی اور کہا کہ میرے رب! میرے ہی بعض حصے نے بعض کو کھا لیا ہے۔ اللہ تعالیٰ نے اسے دو سانسوں کی اجازت دی، ایک سانس جاڑے میں اور ایک گرمی میں۔ تم انتہائی گرمی اور انتہائی سردی جو ان موسموں میں دیکھتے ہو، اس کا یہی سبب ہے۔“' WHERE id = 3127;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے منصور نے، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ میں حاضر خدمت تھا تو نبی کریم صلی اللہ علیہ وسلم کے سامنے ایک ایسے شخص کا ذکر آیا، جو رات بھر دن چڑھے تک پڑا سوتا رہا ہو، آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ ایسا شخص ہے جس کے کان یا دونوں کانوں میں شیطان نے پیشاب کر دیا ہے۔' WHERE id = 3137;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، ان سے ابوحمزہ نے، ان سے اعمش نے، ان سے عدی بن ثابت نے اور ان سے سلیمان بن صرد رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بیٹھا ہوا تھا اور ( قریب ہی ) دو آدمی آپس میں گالی گلوچ کر رہے تھے کہ ایک شخص کا منہ سرخ ہو گیا اور گردن کی رگیں پھول گئیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ مجھے ایک ایسا کلمہ معلوم ہے کہ اگر یہ شخص اسے پڑھ لے تو اس کا غصہ جاتا رہے گا۔ فرمایا «أعوذ بالله من الشيطان‏.‏» ”میں پناہ مانگتا ہوں اللہ کی شیطان سے۔“ تو اس کا غصہ جاتا رہے گا۔ لوگوں نے اس پر اس سے کہا کہ نبی کریم صلی اللہ علیہ وسلم فرما رہے ہیں کہ تمہیں شیطان سے اللہ کی پناہ مانگنی چاہئے، اس نے کہا، کیا میں کوئی دیوانہ ہوں۔' WHERE id = 3148;
UPDATE hadiths SET urdu = '(دوسری سند) ہم سے ابوالمغیرہ نے بیان کیا، کہا ہم سے اوزاعی نے بیان کیا، کہا کہ مجھ سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے عبداللہ بن ابی قتادہ نے، ان سے ان کے والد نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے (مثل روایت سابقہ کی حدیث بیان کی) مجھ سے سلیمان بن عبدالرحمٰن نے بیان کیا، کہا ہم سے ولید نے بیان کیا، کہا ہم سے اوزاعی نے بیان کیا، کہا کہ مجھ سے یحییٰ بن ابی کثیر نے بیان کیا، کہا کہ مجھ سے عبداللہ بن ابی قتادہ نے بیان کیا اور ان سے ان کے والد نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اچھا خواب اللہ تعالیٰ کی طرف سے ہے اور برا خواب شیطان کی طرف سے ہے۔ اس لیے اگر کوئی برا اور ڈراونا خواب دیکھے تو بائیں طرف تھوتھو کر کے شیطان کے شر سے اللہ کی پناہ مانگے۔ اس عمل سے شیطان اسے کوئی نقصان نہ پہنچا سکے گا۔“' WHERE id = 3158;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن راہویہ نے بیان کیا، کہا ہم کو روح بن عبادہ نے خبر دی، کہا ہم کو ابن جریج نے خبر دی، کہا کہ مجھے عطا بن ابی رباح نے خبر دی اور انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب رات کا اندھیرا شروع ہو یا ( آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ ) جب شام ہو جائے تو اپنے بچوں کو اپنے پاس روک لیا کرو، کیونکہ شیاطین اسی وقت پھیلتے ہیں۔ البتہ جب ایک گھڑی رات گزر جائے تو انہیں چھوڑ دو، اور اللہ کا نام لے کر دروازے بند کر لو، کیوں کے شیطان کسی بند دروازے کو نہیں کھول سکتا، ابن جریج نے بیان کیا کہ مجھے عمرو بن دینار نے خبر دی کہ انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے بالکل اسی طرح حدیث سنی تھی جس طرح مجھے عطاء نے خبر دی تھی، البتہ انہوں نے اس کا ذکر نہیں کیا کہ ”اللہ کا نام لو۔“' WHERE id = 3169;
UPDATE hadiths SET urdu = 'ہم سے نصر بن علی نے بیان کیا، انہوں نے کہا ہم کو عبدالاعلیٰ نے خبر دی، انہوں نے کہا ہم سے عبیداللہ بن عمر نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے بیان کیا ”ایک عورت ایک بلی کے سبب سے دوزخ میں گئی، اس نے بلی کو باندھ کر رکھا نہ تو اسے کھانا دیا اور نہ ہی چھوڑا کہ وہ کیڑے مکوڑے کھا کر اپنی جان بچا لیتی۔“ عبدالاعلیٰ نے کہا اور ہم سے عبیداللہ نے بیان کیا، ان سے سعید مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے اسی طرح روایت کیا۔' WHERE id = 3181;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے باپ نے، ان سے زینب بنت ابی سلمہ نے، ان سے (ام المؤمنین) ام سلمہ رضی اللہ عنہما نے کہ ام سلیم رضی اللہ عنہا نے عرض کیا، یا رسول اللہ! اللہ تعالیٰ حق بات سے نہیں شرماتا، تو کیا اگر عورت کو احتلام ہو تو اس پر بھی غسل ہو گا؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”ہاں بشرطیکہ وہ تری دیکھ لے۔“ ام المؤمنین ام سلمہ رضی اللہ عنہا کو اس بات پر ہنسی آ گئی اور فرمانے لگیں، کیا عورت کو بھی احتلام ہوتا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا ” ( اگر ایسا نہیں ہے ) تو پھر بچے میں ( ماں کی ) مشابہت کہاں سے آتی ہے۔“' WHERE id = 3191;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، ہم سے شیبان نے بیان کیا، ان سے یحییٰ نے، ان سے ابوسلمہ نے اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، آپ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کیوں نہ میں تمہیں دجال کے متعلق ایک ایسی بات بتا دوں جو کسی نبی نے اپنی قوم کو اب تک نہیں بتائی۔ وہ کانا ہو گا اور جنت اور جہنم جیسی چیز لائے گا۔ پس جسے وہ جنت کہے گا درحقیقت وہی دوزخ ہو گی اور میں تمہیں اس کے فتنے سے اسی طرح ڈراتا ہوں، جیسے نوح علیہ السلام نے اپنی قوم کو ڈرایا تھا۔“' WHERE id = 3201;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن نصر نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے اعمش نے، ان سے ابوصالح نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ ( قیامت کے دن ) فرمائے گا، اے آدم! آدم علیہ السلام عرض کریں گے میں اطاعت کے لیے حاضر ہوں، مستعد ہوں، ساری بھلائیاں صرف تیرے ہی ہاتھ میں ہیں۔ اللہ تعالیٰ فرمائے گا، جہنم میں جانے والوں کو ( لوگوں میں سے الگ ) نکال لو۔ آدم علیہ السلام عرض کریں گے۔ اے اللہ! جہنمیوں کی تعداد کتنی ہے؟ اللہ تعالیٰ فرمائے گا کہ ہر ایک ہزار میں سے نو سو ننانوے۔ اس وقت ( کی ہولناکی اور وحشت سے ) بچے بوڑھے ہو جائیں گے اور ہر حاملہ عورت اپنا حمل گرا دے گی۔ اس وقت تم ( خوف و دہشت سے ) لوگوں کو مدہوشی کے عالم میں دیکھو گے، حالانکہ وہ بیہوش نہ ہوں گے۔ لیکن اللہ کا عذاب بڑا ہی سخت ہو گا۔ صحابہ نے عرض کیا: یا رسول اللہ! وہ ایک شخص ہم میں سے کون ہو گا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہیں بشارت ہو، وہ ایک آدمی تم میں سے ہو گا اور ایک ہزار دوزخی یاجوج ماجوج کی قوم سے ہوں گے۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا اس ذات کی قسم جس کے ہاتھ میں میری جان ہے، مجھے امید ہے کہ تم ( امت مسلمہ ) تمام جنت والوں کے ایک تہائی ہو گے۔ پھر ہم نے اللہ اکبر کہا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ مجھے امید ہے کہ تم تمام جنت والوں کے آدھے ہو گے پھر ہم نے اللہ اکبر کہا، پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ( محشر میں ) تم لوگ تمام انسانوں کے مقابلے میں اتنے ہو گے جتنے کسی سفید بیل کے جسم پر ایک سیاہ بال، یا جتنے کسی سیاہ بیل کے جسم پر ایک سفید بال ہوتا ہے۔' WHERE id = 3211;
UPDATE hadiths SET urdu = 'ہم سے محمد بن محبوب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب نے، ان سے محمد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ابراہیم علیہ السلام نے تین مرتبہ جھوٹ بولا تھا، دو ان میں سے خالص اللہ عزوجل کی رضا کے لیے تھے۔ ایک تو ان کا فرمانا ( بطور توریہ کے ) کہ ”میں بیمار ہوں“ اور دوسرا ان کا یہ فرمانا کہ ”بلکہ یہ کام تو ان کے بڑے ( بت ) نے کیا ہے۔“ اور بیان کیا کہ ایک مرتبہ ابراہیم علیہ السلام اور سارہ علیہا السلام ایک ظالم بادشاہ کی حدود سلطنت سے گزر رہے تھے۔ بادشاہ کو خبر ملی کہ یہاں ایک شخص آیا ہوا ہے اور اس کے ساتھ دنیا کی ایک خوبصورت ترین عورت ہے۔ بادشاہ نے ابراہیم علیہ السلام کے پاس اپنا آدمی بھیج کر انہیں بلوایا اور سارہ علیہا السلام کے متعلق پوچھا کہ یہ کون ہیں؟ ابراہیم علیہ السلام نے فرمایا کہ یہ میری بہن ہیں۔ پھر آپ سارہ علیہا السلام کے پاس آئے اور فرمایا کہ اے سارہ! یہاں میرے اور تمہارے سوا اور کوئی بھی مومن نہیں ہے اور اس بادشاہ نے مجھ سے پوچھا تو میں نے اس سے کہہ دیا کہ تم میری ( دینی اعتبار سے ) بہن ہو۔ اس لیے اب تم کوئی ایسی بات نہ کہنا جس سے میں جھوٹا بنوں۔ پھر اس ظالم نے سارہ کو بلوایا اور جب وہ اس کے پاس گئیں تو اس نے ان کی طرف ہاتھ بڑھانا چاہا لیکن فوراً ہی پکڑ لیا گیا۔ پھر وہ کہنے لگا کہ میرے لیے اللہ سے دعا کرو ( کہ اس مصیبت سے نجات دے ) میں اب تمہیں کوئی نقصان نہیں پہنچاؤں گا۔ چنانچہ انہوں نے اللہ سے دعا کی اور وہ چھوڑ دیا گیا۔ لیکن پھر دوسری مرتبہ اس نے ہاتھ بڑھایا اور اس مرتبہ بھی اسی طرح پکڑ لیا گیا، بلکہ اس سے بھی زیادہ سخت اور پھر کہنے لگا کہ اللہ سے میرے لیے دعا کرو، میں اب تمہیں کوئی نقصان نہیں پہنچاؤں گا۔ سارہ علیہا السلام نے دعا کی اور وہ چھوڑ دیا گیا۔ اس کے بعد اس نے اپنے کسی خدمت گار کو بلا کر کہا کہ تم لوگ میرے پاس کسی انسان کو نہیں لائے ہو، یہ تو کوئی سرکش جن ہے ( جاتے ہوئے ) سارہ علیہ السلام کے لیے اس نے ہاجرہ علیہا السلام کو خدمت کے لیے دیا۔ جب سارہ آئیں تو ابراہیم علیہ السلام کھڑے نماز پڑھ رہے تھے۔ آپ نے ہاتھ کے اشارہ سے ان کا حال پوچھا۔ انہوں نے کہا کہ اللہ تعالیٰ نے کافر یا ( یہ کہا کہ ) فاجر کے فریب کو اسی کے منہ پر دے مارا اور ہاجرہ علیہا السلام کو خدمت کے لیے دیا۔ ابوہریرہ رضی اللہ عنہ نے کہا کہ اے «بني ماء السماء‏.» ( اے آسمانی پانی کی اولاد! یعنی اہل عرب ) تمہاری والدہ یہی ( ہاجرہ علیہا السلام ) ہیں۔' WHERE id = 3221;
UPDATE hadiths SET urdu = 'ہم سے قیس بن حفص اور موسیٰ بن اسماعیل نے بیان کیا ‘ انہوں نے کہا کہ ہم سے عبدالواحد بن زیاد نے بیان کیا ‘ انہوں نے کہا ہم سے ابوقرہ مسلم بن سالم ہمدانی نے بیان کیا ‘ انہوں نے کہا کہ مجھ سے عبداللہ بن عیسیٰ نے بیان کیا ‘ انہوں نے عبدالرحمٰن بن ابی لیلیٰ سے سنا ‘ انہوں نے بیان کیا کہ ایک مرتبہ کعب بن عجرہ رضی اللہ عنہ سے میری ملاقات ہوئی تو انہوں نے کہا کیوں نہ تمہیں ( حدیث کا ) ایک تحفہ پہنچا دوں جو میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا تھا۔ میں نے عرض کیا جی ہاں مجھے یہ تحفہ ضرور عنایت فرمائیے۔ انہوں نے بیان کیا کہ آپ صلی اللہ علیہ وسلم سے پوچھا تھا یا رسول اللہ! ہم آپ پر اور آپ کے اہل بیت پر کس طرح درود بھیجا کریں؟ اللہ تعالیٰ نے سلام بھیجنے کا طریقہ تو ہمیں خود ہی سکھا دیا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یوں کہا کرو «اللهم صل على محمد،‏‏‏‏ ‏‏‏‏ وعلى آل محمد،‏‏‏‏ ‏‏‏‏ كما صليت على إبراهيم وعلى آل إبراهيم،‏‏‏‏ ‏‏‏‏ إنك حميد مجيد،‏‏‏‏ ‏‏‏‏ اللهم بارك على محمد،‏‏‏‏ ‏‏‏‏ وعلى آل محمد،‏‏‏‏ ‏‏‏‏ كما باركت على إبراهيم،‏‏‏‏ ‏‏‏‏ وعلى آل إبراهيم،‏‏‏‏ ‏‏‏‏ إنك حميد مجيد‏ ‏‏.‏» ”اے اللہ! اپنی رحمت نازل فرما محمد صلی اللہ علیہ وسلم پر اور آل محمد صلی اللہ علیہ وسلم پر جیسا کہ تو نے اپنی رحمت نازل فرمائی ابراہیم پر اور آل ابراہیم علیہ السلام پر۔ بیشک تو بڑی خوبیوں والا اور بزرگی والا ہے۔ اے اللہ! برکت نازل فرما محمد پر اور آل محمد پر جیسا کہ تو نے برکت نازل فرمائی ابراہیم پر اور آل ابراہیم پر۔ بیشک تو بڑی خوبیوں والا اور بڑی عظمت والا ہے۔' WHERE id = 3232;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا ‘ کہا ہم کو عبداللہ نے خبر دی ‘ انہیں معمر نے ‘ ان سے زہری نے بیان کیا ‘ کہا مجھ کو سالم بن عبداللہ نے خبر دی اور انہیں ان کے والد (عبداللہ رضی اللہ عنہ) نے کہ نبی کریم صلی اللہ علیہ وسلم جب مقام حجر سے گزرے تو فرمایا ”ان لوگوں کی بستی میں جنہوں نے ظلم کیا تھا نہ داخل ہو ‘ لیکن اس صورت میں کہ تم روتے ہوئے ہو۔ کہیں ایسا نہ ہو کہ تم پر وہی عذاب آ جائے جو ان پر آیا تھا۔“ پھر آپ صلی اللہ علیہ وسلم نے اپنی چادر چہرہ مبارک پر ڈال لی۔ آپ صلی اللہ علیہ وسلم اس وقت کجاوے پر تشریف رکھتے تھے۔' WHERE id = 3242;
UPDATE hadiths SET urdu = 'مجھے عبدہ بن عبداللہ نے خبر دی ‘ انہوں نے کہا ہم سے عبدالصمد نے بیان کیا۔ ان سے عبدالرحمٰن نے بیان کیا ‘ ان سے ان کے والد عبداللہ بن دینار نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”شریف بن شریف بن شریف بن شریف یوسف بن یعقوب بن اسحاق بن ابراہیم علیہم السلام ہیں۔“' WHERE id = 3252;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سعید اصبہانی نے بیان کیا ‘ کہا ہم کو عبداللہ بن مبارک نے خبر دی ‘ انہیں معمر نے ‘ انہیں ہمام بن منبہ نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”خضر علیہ السلام کا یہ نام اس وجہ سے ہوا کہ وہ ایک سوکھی زمین ( جہاں سبزی کا نام بھی نہ تھا ) پر بیٹھے۔ لیکن جوں ہی وہ وہاں سے اٹھے تو وہ جگہ سرسبز ہو کر لہلہانے لگی۔“' WHERE id = 3263;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا ہم سے یحییٰ نے بیان کیا ‘ ان سے سفیان بن عیینہ نے بیان کیا ‘ کہا کہ مجھ سے اعمش نے بیان کیا (دوسری سند) ہم سے ابونعیم نے بیان کیا ‘ کہا ہم سے سفیان نے بیان کیا ‘ ان سے اعمش نے ‘ ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کوئی شخص میرے متعلق یہ نہ کہے کہ میں یونس علیہ السلام سے بہتر ہوں۔“ مسدد نے یونس بن متی علیہ السلام کے لفظ بڑھا کر روایت کیا۔' WHERE id = 3273;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، کہا ہم سے مغیرہ بن عبدالرحمٰن نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”سلیمان بن داؤد علیہما السلام نے کہا کہ آج رات میں اپنی ستر بیویوں کے پاس جاؤں گا اور ہر بیوی ایک شہسوار جنے گی جو اللہ کے راستے میں جہاد کرے گا۔ ان کے ساتھی نے کہا ان شاءاللہ، لیکن انہوں نے نہیں کہا۔ چنانچہ کسی بیوی کے یہاں بھی بچہ پیدا نہیں ہوا، صرف ایک کے یہاں ہوا اور اس کی بھی ایک جانب بیکار تھی۔“ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر سلیمان علیہ السلام ان شاءاللہ کہہ لیتے ( تو سب کے یہاں بچے پیدا ہوتے ) اور اللہ کے راستے میں جہاد کرتے۔ شعیب اور ابن ابی الزناد نے بجائے ستر کے ) نوے کہا ہے اور یہی بیان زیادہ صحیح ہے۔' WHERE id = 3284;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، کہا ہم سے ولید نے بیان کیا، ان سے اوزاعی نے بیان کیا، کہا کہ مجھ سے عمیر بن ہانی نے بیان کیا، کہا کہ مجھ سے جنادہ بن ابی امیہ نے بیان کیا اور ان سے عبادہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے گواہی دی کہ اللہ کے سوا کوئی معبود نہیں، وہ وحدہ لا شریک ہے اور یہ کہ محمد صلی اللہ علیہ وسلم اس کے بندے اور رسول ہیں اور یہ کہ عیسیٰ علیہ السلام اس کے بندے اور رسول ہیں اور اس کا کلمہ ہیں، جسے پہنچا دیا تھا اللہ نے مریم تک اور ایک روح ہیں اس کی طرف سے اور یہ کہ جنت حق ہے اور دوزخ حق ہے تو اس نے جو بھی عمل کیا ہو گا ( آخر ) اللہ تعالیٰ اسے جنت میں داخل کرے گا۔“ ولید نے بیان کیا، کہ مجھ سے ابن جابر نے بیان کیا، ان سے عمیر نے اور جنادہ نے اور اپنی روایت میں یہ زیادہ کیا ( ایسا شخص ) جنت کے آٹھ دروازوں میں سے جس سے چاہے ( داخل ہو گا ) ۔' WHERE id = 3294;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، انہوں نے کہا کہ ہم سے مغیرہ بن نعمان نے، انہیں سعید بن جبیر نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ” ( قیامت کے دن ) تم لوگ ننگے پاؤں، ننگے بدن اور بغیر ختنہ کے اٹھائے جاؤ گے۔ پھر آپ صلی اللہ علیہ وسلم نے اس آیت کی تلاوت کی ”جس طرح ہم نے انہیں پہلی مرتبہ پیدا کیا تھا اسی طرح ہم دوبارہ لوٹائیں گے، یہ ہماری جانب سے وعدہ ہے اور بیشک ہم اسے کرنے والے ہیں۔“ پھر سب سے پہلے ابراہیم علیہ السلام کو کپڑا پہنایا جائے گا۔ پھر میرے اصحاب کو دائیں ( جنت کی ) طرف لے جایا جائے گا۔ لیکن کچھ کو بائیں ( جہنم کی ) طرف لے جایا جائے گا۔ میں کہوں گا کہ یہ تو میرے اصحاب ہیں لیکن مجھے بتایا جائے گا کہ جب آپ ان سے جدا ہوئے تو اسی وقت انہوں نے ارتداد اختیار کر لیا تھا۔ میں اس وقت وہی کہوں گا جو عبد صالح عیسیٰ ابن مریم علیہما السلام نے کہا تھا کہ جب تک میں ان میں موجود تھا ان کی نگرانی کرتا رہا لیکن جب تو نے مجھے اٹھا لیا تو تو ہی ان کا نگہبان ہے اور تو ہر چیز پر نگہبان ہے۔ آیت «‏‏‏‏العزيز الحكيم‏» تک۔ محمد بن یوسف نے بیان کیا کہ ابوعبداللہ سے روایت ہے اور ان سے قبیصہ نے بیان کیا کہ یہ وہ مرتدین ہیں جنہوں نے ابوبکر رضی اللہ عنہ کے عہد خلافت میں کفر اختیار کیا تھا اور جن سے ابوبکر رضی اللہ عنہ نے جنگ کی تھی۔' WHERE id = 3305;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا کہ مجھ سے ابراہیم بن سعد نے بیان کیا، ان سے صالح نے، ان سے ابن شہاب نے بیان کیا، ان سے ابوسلمہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”یہود و نصاریٰ ( ڈاڑھی وغیرہ ) میں خضاب نہیں لگاتے، تم لوگ اس کے خلاف طریقہ اختیار کرو ( یعنی خضاب لگایا کرو ) ۔“' WHERE id = 3317;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نصر نے بیان کیا، انہوں نے کہا ہم کو عبدالرزاق نے خبر دی، انہیں معمر نے، انہیں ہمام نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ایک شخص نے دوسرے شخص سے مکان خریدا اور مکان کے خریدار کو اس مکان میں ایک گھڑا ملا جس میں سونا تھا جس سے وہ مکان اس نے خریدا تھا اس سے اس نے کہا بھائی گھڑا لے جا۔ کیونکہ میں نے تم سے گھر خریدا ہے سونا نہیں خریدا تھا۔ لیکن پہلے مالک نے کہا کہ میں نے گھر کو ان تمام چیزوں سمیت تمہیں بیچ دیا تھا جو اس کے اندر موجود ہوں۔ یہ دونوں ایک تیسرے شخص کے پاس اپنا مقدمہ لے گئے۔ فیصلہ کرنے والے نے ان سے پوچھا کیا تمہارے کوئی اولاد ہے؟ اس پر ایک نے کہا کہ میرے ایک لڑکا ہے اور دوسرے نے کہا کہ میری ایک لڑکی ہے۔ فیصلہ کرنے والے نے ان سے کہا کہ لڑکے کا لڑکی سے نکاح کر دو اور سونا انہیں پر خرچ کر دو اور خیرات بھی کر دو۔“' WHERE id = 3327;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد بن اسماء نے بیان کیا کہا ہم سے جویریہ بن اسماء نے بیان کیا، ان سے نافع نے ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ” ( بنی اسرائیل کی ) ایک عورت کو ایک بلی کی وجہ سے عذاب دیا گیا تھا جسے اس نے قید کر رکھا تھا جس سے وہ بلی مر گئی تھی اور اس کی سزا میں وہ عورت دوزخ میں گئی۔ جب وہ عورت بلی کو باندھے ہوئے تھی تو اس نے اسے کھانے کے لیے کوئی چیز نہ دی، نہ پینے کے لیے اور نہ اس نے بلی کو چھوڑا ہی کہ وہ زمین کے کیڑے مکوڑے ہی کھا لیتی۔“' WHERE id = 3337;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے شعبہ نے، ان سے عبدالملک نے بیان کیا، ان سے طاؤس نے کہ ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا «إلا المودة في القربى‏» کے متعلق ( طاؤس نے ) بیان کیا کہ قریش کی کوئی شاخ ایسی نہیں تھی جس میں نبی کریم صلی اللہ علیہ وسلم کی قرابت نہ رہی ہو اور اسی وجہ سے یہ آیت نازل ہوئی تھی کہ میرا مطالبہ صرف یہ ہے کہ تم لوگ میری اور اپنی قرابت داری کا لحاظ کرو۔' WHERE id = 3349;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے یزید بن ابی عبید نے اور ان سے سلمہ بن اکوع رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم قبیلہ اسلم کے صحابہ کی طرف سے گزرے جو بازار میں تیر اندازی کر رہے تھے تو آپ صلی اللہ علیہ وسلم نے فرمایا: اے اولاد اسماعیل! خوب تیر اندازی کرو کہ تمہارے باپ اسماعیل علیہ السلام بھی تیرانداز تھے اور آپ صلی اللہ علیہ وسلم نے فرمایا میں فلاں جماعت کے ساتھ ہوں، یہ سن کر دوسری جماعت والوں نے ہاتھ روک لیے تو آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا بات ہوئی؟ انہوں نے عرض کیا کہ جب آپ دوسرے فریق کے ساتھ ہو گئے تو پھر ہم کیسے تیر اندازی کریں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم تیر اندازی جاری رکھو۔ میں تم سب کے ساتھ ہوں۔' WHERE id = 3359;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، کہا کہ مجھ سے سلیمان بن بلال نے بیان کیا، ان سے ثور بن زید نے، ان سے ابولغیث نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیامت اس وقت تک قائم نہیں ہو گی جب تک کہ قبیلہ قحطان میں ایک ایسا شخص پیدا نہیں ہو گا جو لوگوں پر اپنی لاٹھی کے زور سے حکومت کرے گا۔“' WHERE id = 3369;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، کہا ہم کو ابوالزناد نے خبر دی، انہیں اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اے عبدمناف کے بیٹو! اپنی جانوں کو اللہ سے خرید لو ( یعنی نیک کام کر کے انہیں اللہ تعالیٰ کے عذاب سے بچا لو ) ۔ اے عبدالمطلب کے بیٹو! اپنی جانوں کو اللہ تعالیٰ سے خرید لو۔ اے زبیر بن عوام کی والدہ! رسول اللہ کی پھوپھی، اے فاطمہ بنت محمد! تم دونوں اپنی جانوں کو اللہ سے بچا لو۔ میں تمہارے لیے اللہ کی بارگاہ میں کچھ اختیار نہیں رکھتا۔ تم دونوں میرے مال میں جتنا چاہو مانگ سکتی ہو۔“' WHERE id = 3379;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو شعبہ نے خبر دی، انہیں منصور نے، انہیں سالم بن ابی الجعد نے اور انہیں جابر رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میرے نام پر نام رکھا کرو لیکن میری کنیت نہ رکھا کرو۔“' WHERE id = 3389;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو مالک بن انس نے خبر دی، انہیں ربیعہ بن ابی عبدالرحمٰن نے اور انہوں نے انس بن مالک رضی اللہ عنہ سے سنا، آپ نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نہ بہت لمبے تھے اور نہ چھوٹے قد کے، نہ بالکل سفید تھے اور نہ گندمی رنگ کے۔ نہ آپ صلی اللہ علیہ وسلم کے بال بہت زیادہ گھونگھریالے تھے اور نہ بالکل سیدھے لٹکے ہوئے، اللہ تعالیٰ نے آپ کو چالیس سال کی عمر میں نبوت دی اور آپ صلی اللہ علیہ وسلم نے مکہ میں دس سال تک قیام کیا اور مدینہ میں دس سال تک قیام کیا۔ جب اللہ تعالیٰ نے آپ صلی اللہ علیہ وسلم کو وفات دی تو آپ کے سر اور داڑھی کے بیس بال بھی سفید نہیں تھے۔' WHERE id = 3399;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے بیان کیا، کہا مجھ کو عبیداللہ بن عبداللہ نے خبر دی اور انہیں عبداللہ بن عباس رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم ( سر کے آگے کے بالوں کو پیشانی پر ) پڑا رہنے دیتے تھے اور مشرکین کی یہ عادت تھی کہ وہ آگے کے سر کے بال دو حصوں میں تقسیم کر لیتے تھے ( پیشانی پر پڑا نہیں رہنے دیتے تھے ) اور اہل کتاب ( یہود و نصاریٰ ) سر کے آگے کے بال پیشانی پر پڑا رہنے دیتے تھے۔ نبی کریم صلی اللہ علیہ وسلم ان معاملات میں جن کے متعلق اللہ تعالیٰ کا کوئی حکم آپ کو نہ ملا ہوتا۔ اہل کتاب کی موافقت پسند فرماتے ( اور حکم نازل ہونے کے بعد وحی پر عمل کرتے تھے ) پھر نبی کریم صلی اللہ علیہ وسلم بھی سر میں مانگ نکالنے لگے۔' WHERE id = 3409;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے میرے بھائی (عبدالحمید) نے بیان کیا، ان سے سلیمان بن بلال نے، ان سے شریک بن عبداللہ بن ابی نمر نے، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا وہ مسجد الحرام سے نبی کریم صلی اللہ علیہ وسلم کی معراج کا واقعہ بیان کر رہے تھے کہ ( معراج سے پہلے ) تین فرشتے آئے۔ یہ آپ صلی اللہ علیہ وسلم پر وحی نازل ہونے سے بھی پہلے کا واقعہ ہے۔ اس وقت آپ صلی اللہ علیہ وسلم مسجد الحرام میں ( دو آدمیوں حمزہ اور جعفر بن ابی طالب کے درمیان ) سو رہے تھے۔ ایک فرشتے نے پوچھا: وہ کون ہیں؟ ( جن کو لے جانے کا حکم ہے ) دوسرے نے کہا کہ وہ درمیان والے ہیں۔ وہی سب سے بہتر ہیں۔ تیسرے نے کہا کہ پھر جو سب سے بہتر ہیں انہیں ساتھ لے چلو۔ اس رات صرف اتنا ہی واقعہ ہو کر رہ گیا۔ پھر آپ نے انہیں نہیں دیکھا۔ لیکن فرشتے ایک اور رات میں آئے۔ آپ دل کی نگاہ سے دیکھتے تھے اور آپ کی آنکھیں سوتی تھیں پر دل نہیں سوتا تھا، اور تمام انبیاء کی یہی کیفیت ہوتی ہے کہ جب ان کی آنکھیں سوتی ہیں تو دل اس وقت بھی بیدار ہوتا ہے۔ غرض کہ پھر جبرائیل علیہ السلام نے آپ کو اپنے ساتھ لیا اور آسمان پر چڑھا لے گئے۔' WHERE id = 3421;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے زکریا نے بیان کیا کہا کہ مجھ سے عامر نے، کہا کہ مجھ سے جابر رضی اللہ عنہ نے بیان کیا کہ ان کے والد ( عبداللہ بن عمرو بن حرام، جنگ احد میں ) شہید ہو گئے تھے۔ اور وہ مقروض تھے۔ میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور میں نے عرض کیا کہ میرے والد اپنے اوپر قرض چھوڑ گئے۔ ادھر میرے پاس سوا اس پیداوار کے جو کھجوروں سے ہو گی اور کچھ نہیں ہے اور اس کی پیداوار سے تو برسوں میں قرض ادا نہیں ہو سکتا۔ اس لیے آپ میرے ساتھ تشریف لے چلیے تاکہ قرض خواہ آپ کو دیکھ کر زیادہ منہ نہ پھاڑیں۔ آپ صلی اللہ علیہ وسلم تشریف لائے ( لیکن وہ نہیں مانے ) تو آپ صلی اللہ علیہ وسلم کھجور کے جو ڈھیر لگے ہوئے تھے پہلے ان میں سے ایک کے چاروں طرف چلے اور دعا کی۔ اسی طرح دوسرے ڈھیر کے بھی۔ پھر آپ اس پر بیٹھ گئے اور فرمایا کہ کھجوریں نکال کر انہیں دو۔ چنانچہ سارا قرض ادا ہو گیا اور جتنی کھجوریں قرض میں دی تھیں اتنی ہی بچ گئیں۔' WHERE id = 3431;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے جریر بن حازم نے بیان کیا، کہا میں نے حسن سے سنا، انہوں نے بیان کیا کہ ہم سے عمرو بن تغلب رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا ”قیامت کے قریب تم ایک ایسی قوم سے جنگ کرو گے جو بالوں کا جوتا پہنتی ہو گی اور ایک ایسی قوم سے جنگ کرو گے جن کے منہ تہ بہ تہ ڈھالوں کی طرح ہوں گے۔' WHERE id = 3441;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن عبدالرحیم نے بیان کیا، کہا ہم سے ابومعمر اسماعیل بن ابراہیم نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابوالتیاح نے، ان سے ابوزرعہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اس قبیلہ قریش کے بعض آدمی لوگوں کو ہلاک و برباد کر دیں گے۔“ صحابہ نے عرض کیا: ایسے وقت کے لیے آپ ہمیں کیا حکم فرماتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”کاش لوگ ان سے بس الگ ہی رہتے۔“ محمود بن غیلان نے بیان کیا کہ ہم سے ابوداؤد طیالسی نے بیان کیا، کہا ہم کو شعبہ نے خبر دی، انہیں ابوالتیاح نے، انہوں نے ابوزرعہ سے سنا۔' WHERE id = 3453;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے ان سے ابواسحٰق نے اور انہوں نے براء بن عازب رضی اللہ عنہ سے سنا۔ انہوں نے بیان کیا کہ ایک صحابی ( اسید بن حضیر رضی اللہ عنہ ) نے ( نماز میں ) سورۃ الکہف کی تلاوت کی۔ اسی گھر میں گھوڑا بندھا ہوا تھا، گھوڑے نے اچھلنا کودنا شروع کر دیا۔ ( اسید نے ادھر خیال نہ کیا اس کو اللہ کے سپرد کیا ) اس کے بعد جب انہوں نے سلام پھیرا تو دیکھا کہ بادل کے ایک ٹکڑے نے ان کے سارے گھر پر سایہ کر رکھا ہے۔ اس واقعہ کا ذکر انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ قرآن پڑھتا ہی رہ کیونکہ یہ «سكينة» ہے جو قرآن کی وجہ سے نازل ہوئی یا ( اس کے بجائے راوی نے ) «تنزلت للقرآن» کے الفاظ کہے۔' WHERE id = 3463;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب نے، ان سے حمید بن ہلال نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے جعفر بن ابی طالب اور زید بن حارثہ رضی اللہ عنہما کی شہادت کی خبر پہلے ہی صحابہ کو سنا دی تھی، اس وقت آپ کی آنکھوں سے آنسو جاری تھے۔' WHERE id = 3476;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن ابوالاسود نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، کہا ان سے اسماعیل نے بیان کیا، کہا ہم سے قیس نے بیان کیا کہ میں نے مغیرہ بن شعبہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میری امت کے کچھ لوگ ہمیشہ غالب رہیں گے، یہاں تک کہ قیامت یا موت آئے گی اس وقت بھی وہ غالب ہی ہوں گے۔“' WHERE id = 3486;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن رجاء نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے ابواسحٰق نے اور ان سے براء رضی اللہ عنہ نے بیان کیا کہ ابوبکر رضی اللہ عنہ نے ( ان کے والد ) عازب رضی اللہ عنہ سے ایک پالان تیرہ درہم میں خریدا۔ پھر ابوبکر رضی اللہ عنہ نے عازب رضی اللہ عنہ سے کہا کہ براء ( اپنے بیٹے ) سے کہو کہ وہ میرے گھر یہ پالان اٹھا کر پہنچا دیں اس پر عازب رضی اللہ عنہ نے کہا یہ اس وقت تک نہیں ہو سکتا جب تک آپ وہ واقعہ بیان نہ کریں کہ آپ اور رسول اللہ صلی اللہ علیہ وسلم ( مکہ سے ہجرت کرنے کے لیے ) کس طرح نکلے تھے حالانکہ مشرکین آپ دونوں کو تلاش بھی کر رہے تھے۔ انہوں نے کہا کہ مکہ سے نکلنے کے بعد ہم رات بھر چلتے رہے اور دن میں بھی سفر جاری رکھا۔ لیکن جب دوپہر ہو گئی تو میں نے چاروں طرف نظر دوڑائی کہ کہیں کوئی سایہ نظر آ جائے اور ہم اس میں کچھ آرام کر سکیں۔ آخر ایک چٹان دکھائی دی اور میں نے اس کے پاس پہنچ کر دیکھا کہ سایہ ہے۔ پھر میں نے نبی کریم صلی اللہ علیہ وسلم کے لیے ایک فرش وہاں بچھا دیا اور عرض کیا کہ یا رسول اللہ! آپ اب آرام فرمائیں۔ چنانچہ آپ لیٹ گئے۔ پھر میں چاروں طرف دیکھتا ہوا نکلا کہ کہیں لوگ ہماری تلاش میں نہ آئے ہوں۔ پھر مجھ کو بکریوں کا ایک چرواہا دکھائی دیا جو اپنی بکریاں ہانکتا ہوا اسی چٹان کی طرف آ رہا تھا۔ وہ بھی ہماری طرح سایہ کی تلاش میں تھا۔ میں نے بڑھ کر اس سے پوچھا کہ لڑکے تم کس کے غلام ہو۔ اس نے قریش کے ایک شخص کا نام لیا تو میں نے اسے پہچان لیا۔ پھر میں نے اس سے پوچھا: کیا تمہاری بکریوں میں دودھ ہے۔ اس نے کہا جی ہاں۔ میں نے کہا: کیا تم دودھ دوہ سکتے ہوں؟ اس نے کہا کہ ہاں۔ چنانچہ میں نے اس سے کہا اور اس نے اپنے ریوڑ کی ایک بکری باندھ دی۔ پھر میرے کہنے پر اس نے اس کے تھن کے غبار کو جھاڑا۔ اب میں نے کہا کہ اپنا ہاتھ بھی جھاڑ لے۔ اس نے یوں اپنا ایک ہاتھ دوسرے پر مارا اور میرے لیے تھوڑا سا دودھ دوہا۔ آپ صلی اللہ علیہ وسلم کے لیے ایک برتن میں نے پہلے ہی سے ساتھ لے لیا تھا اور اس کے منہ کو کپڑے سے بند کر دیا تھا ( اس میں ٹھنڈا پانی تھا ) پھر میں نے دودھ پر وہ پانی ( ٹھنڈا کرنے کے لیے ) ڈالا اتنا کہ وہ نیچے تک ٹھنڈا ہو گیا تو اسے آپ کی خدمت میں لے کر حاضر ہوا۔ آپ بھی بیدار ہو چکے تھے۔ میں نے عرض کیا: دودھ پی لیجئے۔ آپ نے اتنا پیا کہ مجھے خوشی حاصل ہو گئی، پھر میں نے عرض کیا کہ اب کوچ کا وقت ہو گیا ہے یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے فرمایا ہاں ٹھیک ہے، چلو۔ چنانچہ ہم آگے بڑھے اور مکہ والے ہماری تلاش میں تھے لیکن سراقہ بن مالک بن جعشم کے سوا ہم کو کسی نے نہیں پایا، وہ اپنے گھوڑے پر سوار تھا، میں نے اسے دیکھتے ہی کہا کہ یا رسول اللہ! ہمارا پیچھا کرنے والا دشمن ہمارے قریب آ پہنچا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا: فکر نہ کرو۔ اللہ تعالیٰ ہمارے ساتھ ہے۔' WHERE id = 3497;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، کہا ہم سے عبدالعزیز بن مختار نے بیان کیا، کہا ہم سے خالد حذاء نے، کہا ہم سے ابوعثمان نے بیان کیا، کہا کہ مجھ سے عمرو بن العاص رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے انہیں غزوہ ذات السلاسل کے لیے بھیجا ( عمرو رضی اللہ عنہ نے بیان کیا کہ ) پھر میں آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور میں نے پوچھا کہ سب سے زیادہ محبت آپ کو کس سے ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ عائشہ سے میں نے پوچھا، اور مردوں میں؟ فرمایا کہ اس کے باپ سے۔ میں نے پوچھا، اس کے بعد؟ فرمایا کہ عمر بن خطاب سے۔ اس طرح آپ صلی اللہ علیہ وسلم نے کئی آدمیوں کے نام لیے۔' WHERE id = 3507;
UPDATE hadiths SET urdu = 'مجھ سے ابوعبداللہ احمد بن سعید نے بیان کیا، کہا ہم سے وہب بن جریر نے بیان کیا، کہا ہم سے صخر نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں ایک کنویں پر ( خواب میں ) کھڑا اس سے پانی کھینچ رہا تھا کہ میرے پاس ابوبکر اور عمر بھی پہنچ گئے۔ پھر ابوبکر نے ڈول لے لیا اور ایک یا دو ڈول کھینچے، ان کے کھینچنے میں ضعف تھا اور اللہ تعالیٰ ان کی مغفرت کرے گا۔ پھر ابوبکر کے ہاتھ سے ڈول عمر نے لے لیا اور ان کے ہاتھ میں پہنچتے ہی وہ ایک بہت بڑے ڈول کی شکل میں ہو گیا۔ میں نے کوئی ہمت والا اور بہادر انسان نہیں دیکھا جو اتنی حسن تدبیر اور مضبوط قوت کے ساتھ کام کرنے کا عادی ہو، چنانچہ انہوں نے اتنا پانی کھینچا کہ لوگوں نے اونٹوں کے پانی پلانے کی جگہیں بھر لیں، وہب نے بیان کیا کہ «العطن» اونٹوں کے بیٹھنے کی جگہ کو کہتے ہیں، عرب لوگ بولتے ہیں، اونٹ سیراب ہوئے کہ ( وہیں ) بیٹھ گئے۔' WHERE id = 3519;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے سعید نے بیان کیا، (دوسری سند) امام بخاری رحمہ اللہ فرماتے ہیں اور مجھ سے خلیفہ نے بیان کیا، ان سے محمد بن سواء اور کہمس بن منہال نے بیان کیا، ان سے سعید نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم احد پہاڑ پر چڑھے تو آپ کے ساتھ ابوبکر، عمر اور عثمان رضی اللہ عنہم بھی تھے، پہاڑ لرزنے لگا تو نبی کریم صلی اللہ علیہ وسلم نے اپنے پاؤں سے اسے مارا اور فرمایا ”احد! ٹھہرا رہ کہ تجھ پر ایک نبی، ایک صدیق اور دو شہید ہی تو ہیں۔“' WHERE id = 3529;
UPDATE hadiths SET urdu = 'ہم سے احمد بن شبیب بن سعید نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا، ان سے یونس نے کہ ابن شہاب نے بیان کیا، کہا مجھ کو عروہ نے خبر دی، انہیں عبیداللہ بن عدی بن خیار نے خبر دی کہ مسور بن مخرمہ اور عبدالرحمٰن بن اسود بن عبدیغوث رضی اللہ عنہ نے ان سے کہا کہ تم عثمان رضی اللہ عنہ سے ان کے بھائی ولید کے مقدمہ میں ( جسے عثمان رضی اللہ عنہ نے کوفہ کا گورنر بنایا تھا ) کیوں گفتگو نہیں کرتے، لوگ اس سے بہت ناراض ہیں۔ چنانچہ میں عثمان رضی اللہ عنہ کے پاس گیا، اور جب وہ نماز کے لیے باہر تشریف لائے تو میں نے عرض کیا کہ مجھے آپ سے ایک ضرورت ہے اور وہ ہے آپ کے ساتھ ایک خیر خواہی! اس پر عثمان رضی اللہ عنہ نے فرمایا: بھلے آدمی تم سے ( میں اللہ کی پناہ چاہتا ہوں ) امام بخاری رحمہ اللہ نے کہا: میں سمجھتا ہوں کہ معمر نے یوں روایت کیا، میں تجھ سے اللہ کی پناہ چاہتا ہوں۔ میں واپس ان دونوں کے پاس گیا، اتنے میں عثمان رضی اللہ عنہ کا قاصد مجھ کو بلانے کے لیے آیا میں جب اس کے ساتھ عثمان رضی اللہ عنہ کی خدمت میں حاضر ہوا تو انہوں نے دریافت فرمایا کہ تمہاری خیر خواہی کیا تھی؟ میں نے عرض کیا: اللہ سبحانہ وتعالیٰ نے محمد صلی اللہ علیہ وسلم کو حق کے ساتھ بھیجا اور ان پر کتاب نازل کی آپ بھی ان لوگوں میں شامل تھے جنہوں نے اللہ اور اس کے رسول کی دعوت کو قبول کیا تھا۔ آپ نے دو ہجرتیں کیں۔ نبی کریم صلی اللہ علیہ وسلم کی صحبت اٹھائی اور آپ کے طریقے اور سنت کو دیکھا، لیکن بات یہ ہے کہ لوگ ولید کی بہت شکایتیں کر رہے ہیں۔ عثمان رضی اللہ عنہ نے اس پر پوچھا: تم نے رسول اللہ صلی اللہ علیہ وسلم سے کچھ سنا ہے؟ میں نے عرض کیا کہ نہیں۔ لیکن رسول اللہ صلی اللہ علیہ وسلم کی احادیث ایک کنواری لڑکی تک کو اس کے تمام پردوں کے باوجود جب پہنچ چکی ہیں تو مجھے کیوں نہ معلوم ہوتیں۔ اس پر عثمان نے فرمایا: امابعد: بیشک اللہ تعالیٰ نے محمد صلی اللہ علیہ وسلم کو حق کے ساتھ بھیجا اور میں اللہ اور اس کے رسول کی دعوت کو قبول کرنے والوں میں بھی تھا۔ نبی کریم صلی اللہ علیہ وسلم جس دعوت کو لے کر بھیجے گئے تھے میں اس پر پورے طور سے ایمان لایا اور جیسا کہ تم نے کہا دو ہجرتیں بھی کیں۔ میں نبی کریم صلی اللہ علیہ وسلم کی صحبت میں بھی رہا ہوں اور آپ سے بیعت بھی کی ہے۔ پس اللہ کی قسم میں نے کبھی آپ کے حکم سے سرتابی نہیں کی۔ اور نہ آپ کے ساتھ کبھی کوئی دھوکا کیا، یہاں تک کہ اللہ تعالیٰ نے آپ کو وفات دی۔ اس کے بعد ابوبکر رضی اللہ عنہ کے ساتھ بھی میرا یہی معاملہ رہا۔ اور عمر رضی اللہ عنہ کے ساتھ بھی یہی معاملہ رہا تو کیا جب کہ مجھے ان کا جانشیں بنا دیا گیا ہے تو مجھے وہ حقوق حاصل نہیں ہوں گے جو انہیں تھے؟ میں نے عرض کیا کہ کیوں نہیں، آپ نے فرمایا کہ پھر ان باتوں کے لیے کیا جواز رہ جاتا ہے جو تم لوگوں کی طرف سے مجھے پہنچتی رہتی ہیں لیکن تم نے جو ولید کے حالات کا ذکر کیا ہے، ان شاءاللہ ہم اس کی سزا جو واجبی ہے اس کو دیں گے۔ پھر عثمان رضی اللہ عنہ نے علی رضی اللہ عنہ کو بلایا اور ان سے فرمایا کہ ولید کو حد لگائیں۔ چنانچہ انہوں نے ولید کو اسی کوڑے حد کے لگائے۔' WHERE id = 3539;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے سعد نے، انہوں نے ابراہیم بن سعد سے سنا، ان سے ان کے والد نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے علی رضی اللہ عنہ سے فرمایا کہ کیا تم اس پر خوش نہیں ہو کہ تم میرے لیے ایسے ہو جیسے موسیٰ علیہ السلام کے لیے ہارون علیہ السلام تھے۔' WHERE id = 3549;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے عبدالعزیز نے بیان کیا جو ابوسلمہ کے صاحبزادے تھے، ان سے محمد نے بیان کیا، ان سے محمد بن منکدر نے بیان کیا، اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ہر نبی کے حواری ہوتے ہیں اور میرے حواری زبیر بن عوام ( رضی اللہ عنہ ) ہیں۔' WHERE id = 3560;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے زہری نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ایک قیافہ شناس میرے یہاں آیا۔ نبی کریم صلی اللہ علیہ وسلم اس وقت وہیں تشریف رکھتے تھے اور اسامہ بن زید اور زید بن حارثہ ( ایک چادر میں ) لیٹے ہوئے تھے۔ ( منہ اور جسم کا سارا حصہ قدموں کے سوا چھپا ہوا تھا ) اس قیافہ شناس نے کہا کہ یہ پاؤں بعض، بعض سے نکلے ہوئے معلوم ہوتے ہیں۔ ( یعنی باپ بیٹے کے ہیں ) قیافہ شناس نے پھر بتایا کہ نبی کریم صلی اللہ علیہ وسلم اس کے اس اندازہ پر بہت خوش ہوئے اور پھر آپ نے عائشہ رضی اللہ عنہا سے بھی یہ واقعہ بیان فرمایا۔' WHERE id = 3571;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحٰق نے، ان سے صلہ نے اور ان سے حذیفہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اہل نجران سے فرمایا کہ میں تمہارے یہاں ایک امین کو بھیجوں گا جو حقیقی معنوں میں امین ہو گا۔ یہ سن کر تمام صحابہ کرام رضی اللہ عنہم کو شوق ہوا لیکن آپ صلی اللہ علیہ وسلم نے ابوعبیدہ رضی اللہ عنہ کو بھیجا۔' WHERE id = 3583;
UPDATE hadiths SET urdu = 'ہم سے ابن نمیر نے بیان کیا، ان سے محمد بن عبید نے کہا، ہم سے اسماعیل نے بیان کیا، اور ان سے قیس نے کہ بلال رضی اللہ عنہ نے ابوبکر رضی اللہ عنہ سے کہا: اگر آپ نے مجھے اپنے لیے خریدا ہے تو پھر اپنے پاس ہی رکھئے اور اگر اللہ کے لیے خریدا ہے تو پھر مجھے آزاد کر دیجئیے اور اللہ کے راستے میں عمل کرنے دیجئیے۔' WHERE id = 3593;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے ابن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، ان سے ابن ابی ملیکہ نے اور ان سے مسور بن مخرمہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ فاطمہ میرے جسم کا ایک ٹکڑا ہے جس نے اسے ناراض کیا اس نے مجھے ناراض کیا۔' WHERE id = 3605;
UPDATE hadiths SET urdu = 'مجھ سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ بعاث کی جنگ کو ( جو اسلام سے پہلے اوس اور خزرج میں ہوئی تھی ) اللہ تعالیٰ نے اپنے رسول صلی اللہ علیہ وسلم کے مفاد میں پہلے ہی مقدم کر رکھا تھا چنانچہ جب آپ مدینہ میں تشریف لائے تو یہ قبائل آپس کی پھوٹ کا شکار تھے اور ان کے سردار کچھ قتل کئے جا چکے تھے، کچھ زخمی تھے، تو اللہ تعالیٰ نے اس جنگ کو آپ سے پہلے اس لیے مقدم کیا تھا تاکہ وہ آپ کے تشریف لاتے ہی مسلمان ہو جائیں۔' WHERE id = 3615;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عمرو بن مرہ نے، انہوں نے ابوحمزہ سے سنا اور انہوں نے زید بن ارقم رضی اللہ عنہ سے کہ انصار نے عرض کیا: یا رسول اللہ! ہر نبی کے تابعدار لوگ ہوتے ہیں اور ہم نے آپ کی تابعداری کی ہے۔ آپ اللہ سے دعا فرمائیں کہ اللہ ہمارے تابعداروں کو بھی ہم میں شریک کر دے۔ تو آپ صلی اللہ علیہ وسلم نے اس کی دعا فرمائی۔ پھر میں نے اس حدیث کا ذکر عبدالرحمٰن بن ابی لیلیٰ کے سامنے کیا تو انہوں نے کہا کہ زید بن ارقم رضی اللہ عنہ نے بھی یہ حدیث بیان کی تھی۔' WHERE id = 3625;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن عبیداللہ نے بیان کیا، کہا ہم سے ابن حازم نے بیان کیا، ان سے ان کے والد نے اور ان سے سہل رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ہمارے پاس تشریف لائے تو ہم خندق کھود رہے تھے اور اپنے کندھوں پر مٹی اٹھا رہے تھے۔ اس وقت آپ نے یہ دعا فرمائی «اللهم لا عيش إلا عيش الآخره فاغفر للمهاجرين والأنصار‏ ‏‏.» ”اے اللہ! آخرت کی زندگی کے سوا اور کوئی زندگی حقیقی زندگی نہیں، پس انصار اور مہاجرین کی تو مغفرت فرما۔“' WHERE id = 3635;
UPDATE hadiths SET urdu = 'ہم سے اسحٰق نے بیان کیا، انہوں نے کہا ہم سے عبدالصمد نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا کہ ہم سے قتادہ نے بیان کیا، انہوں نے کہا میں نے انس بن مالک رضی اللہ عنہ سے سنا کہ ابواسید رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”انصار کا بہترین گھرانہ بنو نجار کا گھرانہ ہے، پھر بنو عبدالاشھل کا، پھر بنو عبدالحارث کا، پھر بنو ساعدہ کا اور خیر انصار کے تمام گھرانوں میں ہے۔ سعد بن عبادہ رضی اللہ عنہ نے کہا اور وہ اسلام قبول کرنے میں بڑی قدامت رکھتے تھے کہ میرا خیال ہے، نبی کریم صلی اللہ علیہ وسلم نے ہم پر دوسروں کو فضیلت دے دی ہے، ان سے کہا گیا کہ نبی کریم صلی اللہ علیہ وسلم نے تم کو بھی تو بہت سے لوگوں پر فضیلت دی ہے ( اعتراض کی کیا بات ہے ) ۔' WHERE id = 3645;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے حمید بن عبدالرحمٰن نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ خدیجہ رضی اللہ عنہا کے معاملہ میں، میں جتنی غیرت محسوس کرتی تھی اتنی کسی عورت کے معاملے میں نہیں کیونکہ رسول اللہ صلی اللہ علیہ وسلم ان کا ذکر اکثر کیا کرتے تھے۔ انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے میرا نکاح ان کی وفات کے تین سال بعد ہوا تھا اور اللہ تعالیٰ نے انہیں حکم دیا تھا یا جبرائیل علیہ السلام کے ذریعہ یہ پیغام پہنچایا تھا کہ نبی کریم صلی اللہ علیہ وسلم انہیں جنت میں موتیوں کے ایک محل کی بشارت دے دیں۔' WHERE id = 3655;
UPDATE hadiths SET urdu = 'موسیٰ نے بیان کیا، ان سے سالم بن عبداللہ نے بیان کیا اور مجھے یقین ہے کہ انہوں نے یہ ابن عمر رضی اللہ عنہما سے بیان کیا تھا کہ زید بن عمرو بن نفیل شام گئے دین ( خالص ) کی تلاش میں نکلے، وہاں وہ ایک یہودی عالم سے ملے تو انہوں نے ان کے دین کے بارے میں پوچھا اور کہا ممکن ہے کہ میں تمہارا دین اختیار کر لوں اس لیے تم مجھے اپنے دین کے متعلق بتاؤ یہودی عالم نے کہا کہ ہمارے دین میں تم اس وقت تک داخل نہیں ہو سکتے جب تک تم اللہ کے غضب کے ایک حصہ کے لیے تیار نہ ہو جاؤ، اس پر زید رضی اللہ عنہ نے کہا کہ واہ میں اللہ کے غضب ہی سے بھاگ کر آیا ہوں، پھر اللہ کے غضب کو میں اپنے اوپر کبھی نہ لوں گا اور نہ مجھ کو اسے اٹھانے کی طاقت ہے! کیا تم مجھے کسی اور دوسرے دین کا کچھ پتہ بتا سکتے ہو؟ اس عالم نے کہا میں نہیں جانتا ( کوئی دین سچا ہو تو دین حنیف ہو ) ۔ زید رضی اللہ عنہ نے پوچھا دین حنیف کیا ہے؟ اس عالم نے کہا کہ ابراہیم علیہ السلام کا دین جو نہ یہودی تھے اور نہ نصرانی اور وہ اللہ کے سوا کسی کی عبادت نہیں کرتے تھے۔ زید رضی اللہ عنہ وہاں سے چلے آئے اور ایک نصرانی پادری سے ملے، ان سے بھی اپنا خیال بیان کیا اس نے بھی یہی کہا کہ تم ہمارے دین میں آؤ گے تو اللہ تعالیٰ کی لعنت میں سے ایک حصہ لو گے۔ زید رضی اللہ عنہ نے کہا میں اللہ کی لعنت سے ہی بچنے کے لیے تو یہ سب کچھ کر رہا ہوں اللہ کی لعنت اٹھانے کی مجھ میں طاقت نہیں اور نہ میں اس کا یہ غضب کس طرح اٹھا سکتا ہوں! کیا تم میرے لیے اس کے سوا کوئی اور دین بتلا سکتے ہو؟ پادری نے کہا کہ میری نظر میں ہو تو صرف ایک دین حنیف سچا دین ہے زید نے پوچھا دین حنیف کیا ہے؟ کہا کہ وہ دین ابراہیم ہے جو نہ یہودی تھے اور نہ نصرانی اور اللہ کے سوا وہ کسی کی پوجا نہیں کرتے تھے۔ زید نے جب دین ابراہیم کے بارے میں ان کی یہ رائے سنی تو وہاں سے روانہ ہو گئے اور اس سر زمین سے باہر نکل کر اپنے دونوں ہاتھ آسمان کی طرف اٹھائے اور یہ دعا کی «اللهم إني أشهد أني على دين إبراهيم‏.‏» اے اللہ! میں گواہی دیتا ہوں کہ میں دین ابراہیم پر ہوں۔' WHERE id = 3665;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن سلیمان نے بیان کیا، کہا مجھ سے عبداللہ بن وہب نے بیان کیا کہ مجھے عمرو بن حارث نے خبر دی، ان سے عبدالرحمٰن بن قاسم نے بیان کیا کہ ان کے والد قاسم بن محمد جنازہ کے آگے آگے چلا کرتے تھے اور جنازہ کو دیکھ کر کھڑے نہیں ہوتے تھے۔ عائشہ رضی اللہ عنہا کے حوالے سے وہ بیان کرتے تھے کہ زمانہ جاہلیت میں لوگ جنازہ کے لیے کھڑے ہو جایا کرتے تھے اور اسے دیکھ کر دو بار کہتے تھے کہ اے مرنے والے جس طرح اپنی زندگی میں تو اپنے گھر والوں کے ساتھ تھا اب ویسا ہی کسی پرندے کے بھیس میں ہے۔' WHERE id = 3675;
UPDATE hadiths SET urdu = 'اور عبداللہ بن وہب نے بیان کیا، انہیں عمرو نے خبر دی، انہیں بکیر بن اشج نے اور عبداللہ بن عباس رضی اللہ عنہما کے مولا کریب نے ان سے بیان کیا کہ عبداللہ بن عباس رضی اللہ عنہما نے بتایا صفا اور مروہ کے درمیان نالے کے اندر زور سے دوڑنا سنت نہیں ہے یہاں جاہلیت کے دور میں لوگ تیزی کے ساتھ دوڑا کرتے تھے اور کہتے تھے کہ ہم تو اس پتھریلی جگہ سے دوڑ ہی کر پار ہوں گے۔' WHERE id = 3685;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن حماد آملی نے بیان کیا، کہا کہ مجھ سے یحییٰ بن معین نے بیان کیا، کہا ہم سے اسماعیل بن مجالد نے بیان کیا، ان سے بیان نے، ان سے وبرہ نے ان سے ہمام بن حارث نے بیان کیا کہ عمار بن یاسر رضی اللہ عنہما نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو اس حالت میں بھی دیکھا ہے جب نبی کریم صلی اللہ علیہ وسلم کے ساتھ پانچ غلام، دو عورتوں اور ابوبکر صدیق رضی اللہ عنہم کے سوا اور کوئی ( مسلمان ) نہیں تھا۔' WHERE id = 3695;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، کہا ہم سے اسماعیل نے بیان کیا، کہا ہم سے قیس نے، کہا کہ میں نے سعید بن زید رضی اللہ عنہ سے سنا انہوں نے مسلمانوں کو مخاطب کر کے کہا ایک وقت تھا کہ عمر رضی اللہ عنہ جب اسلام میں داخل نہیں ہوئے تھے تو مجھے اور اپنی بہن کو اس لیے باندھ رکھا تھا کہ ہم اسلام کیوں لائے اور آج تم نے جو کچھ عثمان رضی اللہ عنہ کے ساتھ برتاؤ کیا ہے اگر اس پر احد پہاڑ بھی اپنی جگہ سے سرک جائے تو اسے ایسا ہی کرنا چاہیے۔' WHERE id = 3705;
UPDATE hadiths SET urdu = 'ہم سے ابوربیع سلیمان بن داؤد نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ابن جریج نے، ان سے عطاء بن ابی رباح نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ جس دن نجاشی ( حبشہ کے بادشاہ ) کی وفات ہوئی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”آج ایک مرد صالح اس دنیا سے چلا گیا، اٹھو اور اپنے بھائی اصحمہ کی نماز جنازہ پڑھ لو۔“' WHERE id = 3715;
UPDATE hadiths SET urdu = 'ہم سے ہدبہ بن خالد نے بیان کیا، انہوں نے کہا ہم سے ہمام بن یحییٰ نے بیان کیا، ان سے قتادہ نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا اور ان سے مالک بن صعصعہ رضی اللہ عنہ نے بیان کیا، کہ نبی کریم صلی اللہ علیہ وسلم نے ان سے شب معراج کا واقعہ بیان کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں حطیم میں لیٹا ہوا تھا۔ بعض دفعہ قتادہ نے حطیم کے بجائے حجر بیان کیا کہ میرے پاس ایک صاحب ( جبرائیل علیہ السلام ) آئے اور میرا سینہ چاک کیا۔ قتادہ نے بیان کیا کہ میں نے انس رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ یہاں سے یہاں تک۔ میں نے جارود سے سنا جو میرے قریب ہی بیٹھے تھے۔ پوچھا کہ انس رضی اللہ عنہ کی اس لفظ سے کیا مراد تھی؟ تو انہوں نے کہا کہ حلق سے ناف تک چاک کیا ( قتادہ نے بیان کیا کہ ) میں نے انس سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے سینے کے اوپر سے ناف تک چاک کیا، پھر میرا دل نکالا اور ایک سونے کا طشت لایا گیا جو ایمان سے بھرا ہوا تھا، اس سے میرا دل دھویا گیا اور پہلے کی طرح رکھ دیا گیا۔ اس کے بعد ایک جانور لایا گیا جو گھوڑے سے چھوٹا اور گدھے سے بڑا تھا اور سفید! جارود نے انس رضی اللہ عنہ سے پوچھا: ابوحمزہ! کیا وہ براق تھا؟ آپ نے فرمایا کہ ہاں۔ اس کا ہر قدم اس کے منتہائے نظر پر پڑتا تھا ( نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ) مجھے اس پر سوار کیا گیا اور جبرائیل مجھے لے کر چلے آسمان دنیا پر پہنچے تو دروازہ کھلوایا، پوچھا گیا کون صاحب ہیں؟ انہوں نے بتایا کہ جبرائیل ( علیہ السلام ) پوچھا گیا اور آپ کے ساتھ کون ہے؟ آپ نے بتایا کہ محمد ( صلی اللہ علیہ وسلم ) ۔ پوچھا گیا، کیا انہیں بلانے کے لیے آپ کو بھیجا گیا تھا؟ انہوں نے جواب دیا کہ ہاں۔ اس پر آواز آئی ( انہیں ) خوش آمدید! کیا ہی مبارک آنے والے ہیں وہ، اور دروازہ کھول دیا۔ جب میں اندر گیا تو میں نے وہاں آدم علیہ السلام کو دیکھا، جبرائیل علیہ السلام نے فرمایا یہ آپ کے جد امجد آدم علیہ السلام ہیں انہیں سلام کیجئے۔ میں نے ان کو سلام کیا اور انہوں نے جواب دیا اور فرمایا: خوش آمدید نیک بیٹے اور نیک نبی! جبرائیل علیہ السلام اوپر چڑھے اور دوسرے آسمان پر آئے وہاں بھی دروازہ کھلوایا آواز آئی کون صاحب آئے ہیں؟ بتایا کہ جبرائیل ( علیہ السلام ) پوچھا گیا آپ کے ساتھ اور کوئی صاحب بھی ہیں؟ کہا محمد ( صلی اللہ علیہ وسلم ) ۔ پوچھا گیا کیا آپ کو انہیں بلانے کے لیے بھیجا گیا تھا؟ انہوں نے جواب دیا کہ ہاں۔ پھر آواز آئی انہیں خوش آمدید۔ کیا ہی اچھے آنے والے ہیں وہ۔ پھر دروازہ کھلا اور میں اندر گیا تو وہاں یحییٰ اور عیسیٰ علیہما السلام موجود تھے۔ یہ دونوں خالہ زاد بھائی ہیں۔ جبرائیل علیہ السلام نے فرمایا یہ عیسیٰ اور یحییٰ علیہما السلام ہیں انہیں سلام کیجئے میں نے سلام کیا اور ان حضرات نے میرے سلام کا جواب دیا اور فرمایا خوش آمدید نیک نبی اور نیک بھائی! یہاں سے جبرائیل علیہ السلام مجھے تیسرے آسمان کی طرف لے کر چڑھے اور دروازہ کھلوایا۔ پوچھا گیا کون صاحب آئے ہیں؟ جواب دیا کہ جبرائیل۔ پوچھا گیا اور آپ کے ساتھ کون صاحب آئے ہیں؟ جواب دیا کہ محمد ( صلی اللہ علیہ وسلم ) ۔ پوچھا گیا کیا انہیں لانے کے لیے آپ کو بھیجا گیا تھا؟ جواب دیا کہ ہاں۔ اس پر آواز آئی انہیں خوش آمدید۔ کیا ہی اچھے آنے والے ہیں وہ، دروازہ کھلا اور جب میں اندر داخل ہوا تو وہاں یوسف علیہ السلام موجود تھے۔ جبرائیل علیہ السلام نے فرمایا یہ یوسف ہیں انہیں سلام کیجئے میں نے سلام کیا تو انہوں نے جواب دیا اور فرمایا: خوش آمدید نیک نبی اور نیک بھائی! پھر جبرائیل علیہ السلام مجھے لے کر اوپر چڑھے اور چوتھے آسمان پر پہنچے دروازہ کھلوایا تو پوچھا گیا کون صاحب ہیں؟ بتایا کہ جبرائیل! پوچھا گیا اور آپ کے ساتھ کون ہے؟ کہا کہ محمد ( صلی اللہ علیہ وسلم ) ۔ پوچھا گیا کیا انہیں بلانے کے لیے آپ کو بھیجا گیا تھا؟ جواب دیا کہ ہاں کہا کہ انہیں خوش آمدید۔ کیا ہی اچھے آنے والے ہیں وہ! اب دروازہ کھلا جب میں وہاں ادریس علیہ السلام کی خدمت میں پہنچا تو جبرائیل علیہ السلام نے فرمایا یہ ادریس علیہ السلام ہیں انہیں سلام کیجئے میں نے انہیں سلام کیا اور انہوں نے جواب دیا اور فرمایا خوش آمدید پاک بھائی اور نیک نبی۔ پھر مجھے لے کر پانچویں آسمان پر آئے اور دروازہ کھلوایا پوچھا گیا کون صاحب ہیں؟ جواب دیا کہ جبرائیل پوچھا گیا آپ کے ساتھ کون صاحب آئے ہیں؟ جواب دیا کہ محمد ( صلی اللہ علیہ وسلم ) ۔ پوچھا گیا کہ انہیں بلانے کے لیے آپ کو بھیجا گیا تھا؟ جواب دیا کہ ہاں اب آواز آئی خوش آمدید کیا ہی اچھے آنے والے ہیں وہ، یہاں جب میں ہارون علیہ السلام کی خدمت میں حاضر ہوا تو جبرائیل علیہ السلام نے بتایا کہ یہ ہارون ہیں انہیں سلام کیجئے میں نے انہیں سلام کیا انہوں نے جواب کے بعد فرمایا خوش آمدید نیک نبی اور نیک بھائی! یہاں سے لے کر مجھے آگے بڑھے اور چھٹے آسمان پر پہنچے اور دروازہ کھلوایا پوچھا گیا کون صاحب آئے ہیں؟ بتایا کہ جبرائیل، پوچھا گیا آپ کے ساتھ کوئی دوسرے صاحب بھی آئے ہیں؟ جواب دیا کہ محمد ( صلی اللہ علیہ وسلم ) ۔ پوچھا گیا کیا انہیں بلانے کے لیے آپ کو بھیجا گیا تھا؟ جواب دیا کہ ہاں۔ پھر کہا انہیں خوش آمدید کیا ہی اچھے آنے والے ہیں وہ۔ میں جب وہاں موسیٰ علیہ السلام کی خدمت میں حاضر ہوا تو جبرائیل علیہ السلام نے فرمایا کہ یہ موسیٰ علیہ السلام ہیں انہیں سلام کیجئے، میں نے سلام کیا اور انہوں نے جواب کے بعد فرمایا خوش آمدید نیک نبی اور نیک بھائی! جب میں آگے بڑھا تو وہ رونے لگے کسی نے پوچھا آپ رو کیوں رہے ہیں؟ تو انہوں نے فرمایا میں اس پر رو رہا ہوں کہ یہ لڑکا میرے بعد نبی بنا کر بھیجا گیا لیکن جنت میں اس کی امت کے لوگ میری امت سے زیادہ ہوں گے۔ پھر جبرائیل علیہ السلام مجھے لے کر ساتویں آسمان کی طرف گئے اور دروازہ کھلوایا۔ پوچھا گیا کون صاحب آئے ہیں؟ جواب دیا کہ جبرائیل، پوچھا گیا اور آپ کے ساتھ کون صاحب آئے ہیں؟ جواب دیا کہ محمد ( صلی اللہ علیہ وسلم ) ۔ پوچھا گیا کیا انہیں بلانے کے لیے آپ کو بھیجا گیا تھا؟ جواب دیا کہ ہاں۔ کہا کہ انہیں خوش آمدید۔ کیا ہی اچھے آنے والے ہیں وہ، میں جب اندر گیا تو ابراہیم علیہ السلام تشریف رکھتے تھے۔ جبرائیل علیہ السلام نے فرمایا کہ یہ آپ کے جد امجد ہیں، انہیں سلام کیجئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں نے ان کو سلام کیا تو انہوں نے جواب دیا اور فرمایا خوش آمدید نیک نبی اور نیک بیٹے! پھر سدرۃ المنتہیٰ کو میرے سامنے کر دیا گیا میں نے دیکھا کہ اس کے پھل مقام حجر کے مٹکوں کی طرح ( بڑے بڑے ) تھے اور اس کے پتے ہاتھیوں کے کان کی طرح تھے۔ جبرائیل علیہ السلام نے فرمایا کہ یہ سدرۃ المنتہیٰ ہے۔ وہاں میں نے چار نہریں دیکھیں دو باطنی اور دو ظاہری۔ میں نے پوچھا اے جبرائیل! یہ کیا ہیں؟ انہوں نے بتایا کہ جو دو باطنی نہریں ہیں وہ جنت سے تعلق رکھتی ہیں اور دو ظاہری نہریں، نیل اور فرات ہیں۔ پھر میرے سامنے بیت المعمور کو لایا گیا، وہاں میرے سامنے ایک گلاس میں شراب ایک میں دودھ اور ایک میں شہد لایا گیا۔ میں نے دودھ کا گلاس لے لیا تو جبرائیل علیہ السلام نے فرمایا یہی فطرت ہے اور آپ اس پر قائم ہیں اور آپ کی امت بھی! پھر مجھ پر روزانہ پچاس نمازیں فرض کی گئیں میں واپس ہوا اور موسیٰ علیہ السلام کے پاس سے گزرا تو انہوں نے پوچھا کس چیز کا آپ کو حکم ہوا؟ میں نے کہا کہ روزانہ پچاس وقت کی نمازوں کا۔ موسیٰ علیہ السلام نے فرمایا لیکن آپ کی امت میں اتنی طاقت نہیں ہے۔ اس سے پہلے میرا واسطہ لوگوں سے پڑ چکا ہے اور بنی اسرائیل کا مجھے تلخ تجربہ ہے۔ اس لیے آپ اپنے رب کے حضور میں دوبارہ جائیے اور اپنی امت پر تخفیف کے لیے عرض کیجئے۔ چنانچہ میں اللہ تعالیٰ کے دربار میں دوبارہ حاضر ہوا اور تخفیف کے لیے عرض کی تو دس وقت کی نمازیں کم کر دی گئیں۔ پھر میں جب واپسی میں موسیٰ علیہ السلام کے پاس سے گزرا تو انہوں نے پھر وہی سوال کیا میں دوبارہ بارگاہ رب تعالیٰ میں حاضر ہوا اور اس مرتبہ بھی دس وقت کی نمازیں کم ہوئیں۔ پھر میں موسیٰ علیہ السلام کے پاس سے گزرا اور تو انہوں نے وہی مطالبہ کیا میں نے اس مرتبہ بھی بارگاہ رب تعالیٰ میں حاضر ہو کر دس وقت کی نمازیں کم کرائیں۔ موسیٰ علیہ السلام کے پاس سے پھر گزرا انہوں نے اپنی رائے کا اظہار کیا پھر بارگاہ الٰہی میں حاضر ہوا تو مجھے دس وقت کی نمازوں کا حکم ہوا میں واپس ہونے لگا تو آپ نے پھر وہی کہا اب بارگاہ الٰہی میں حاضرہوا تو روزانہ صرف پانچ وقت کی نمازوں کا حکم باقی رہا۔ موسیٰ علیہ السلام کے پاس آیا تو آپ نے دریافت فرمایا اب کیا حکم ہوا؟ میں نے موسیٰ علیہ السلام کو بتایا کہ روزانہ پانچ وقت کی نمازوں کا حکم ہوا ہے۔ فرمایا کہ آپ کی امت اس کی بھی طاقت نہیں رکھتی میرا واسطہ آپ سے پہلے لوگوں سے پڑ چکا ہے اور بنی اسرائیل کا مجھے تلخ تجربہ ہے۔ اپنے رب کے دربار میں پھر حاضر ہو کر تخفیف کے لیے عرض کیجئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا رب تعالیٰ سے میں بہت سوال کر چکا اور اب مجھے شرم آتی ہے۔ اب میں بس اسی پر راضی ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر جب میں وہاں سے گزرنے لگا تو ندا آئی ”میں نے اپنا فریضہ جاری کر دیا اور اپنے بندوں پر تخفیف کر چکا۔“' WHERE id = 3725;
UPDATE hadiths SET urdu = 'ہم سے (عبداللہ بن زبیر) حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے اعمش نے بیان کیا، کہا کہ میں نے ابووائل شقیق بن سلمہ سے سنا، انہوں نے بیان کیا کہ ہم خباب بن ارت رضی اللہ عنہ کی عیادت کے لیے گئے تو انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ ہم نے صرف اللہ کی خوشنودی حاصل کرنے کے لیے ہجرت کی تھی۔ اللہ تعالیٰ ہمیں اس کا اجر دے گا۔ پھر ہمارے بہت سے ساتھی اس دنیا سے اٹھ گئے اور انہوں نے ( دنیا میں ) اپنے اعمال کا پھل نہیں دیکھا۔ انہیں میں مصعب بن عمیر رضی اللہ عنہ احد کی لڑائی میں شہید کئے گئے تھے اور صرف ایک دھاری دار چادر چھوڑی تھی۔ ( کفن دیتے وقت ) جب ہم ان کی چادر سے ان کا سر ڈھانکتے تو پاؤں کھل جاتے اور پاؤں ڈھانکتے تو سر کھل جاتا۔ رسول اللہ صلی اللہ علیہ وسلم نے ہمیں حکم دیا کہ ان کا سر ڈھانک دیں اور پاؤں پر اذخر گھاس ڈال دیں۔ ( تاکہ چھپ جائیں ) اور ہم میں ایسے بھی ہیں کہ ( اس دنیا میں بھی ) ان کے اعمال کا میوہ پک گیا، پس وہ اس کو چن رہے ہیں۔' WHERE id = 3735;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی شیبہ نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد اور فاطمہ بنت منذر نے اور ان سے اسماء رضی اللہ عنہا نے کہ جب نبی کریم صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ مدینہ ہجرت کر کے جانے لگے تو میں نے آپ دونوں کے لیے ناشتہ تیار کیا۔ میں نے اپنے والد ( ابوبکر رضی اللہ عنہ ) سے کہا کہ میرے پٹکے کے سوا اور کوئی چیز اس وقت میرے پاس ایسی نہیں جس سے میں اس ناشتہ کو باندھ دوں۔ اس پر انہوں نے کہا کہ پھر اس کے دو ٹکڑے کر لو۔ چنانچہ میں نے ایسا ہی کیا اور اس وقت سے میرا نام ذات النطاقین ( دو پٹکوں والی ) ہو گیا اور ابن عباس رضی اللہ عنہما نے اسماء کو «ذات النطاقين‏.‏» کہا۔' WHERE id = 3745;
UPDATE hadiths SET urdu = 'ہم سے احمد بن عثمان نے بیان کیا، کہا کہ ان سے شریح بن مسلمہ نے بیان کیا، ان سے ابراہیم بن یوسف نے، ان سے ان کے والد یوسف بن اسحاق نے، ان سے ابواسحاق سبیعی نے بیان کیا کہ میں نے براء بن عازب رضی اللہ عنہما سے حدیث سنی وہ بیان کرتے تھے کہ ابوبکر رضی اللہ عنہ نے عازب رضی اللہ عنہ سے ایک پالان خریدا اور میں ان کے ساتھ اٹھا کر پہنچانے لایا تھا۔ انہوں نے بیان کیا کہ ابوبکر رضی اللہ عنہ سے عازب رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم کے سفر ہجرت کا حال پوچھا تو انہوں نے بیان کیا کہ چونکہ ہماری نگرانی ہو رہی تھی ( یعنی کفار ہماری تاک میں تھے ) اس لیے ہم ( غار سے ) رات کے وقت باہر آئے اور پوری رات اور دن بھر بہت تیزی کے ساتھ چلتے رہے، جب دوپہر ہوئی تو ہمیں ایک چٹان دکھائی دی۔ ہم اس کے قریب پہنچے تو اس کی آڑ میں تھوڑا سا سایہ بھی موجود تھا۔ ابوبکر رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے لیے ایک چمڑا بچھا دیا جو میرے ساتھ تھا۔ آپ اس پر لیٹ گئے، اور میں قرب و جوار کی گرد جھاڑنے لگا۔ اتفاق سے ایک چرواہا نظر پڑا جو اپنی بکریوں کے تھوڑے سے ریوڑ کے ساتھ اسی چٹان کی طرف آ رہا تھا اس کا مقصد اس چٹان سے وہی تھا جس کے لیے ہم یہاں آئے تھے ( یعنی سایہ حاصل کرنا ) میں نے اس سے پوچھا لڑکے تو کس کا غلام ہے؟ اس نے بتایا کہ فلاں کا ہوں۔ میں نے اس سے پوچھا کیا تم اپنی بکریوں سے کچھ دودھ نکال سکتے ہو اس نے کہا کہ ہاں پھر وہ اپنے ریوڑ سے ایک بکری لایا تو میں نے اس سے کہا کہ پہلے اس کا تھن جھاڑ لو۔ انہوں نے بیان کیا کہ پھر اس نے کچھ دودھ دوہا۔ میرے ساتھ پانی کا ایک چھاگل تھا۔ اس کے منہ پر کپڑا بندھا ہوا تھا۔ یہ پانی میں نے نبی کریم صلی اللہ علیہ وسلم کے لیے ساتھ لے رکھا تھا۔ وہ پانی میں نے اس دودھ پر اتنا ڈالا کہ وہ نیچے تک ٹھنڈا ہو گیا تو میں اسے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں لے کر حاضر ہوا اور عرض کیا دودھ نوش فرمایئے یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے اسے نوش فرمایا جس سے مجھے بہت خوشی حاصل ہوئی۔ اس کے بعد ہم نے پھر کوچ شروع کیا اور ڈھونڈنے والے لوگ ہماری تلاش میں تھے۔' WHERE id = 3755;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے ہشام بن یوسف نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، کہا مجھ سے عروہ بن زبیر نے بیان کیا، انہیں عبیداللہ بن عدی نے خبر دی کہ میں عثمان کی خدمت میں حاضر ہوا ( دوسری سند ) اور بشر بن شعیب نے بیان کیا کہ مجھ سے میرے والد نے بیان کیا، ان سے زہری نے کہا، مجھ سے عروہ بن زبیر نے بیان کیا اور انہیں عبیداللہ بن عدی بن خیار نے خبر دی کہ میں عثمان رضی اللہ عنہ کی خدمت میں حاضر ہوا تو انہوں نے حمد و شہادت پڑھنے کے بعد فرمایا: امابعد! کوئی شک و شبہ نہیں کہ اللہ تعالیٰ نے محمد صلی اللہ علیہ وسلم کو حق کے ساتھ مبعوث کیا، میں بھی ان لوگوں میں تھا جنہوں نے اللہ اور اس کے رسول کی دعوت پر ( ابتداء ہی میں ) لبیک کہا اور میں ان تمام چیزوں پر ایمان لایا جنہیں لے کر نبی کریم صلی اللہ علیہ وسلم مبعوث ہوئے تھے۔ پھر میں نے دو ہجرت کی اور نبی کریم صلی اللہ علیہ وسلم کی دامادی کا شرف مجھے حاصل ہوا اور آپ صلی اللہ علیہ وسلم سے میں نے بیعت کی اللہ کی قسم کہ میں نے آپ کی نہ کبھی نافرمانی کی اور نہ کبھی آپ سے دھوکہ بازی کی، یہاں تک کہ آپ کا انتقال ہو گیا۔ شعیب کے ساتھ اس روایت کی متابعت اسحاق کلبی نے بھی کی ہے، ان سے زہری نے اس حدیث کو اسی طرح بیان کیا۔' WHERE id = 3765;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف بیکندی نے بیان کیا، ان سے سفیان بن عیینہ نے بیان کیا، ان سے حمید طویل نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ جب عبدالرحمٰن بن عوف رضی اللہ عنہ ہجرت کر کے آئے تو نبی کریم صلی اللہ علیہ وسلم ان کا بھائی چارہ سعد بن ربیع انصاری رضی اللہ عنہ کے ساتھ کرایا تھا۔ سعد رضی اللہ عنہ نے ان سے کہا کہ ان کے اہل و مال میں سے آدھا وہ قبول کر لیں لیکن عبدالرحمٰن رضی اللہ عنہ نے کہا کہ اللہ تعالیٰ آپ کے اہل و مال میں برکت دے۔ آپ تو مجھے بازار کا راستہ بتا دیں۔ چنانچہ انہوں نے تجارت شروع کر دی اور پہلے دن انہیں کچھ پنیر اور گھی میں نفع ملا۔ چند دنوں کے بعد انہیں نبی کریم صلی اللہ علیہ وسلم نے دیکھا کہ ان کے کپڑوں پر ( خوشبو کی ) زردی کا نشان ہے تو آپ صلی اللہ علیہ وسلم نے فرمایا عبدالرحمٰن یہ کیا ہے؟ انہوں نے عرض کیا: یا رسول اللہ! میں نے ایک انصاری عورت سے شادی کر لی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ انہیں مہر میں تم نے کیا دیا؟ انہوں نے بتایا کہ ایک گھٹلی برابر سونا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اب ولیمہ کرو خواہ ایک ہی بکری کا ہو۔' WHERE id = 3775;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے وہب نے بیان کیا، ان سے شعبہ نے، ان سے ابواسحاق نے کہ میں ایک وقت زید بن ارقم رضی اللہ عنہ کے پہلو میں بیٹھا ہوا تھا۔ ان سے پوچھا گیا تھا کہ نبی کریم صلی اللہ علیہ وسلم نے کتنے غزوے کئے؟ انہوں نے کہا انیس۔ میں نے پوچھا آپ نبی کریم صلی اللہ علیہ وسلم کے ساتھ کتنے غزوات میں شریک رہے؟ تو انہوں نے کہا کہ سترہ میں۔ میں نے پوچھا آپ صلی اللہ علیہ وسلم کا سب سے پہلا غزوہ کون سا تھا؟ کہا کہ عسیرہ یا عشیرہ۔ پھر میں نے اس کا ذکر قتادہ سے کیا تو انہوں نے کہا کہ ( صحیح لفظ ) عشیرہ ہے۔' WHERE id = 3786;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن ابی شیبہ نے بیان کیا، ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے سفیان ثوری نے، ان سے ابواسحاق نے اور ان سے براء رضی اللہ عنہ نے (دوسری سند) اور ہم سے محمد بن کثیر نے بیان کیا، انہیں سفیان نے خبر دی، انہیں ابواسحاق نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ ہم آپس میں یہ گفتگو کیا کرتے تھے کہ جنگ بدر میں اصحاب بدر کی تعداد بھی تین سو دس سے اوپر، کچھ اوپر تھی، جتنی ان اصحاب طالوت کی تعداد تھی جنہوں نے ان کے ساتھ نہر فلسطین پار کی تھی اور اسے پار کرنے والے صرف ایماندار ہی تھے۔' WHERE id = 3796;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا، ہم سے ہشیم نے بیان کیا، ہم کو ابوہاشم نے خبر دی، انہیں ابومجلز نے، انہیں قیس نے، انہوں نے کہا کہ میں نے ابوذر رضی اللہ عنہ سے سنا، وہ قسمیہ کہتے تھے کہ یہ آیت «هذان خصمان اختصموا في ربهم» ان کے بارے میں اتری جو بدر کی لڑائی میں مقابلے کے لیے نکلے تھے یعنی حمزہ، علی اور عبیدہ بن حارث رضی اللہ عنہم ( مسلمانوں کی طرف سے ) اور عتبہ، شیبہ، ربیعہ کے بیٹے اور ولید بن عتبہ ( کافروں کی طرف سے ) ۔' WHERE id = 3807;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن ابراہیم نے بیان کیا ‘ ہم کو عبداللہ بن ادریس نے خبر دی ‘ کہا کہ میں نے حسین بن عبدالرحمٰن سے سنا ‘ انہوں نے سعد بن عبیدہ سے ‘ انہوں نے ابوعبدالرحمٰن سلمی سے کہ علی رضی اللہ عنہ نے کہا مجھے ‘ ابومرثد رضی اللہ عنہ اور زبیر رضی اللہ عنہ کو رسول اللہ صلی اللہ علیہ وسلم نے ایک مہم پر بھیجا۔ ہم سب شہسوار تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم لوگ سیدھے چلے جاؤ۔ جب روضہ خاخ پر پہنچو تو وہاں تمہیں مشرکین کی ایک عورت ملے گی ‘ وہ ایک خط لیے ہوئے ہے جسے حاطب بن ابی بلتعہ نے مشرکین کے نام بھیجا ہے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے جس جگہ کا پتہ دیا تھا ہم نے وہیں اس عورت کو ایک اونٹ پر جاتے ہوئے پا لیا۔ ہم نے اس سے کہا کہ خط دے دو۔ وہ کہنے لگی کہ میرے پاس تو کوئی خط نہیں ہے۔ ہم نے اس کے اونٹ کو بیٹھا کر اس کی تلاشی لی تو واقعی ہمیں بھی کوئی خط نہیں ملا۔ لیکن ہم نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کی بات کبھی غلط نہیں ہو سکتی خط نکال ورنہ ہم تجھے ننگا کر دیں گے۔ جب اس نے ہمارا یہ سخت رویہ دیکھا تو ازار باندھنے کی جگہ کی طرف اپنا ہاتھ لے گئی وہ ایک چادر میں لپٹی ہوئی تھی اور اس نے خط نکال کر ہم کو دے دیا ہم اسے لے کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ عمر رضی اللہ عنہ نے کہا کہ اس نے ( یعنی حاطب بن ابی بلتعہ نے ) اللہ اور اس کے رسول اور مسلمانوں سے دغا کی ہے آپ مجھے اجازت دیں تاکہ میں اس کی گردن مار دوں لیکن آپ صلی اللہ علیہ وسلم نے ان سے دریافت فرمایا کہ تم نے یہ کام کیوں کیا؟ حاطب رضی اللہ عنہ بولے: اللہ کی قسم! یہ وجہ ہرگز نہیں تھی کہ اللہ اور اس کے رسول پر میرا ایمان باقی نہیں رہا تھا میرا مقصد تو صرف اتنا تھا کہ قریش پر اس طرح میرا ایک احسان ہو جائے اور اس کی وجہ سے وہ ( مکہ میں باقی رہ جانے والے ) میرے اہل و عیال کی حفاظت کریں۔ آپ کے اصحاب میں جتنے بھی حضرات ( مہاجرین ) ہیں ان سب کا قبیلہ وہاں موجود ہے اور اللہ ان کے ذریعے ان کے اہل و مال کی حفاظت کرتا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہوں نے سچی بات بتا دی ہے اور تم لوگوں کو چاہئے کہ ان کے متعلق اچھی بات ہی کہو۔ عمر رضی اللہ عنہ نے پھر عرض کیا کہ اس شخص نے اللہ، اس کے رسول اور مسلمانوں سے دغا کی ہے آپ مجھے اجازت دیجئیے کہ میں اس کی گردن مار دوں۔ آپ صلی اللہ علیہ وسلم نے ان سے فرمایا کہ کیا یہ بدر والوں میں سے نہیں ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ اہل بدر کے حالات کو پہلے ہی سے جانتا تھا اور وہ خود فرما چکا ہے کہ ”تم جو چاہو کرو، تمہیں جنت ضرور ملے گی۔“ ( یا آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ ) میں نے تمہاری مغفرت کر دی ہے یہ سن کر عمر رضی اللہ عنہ کی آنکھوں میں آنسو آ گئے اور عرض کیا، اللہ اور اس کے رسول کو زیادہ علم ہے۔' WHERE id = 3819;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، ہم سے حماد نے بیان کیا، ان سے یحییٰ نے، ان سے معاذ بن رفاعہ بن رافع نے کہ رفاعہ رضی اللہ عنہ بدر کی لڑائی میں شریک ہوئے تھے اور ( ان کے والد ) رافع رضی اللہ عنہ بیعت عقبہ میں شریک ہوئے تھے تو آپ اپنے بیٹے ( رفاعہ ) سے کہا کرتے تھے کہ بیعت عقبہ کے برابر بدر کی شرکت سے مجھے زیادہ خوشی نہیں ہے۔ بیان کیا کہ جبرائیل علیہ السلام نے نبی کریم صلی اللہ علیہ وسلم سے اس بارے میں پوچھا تھا۔' WHERE id = 3829;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں یونس بن یزید نے خبر دی، (دوسری سند) امام بخاری رحمہ اللہ نے کہا ہم کو احمد بن صالح نے خبر دی، ان سے عنبسہ بن خالد نے بیان کیا، کہا ہم سے یونس نے بیان کیا، ان سے زہری نے، انہیں علی بن حسین (امام زین العابدین) نے خبر دی، انہیں حسین بن علی رضی اللہ عنہما نے خبر دی اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ جنگ بدر کی غنیمت میں سے مجھے ایک اور اونٹنی ملی تھی اور اسی جنگ کی غنیمت میں سے اللہ تعالیٰ نے رسول اللہ صلی اللہ علیہ وسلم کا جو خمس کے طور پر حصہ مقرر کیا تھا اس میں سے بھی نبی کریم صلی اللہ علیہ وسلم نے مجھے ایک اونٹنی عنایت فرمائی تھی۔ پھر میرا ارادہ ہوا کہ نبی کریم صلی اللہ علیہ وسلم کی صاحبزادی فاطمہ رضی اللہ عنہا کی رخصتی کرا لاؤں۔ اس لیے بنی قینقاع کے ایک سنار سے بات چیت کی کہ وہ میرے ساتھ چلے اور ہم اذخر گھاس لائیں۔ میرا ارادہ تھا کہ میں اس گھاس کو سناروں کے ہاتھ بیچ دوں گا اور اس کی قیمت ولیمہ کی دعوت میں لگاؤں گا۔ میں ابھی اپنی اونٹنی کے لیے پالان، ٹوکرے اور رسیاں جمع کر رہا تھا۔ اونٹنیاں ایک انصاری صحابی کے حجرہ کے قریب بیٹھی ہوئی تھیں۔ میں جن انتظامات میں تھا جب وہ پورے ہو گئے تو ( اونٹنیوں کو لینے آیا ) وہاں دیکھا کہ ان کے کوہان کسی نے کاٹ دیئے ہیں اور کوکھ چیر کر اندر سے کلیجی نکال لی ہے۔ یہ حالت دیکھ کر میں اپنے آنسوؤں کو نہ روک سکا۔ میں نے پوچھا، یہ کس نے کیا ہے؟ لوگوں نے بتایا کہ حمزہ بن عبدالمطلب رضی اللہ عنہ نے اور وہ ابھی اسی حجرہ میں انصار کے ساتھ شراب نوشی کی ایک مجلس میں موجود ہیں۔ ان کے پاس ایک گانے والی ہے اور ان کے دوست احباب ہیں۔ گانے والی نے گاتے ہوئے جب یہ مصرع پڑھا۔ ہاں، اے حمزہ! یہ عمدہ اور فربہ اونٹنیاں ہیں، تو حمزہ رضی اللہ عنہ نے کود کر اپنی تلوار تھامی اور ان دونوں اونٹنیوں کے کوہان کاٹ ڈالے اور ان کی کوکھ چیر کر اندر سے کلیجی نکال لی۔ علی رضی اللہ عنہ نے بیان کیا کہ پھر میں وہاں سے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ زید بن حارثہ رضی اللہ عنہ بھی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں موجود تھے۔ آپ صلی اللہ علیہ وسلم نے میرے غم کو پہلے ہی جان لیا اور فرمایا کہ کیا بات پیش آئی؟ میں بولا: یا رسول اللہ! آج جیسی تکلیف کی بات کبھی پیش نہیں آئی تھی۔ حمزہ رضی اللہ عنہ نے میری دونوں اونٹنیوں کو پکڑ کے ان کے کوہان کاٹ ڈالے اور ان کی کوکھ چیر ڈالی ہے۔ وہ یہیں ایک گھر میں شراب کی مجلس جمائے بیٹھے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے اپنی چادر مبارک منگوائی اور اسے اوڑھ کر آپ تشریف لے چلے۔ میں اور زید بن حارثہ رضی اللہ عنہ بھی ساتھ ساتھ ہولئے۔ جب اس گھر کے قریب آپ تشریف لے گئے اور حمزہ رضی اللہ عنہ نے جو کچھ کیا تھا اس پر انہیں تنبیہ فرمائی۔ حمزہ رضی اللہ عنہ شراب کے نشے میں مست تھے اور ان کی آنکھیں سرخ تھیں۔ انہوں نے آپ صلی اللہ علیہ وسلم کی طرف نظر اٹھائی، پھر ذرا اور اوپر اٹھائی اور آپ کے گھٹنوں پر دیکھنے لگے، پھر اور نظر اٹھائی اور آپ کے چہرہ پر دیکھنے لگے۔ پھر کہنے لگے، تم سب میرے باپ کے غلام ہو۔ آپ صلی اللہ علیہ وسلم سمجھ گئے کہ وہ اس وقت بیہوش ہیں۔ اس لیے آپ فوراً الٹے پاؤں اس گھر سے باہر نکل آئے، ہم بھی آپ کے ساتھ تھے۔' WHERE id = 3839;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ بن مبارک مروزی نے خبر دی، کہا ہم کو معمر اور یونس دونوں نے خبر دی، انہیں زہری نے، انہیں عروہ بن زبیر نے خبر دی، انہیں مسور بن مخرمہ رضی اللہ عنہما نے خبر دی کہ عمرو بن عوف رضی اللہ عنہ جو بنی عامر بن لوی کے حلیف تھے اور بدر کی لڑائی میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ شریک تھے۔ ( نے بیان کیا کہ ) نبی کریم صلی اللہ علیہ وسلم نے ابوعبیدہ بن جراح رضی اللہ عنہ کو بحرین، وہاں کا جزیہ لانے کے لیے بھیجا۔ نبی کریم صلی اللہ علیہ وسلم نے بحرین والوں سے صلح کی تھی اور ان پر علاء بن حضرمی رضی اللہ عنہ کو امیر بنایا تھا، پھر ابوعبیدہ رضی اللہ عنہ بحرین سے مال ایک لاکھ درہم لے کر آئے۔ جب انصار کو ابوعبیدہ رضی اللہ عنہ کے آنے کی خبر ہوئی تو انہوں نے فجر کی نماز نبی کریم صلی اللہ علیہ وسلم کے ساتھ پڑھی۔ آپ صلی اللہ علیہ وسلم جب نماز سے فارغ ہوئے تو تمام انصار آپ کے سامنے آئے۔ آپ صلی اللہ علیہ وسلم انہیں دیکھ کر مسکرائے اور فرمایا: میرا خیال ہے کہ تمہیں یہ اطلاع مل گئی ہے کہ ابوعبیدہ مال لے کر آئے ہیں۔ انہوں نے عرض کیا: جی ہاں، یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر تمہیں خوشخبری ہو اور جس سے تمہیں خوشی ہو گی اس کی امید رکھو۔ اللہ کی قسم! مجھے تمہارے متعلق محتاجی سے ڈر نہیں لگتا، مجھے تو اس کا خوف ہے کہ دنیا تم پر بھی اسی طرح کشادہ کر دی جائے گی جس طرح تم سے پہلوں پر کشادہ کی گئی تھی، پھر پہلوں کی طرح اس کے لیے تم آپس میں رشک کرو گے اور جس طرح وہ ہلاک ہو گئے تھے تمہیں بھی یہ چیز ہلاک کر کے رہے گی۔' WHERE id = 3850;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہ ہم کو ہشام نے خبر دی، انہیں معمر نے، انہیں ہشام بن عروہ نے، انہیں ان کے والد نے اور ان سے زبیر رضی اللہ عنہ نے بیان کیا کہ بدر کے دن مہاجرین کے سو حصے لگائے گئے تھے۔' WHERE id = 3861;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، ہم کو عبدالوہاب نے خبر دی، انہوں نے کہا ہم سے خالد نے بیان کیا، ان سے عکرمہ نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے غزوہ احد کے موقع پر فرمایا ”یہ جبرائیل علیہ السلام ہیں، ہتھیار بند، اپنے گھوڑے کی لگام تھامے ہوئے۔“' WHERE id = 3873;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم کو عمرو بن دینار نے خبر دی اور ان سے جابر بن عبداللہ انصاری رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھ سے دریافت فرمایا ”جابر! کیا نکاح کر لیا؟“ میں نے عرض کیا، جی ہاں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کنواری سے یا بیوہ سے؟“ میں نے عرض کیا کہ بیوہ سے۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”کسی کنواری لڑکی سے کیوں نہ کیا؟ جو تمہارے ساتھ کھیلا کرتی۔“ میں نے عرض کیا: یا رسول اللہ! میرے والد احد کی لڑائی میں شہید ہو گئے۔ نو لڑکیاں چھوڑیں۔ پس میری نو بہنیں موجود ہیں۔ اسی لیے میں نے مناسب نہیں خیال کیا کہ انہیں جیسی نا تجربہ کار لڑکی ان کے پاس لا کر بٹھا دوں، بلکہ ایک ایسی عورت لاؤں جو ان کی دیکھ بھال کر سکے اور ان کی صفائی و ستھرائی کا خیال رکھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم نے اچھا کیا۔' WHERE id = 3883;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، ان سے عبدالعزیز نے بیان کیا اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ غزوہ احد میں جب مسلمان نبی کریم صلی اللہ علیہ وسلم کے پاس سے منتشر ہو کر پسپا ہو گئے تو طلحہ رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کی اپنے چمڑے کی ڈھال سے حفاظت کر رہے تھے۔ ابوطلحہ رضی اللہ عنہ بڑے تیرانداز تھے اور کمان خوب کھینچ کر تیر چلایا کرتے تھے۔ اس دن انہوں نے دو یا تین کمانیں توڑ دی تھیں۔ مسلمانوں میں سے کوئی اگر تیر کا ترکش لیے گزرتا تو نبی کریم صلی اللہ علیہ وسلم ان سے فرماتے یہ تیر ابوطلحہ کے لیے یہیں رکھتے جاؤ۔ انس رضی اللہ عنہ نے بیان کیا کہ آپ صلی اللہ علیہ وسلم مشرکین کو دیکھنے کے لیے سر اٹھا کر جھانکتے تو ابوطلحہ رضی اللہ عنہ عرض کرتے: میرے ماں باپ آپ پر فدا ہوں، سر مبارک اوپر نہ اٹھایئے کہیں ایسا نہ ہو کہ ادھر سے کوئی تیر آپ کو لگ جائے۔ میری گردن آپ سے پہلے ہے اور میں نے دیکھا کہ جنگ میں عائشہ بنت ابی بکر رضی اللہ عنہا اور ( انس رضی اللہ عنہ کی والدہ ) ام سلیم رضی اللہ عنہا اپنے کپڑے اٹھائے ہوئے ہیں کہ ان کی پنڈلیاں نظر آ رہی تھیں اور مشکیزے اپنی پیٹھوں پر لیے دوڑ رہی ہیں اور اس کا پانی زخمی مسلمانوں کو پلا رہی ہیں پھر ( جب اس کا پانی ختم ہو جاتا ہے ) تو واپس آتی ہیں اور مشک بھر کر پھر لے جاتی ہیں اور مسلمانوں کو پلاتی ہیں۔ اس دن ابوطلحہ رضی اللہ عنہ کے ہاتھ سے دو یا تین مرتبہ تلوار گر گئی تھی۔' WHERE id = 3894;
UPDATE hadiths SET urdu = 'مجھ سے مخلد بن مالک نے بیان کیا، کہا ہم سے یحییٰ بن سعید اموی نے بیان کیا، کہا ہم سے ابن جریج نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا، ان سے عکرمہ نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ اللہ تعالیٰ کا اس شخص پر انتہائی غضب نازل ہوا جسے اللہ کے نبی نے قتل کیا تھا۔ اللہ تعالیٰ کا انتہائی غضب اس قوم پر نازل ہوا جنہوں نے اللہ کے نبی کے چہرہ مبارک کو ( غزوہ احد کے موقع پر ) خون آلود کر دیا تھا۔' WHERE id = 3904;
UPDATE hadiths SET urdu = 'مجھ سے عمرو بن خالد نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے یزید بن ابی حبیب نے، ان سے ابوالخیر نے اور ان سے عقبہ بن عامر رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم ایک دن باہر تشریف لائے اور شہداء احد پر نماز جنازہ ادا کی، جیسے مردوں پر ادا کی جاتی ہے۔ پھر آپ صلی اللہ علیہ وسلم منبر پر تشریف لائے اور فرمایا کہ میں تمہارے آگے جاؤں گا، میں تمہارے حق میں گواہ رہوں گا۔ میں اب بھی اپنے حوض ( حوض کوثر ) کو دیکھ رہا ہوں۔ مجھے دنیا کے خزانوں کی کنجی عطا فرمائی گئی ہے یا ( آپ حوض کوثر نے یوں فرمایا ) «مفاتيح الأرض» یعنی زمین کی کنجیاں دی گئی ہیں۔ ( دونوں جملوں کا مطلب ایک ہی ہے ) ۔ اللہ کی قسم! میں تمہارے بارے میں اس سے نہیں ڈرتا کہ تم میرے بعد شرک کرنے لگو گے بلکہ مجھے اس کا ڈر ہے کہ تم دنیا کے لیے حرص کرنے لگو گے۔' WHERE id = 3914;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ان لوگوں کے لیے جنہوں نے آپ کے معزز اصحاب ( قاریوں ) کو بئرمعونہ میں شہید کر دیا تھا۔ تیس دن تک صبح کی نماز میں بددعا کی تھی آپ صلی اللہ علیہ وسلم قبائل رعل، بنو لحیان اور عصیہ کے لیے ان نمازوں میں بددعا کرتے تھے، جنہوں نے اللہ اور اس کے رسول صلی اللہ علیہ وسلم کی نافرمانی کی تھی۔ انس رضی اللہ عنہ نے بیان کیا کہ پھر اللہ تعالیٰ نے اپنے نبی کریم صلی اللہ علیہ وسلم پر انہی اصحاب کے بارے میں جو بئرمعونہ میں شہید کر دیئے گئے تھے، قرآن مجید کی آیت نازل کی۔ ہم اس آیت کی تلاوت کیا کرتے تھے لیکن بعد میں وہ آیت منسوخ ہو گئی ( اس آیت کا ترجمہ یہ ہے ) ”ہماری قوم کو خبر پہنچا دو کہ ہم اپنے رب سے آ ملے ہیں۔ ہمارا رب ہم سے راضی ہے اور ہم بھی اس سے راضی ہیں۔“' WHERE id = 3924;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے شعبہ نے بیان کیا، کہا مجھ سے حکم بن عتیبہ نے بیان کیا، ان سے مجاہد نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”پروا ہوا کے ذریعے میری مدد کی گئی اور قوم عاد پچھوا ہوا سے ہلاک کر دی گئی تھی۔“' WHERE id = 3934;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا ‘ کہا ہم کو فزاری اور عبدہ نے خبر دی ‘ ان سے اسماعیل بن ابی خالد نے بیان کیا کہ میں نے عبداللہ بن ابی اوفی رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے احزاب ( افواج کفار ) کے لیے ( غزوہ خندق کے موقع پر ) بددعا کی ”اے اللہ! کتاب کے نازل کرنے والے! جلدی حساب لینے والے! کفار کے لشکر کو شکست دے۔ اے اللہ! انہیں شکست دے۔ یا اللہ! ان کی طاقت کو متزلزل کر دے۔“' WHERE id = 3944;
UPDATE hadiths SET urdu = 'اور عبداللہ بن رجاء نے کہا ‘ انہیں عمران قطان نے خبر دی ‘ انہیں یحییٰ بن کثیر نے ‘ انہیں ابوسلمہ نے اور انہیں جابر بن عبداللہ رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے اپنے اصحاب کے ساتھ نماز خوف ساتویں غزوہ میں پڑھی تھی۔ یعنی غزوہ ذات الرقاع میں۔ عبداللہ بن عباس رضی اللہ عنہما نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے نماز خوف ذو قرد میں پڑھی تھی۔' WHERE id = 3954;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا ‘ کہا کہ مجھ سے میرے بھائی عبدالحمید نے بیان کیا ‘ ان سے سلیمان بن بلال نے ‘ ان سے محمد بن ابی عتیق نے ‘ ان سے ابن شہاب نے ‘ ان سے سنان بن ابی سنان دولی نے ‘ انہیں جابر رضی اللہ عنہ نے خبر دی کہ وہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ اطراف نجد میں غزوہ کے لیے گئے تھے۔ پھر جب نبی کریم صلی اللہ علیہ وسلم واپس ہوئے تو وہ بھی واپس ہوئے۔ قیلولہ کا وقت ایک وادی میں آیا ‘ جہاں ببول کے درخت بہت تھے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم وہیں اتر گئے اور صحابہ رضی اللہ عنہم درختوں کے سائے کے لیے پوری وادی میں پھیل گئے۔ آپ صلی اللہ علیہ وسلم نے بھی ایک ببول کے درخت کے نیچے قیام فرمایا اور اپنی تلوار اس درخت پر لٹکا دی۔ جابر رضی اللہ عنہ نے بیان کیا کہ ابھی تھوڑی دیر ہمیں سوئے ہوئے ہوئی تھی کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں پکارا۔ ہم جب خدمت میں حاضر ہوئے تو آپ کے پاس ایک بدوی بیٹھا ہوا تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس شخص نے میری تلوار ( مجھ ہی پر ) کھینچ لی تھی ‘ میں اس وقت سویا ہوا تھا ‘ میری آنکھ کھلی تو میری ننگی تلوار اس کے ہاتھ میں تھی۔ اس نے مجھ سے کہا ‘ تمہیں میرے ہاتھ سے آج کون بچائے گا؟ میں نے کہا کہ اللہ! اب دیکھو یہ بیٹھا ہوا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے اسے پھر کوئی سزا نہیں دی۔' WHERE id = 3964;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا ‘ کہا ہم سے عبدہ بن سلیمان نے بیان کیا ‘ ان سے ہشام نے، ان سے ان کے والد نے بیان کیا کہ میں عائشہ رضی اللہ عنہا کے سامنے حسان بن ثابت رضی اللہ عنہ کو برا کہنے لگا تو انہوں نے کہا کہ انہیں برا نہ کہو ‘ کیونکہ وہ رسول اللہ صلی اللہ علیہ وسلم کی طرف سے کفار کو جواب دیتے تھے اور عائشہ رضی اللہ عنہا نے بیان کیا کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے مشرکین قریش کی ہجو کہنے کی اجازت چاہی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر میرے نسب کا کیا ہو گا؟ حسان رضی اللہ عنہ نے کہا کہ میں آپ کو ان سے اس طرح الگ کر لوں گا جیسے بال گندھے ہوئے آٹے سے کھینچ لیا جاتا ہے۔ اور محمد بن عقبہ ( امام بخاری رحمہ اللہ کے شیخ ) نے بیان کیا ‘ ہم سے عثمان بن فرقد نے بیان کیا ‘ کہا میں نے ہشام سے سنا ‘ انہوں نے اپنے والد سے ‘ انہوں نے بیان کیا کہ میں نے حسان بن ثابت رضی اللہ عنہ کو برا بھلا کہا کیونکہ انہوں نے بھی عائشہ رضی اللہ عنہا پر تہمت لگانے میں بہت حصہ لیا تھا۔' WHERE id = 3974;
UPDATE hadiths SET urdu = 'اور عبیداللہ بن معاذ نے بیان کیا ‘ ان سے ان کے والد نے بیان کیا ‘ ان سے شعبہ نے بیان کیا ‘ ان سے عمرو بن مرہ نے ‘ ان سے عبداللہ بن ابی اوفی رضی اللہ عنہما نے بیان کیا کہ درخت والوں ( بیعت رضوان کرنے والوں ) کی تعداد تیرہ سو تھی۔ قبیلہ اسلم مہاجرین کا آٹھواں حصہ تھے۔ اس روایت کی متابعت محمد بن بشار نے کی ‘ ان سے ابوداؤد طیالسی نے بیان کیا اور ان سے شعبہ نے۔' WHERE id = 3984;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا کہ ہم سے حاتم بن اسماعیل نے بیان کیا ‘ ان سے یزید بن ابی عبید نے بیان کیا کہ میں نے سلمہ بن اکوع رضی اللہ عنہ سے پوچھا کہ صلح حدیبیہ کے موقع پر آپ لوگوں نے رسول اللہ صلی اللہ علیہ وسلم سے کس چیز پر بیعت کی تھی؟ انہوں نے بتلایا کہ موت پر۔' WHERE id = 3996;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے امام مالک رحمہ اللہ نے بیان کیا ‘ ان سے نافع نے کہ عبداللہ بن عمر رضی اللہ عنہما فتنہ کے زمانہ میں عمرہ کے ارادہ سے نکلے۔ پھر انہوں نے کہا کہ اگر بیت اللہ جانے سے مجھے روک دیا گیا تو میں وہی کام کروں گا جو رسول اللہ صلی اللہ علیہ وسلم نے کیا تھا۔ چنانچہ آپ نے صرف عمرہ کا احرام باندھا کیونکہ نبی کریم صلی اللہ علیہ وسلم نے بھی صلح حدیبیہ کے موقع پر صرف عمرہ ہی کا احرام باندھا تھا۔' WHERE id = 4008;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن عبدالرحیم نے بیان کیا ‘ کہا ہم سے ابوعمر حفص بن عمر الحوضی نے بیان کیا ‘ کہا ہم سے حماد بن زید نے بیان کیا ‘ کہا ہم سے ایوب اور حجاج صواف نے بیان کیا ‘ کہا ہم سے ابوقلابہ کے مولیٰ ابورجاء نے بیان کیا ‘ وہ ابوقلابہ کے ساتھ شام میں تھے کہ خلیفہ عمر بن عبدالعزیز نے ایک دن لوگوں سے مشورہ کیا کہ اس ”قسامہ“ کے بارے میں تمہاری کیا رائے ہے؟ لوگوں نے کہا کہ یہ حق ہے۔ اس کا فیصلہ رسول اللہ صلی اللہ علیہ وسلم اور پھر خلفاء راشدین آپ سے پہلے کرتے رہے ہیں۔ ابورجاء نے بیان کیا کہ اس وقت ابوقلابہ ‘ عمر بن عبدالعزیز رحمہ اللہ کے تخت کے پیچھے تھے۔ اتنے میں عنبسہ بن سعید نے کہا کہ پھر قبیلہ عرینہ کے لوگوں کے بارے میں انس رضی اللہ عنہ کی حدیث کہاں گئی؟ اس پر ابوقلابہ نے کہا کہ انس رضی اللہ عنہ نے خود مجھ سے یہ بیان کیا۔ عبدالعزیز بن صہیب نے ( اپنی روایت میں ) انس رضی اللہ عنہ کے حوالہ سے صرف عرینہ کا نام لیا اور ابوقلابہ نے اپنی روایت میں انس رضی اللہ عنہ کے حوالے سے صرف عکل کا نام لیا پھر یہی قصہ بیان کیا۔' WHERE id = 4018;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا ہم کو شعیب نے خبر دی ‘ ان سے زہری نے بیان کیا ‘ انہیں سعید بن مسیب نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ہم خیبر کی جنگ میں شریک تھے۔ رسول اللہ صلی اللہ علیہ وسلم نے ایک صاحب کے متعلق جو آپ کے ساتھ تھے اور خود کو مسلمان کہتے تھے فرمایا کہ یہ شخص اہل دوزخ میں سے ہے۔ پھر جب لڑائی شروع ہوئی تو وہ صاحب بڑی پامردی سے لڑے اور بہت زیادہ زخمی ہو گئے۔ ممکن تھا کہ کچھ لوگ شبہ میں پڑ جاتے لیکن ان صاحب کے لیے زخموں کی تکلیف ناقابل برداشت تھی۔ چنانچہ انہوں نے اپنے ترکش میں سے تیر نکالا اور اپنے سینہ میں چبھو دیا۔ یہ منظر دیکھ کر مسلمان دوڑتے ہوئے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا: یا رسول اللہ! اللہ تعالیٰ نے آپ کا فرمان سچ کر دکھایا۔ اس شخص نے خود اپنے سینے میں تیر چبھو کر خودکشی کر لی ہے۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اے فلاں! جا اور اعلان کر دے کہ جنت میں صرف مومن ہی داخل ہوں گے۔ یوں اللہ تعالیٰ اپنے دین کی مدد فاجر شخص سے بھی لے لیتا ہے۔ اس روایت کی متابعت معمر نے زہری سے کی۔' WHERE id = 4028;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا ‘ کہا ہم کو محمد بن جعفر بن ابی کثیر نے خبر دی ‘ کہا کہ مجھے حمید نے خبر دی اور انہوں نے انس بن مالک رضی اللہ عنہ سے سنا ‘ وہ بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے مدینہ اور خیبر کے درمیان ( مقام سد الصہباء میں ) تین دن تک قیام فرمایا اور وہیں صفیہ رضی اللہ عنہا سے خلوت کی تھی پھر میں نے نبی کریم صلی اللہ علیہ وسلم کی طرف سے مسلمانوں کو ولیمہ کی دعوت دی۔ آپ کے ولیمہ میں نہ روٹی تھی ‘ نہ گوشت تھا صرف اتنا ہوا کہ آپ نے بلال رضی اللہ عنہ کو دستر خوان بچھانے کا حکم دیا اور وہ بچھا دیا گیا۔ پھر اس پر کھجور ‘ پنیر اور گھی ( کا ملیدہ ) رکھ دیا۔ مسلمانوں نے کہا کہ صفیہ رضی اللہ عنہا امہات المؤمنین میں سے ہیں یا باندی ہیں؟ کچھ لوگوں نے کہا کہ اگر نبی کریم صلی اللہ علیہ وسلم نے انہیں پردے میں رکھا تو وہ امہات المؤمنین میں سے ہوں گی اور اگر آپ نے انہیں پردے میں نہیں رکھا تو پھر یہ اس کی علامت ہو گی کہ وہ باندی ہیں۔ آخر جب کوچ کا وقت ہوا تو نبی کریم صلی اللہ علیہ وسلم نے ان کے لیے اپنی سواری پر پیچھے بیٹھنے کی جگہ بنائی اور ان کے لیے پردہ کیا۔' WHERE id = 4038;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن ابی الحسین نے بیان کیا ‘ کہا ہم سے عمر بن حفص نے بیان کیا ‘ کہا مجھ سے میرے والد نے ‘ ان سے ابوعاصم نے بیان کیا ‘ ان سے عامر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ مجھے معلوم نہیں کہ آیا نبی کریم صلی اللہ علیہ وسلم نے گدھے کا گوشت کھانے سے اس لیے منع کیا تھا کہ اس سے بوجھ ڈھونے والے کا کام لیا جاتا ہے اور آپ نے پسند نہیں فرمایا کہ بوجھ ڈھونے والے جانور ختم ہو جائیں یا آپ نے صرف غزوہ خیبر کے موقع پر پالتو گدھوں کے گوشت کی ممانعت کی تھی۔' WHERE id = 4050;
UPDATE hadiths SET urdu = 'مجھ سے علی بن عبداللہ نے بیان کیا ‘ کہا ہم سے سفیان نے بیان کیا ‘ کہا کہ میں نے زہری سے سنا اور ان سے اسماعیل بن امیہ نے سوال کیا تھا تو انہوں نے بیان کیا کہ مجھے عنبسہ بن سعید نے خبر دی کہ ابوہریرہ رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ سے ( خیبر کی غنیمت میں سے ) حصہ مانگا۔ سعید بن عاص کے ایک لڑکے ( ابان بن سعید رضی اللہ عنہ ) نے کہا: یا رسول اللہ! انہیں نہ دیجئیے۔ اس پر ابوہریرہ رضی اللہ عنہ نے کہا کہ یہ شخص تو ابن قوقل کا قاتل ہے۔ ابان رضی اللہ عنہ اس پر بولے حیرت ہے اس «وبر» ( بلی سے چھوٹا ایک جانور ) پر جو قدوم الضان پہاڑی سے اتر آیا ہے۔' WHERE id = 4060;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ ان سے اسماعیل بن ابی خالد نے ‘ انہوں نے عبداللہ بن ابی اوفی رضی اللہ عنہما سے سنا ‘ وہ بیان کرتے تھے کہ جب رسول اللہ صلی اللہ علیہ وسلم نے عمرہ کیا تو ہم آپ پر آڑ کئے ہوئے مشرکین کے لڑکوں اور مشرکین سے آپ کی حفاظت کرتے رہتے تھے تاکہ وہ آپ کو کوئی ایذا نہ دے سکیں۔' WHERE id = 4074;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ ان سے اسماعیل بن ابی خالد نے ‘ ان سے قیس بن ابی حازم نے بیان کیا کہ میں نے خالد بن ولید رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ غزوہ موتہ میں میرے ہاتھ نو تلواریں ٹوٹی تھیں۔ صرف ایک یمن کا بنا ہوا چوڑے پھل کا تیغہ باقی رہ گیا تھا۔' WHERE id = 4084;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا ‘ کہا ہم سے لیث بن مسعود نے ‘ کہا کہ مجھ سے عقیل بن خالد نے بیان کیا ‘ ان سے ابن شہاب نے ‘ کہا کہ مجھے عبیداللہ بن عبداللہ بن عتبہ نے خبر دی اور انہیں ابن عباس رضی اللہ عنہما نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم نے غزوہ فتح مکہ رمضان میں کیا تھا۔ زہری نے ابن سعد سے بیان کیا کہ میں نے سعید بن مسیب سے سنا کہ وہ بھی اسی طرح بیان کرتے تھے۔ زہری نے عبیداللہ سے روایت کیا ‘ ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ ( غزوہ فتح کے سفر میں جاتے ہوئے ) رسول اللہ صلی اللہ علیہ وسلم روزے سے تھے لیکن جب آپ مقام کدید پہنچے ‘ جو قدید اور عسفان کے درمیان ایک چشمہ ہے تو آپ صلی اللہ علیہ وسلم نے روزہ توڑ دیا۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے روزہ نہیں رکھا یہاں تک کہ رمضان کا مہینہ ختم ہو گیا۔' WHERE id = 4094;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا ‘ کہا ہم کو سلیمان بن عیینہ نے خبر دی ‘ انہیں ابن ابی نجیح نے ‘ انہیں مجاہد نے ‘ انہیں ابومعمر نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ فتح مکہ کے دن جب نبی کریم صلی اللہ علیہ وسلم مکہ میں داخل ہوئے تو بیت اللہ کے چاروں طرف تین سو ساٹھ بت تھے۔ نبی کریم صلی اللہ علیہ وسلم ایک چھڑی سے جو دست مبارک میں تھی ‘ مارتے جاتے تھے اور اس آیت کی تلاوت کرتے جاتے «جاء الحق وزهق الباطل،‏‏‏‏ ‏‏‏‏ جاء الحق،‏‏‏‏ ‏‏‏‏ وما يبدئ الباطل وما يعيد» کہ ”حق قائم ہو گیا اور باطل مغلوب ہو گیا ‘ حق قائم ہو گیا اور باطل سے نہ شروع میں کچھ ہو سکا ہے نہ آئندہ کچھ ہو سکتا ہے۔“' WHERE id = 4105;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا ‘ کہا ہم سے سفیان ثوری نے بیان کیا (دوسری سند) اور ہم سے قبیصہ بن عقبہ نے بیان کیا ‘ کہا ہم سے سفیان ثوری نے بیان کیا ‘ ان سے یحییٰ بن ابی اسحاق نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ( مکہ میں ) دس دن ٹھہرے تھے اور اس مدت میں ہم نماز قصر کرتے تھے۔' WHERE id = 4115;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن یزید نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن حمزہ نے بیان کیا، انہوں نے کہا کہ مجھ سے ابوعمرو اوزاعی نے بیان کیا، ان سے عبدہ بن ابی لبابہ نے، ان سے مجاہد بن جبر مکی نے کہ عبداللہ بن عمر رضی اللہ عنہما کہا کرتے تھے کہ فتح مکہ کے بعد ہجرت باقی نہیں رہی۔' WHERE id = 4127;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے برید بن عبداللہ نے، ان سے ابوبردہ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ جب رسول اللہ صلی اللہ علیہ وسلم غزوہ حنین سے فارغ ہو گئے تو آپ نے ایک دستے کے ساتھ ابوعامر رضی اللہ عنہ کو وادی اوطاس کی طرف بھیجا۔ اس معرکہ میں درید ابن الصمہ سے مقابلہ ہوا۔ درید قتل کر دیا گیا اور اللہ تعالیٰ نے اس کے لشکر کو شکست دے دی۔ ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ ابوعامر رضی اللہ عنہ کے ساتھ نبی کریم صلی اللہ علیہ وسلم نے مجھے بھی بھیجا تھا۔ ابوعامر رضی اللہ عنہ کے گھٹنے میں تیر آ کر لگا۔ بنی جعشم کے ایک شخص نے ان پر تیر مارا تھا اور ان کے گھٹنے میں اتار دیا تھا۔ میں ان کے پاس پہنچا اور کہا:چچا! یہ تیر آپ پر کس نے پھینکا؟ انہوں نے ابوموسیٰ رضی اللہ عنہ کو اشارے سے بتایا کہ وہ جعشمی میرا قاتل ہے جس نے مجھے نشانہ بنایا ہے۔ میں اس کی طرف لپکا اور اس کے قریب پہنچ گیا لیکن جب اس نے مجھے دیکھا تو وہ بھاگ پڑا میں نے اس کا پیچھا کیا اور میں یہ کہتا جاتا تھا، تجھے شرم نہیں آتی، تجھ سے مقابلہ نہیں کیا جاتا۔ آخر وہ رک گیا اور ہم نے ایک دوسرے پر تلوار سے وار کیا۔ میں نے اسے قتل کر دیا اور ابوعامر رضی اللہ عنہ سے جا کر کہا کہ اللہ نے آپ کے قاتل کو قتل کروا دیا۔ انہوں نے فرمایا کہ میرے ( گھٹنے میں سے ) تیر نکال لے، میں نے نکال دیا تو اس سے پانی جاری ہو گیا پھر انہوں نے فرمایا: بھتیجے! نبی کریم صلی اللہ علیہ وسلم کو میرا سلام پہنچانا اور عرض کرنا کہ میرے لیے مغفرت کی دعا فرمائیں۔ ابوعامر رضی اللہ عنہ نے لوگوں پر مجھے اپنا نائب بنا دیا۔ اس کے بعد وہ تھوڑی دیر اور زندہ رہے اور شہادت پائی۔ میں واپس ہوا اور نبی کریم صلی اللہ علیہ وسلم کی خدمت میں پہنچا۔ آپ اپنے گھر میں بانوں کی ایک چارپائی پر تشریف فرما تھے۔ اس پر کوئی بستر بچھا ہوا نہیں تھا اور بانوں کے نشانات آپ کی پیٹھ اور پہلو پر پڑ گئے تھے۔ میں نے آپ سے اپنے اور ابوعامر رضی اللہ عنہ کے واقعات بیان کئے اور یہ کہ انہوں نے دعا مغفرت کے لیے درخواست کی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے پانی طلب فرمایا اور وضو کیا پھر ہاتھ اٹھا کر دعا کی، اے اللہ! عبید ابوعامر کی مغفرت فرما۔ میں نے آپ صلی اللہ علیہ وسلم کی بغل میں سفیدی ( جب آپ دعا کر رہے تھے ) دیکھی۔ پھر نبی کریم صلی اللہ علیہ وسلم نے دعا کی، اے اللہ! قیامت کے دن ابوعامر کو اپنی بہت سی مخلوق سے بلند تر درجہ عطا فرمائیو۔ میں نے عرض کیا اور میرے لیے بھی اللہ سے مغفرت کی دعا فرما دیجئیے۔ آپ صلی اللہ علیہ وسلم نے دعا کی اے اللہ! عبداللہ بن قیس ابوموسیٰ کے گناہوں کو بھی معاف فرما اور قیامت کے دن اچھا مقام عطا فرمائیو۔ ابوبردہ نے بیان کیا کہ ایک دعا ابوعامر رضی اللہ عنہ کے لیے تھی اور دوسری ابوموسیٰ رضی اللہ عنہ کے لیے۔' WHERE id = 4138;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے اعمش نے، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ جب رسول اللہ صلی اللہ علیہ وسلم حنین کے مال غنیمت کی تقسیم کر رہے تھے تو انصار کے ایک شخص نے ( جو منافق تھا ) کہا کہ اس تقسیم میں اللہ کی خوشنودی کا کوئی خیال نہیں رکھا گیا۔ میں نے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو کر آپ صلی اللہ علیہ وسلم کو اس بدگو کی اطلاع دی تو آپ صلی اللہ علیہ وسلم کے چہرہ مبارک کا رنگ بدل گیا پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ موسیٰ علیہ السلام پر رحم فرمائے، انہیں اس سے بھی زیادہ دکھ پہنچایا گیا پس انہوں نے صبر کیا۔' WHERE id = 4149;
UPDATE hadiths SET urdu = 'مجھ سے احمد بن عثمان بن حکیم نے بیان کیا، کہا ہم سے شریح بن مسلمہ نے بیان کیا، کہا ہم سے ابراہیم بن یوسف بن اسحاق بن ابی اسحاق نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، ان سے ابواسحاق نے کہا کہ میں نے براء بن عازب رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے ہمیں خالد بن ولید رضی اللہ عنہ کے ساتھ یمن بھیجا، بیان کیا کہ پھر اس کے بعد ان کی جگہ علی رضی اللہ عنہ کو بھیجا اور آپ نے انہیں ہدایت کی کہ خالد کے ساتھیوں سے کہو کہ جو ان میں سے تمہارے ساتھ یمن میں رہنا چاہے وہ تمہارے ساتھ پھر یمن کو لوٹ جائے اور جو وہاں سے واپس آنا چاہے وہ چلا آئے۔ براء رضی اللہ عنہ کہتے ہیں کہ میں ان لوگوں میں سے تھا جو یمن کو لوٹ گئے۔ انہوں نے بیان کیا کہ مجھے غنیمت میں کئی اوقیہ چاندی کے ملے تھے۔' WHERE id = 4161;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا کہ ہم نے عمرو بن دینار سے جو یاد کیا وہ یہ ہے کہ انہوں نے بیان کیا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ ہمیں رسول اللہ صلی اللہ علیہ وسلم نے تین سو سواروں کے ساتھ بھیجا اور ہمارا امیر ابوعبیدہ بن جراح رضی اللہ عنہ کو بنایا۔ تاکہ ہم قریش کے قافلہ تجارت کی تلاش میں رہیں۔ ساحل سمندر پر ہم پندرہ دن تک پڑاؤ ڈالے رہے۔ ہمیں ( اس سفر میں ) بڑی سخت بھوک اور فاقے کا سامنا کرنا پڑا، یہاں تک نوبت پہنچی کہ ہم نے ببول کے پتے کھا کر وقت گذارا۔ اسی لیے اس فوج کا لقب پتوں کی فوج ہو گیا۔ پھر اتفاق سے سمندر نے ہمارے لیے ایک مچھلی جیسا جانور ساحل پر پھینک دیا، اس کا نام عنبر تھا، ہم نے اس کو پندرہ دن تک کھایا اور اس کی چربی کو تیل کے طور پر ( اپنے جسموں پر ) ملا۔ اس سے ہمارے بدن کی طاقت و قوت پھر لوٹ آئی۔ بعد میں ابوعبیدہ رضی اللہ عنہ نے اس کی ایک پسلی نکال کر کھڑی کروائی اور جو لشکر میں سب سے لمبے آدمی تھے، انہیں اس کے نیچے سے گزارا۔ سفیان بن عیینہ نے ایک مرتبہ اس طرح بیان کیا کہ ایک پسلی نکال کر کھڑی کر دی اور ایک شخص کو اونٹ پر سوار کرایا وہ اس کے نیچے سے نکل گیا۔ جابر رضی اللہ عنہ نے بیان کیا کہ لشکر کے ایک آدمی نے پہلے تین اونٹ ذبح کئے پھر تین اونٹ ذبح کئے اور جب تیسری مرتبہ تین اونٹ ذبح کئے تو ابوعبیدہ نے انہیں روک دیا کیونکہ اگر سب اونٹ ذبح کر دیتے تو سفر کیسے ہوتا اور عمرو بن دینار نے بیان کیا کہ ہم کو ابوصالح ذکوان نے خبر دی کہ قیس بن سعد رضی اللہ عنہ نے ( واپس آ کر ) اپنے والد ( سعد بن عبادہ رضی اللہ عنہ ) سے کہا کہ میں بھی لشکر میں تھا جب لوگوں کو بھوک لگی تو ابوعبیدہ رضی اللہ عنہ نے کہا کہ اونٹ ذبح کرو، قیس بن سعد رضی اللہ عنہ نے بیان کیا کہ میں نے ذبح کر دیا کہا کہ پھر بھوکے ہوئے تو انہوں نے کہا کہ اونٹ ذبح کرو، میں نے ذبح کیا، بیان کیا کہ جب پھر بھوکے ہوئے تو کہا کہ اونٹ ذبح کرو، میں نے ذبح کیا، پھر بھوکے ہوئے تو کہا کہ اونٹ ذبح کرو، پھر قیس رضی اللہ عنہ نے بیان کیا کہ اس مرتبہ مجھے امیر لشکر کی طرف سے منع کر دیا گیا۔' WHERE id = 4172;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد الجعفی نے بیان کیا، کہا ہم سے ابوعامر عبدالملک نے بیان کیا، انہوں نے کہا کہ ہم سے ابراہیم نے بیان کیا، (یہ طہمان کے بیٹے ہیں۔) ان سے ابوجمرہ نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کی مسجد یعنی مسجد نبوی کے بعد سب سے پہلا جمعہ جواثی کی مسجد عبدالقیس میں قائم ہوا۔ جواثی بحرین کا ایک گاؤں تھا۔' WHERE id = 4182;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے عبدالسلام بن حرب نے بیان کیا، ان سے ایوب سختیانی نے، ان سے ابوقلابہ نے اور ان سے زہدم نے کہ جب ابوموسیٰ رضی اللہ عنہ ( کوفہ کے امیر بن کر عثمان رضی اللہ عنہ کے عہد خلافت میں ) آئے تو اس قبیلہ جرم کا انہوں نے بہت اعزاز کیا۔ زہدم کہتے ہیں ہم آپ کی خدمت میں بیٹھے ہوئے تھے اور وہ مرغ کا ناشتہ کر رہے تھے۔ حاضرین میں ایک اور صاحب بھی بیٹھے ہوئے تھے۔ ابوموسیٰ رضی اللہ عنہ نے انہیں بھی کھانے پر بلایا تو ان صاحب نے کہا کہ جب سے میں نے مرغیوں کو کچھ ( گندی ) چیزیں کھاتے دیکھا ہے، اسی وقت سے مجھے اس کے گوشت سے گھن آنے لگی ہے۔ ابوموسیٰ رضی اللہ عنہ نے کہا کہ آؤ بھائی میں نے رسول اللہ صلی اللہ علیہ وسلم کو اس کا گوشت کھاتے دیکھا ہے۔ ان صاحب نے کہا لیکن میں نے اس کا گوشت نہ کھانے کی قسم کھا رکھی ہے۔ انہوں نے کہا کہ تم آ تو جاؤ میں تمہیں تمہاری قسم کے بارے میں بھی علاج بتاؤں گا۔ ہم قبیلہ اشعر کے چند لوگ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ سے ( غزوہ تبوک کے لیے ) جانور مانگے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ سواری نہیں ہے۔ ہم نے پھر آپ سے مانگا تو آپ نے اس مرتبہ قسم کھائی کہ آپ ہم کو سواری نہیں دیں گے لیکن ابھی کچھ زیادہ دیر نہیں ہوئی تھی کہ غنیمت میں کچھ اونٹ آئے اور نبی کریم صلی اللہ علیہ وسلم نے ان میں سے پانچ اونٹ ہم کو دلائے۔ جب ہم نے انہیں لے لیا تو پھر ہم نے کہا کہ یہ تو ہم نے نبی کریم صلی اللہ علیہ وسلم کو دھوکا دیا۔ آپ کو غفلت میں رکھا، قسم یاد نہیں دلائی۔ ایسی حالت میں ہماری بھلائی کبھی نہیں ہو گی۔ آخر میں آپ کے پاس آیا اور میں نے کہا: یا رسول اللہ! آپ نے تو قسم کھا لی تھی کہ آپ ہم کو سواری نہیں دیں گے پھر آپ نے سواری دے دی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ٹھیک ہے لیکن جب بھی میں کوئی قسم کھاتا ہوں اور اس کے سوا دوسری صورت مجھے اس سے بہتر نظر آتی ہے تو میں وہی کرتا ہوں جو بہتر ہوتا ہے ( اور قسم کا کفارہ دے دیتا ہوں ) ۔' WHERE id = 4193;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ حجۃ الوداع کے موقع پر ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ روانہ ہوئے۔ ہم نے عمرہ کا احرام باندھا تھا پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ جس کے ساتھ ہدی ہو وہ عمرہ کے ساتھ حج کا بھی احرام باندھ لے اور جب تک دونوں کے ارکان نہ ادا کر لے احرام نہ کھولے۔ پھر میں آپ صلی اللہ علیہ وسلم کے ساتھ جب مکہ آئی تو مجھ کو حیض آ گیا۔ اس لیے نہ بیت اللہ کا طواف کر سکی اور نہ صفا اور مروہ کی سعی کر سکی۔ میں نے اس کی شکایت آپ صلی اللہ علیہ وسلم سے کی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ سر کھول لے اور کنگھا کر لے۔ اس کے بعد حج کا احرام باندھ لو اور عمرہ چھوڑ دو۔ میں نے ایسا ہی کیا۔ پھر جب ہم حج ادا کر چکے تو نبی کریم صلی اللہ علیہ وسلم نے مجھے ( میرے بھائی ) عبدالرحمٰن بن ابی بکر رضی اللہ عنہما کے ساتھ تنعیم سے ( عمرہ کی ) نیت کرنے کے لیے بھیجا اور میں نے عمرہ کیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ تمہارے اس چھوٹے ہوئے عمرہ کی قضاء ہے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ جن لوگوں نے صرف عمرہ کا احرام باندھا تھا۔ انہوں نے بیت اللہ کے طواف اور صفا اور مروہ کی سعی کے بعد احرام کھول دیا۔ پھر منیٰ سے واپسی کے بعد انہوں نے دوسرا طواف ( حج کا ) کیا، لیکن جن لوگوں نے حج اور عمرہ دونوں کا احرام ایک ساتھ باندھا تھا، انہوں نے ایک ہی طواف کیا۔' WHERE id = 4203;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے قیس بن مسلم نے، ان سے طارق بن شہاب نے کہ چند یہودیوں نے کہا کہ اگر یہ آیت ہمارے یہاں نازل ہوئی ہوتی تو ہم اس دن عید منایا کرتے۔ عمر رضی اللہ عنہ نے فرمایا، کون سی آیت؟ انہوں نے کہا «اليوم أكملت لكم دينكم وأتممت عليكم نعمتي‏» ”آج میں نے تم پر اپنے دین کو مکمل کیا اور اپنی نعمت تم پر پوری کر دی۔“ اس پر عمر رضی اللہ عنہ نے فرمایا کہ مجھے خوب معلوم ہے کہ یہ آیت کہاں نازل ہوئی تھی۔ جب یہ آیت نازل ہوئی تو رسول صلی اللہ علیہ وسلم میدان عرفات میں کھڑے ہوئے تھے ( یعنی حجۃ الوداع میں ) ۔' WHERE id = 4214;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن سعید نے بیان کیا، کہا ہم سے محمد بن بکر نے بیان کیا، کہا ہم کو ابن جریج نے خبر دی، کہا کہ میں نے عطاء سے سنا، انہوں نے خبر دیتے ہوئے کہا کہ مجھے صفوان بن یعلٰی بن امیہ نے خبر دی اور ان سے ان کے والد نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ غزوہ عسرت میں شریک تھا۔ بیان کیا کہ یعلٰی رضی اللہ عنہ کہا کرتے تھے کہ مجھے اپنے تمام عملوں میں اسی پر سب سے زیادہ بھروسہ ہے۔ عطاء نے بیان کیا، ان سے صفوان نے بیان کیا کہ یعلٰی رضی اللہ عنہ نے کہا، میں نے ایک مزدور بھی اپنے ساتھ لے لیا تھا۔ وہ ایک شخص سے لڑ پڑا اور ایک نے دوسرے کا ہاتھ دانت سے کاٹا۔ عطاء نے بیان کیا کہ مجھے صفوان رضی اللہ عنہ نے خبر دی کہ ان دونوں میں سے کس نے اپنے مقابل کا ہاتھ کاٹا تھا، یہ مجھے یاد نہیں ہے۔ بہرحال جس کا ہاتھ کاٹا گیا تھا اس نے اپنا ہاتھ کاٹنے والے کے منہ سے جو کھینچا تو کاٹنے والے کے آگے کا ایک دانت بھی ساتھ چلا آیا۔ وہ دونوں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے تو آپ صلی اللہ علیہ وسلم نے دانت کے ٹوٹنے پر کوئی قصاص نہیں دلوایا۔ عطاء نے بیان کیا میرا خیال ہے کہ انہوں نے یہ بھی بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا پھر کیا وہ تیرے منہ میں اپنا ہاتھ رہنے دیتا تاکہ تو اسے اونٹ کی طرح چبا جاتا۔' WHERE id = 4224;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے زہری نے اور ان سے سائب بن یزید رضی اللہ عنہ نے کہ مجھے یاد ہے، جب میں بچوں کے ساتھ نبی کریم صلی اللہ علیہ وسلم کا استقبال کرنے گیا تھا۔ آپ صلی اللہ علیہ وسلم غزوہ تبوک سے واپس تشریف لا رہے تھے۔' WHERE id = 4234;
UPDATE hadiths SET urdu = 'مجھ سے حبان بن موسیٰ مروزی نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں یونس نے خبر دی، انہیں ابن شہاب نے کہا کہ مجھے عروہ بن زبیر نے خبر دی اور انہیں عائشہ رضی اللہ عنہا نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم جب بیمار پڑتے تو اپنے اوپر معوذتین ( سورۃ الفلق اور سورۃ الناس ) پڑھ کر دم کر لیا کرتے تھے اور اپنے جسم پر اپنے ہاتھ پھیر لیا کرتے تھے، پھر جب وہ مرض آپ کو لاحق ہوا جس میں آپ کی وفات ہوئی تو میں معوذتین پڑھ کر آپ پر دم کیا کرتی تھی اور ہاتھ پر دم کر کے نبی کریم صلی اللہ علیہ وسلم کے جسم پر پھیرا کرتی تھی۔' WHERE id = 4245;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب نے، ان سے ابن ابی ملیکہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کی وفات میرے گھر میں، میری باری کے دن ہوئی۔ آپ اس وقت میرے سینے سے ٹیک لگائے ہوئے تھے۔ جب آپ بیمار پڑے تو ہم آپ کی صحت کے لیے دعائیں کیا کرتے تھے۔ اس بیماری میں بھی میں آپ کے لیے دعا کرنے لگی لیکن آپ صلی اللہ علیہ وسلم فرما رہے تھے اور آپ کا سر آسمان کی طرف اٹھا ہوا تھا «في الرفيق الأعلى في الرفيق الأعلى» اور عبدالرحمٰن بن ابی بکر رضی اللہ عنہما آئے تو ان کے ہاتھ میں ایک تازہ ٹہنی تھی۔ آپ صلی اللہ علیہ وسلم نے اس کی طرف دیکھا تو میں سمجھ گئی کہ آپ صلی اللہ علیہ وسلم مسواک کرنا چاہتے ہیں۔ چنانچہ وہ ٹہنی میں نے ان سے لے لی۔ پہلے میں نے اسے چبایا، پھر صاف کر کے آپ کو دے دی۔ آپ صلی اللہ علیہ وسلم نے اس سے مسواک کی، جس طرح پہلے آپ مسواک کیا کرتے تھے اس سے بھی اچھی طرح سے۔ پھر آپ صلی اللہ علیہ وسلم نے وہ مسواک مجھے عنایت فرمائی اور آپ کا ہاتھ جھک گیا، یا ( راوی نے یہ بیان کیا کہ ) مسواک آپ کے ہاتھ سے چھوٹ گئی۔ اس طرح اللہ تعالیٰ نے میرے اور آپ صلی اللہ علیہ وسلم کے تھوک کو اس دن جمع کر دیا جو آپ کی دنیا کی زندگی کا سب سے آخری اور آخرت کی زندگی کا سب سے پہلا دن تھا۔' WHERE id = 4256;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے عبداللہ بن دینار نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک لشکر روانہ فرمایا اور اس کا امیر اسامہ بن زید رضی اللہ عنہما کو بنایا۔ بعض لوگوں نے ان کی امارت پر اعتراض کیا۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے صحابہ رضی اللہ عنہم کو خطاب کیا اور فرمایا کہ اگر آج تم اس کی امارت پر اعتراض کرتے ہو تو تم اس سے پہلے اس کے والد کی امارت پر اسی طرح اعتراض کر چکے ہو اور اللہ کی قسم! اس کے والد ( زید رضی اللہ عنہ ) امارت کے بہت لائق تھے اور مجھے سب سے زیادہ عزیز تھے اور یہ ( یعنی اسامہ رضی اللہ عنہ ) بھی ان کے بعد مجھے سب سے زیادہ عزیز ہے۔' WHERE id = 4269;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن سلام نے بیان کیا، کہا کہ ہم سے عبدالرحمٰن بن مہدی نے، ان سے عبداللہ بن مبارک نے، ان سے معمر نے، ان سے ہمام بن منبہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بنی اسرائیل کو یہ حکم ہوا تھا کہ شہر کے دروازے میں جھکتے ہوئے داخل ہوں اور «حطة‏» کہتے ہوئے ( یعنی ) ”اے اللہ! ہمارے گناہ معاف کر دے۔“ لیکن وہ الٹے چوتڑوں کے بل گھسٹتے ہوئے داخل ہوئے اور کلمہ «حطة‏» کو بھی بدل دیا اور کہا کہ «حبة في شعرة» یعنی دل لگی کے طور پر کہنے لگے کہ ”دانہ بال کے اندر ہونا چاہیے۔“' WHERE id = 4279;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے معتمر نے بیان کیا، ان سے ان کے والد نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ میرے سوا ان صحابہ رضی اللہ عنہم میں سے جنہوں نے دونوں قبلوں کی طرف نماز پڑھی تھی اور کوئی اب زندہ نہیں رہا۔' WHERE id = 4289;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ انصاری نے بیان کیا، کہا ہم سے حمیدی نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کتاب اللہ کا حکم قصاص کا ہے۔' WHERE id = 4299;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے حصین بن عبدالرحمٰن نے، ان سے عامر شعبی نے عدی بن حاتم رضی اللہ عنہ سے، انہوں نے بیان کیا کہ انھوں نے ایک سفید دھاگا اور ایک سیاہ دھاگا لیا ( اور سوتے ہوئے اپنے ساتھ رکھ لیا ) ۔ جب رات کا کچھ حصہ گزر گیا تو انہوں نے اسے دیکھا، وہ دونوں میں تمیز نہیں ہوئی۔ جب صبح ہوئی تو عرض کیا: یا رسول اللہ! میں نے اپنے تکئے کے نیچے ( سفید و سیاہ دھاگے رکھے تھے اور کچھ نہیں ہوا ) تو نبی کریم صلی اللہ علیہ وسلم نے اس پر بطور مذاق کے فرمایا کہ پھر تو تمہارا تکیہ بہت لمبا چوڑا ہو گا کہ صبح کا سفیدی خط اور سیاہ خط اس کے نیچے آ گیا تھا۔' WHERE id = 4309;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، ان سے عبدالعزیز نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم دعا کرتے تھے ” «اللهم ربنا آتنا في الدنيا حسنة وفي الآخرة حسنة وقنا عذاب النار» ”اے پروردگار! ہمارے! ہم کو دنیا میں بھی بہتری دے اور آخرت میں بھی بہتری اور ہم کو دوزخ کے عذاب سے بچائیو۔“' WHERE id = 4320;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن ابی اسود نے بیان کیا، کہا ہم سے حمید بن اسود اور یزید بن زریع نے بیان کیا، کہا کہ ہم سے حبیب بن شہید نے بیان کیا، ان سے ابن ابی ملیکہ نے بیان کیا کہ ابن زبیر رضی اللہ عنہما نے عثمان بن عفان رضی اللہ عنہ سے کہا کہ سورۃ البقرہ کی آیت «والذين يتوفون منكم ويذرون أزواجا‏» یعنی ”جو لوگ تم میں سے وفات پا جائیں اور بیویاں چھوڑ جائیں۔“ اللہ تعالیٰ کے فرمان «غير إخراج‏» تک کو دوسری آیت نے منسوخ کر دیا ہے۔ اس کو آپ نے مصحف میں کیوں لکھوایا، چھوڑ کیوں نہیں دیا؟ انہوں نے کہا: میرے بھتیجے! میں کسی آیت کو اس کے ٹھکانے سے بدلنے والا نہیں۔ یہ حمید نے کہا یا کچھ ایسا ہی جواب دیا۔' WHERE id = 4332;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن منصور نے بیان کیا، انہیں روح بن عبادہ نے خبر دی، انہیں شعبہ نے خبر دی، انہیں خالد حذاء نے، انہیں مروان اصفر نے اور انہیں نبی کریم صلی اللہ علیہ وسلم کے ایک صحابی نے، کہا کہ وہ ابن عمر رضی اللہ عنہما ہیں۔ انہوں نے آیت «إن تبدوا ما في أنفسكم أو تخفوه‏» کے متعلق بتلایا کہ اس آیت کو اس کے بعد کی آیت ( «لا يكلف الله نفسا إلا وسعها» ) نے منسوخ کر دیا ہے۔' WHERE id = 4342;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا عمرو بن دینار نے کہا، انہوں نے جابر بن عبداللہ انصاری رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا عمرو بن دینار نے کہا، انہوں نے جابر بن عبداللہ انصاری رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ' WHERE id = 4353;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام نے خبر دی، انہیں ابن جریج نے خبر دی، انہیں ابن ابی ملیکہ نے اور انہیں علقمہ بن وقاص نے خبر دی کہ مروان بن حکم نے ( جب وہ مدینہ کے امیر تھے ) اپنے دربان سے کہا کہ رافع! ابن عباس رضی اللہ عنہما کے یہاں جاؤ اور ان سے پوچھو کہ آیت «لا يحسبن الذين يفرحون‏» کی رو سے تو ہم سب کو عذاب ہونا چاہیئے کیونکہ ہر ایک آدمی ان نعمتوں پر جو اس کو ملی ہیں، خوش ہے اور یہ چاہتا ہے کہ جو کام اس نے کیا نہیں اس پر بھی اس کی تعریف ہو۔ ابورافع نے ابن عباس رضی اللہ عنہما سے جا کر پوچھا، تو ابن عباس رضی اللہ عنہما نے کہا، تم مسلمانوں سے اس آیت کا کیا تعلق! یہ تو رسول اللہ صلی اللہ علیہ وسلم نے یہودیوں کو بلایا تھا اور ان سے ایک دین کی بات پوچھی تھی۔ ( جو ان کی آسمانی کتاب میں موجود تھی ) انہوں نے اصل بات کو تو چھپایا اور دوسری غلط بات بیان کر دی، پھر بھی اس بات کے خواہشمند رہے کہ نبی کریم صلی اللہ علیہ وسلم کے سوال کے جواب میں جو کچھ انہوں نے بتایا ہے اس پر ان کی تعریف کی جائے اور ادھر اصل حقیقت کو چھپا کر بھی بڑے خوش تھے۔ پھر ابن عباس رضی اللہ عنہما نے اس آیت کی تلاوت «وإذ أخذ الله ميثاق الذين أوتوا الكتاب‏» کی ”اور وہ وقت یاد کرو جب اللہ نے اہل کتاب سے عہد لیا تھا کہ کتاب کو پوری ظاہر کر دینا لوگوں پر، آیت «يفرحون بما أتوا ويحبون أن يحمدوا بما لم يفعلوا‏» ”جو لوگ اپنے کرتوتوں پر خوش ہیں اور چاہتے ہیں کہ جو کام نہیں کئے ہیں، ان پر بھی ان کی تعریف کی جائے۔“ تک۔ ہشام بن یوسف کے ساتھ اس حدیث کو عبدالرزاق نے بھی ابن جریج سے روایت کیا۔ ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو حجاج بن محمد نے خبر دی، انہوں نے ابن جریج سے کہا مجھ کو ابن ابی ملیکہ نے خبر دی، ان کو حمید بن عبدالرحمٰن بن عوف رضی اللہ عنہ نے کہ مروان نے اپنے دربان رافع سے کہا، پھر یہی حدیث بیان کی۔' WHERE id = 4363;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، ان سے ورقاء بن عمر یشکری نے، ان سے ابن ابی نجیح نے، ان سے عطاء نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ ابتداء اسلام میں میت کا سارا مال اولاد کو ملتا تھا، البتہ والدین کو وہ ملتا جو میت ان کے لیے وصیت کر جائے، پھر اللہ تعالیٰ نے جیسا مناسب سمجھا اس میں نسخ کر دیا۔ چنانچہ اب مرد کا حصہ دو عورتوں کے حصہ کے برابر ہے اور میت کے والدین یعنی ان دونوں میں ہر ایک کے لیے اس مال کا چھٹا حصہ ہے۔ بشرطیکہ میت کے کوئی اولاد ہو، لیکن اگر اس کے کوئی اولاد نہ ہو، بلکہ اس کے والدین ہی اس کے وارث ہوں تو اس کی ماں کا ایک تہائی حصہ ہو گا اور بیوی کا آٹھواں حصہ ہو گا، جبکہ اولاد ہو، لیکن اگر اولاد نہ ہو تو چوتھائی ہو گا اور شوہر کا آدھا حصہ ہو گا، جبکہ اولاد نہ ہو لیکن اگر اولاد ہو تو چوتھائی ہو گا۔' WHERE id = 4373;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب نے، ان سے ابن ابی ملیکہ نے کہ ابن عباس رضی اللہ عنہما نے آیت «لا المستضعفين من الرجال والنساء والولدان‏» کی تلاوت کی اور فرمایا کہ میں اور میری والدہ بھی ان لوگوں میں سے تھیں، جنہیں اللہ تعالیٰ نے معذور رکھا تھا۔ اور ابن عباس رضی اللہ عنہما سے روایت ہے کہ «حصرت‏» معنی میں «ضاقت» کے ہے۔ «تلووا‏» یعنی تمہاری زبانوں سے گواہی ادا ہو گی۔ اور ابن عباس رضی اللہ عنہما کے سوا دوسرے شخص ( ابوعبیدہ رضی اللہ عنہ ) نے کہا «مراغم» کا معنی ہجرت کا مقام۔ عرب لوگ کہتے ہیں «راغمت قومي‏.‏» یعنی میں نے اپنی قوم والوں کو جمع کر دیا۔ «موقوتا‏» کے معنی ایک وقت مقررہ پر یعنی جو وقت ان کے لیے مقرر ہو۔' WHERE id = 4383;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا ہم سے شیبان نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے ابوسلمہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے عشاء کی نماز میں ( رکوع سے اٹھتے ہوئے ) «سمع الله لمن حمده‏ ‏‏.‏» کہا اور پھر سجدہ میں جانے سے پہلے یہ دعا کی ”اے اللہ! عیاش بن ابی ربیعہ کو نجات دے۔ اے اللہ! سلمہ بن ہشام کو نجات دے۔ اے اللہ! ولید بن ولید کو نجات دے۔ اے اللہ کمزور مومنوں کو نجات دے۔ اے اللہ! کفار مضر کو سخت سزا دے۔ اے اللہ انہیں ایسی قحط سالی میں مبتلا کر جیسی یوسف علیہ السلام کے زمانے میں قحط سالی آئی تھی۔“' WHERE id = 4393;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا کہ مجھ سے عبداللہ بن وہب نے بیان کیا، کہا کہ مجھے عمرو بن حارث نے خبر دی، ان سے عبدالرحمٰن بن قاسم نے بیان کیا، ان سے ان کے والد قاسم نے اور ان سے عائشہ رضی اللہ عنہا نے کہ میرا ہار مقام بیداء میں گم ہو گیا تھا۔ ہم مدینہ واپس آ رہے تھے، نبی کریم صلی اللہ علیہ وسلم نے وہیں اپنی سواری روک دی اور اتر گئے، پھر نبی کریم صلی اللہ علیہ وسلم سر مبارک میری گود میں رکھ کر سو رہے تھے کہ ابوبکر رضی اللہ عنہ اندر آ گئے اور میرے سینے پر زور سے ہاتھ مار کر فرمایا کہ ایک ہار کے لیے تم نے نبی کریم صلی اللہ علیہ وسلم کو روک لیا لیکن نبی کریم صلی اللہ علیہ وسلم کے آرام کے خیال سے میں بےحس و حرکت بیٹھی رہی حالانکہ مجھے تکلیف ہوئی تھی۔ پھر نبی کریم صلی اللہ علیہ وسلم بیدار ہوئے اور صبح کا وقت ہوا اور پانی کی تلاش ہوئی لیکن کہیں پانی کا نام و نشان نہ تھا۔ اسی وقت یہ آیت اتری «يا أيها الذين آمنوا إذا قمتم إلى الصلاة‏» الخ۔ اسید بن حضیر رضی اللہ عنہ نے کہا: اے آل ابی بکر! تمہیں اللہ تعالیٰ نے لوگوں کے لیے باعث برکت بنایا ہے۔ یقیناً تم لوگوں کے لیے باعث برکت ہو۔ تمہارا ہار گم ہوا اللہ نے اس کی وجہ سے تیمم کی آیت نازل فرما دی جو قیامت تک مسلمانوں کے لیے آسانی اور برکت ہے۔' WHERE id = 4403;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، کہا ہم کو ابن عیینہ نے خبر دی، انہیں عمرو نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ غزوہ احد میں بہت سے صحابہ رضی اللہ عنہم نے صبح صبح شراب پی تھی اور اسی دن وہ سب شہید کر دیئے گئے تھے۔ اس وقت شراب حرام نہیں ہوئی تھی ( اس لیے وہ گنہگار نہیں ٹھہرے ) ۔' WHERE id = 4413;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، انہوں نے کہا ہم سے حماد بن زید نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ جب یہ آیت «قل هو القادر على أن يبعث عليكم عذابا من فوقكم‏» نازل ہوئی تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اے اللہ! میں تیرے منہ کی پناہ مانگتا ہوں۔ پھر یہ اترا «أو من تحت أرجلكم‏» آپ صلی اللہ علیہ وسلم نے فرمایا کہ یا اللہ! میں تیرے منہ کی پناہ مانگتا ہوں۔ پھر یہ اترا «أو يلبسكم شيعا ويذيق بعضكم بأس بعض‏» اس وقت نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ پہلے عذابوں سے ہلکا یا آسان ہے۔' WHERE id = 4423;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، انہوں نے کہا ہم سے سفیان ثوری نے بیان کیا، ان سے عمرو بن یحییٰ مازنی نے، ان سے ان کے والد یحییٰ مازنی نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ ایک یہودی رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا، اس کے منہ پر کسی نے طمانچہ مارا تھا۔ اس نے کہا: اے محمد! آپ کے انصاری صحابہ میں سے ایک شخص نے مجھے طمانچہ مارا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں بلاؤ۔ لوگوں نے انہیں بلایا، پھر آپ صلی اللہ علیہ وسلم نے ان سے پوچھا تم نے اسے طمانچہ کیوں مارا ہے؟ اس نے عرض کیا: یا رسول اللہ! میں یہودیوں کی طرف سے گزرا تو میں نے سنا کہ یہ کہہ رہا تھا۔ اس ذات کی قسم! جس نے موسیٰ علیہ السلام کو تمام انسانوں پر فضیلت دی۔ میں نے کہا اور محمد صلی اللہ علیہ وسلم پر بھی۔ مجھے اس کی بات پر غصہ آ گیا اور میں نے اسے طمانچہ مار دیا۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ مجھے انبیاء پر فضیلت نہ دیا کرو۔ قیامت کے دن تمام لوگ بیہوش کر دیئے جائیں گے۔ سب سے پہلے میں ہوش میں آؤں گا لیکن میں موسیٰ علیہ السلام کو دیکھوں گا کہ وہ عرش کا ایک پایہ پکڑے کھڑے ہوں گے اب مجھے نہیں معلوم کہ وہ مجھ سے پہلے ہوش میں آ گئے یا طور کی بے ہوشی کا انہیں بدلہ دیا گیا۔' WHERE id = 4433;
UPDATE hadiths SET urdu = 'مجھ سے احمد بن نضر نے بیان کیا، کہا ہم سے عبیداللہ بن معاذ نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے صاحب الزیادی عبدالحمید نے جو کردید کے صاحبزادے تھے، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا کہ ابوجہل نے کہا تھا کہ اے اللہ! اگر یہ کلام تیری طرف سے واقعی حق ہے تو ہم پر آسمانوں سے پتھر برسا دے یا پھر کوئی اور ہی عذاب درد ناک لے آ!“ تو اس پر آیت «وما كان الله ليعذبهم وأنت فيهم وما كان الله معذبهم وهم يستغفرون * وما لهم أن لا يعذبهم الله وهم يصدون عن المسجد الحرام‏» ”حالانکہ اللہ ایسا نہیں کرے گا کہ انہیں عذاب دے، اس حال میں کہ آپ ان میں موجود ہوں اور نہ اللہ ان پر عذاب لائے گا اس حال میں کہ وہ استغفار کر رہے ہوں۔ ان لوگوں کے لیے کیا وجہ کہ اللہ ان پر عذاب ( ہی سرے سے ) نہ لائے درآں حالیکہ وہ مسجد الحرام سے روکتے ہیں۔“ آخر آیت تک۔' WHERE id = 4443;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، کہا ہم سے اسماعیل بن ابی خالد نے بیان کیا، کہا ہم سے زید بن وہب نے بیان کیا کہ ہم حذیفہ بن یمان کی خدمت میں حاضر تھے۔ انہوں نے کہا یہ آیت جن لوگوں کے بارے میں اتری ان میں سے اب صرف تین شخص باقی ہیں، اسی طرح منافقوں میں سے بھی اب چار شخص باقی ہیں۔ اتنے میں ایک دیہاتی کہنے لگا آپ تو نبی کریم صلی اللہ علیہ وسلم کے صحابی ہیں، ہمیں ان لوگوں کے متعلق بتائیے کہ ان کا کیا حشر ہو گا جو ہمارے گھروں میں چھید کر کے اچھی چیزیں چرا کر لے جاتے ہیں؟ انہوں نے کہا کہ یہ لوگ فاسق بدکار ہیں۔ ہاں ان منافقوں میں چار کے سوا اور کوئی باقی نہیں رہا ہے اور ایک تو اتنا بوڑھا ہو چکا ہے کہ اگر ٹھنڈا پانی پیتا ہے تو اس کی ٹھنڈ کا بھی اسے پتہ نہیں چلتا۔' WHERE id = 4453;
UPDATE hadiths SET urdu = 'مجھ سے ابو محمد بشر بن خالد نے بیان کیا، کہا ہم کو محمد بن جعفر نے خبر دی، انہیں شعبہ نے، انہیں سلیمان اعمش نے، انہیں ابووائل نے اور ان سے ابومسعود انصاری رضی اللہ عنہ نے بیان کیا کہ جب ہمیں خیرات کرنے کا حکم ہوا تو ہم مزدوری پر بوجھ اٹھاتے ( اور اس کی مزدوری صدقہ میں دے دیتے ) چنانچہ ابوعقیل اسی مزدوری سے آدھا صاع خیرات لے کر آئے اور ایک دوسرے صحابی عبدالرحمٰن بن عوف اس سے زیادہ لائے۔ اس پر منافقوں نے کہا کہ اللہ کو اس ( یعنی عقیل ) کے صدقہ کی کوئی ضرورت نہیں تھی اور اس دوسرے ( عبدالرحمٰن بن عوف ) نے تو محض دکھاوے کے لیے اتنا بہت سا صدقہ دیا ہے۔ چنانچہ یہ آیت نازل ہوئی «الذين يلمزون المطوعين من المؤمنين في الصدقات والذين لا يجدون إلا جهدهم‏» کہ ”یہ ایسے لوگ ہیں جو صدقات کے بارے میں نفل صدقہ دینے والے مسلمانوں پر طعن کرتے ہیں اور خصوصاً ان لوگوں پر جنہیں بجز ان کی محنت مزدوری کے کچھ نہیں ملتا۔“ آخر آیت تک۔' WHERE id = 4463;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عبدالرحمٰن بن عبداللہ بن کعب بن مالک نے اور ان سے عبداللہ بن کعب بن مالک نے، وہ کعب بن مالک رضی اللہ عنہ کو ساتھ لے کر چلتے تھے۔ ( جب وہ نابینا ہو گئے تھے ) عبداللہ نے بیان کیا کہ میں نے کعب بن مالک رضی اللہ عنہ سے سنا، وہ غزوہ تبوک میں اپنی غیر حاضری کا قصہ بیان کر رہے تھے، کہا کہ اللہ کی قسم! سچ بولنے کا جتنا عمدہ پھل اللہ تعالیٰ نے مجھے دیا، کسی کو نہ دیا ہو گا۔ جب سے رسول اللہ صلی اللہ علیہ وسلم کے سامنے میں نے اس بارے میں سچی بات کہی تھی، اس وقت سے آج تک کبھی جھوٹ کا ارادہ بھی نہیں کیا اور اللہ نے اپنے رسول صلی اللہ علیہ وسلم پر یہ آیت نازل کی تھی «لقد تاب الله على النبي والمهاجرين‏» کہ ”بیشک اللہ نے نبی پر اور مہاجرین و انصار پر رحمت کے ساتھ توجہ فرمائی۔ آخر آیت «وكونوا مع الصادقين‏» تک۔' WHERE id = 4473;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا ہم سے عبدالصمد نے بیان کیا، ان سے عبدالرحمٰن بن عبداللہ بن دینار نے بیان کیا، ان سے ان کے والد نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کریم بن کریم بن کریم بن کریم یوسف بن یعقوب بن اسحاق بن ابراہیم تھے۔ ( علیہم الصلٰوۃ والسلام ) ۔' WHERE id = 4483;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، ان سے عطاء بن ابی رباح نے اور انہوں نے ابن عباس رضی اللہ عنہما سے سنا کہ آیت «ألم تر إلى الذين بدلوا نعمة الله كفرا‏» میں کفار سے اہل مکہ مراد ہیں۔' WHERE id = 4495;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا، کہا ہم سے عبداللہ بن وہب نے بیان کیا، کہا کہ مجھے یونس بن یزید نے خبر دی، انہیں ابن شہاب نے، ان سے ابوسلمہ نے بیان کیا اور انہوں نے جابر بن عبداللہ انصاری رضی اللہ عنہما سے سنا کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب قریش نے مجھ کو واقعہ معراج کے سلسلہ میں جھٹلایا تو میں ( کعبہ کے ) مقام حجر میں کھڑا ہوا تھا اور میرے سامنے پورا بیت المقدس کر دیا گیا تھا۔ میں اسے دیکھ دیکھ کر اس کی ایک ایک علامت بیان کرنے لگا۔ یعقوب بن ابراہیم نے اپنی روایت میں یہ زیادہ کیا کہ ہم سے ابن شہاب کے بھتیجے نے اپنے چچا ابن شہاب سے بیان کیا کہ ( رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ) جب مجھے قریش نے بیت المقدس کے معراج کے سلسلہ میں جھٹلایا، پھر پہلی حدیث کی طرح بیان کیا۔ «قاصفا‏» وہ آندھی جو ہر چیز کو تباہ کر دے۔' WHERE id = 4505;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، انہوں نے کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عبداللہ ابن ابی نجیح نے، ان سے مجاہد نے، ان سے ابومعمر نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جب مکہ میں ( فتح کے بعد ) داخل ہوئے تو کعبہ کے چاروں طرف تین سو ساٹھ بت تھے۔ نبی کریم صلی اللہ علیہ وسلم اپنے ہاتھ کی لکڑی سے ایک کو ٹکراتے جاتے اور پڑھتے جاتے «جاء الحق وزهق الباطل إن الباطل كان زهوقا‏»،‏‏‏‏ «جاء الحق وما يبدئ الباطل وما يعيد‏» حق آیا اور جھوٹ نابود ہوا بیشک جھوٹ نابود ہونے والا ہی تھا۔' WHERE id = 4515;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے، ہم سے اعمش نے، ہم سے ابوصالح نے بیان کیا اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ قیامت کے دن موت ایک چتکبرے مینڈھے کی شکل میں لائی جائے گی۔ ایک آواز دینے والا فرشتہ آواز دے گا کہ اے جنت والو! تمام جنتی گردن اٹھا اٹھا کر دیکھیں گے، آواز دینے والا فرشتہ پوچھے گا۔ تم اس مینڈھے کو بھی پہچانتے ہو؟ وہ بولیں گے کہ ہاں، یہ موت ہے اور ان سے ہر شخص اس کا ذائقہ چکھ چکا ہو گا۔ پھر اسے ذبح کر دیا جائے گا اور آواز دینے والا جنتیوں سے کہے گا کہ اب تمہارے لیے ہمیشگی ہے، موت تم پر کبھی نہ آئے گی اور اے جہنم والو! تمہیں بھی ہمیشہ اسی طرح رہنا ہے، تم پر بھی موت کبھی نہیں آئے گی۔ پھر آپ صلی اللہ علیہ وسلم نے یہ آیت تلاوت کی «وأنذرهم يوم الحسرة إذ قضي الأمر وهم في غفلة‏» الخ ”اور انہیں حسرت کے دن سے ڈرا دو۔ جبکہ اخیر فیصلہ کر دیا جائے گا اور یہ لوگ غفلت میں پڑے ہوئے ہیں ( یعنی دنیادار لوگ ) اور ایمان نہیں لاتے۔“' WHERE id = 4525;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے مغیرہ بن نعمان نے جو قبیلہ نخعی کا ایک بوڑھا تھا، ان سے سعید بن جبیر نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک دن خطبہ سنایا۔ فرمایا تم قیامت کے دن اللہ کے سامنے ننگے پاؤں ننگے بدن بےختنہ حشر کئے جاؤ گے جیسا کہ ارشاد باری ہے «كما بدأنا أول خلق نعيده وعدا علينا إنا كنا فاعلين‏» پھر سب سے پہلے قیامت کے دن ابراہیم علیہ السلام کو کپڑے پہنائے جائیں گے۔ سن لو! میری امت کے کچھ لوگ لائے جائیں گے فرشتے ان کو پکڑ کر بائیں طرف والے دوزخیوں میں لے جائیں گے۔ میں عرض کروں گا پروردگار! یہ تو میرے ساتھ والے ہیں۔ ارشاد ہو گا تم نہیں جانتے انہوں نے تمہاری وفات کے بعد کیا کیا کرتوت کئے ہیں۔ اس وقت میں وہی کہوں گا جو اللہ کے نیک بندے عیسیٰ علیہ السلام نے کہا کہ میں جب تک ان لوگوں میں رہا ان کا حال دیکھتا رہا آخر آیت تک۔ ارشاد ہو گا یہ لوگ اپنی ایڑیوں کے بل اسلام سے پھر گئے جب تو ان سے جدا ہوا۔' WHERE id = 4535;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے یونس بن یزید نے، ان سے ابن شہاب نے بیان کیا، انہیں عروہ بن زبیر، سعید بن مسیب، علقمہ بن وقاص اور عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا پر تہمت لگانے کا واقعہ بیان کیا۔ یعنی جس میں تہمت لگانے والوں نے ان کے متعلق افواہ اڑائی تھی اور پھر اللہ تعالیٰ نے ان کو اس سے بری قرار دیا تھا۔ ان تمام راویوں نے پوری حدیث کا ایک ایک ٹکڑا بیان کیا اور ان راویوں میں سے بعض کا بیان بعض دوسرے کے بیان کی تصدیق کرتا ہے۔ یہ الگ بات ہے کہ ان میں سے بعض راوی کو بعض دوسرے کے مقابلہ میں حدیث زیادہ بہتر طریقہ پر محفوظ، یاد تھی۔ مجھ سے یہ حدیث عروہ نے عائشہ رضی اللہ عنہا سے اس طرح بیان کی کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے کہا کہ جب نبی کریم صلی اللہ علیہ وسلم سفر کا ارادہ کرتے تو اپنی بیویوں میں سے کسی کو اپنے ساتھ لے جانے کے لیے قرعہ ڈالتے جن کا نام نکل جاتا انہیں اپنے ساتھ لے جاتے۔ انہوں نے بیان کیا کہ ایک غزوہ کے موقع پر اسی طرح آپ نے قرعہ ڈالا اور میرا نام نکلا۔ میں آپ کے ساتھ روانہ ہوئی۔ یہ واقعہ پردہ کے حکم نازل ہونے کے بعد کا ہے۔ مجھے ہودج سمیت اونٹ پر چڑھا دیا جاتا اور اسی طرح اتار لیا جاتا تھا۔ یوں ہمارا سفر جاری رہا۔ پھر جب آپ اس غزوہ سے فارغ ہو کر واپس لوٹے اور ہم مدینہ کے قریب پہنچ گئے تو ایک رات جب کوچ کا حکم ہوا۔ میں ( قضائے حاجت کے لیے ) پڑاؤ سے کچھ دور گئی اور قضائے حاجت کے بعد اپنے کجاوے کے پاس واپس آ گئی۔ اس وقت مجھے خیال ہوا کہ میرا ظفار کے نگینوں کا بنا ہوا ہار کہیں راستہ میں گر گیا ہے۔ میں اسے ڈھونڈنے لگی اور اس میں اتنا محو ہو گئی کہ کوچ کا خیال ہی نہ رہا۔ اتنے میں جو لوگ میرے ہودج کو سوار کیا کرتے تھے آئے اور میرے ہودج کو اٹھا کر اس اونٹ پر رکھ دیا جو میری سواری کے لیے تھا۔ انہوں نے یہی سمجھا کہ میں اس میں بیٹھی ہوئی ہوں۔ ان دنوں عورتیں بہت ہلکی پھلکی ہوا کرتی تھیں گوشت سے ان کا جسم بھاری نہیں ہوتا تھا کیونکہ کھانے پینے کو بہت کم ملتا تھا۔ یہی وجہ تھی کہ جب لوگوں نے ہودج کو اٹھایا تو اس کے ہلکے پن میں انہیں کوئی اجنبیت نہیں محسوس ہوئی۔ میں یوں بھی اس وقت کم عمر لڑکی تھی۔ چنانچہ ان لوگوں نے اس اونٹ کو اٹھایا اور چل پڑے۔ مجھے ہار اس وقت ملا جب لشکر گزر چکا تھا۔ میں جب پڑاؤ پر پہنچی تو وہاں نہ کوئی پکارنے والا تھا اور نہ کوئی جواب دینے والا۔ میں وہاں جا کر بیٹھ گئی جہاں پہلے بیٹھی ہوئی تھی۔ مجھے یقین تھا کہ جلد ہی انہیں میرے نہ ہونے کا علم ہو جائے گا اور پھر وہ مجھے تلاش کرنے کے لیے یہاں آئیں گے۔ میں اپنی اسی جگہ پر بیٹھی تھی کہ میری آنکھ لگ گئی اور میں سو گئی۔ صفوان بن معطل سلمی ثم ذکوانی لشکر کے پیچھے پیچھے آ رہے تھے ( تاکہ اگر لشکر والوں سے کوئی چیز چھوٹ جائے تو اسے اٹھا لیں سفر میں یہ دستور تھا ) رات کا آخری حصہ تھا، جب میرے مقام پر پہنچے تو صبح ہو چکی تھی۔ انہوں نے ( دور سے ) ایک انسانی سایہ دیکھا کہ پڑا ہوا ہے وہ میرے قریب آئے اور مجھے دیکھتے ہی پہچان گئے۔ پردہ کے حکم سے پہلے انہوں نے مجھے دیکھا تھا۔ جب وہ مجھے پہچان گئے تو «إنا لله» پڑھنے لگے۔ میں ان کی آواز پر جاگ گئی اور چہرہ چادر سے چھپا لیا۔ اللہ کی قسم! اس کے بعد انہوں نے مجھ سے ایک لفظ بھی نہیں کہا اور نہ میں نے «إنا لله وإنا إليه راجعون» کے سوا ان کی زبان سے کوئی کلمہ سنا۔ اس کے بعد انہوں نے اپنا اونٹ بٹھا دیا اور میں اس پر سوار ہو گئی وہ ( خود پیدل ) اونٹ کو آگے سے کھینچتے ہوئے لے چلے۔ ہم لشکر سے اس وقت ملے جب وہ بھری دوپہر میں ( دھوپ سے بچنے کے لیے ) پڑاؤ کئے ہوئے تھے، اس تہمت میں پیش پیش عبداللہ بن ابی ابن سلول منافق تھا۔ مدینہ پہنچ کر میں بیمار پڑ گئی اور ایک مہینہ تک بیمار رہی۔ اس عرصہ میں لوگوں میں تہمت لگانے والوں کی باتوں کا برابر چرچا رہا لیکن مجھے ان باتوں کا کوئی احساس بھی نہ تھا۔ صرف ایک معاملہ سے مجھے شبہ سا ہوتا تھا کہ میں اپنی بیماری میں رسول اللہ صلی اللہ علیہ وسلم کی طرف سے لطف و محبت کا اظہار نہیں دیکھتی تھی جو پہلی بیماریوں کے دنوں میں دیکھ چکی تھی۔ نبی کریم صلی اللہ علیہ وسلم اندر تشریف لاتے سلام کر کے صرف اتنا پوچھ لیتے کہ کیا حال ہے؟ اور پھر واپس چلے جاتے۔ نبی کریم صلی اللہ علیہ وسلم کے اسی طرز عمل سے شبہ ہوتا تھا لیکن صورت حال کا مجھے کوئی احساس نہیں تھا۔ ایک دن جب ( بیماری سے کچھ افاقہ تھا ) کمزوری باقی تھی تو میں باہر نکلی میرے ساتھ ام مسطح رضی اللہ عنہا بھی تھیں ہم مناصع کی طرف گئے۔ قضائے حاجت کے لیے ہم وہیں جایا کرتے تھے اور قضائے حاجت کے لیے ہم صرف رات ہی کو جایا کرتے تھے۔ یہ اس سے پہلے کی بات ہے جب ہمارے گھروں کے قریب بتی الخلاء نہیں بنے تھے۔ اس وقت تک ہم قدیم عرب کے دستور کے مطابق قضائے حاجت آبادی سے دور جا کر کیا کرتے تھے۔ اس سے ہمیں بدبو سے تکلیف ہوتی تھی کہ بیت الخلاء ہمارے گھر کے قریب بنا دیئے جائیں۔ خیر میں اور ام مسطح قضائے حاجت کے لیے روانہ ہوئے۔ وہ ابورہم بن عبد مناف کی بیٹی تھیں اور ان کی والدہ ( رانطہٰ نامی ) صخر بن عامر کی بیٹی تھیں۔ اس طرح وہ ابوبکر رضی اللہ عنہ کی خالہ ہوتی ہیں۔ ان کے لڑکے مسطح بن اثاثہ ہیں۔ قضائے حاجت کے بعد جب ہم گھر واپس آنے لگے تو مسطح کی ماں کا پاؤں انہیں کی چادر میں الجھ کر پھسل گیا۔ اس پر ان کی زبان سے نکلا مسطح برباد ہو، میں نے کہا تم نے بری بات کہی، تم ایک ایسے شخص کو برا کہتی ہو جو غزوہ بدر میں شریک رہا ہے۔ انہوں نے کہا، واہ اس کی باتیں تو نے نہیں سنی؟ میں نے پوچھا: انہوں نے کیا کہا ہے؟ پھر انہوں نے مجھے تہمت لگانے والوں کی باتیں بتائیں میں پہلے سے بیمار تھی ہی، ان باتوں کو سن کر میرا مرض اور بڑھ گیا پھر جب میں گھر پہنچی اور رسول اللہ صلی اللہ علیہ وسلم اندر تشریف لائے تو آپ نے سلام کیا اور دریافت فرمایا کہ کیسی طبیعت ہے؟ میں نے عرض کیا کہ کیا آپ مجھے اپنے ماں باپ کے گھر جانے کی اجازت دیں گے؟ میرا مقصد ماں باپ کے یہاں جانے سے صرف یہ تھا کہ اس خبر کی حقیقت ان سے پوری طرح معلوم ہو جائے گی۔ نبی کریم صلی اللہ علیہ وسلم نے مجھے جانے کی اجازت دے دی اور میں اپنے والدین کے گھر آ گئی۔ میں نے والدہ سے پوچھا کہ یہ لوگ کس طرح کی باتیں کر رہے ہیں؟ انہوں نے فرمایا بیٹی صبر کرو، کم ہی کوئی ایسی حسین و جمیل عورت کسی ایسے مرد کے نکاح میں ہو گی جو اس سے محبت رکھتا ہو اور اس کی سوکنیں بھی ہوں اور پھر بھی وہ اس طرح اسے نیچا دکھانے کی کوشش نہ کریں۔ بیان کیا کہ اس پر میں نے کہا: سبحان اللہ! کیا اس طرح کا چرچا لوگوں نے بھی کر دیا؟ انہوں نے بیان کیا کہ اس کے بعد میں رونے لگی اور رات بھر روتی رہی۔ صبح ہو گئی لیکن میرے آنسو نہیں تھمتے تھے اور نہ نیند کا نام و نشان تھا۔ صبح ہو گئی اور میں روئے جا رہی تھی اسی عرصہ میں نبی کریم صلی اللہ علیہ وسلم نے علی بن ابی طالب اور اسامہ بن زید رضی اللہ عنہم کو بلایا کیونکہ اس معاملہ میں آپ پر کوئی وحی نازل نہیں ہوئی تھی۔ آپ ان سے میرے چھوڑ دینے کے لیے مشورہ لینا چاہتے تھے۔ کیونکہ وحی اترنے میں دیر ہو گئی تھی۔ عائشہ رضی اللہ عنہا کہتی ہیں کہ اسامہ بن زید رضی اللہ عنہما نے نبی کریم صلی اللہ علیہ وسلم کو اسی کے مطابق مشورہ دیا جس کا انہیں علم تھا کہ آپ کی اہلیہ ( یعنی خود عائشہ صدیقہ رضی اللہ عنہا ) اس تہمت سے بَری ہیں۔ اس کے علاوہ وہ یہ بھی جانتے تھے کہ نبی کریم صلی اللہ علیہ وسلم کو ان سے کتنا تعلق خاطر ہے۔ انہوں نے عرض کیا کہ یا رسول اللہ! آپ کی بیوی کے بارے میں خیر و بھلائی کے سوا اور ہمیں کسی چیز کا علم نہیں اور علی نے عرض کیا کہ یا رسول اللہ! اللہ تعالیٰ نے آپ پر کوئی تنگی نہیں کی ہے، عورتیں ان کے سوا اور بھی بہت ہیں، ان کی باندی ( بریرہ ) سے بھی آپ اس معاملہ میں دریافت فرما لیں۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے بریرہ کو بلایا اور دریافت فرمایا: بریرہ! کیا تم نے کوئی ایسی چیز دیکھی ہے جس سے تجھ کو شبہ گزرا ہو؟ انہوں نے عرض کیا، نہیں حضور! اس ذات کی قسم جس نے آپ کو حق کے ساتھ بھیجا ہے، میں نے ان میں کوئی ایسی بات نہیں پائی جس پر میں عیب لگا سکوں، ایک بات ضرور ہے کہ وہ کم عمر لڑکی ہیں، آٹا گوندھنے میں بھی سو جاتی ہیں اور اتنے میں کوئی بکری یا پرندہ وغیرہ وہاں پہنچ جاتا ہے اور ان کا گوندھا ہوا آٹا کھا جاتا ہے۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم کھڑے ہوئے اور اس دن آپ نے عبداللہ بن ابی بن سلول کی شکایت کی۔ بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ممبر پر کھڑے ہو کر فرمایا کہ اے مسلمانو! ایک ایسے شخص کے بارے میں کون میری مدد کرتا ہے جس کی اذیت رسانی اب میرے گھر پہنچ گئی ہے۔ اللہ کی قسم کہ میں اپنی بیوی کو نیک پاک دامن ہونے کے سوا کچھ نہیں جانتا اور یہ لوگ جس مرد کا نام لے رہے ہیں ان کے بارے میں بھی خیر کے سوا میں اور کچھ نہیں جانتا۔ وہ جب بھی میرے گھر میں گئے تو میرے ساتھ ہی گئے ہیں۔ اس پر سعد بن معاذ انصاری رضی اللہ عنہ اٹھے اور کہا کہ یا رسول اللہ! میں آپ کی مدد کروں گا اور اگر وہ شخص قبیلہ اوس سے تعلق رکھتا ہے تو میں اس کی گردن اڑا دوں گا اور اگر وہ ہمارے بھائیوں یعنی خزرج میں کا کوئی آدمی ہے تو آپ ہمیں حکم دیں، تعمیل میں کوتاہی نہیں ہو گی۔ راوی نے بیان کیا کہ اس کے بعد سعد بن عبادہ رضی اللہ عنہ کھڑے ہوئے، وہ قبیلہ خزرج کے سردار تھے، اس سے پہلے وہ مرد صالح تھے لیکن آج ان پر قومی حمیت غالب آ گئی تھی ( عبداللہ بن ابی ابن سلول منافق ) ان ہی کے قبیلہ سے تعلق رکھتا تھا انہوں نے اٹھ کر سعد بن معاذ رضی اللہ عنہ سے کہا: اللہ کی قسم! تم نے جھوٹ کہا ہے تم اسے قتل نہیں کر سکتے، تم میں اس کے قتل کی طاقت نہیں ہے۔ پھر اسید بن حضیر رضی اللہ عنہ کھڑے ہوئے وہ سعد بن معاذ کے چچیرے بھائی تھے انہوں نے سعد بن عبادہ سے کہا کہ اللہ کی قسم! تم جھوٹ بولتے ہو، ہم اسے ضرور قتل کریں گے، کیا تم منافق ہو گئے ہو کہ منافقوں کی طرفداری میں لڑتے ہو؟ اتنے میں دونوں قبیلے اوس و خزرج اٹھ کھڑے ہوئے اور نوبت آپس ہی میں لڑنے تک پہنچ گئی۔ رسول اللہ صلی اللہ علیہ وسلم ممبر پر کھڑے تھے۔ آپ لوگوں کو خاموش کرنے لگے۔ آخر سب لوگ چپ ہو گئے اور نبی کریم صلی اللہ علیہ وسلم بھی خاموش ہو گئے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ اس دن بھی میں برابر روتی رہی نہ آنسو تھمتا تھا اور نہ نیند آتی تھی۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ جب ( دوسری ) صبح ہوئی تو میرے والدین میرے پاس ہی موجود تھے، دو راتیں اور ایک دن مجھے مسلسل روتے ہوئے گزر گیا تھا۔ اس عرصہ میں نہ مجھے نیند آتی تھی اور نہ آنسو تھمتے تھے۔ والدین سوچنے لگے کہ کہیں روتے روتے میرا دل نہ پھٹ جائے۔ انہوں نے بیان کیا کہ ابھی وہ اسی طرح میرے پاس بیٹھے ہوئے تھے اور میں روئے جا رہی تھی کہ قبیلہ انصار کی ایک خاتون نے اندر آنے کی اجازت چاہی، میں نے انہیں اندر آنے کی اجازت دے دی، وہ بھی میرے ساتھ بیٹھ کر رونے لگیں۔ ہم اسی حال میں تھے کہ رسول اللہ صلی اللہ علیہ وسلم اندر تشریف لائے اور بیٹھ گئے۔ انہوں نے کہا کہ جب سے مجھ پر تہمت لگائی گئی تھی اس وقت سے اب تک نبی کریم صلی اللہ علیہ وسلم میرے پاس نہیں بیٹھے تھے، آپ نے ایک مہینہ تک اس معاملہ میں انتظار کیا اور آپ صلی اللہ علیہ وسلم پر اس سلسلہ میں کوئی وحی نازل نہیں ہوئی۔ انہوں نے بیان کیا کہ بیٹھنے کے بعد نبی کریم صلی اللہ علیہ وسلم نے خطبہ پڑھا پھر فرمایا، امابعد! اے عائشہ! تمہارے بارے میں مجھے اس اس طرح کی خبریں پہنچی ہیں پس اگر تم بَری ہو تو اللہ تعالیٰ تمہاری برات خود کر دے گا۔ لیکن اگر تم سے غلطی سے گناہ ہو گیا ہے تو اللہ سے دعائے مغفرت کرو اور اس کی بارگاہ میں توبہ کرو، کیونکہ بندہ جب اپنے گناہ کا اقرار کر لیتا ہے اور پھر اللہ سے توبہ کرتا ہے تو اللہ تعالیٰ بھی اس کی توبہ قبول کر لیتا ہے۔ عائشہ رضی اللہ عنہا نے کہا کہ جب نبی کریم صلی اللہ علیہ وسلم اپنی گفتگو ختم کر چکے تو یکبارگی میرے آنسو اس طرح خشک ہو گئے جیسے ایک قطرہ بھی باقی نہ رہا ہو۔ میں نے اپنے والد ( ابوبکر ) سے کہا کہ آپ میری طرف سے رسول اللہ صلی اللہ علیہ وسلم کو جواب دیجئیے۔ انہوں نے فرمایا کہ اللہ کی قسم! میں نہیں سمجھتا کہ مجھے رسول اللہ صلی اللہ علیہ وسلم سے اس سلسلہ میں کیا کہنا ہے۔ پھر میں نے اپنی والدہ سے کہا کہ نبی کریم صلی اللہ علیہ وسلم کی باتوں کا میری طرف سے آپ جواب دیں۔ انہوں نے بھی یہی کہا کہ اللہ کی قسم! مجھے نہیں معلوم کہ میں آپ سے کیا عرض کروں۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر میں خود ہی بولی میں اس وقت نوعمر لڑکی تھی، میں نے بہت زیادہ قرآن بھی نہیں پڑھا تھا ( میں نے کہا کہ ) اللہ کی قسم! میں تو یہ جانتی ہوں کہ ان افواہوں کے متعلق جو کچھ آپ لوگوں نے سنا ہے وہ آپ لوگوں کے دل میں جم گیا ہے اور آپ لوگ اسے صحیح سمجھنے لگے ہیں، اب اگر میں یہ کہتی ہوں کہ میں ان تہمتوں سے بَری ہوں اور اللہ خوب جانتا ہے کہ میں واقعی بَری ہوں، تو آپ لوگ میری بات کا یقین نہیں کریں گے، لیکن اگر میں تہمت کا اقرار کر لوں، حالانکہ اللہ کے علم میں ہے کہ میں اس سے قطعاً بَری ہوں، تو آپ لوگ میری تصدیق کرنے لگیں گے۔ اللہ کی قسم! میرے پاس آپ لوگوں کے لیے کوئی مثال نہیں ہے سوا یوسف کے والد کے اس ارشاد کے کہ انہوں نے فرمایا تھا «فصبر جميل والله المستعان على ما تصفون‏» ”پس صبر ہی اچھا ہے اور تم جو کچھ بیان کرتے ہو اس پر اللہ ہی مدد کرے گا“ بیان کیا کہ پھر میں نے اپنا رخ دوسری طرف کر لیا اور اپنے بستر پر لیٹ گئی۔ کہا کہ مجھے پورا یقین تھا کہ میں بَری ہوں اور اللہ تعالیٰ میری برات ضرور کرے گا لیکن اللہ کی قسم! مجھے اس کا وہم و گمان بھی نہیں تھا کہ اللہ تعالیٰ میرے بارے میں ایسی وحی نازل فرمائے گا جس کی تلاوت کی جائے گی۔ میں اپنی حیثیت اس سے بہت کم تر سمجھتی تھی کہ اللہ تعالیٰ میرے بارے میں ( قرآن مجید کی آیت ) نازل فرمائے۔ البتہ مجھے اس کی توقع ضرور تھی کہ نبی کریم صلی اللہ علیہ وسلم میرے متعلق کوئی خواب دیکھیں گے اور اللہ تعالیٰ اس کے ذریعہ میری برات کر دے گا۔ بیان کیا کہ اللہ کی قسم رسول اللہ صلی اللہ علیہ وسلم ابھی اپنی اسی مجلس میں تشریف رکھتے تھے گھر والوں میں سے کوئی باہر نہ تھا کہ آپ پر وحی کا نزول شروع ہوا اور وہی کیفیت آپ صلی اللہ علیہ وسلم پر طاری ہوئی تھی جو وحی کے نازل ہوتے ہوئے طاری ہوتی تھی یعنی آپ صلی اللہ علیہ وسلم پسینے پسینے ہو گئے اور پسینہ موتیوں کی طرف آپ کے جسم اطہر سے ڈھلنے لگا حالانکہ سردی کے دن تھے۔ یہ کیفیت آپ پر اس وحی کی شدت کی وجہ سے طاری ہوتی تھی جو آپ پر نازل ہوتی تھی۔ بیان کیا کہ پھر جب نبی کریم صلی اللہ علیہ وسلم کی کیفیت ختم ہوئی تو آپ صلی اللہ علیہ وسلم تبسم فرما رہے تھے اور سب سے پہلا کلمہ جو آپ کی زبان مبارک سے نکلا، یہ تھا کہ عائشہ! اللہ نے تمہیں بَری قرار دیا ہے۔ میری والدہ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم کے سامنے ( آپ کا شکر ادا کرنے کے لیے ) کھڑی ہو جاؤ۔ بیان کیا کہ میں نے کہا: اللہ کی قسم! میں ہرگز آپ کے سامنے کھڑی نہیں ہوں گی اور اللہ پاک کے سوا اور کسی کی تعریف نہیں کروں گی۔ اللہ تعالیٰ نے جو آیت نازل کی تھی وہ یہ تھی «إن الذين جاءوا بالإفك عصبة منكم لا تحسبوه‏» کہ ”بیشک جن لوگوں نے تہمت لگائی ہے وہ تم میں سے ایک چھوٹا سے گروہ ہے“ مکمل دس آیتوں تک۔ جب اللہ تعالیٰ نے یہ آیتیں میری برات میں نازل کر دیں تو ابوبکر صدیق رضی اللہ عنہ جو مسطح بن اثاثہ رضی اللہ عنہ کے اخراجات ان سے قرابت اور ان کی محتاجی کی وجہ سے خود اٹھایا کرتے تھے انہوں نے ان کے متعلق کہا کہ اللہ کی قسم! اب مسطح پر کبھی کچھ بھی خرچ نہیں کروں گا۔ اس نے عائشہ ( رضی اللہ عنہا ) پر کیسی کیسی تہمتیں لگا دی ہیں۔ اس پر اللہ تعالیٰ نے یہ آیت نازل کی «ولا يأتل أولو الفضل منكم والسعة أن يؤتوا أولي القربى والمساكين والمهاجرين في سبيل الله وليعفوا وليصفحوا ألا تحبون أن يغفر الله لكم والله غفور رحيم‏» ”اور جو لوگ تم میں بزرگی اور وسعت والے ہیں، وہ قرابت والوں کو اور مسکینوں کو اور اللہ کے راستے میں ہجرت کرنے والوں کی مدد دینے سے قسم نہ کھا بیٹھیں بلکہ چاہئے کہ ان کی لغزشوں کو معاف کرتے رہیں اور درگزر کرتے رہیں، کیا تم یہ نہیں چاہتے کہ اللہ تمہارے قصور معاف کرتا رہے، بیشک اللہ بڑا مغفرت والا، بڑا ہی رحمت والا ہے۔“ ابوبکر رضی اللہ عنہ بولے، ہاں اللہ کی قسم! میری تو یہی خواہش ہے کہ اللہ تعالیٰ میری مغفرت فرما دے چنانچہ مسطح رضی اللہ عنہ کو وہ تمام اخراجات دینے لگے جو پہلے دیا کرتے تھے اور فرمایا کہ اللہ کی قسم! اب کبھی ان کا خرچ بند نہیں کروں گا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ام المؤمنین زینب بن جحش رضی اللہ عنہا سے بھی میرے معاملہ میں پوچھا تھا۔ آپ نے دریافت فرمایا کہ زینب! تم نے بھی کوئی چیز کبھی دیکھی ہے؟ انہوں نے عرض کیا: یا رسول اللہ! میرے کان اور میری آنکھ کو اللہ سلامت رکھے، میں نے ان کے اندر خیر کے سوا اور کوئی چیز نہیں دیکھی۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ ازواج مطہرات میں وہی ایک تھیں جو مجھ سے بھی اوپر رہنا چاہتی تھیں لیکن اللہ تعالیٰ نے ان کی پرہیزگاری کی وجہ سے انہیں تہمت لگانے سے محفوظ رکھا۔ لیکن ان کی بہن حمنہ ان کے لیے لڑی اور تہمت لگانے والوں کے ساتھ وہ بھی ہلاک ہو گئی۔' WHERE id = 4545;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے یونس بن محمد بغدادی نے بیان کیا، کہا ہم سے شیبان نے بیان کیا، ان سے قتادہ نے، کہا ہم سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ایک صاحب نے پوچھا، اے اللہ کے نبی! کافر کو قیامت کے دن اس کے چہرے کے بل کس طرح چلایا جائے گا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ جس نے اسے اس دنیا میں دو پاؤں پر چلایا ہے اس پر قادر ہے کہ قیامت کے دن اس کو اس کے چہرے کے بل چلا دے۔ قتادہ نے کہا یقیناً ہمارے رب کی عزت کی قسم! یونہی ہو گا۔' WHERE id = 4555;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے میرے والد نے بیان کیا، کہا ہم سے اعمش نے، کہا کہ مجھ سے عمرو بن مرہ نے بیان کیا، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب آیت «وأنذر عشيرتك الأقربين‏» ”اور آپ اپنے خاندانی قرابت داروں کو ڈراتے رہئیے“ نازل ہوئی تو نبی کریم صلی اللہ علیہ وسلم صفا پہاڑی پر چڑھ گئے اور پکارنے لگے۔ اے بنی فہر! اور اے بنی عدی! اور قریش کے دوسرے خاندان والو! اس آواز پر سب جمع ہو گئے اگر کوئی کسی وجہ سے نہ آ سکا تو اس نے اپنا کوئی چودھری بھیج دیا، تاکہ معلوم ہو کہ کیا بات ہے۔ ابولہب قریش کے دوسرے لوگوں کے ساتھ مجمع میں تھا۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں خطاب کر کے فرمایا کہ تمہارا کیا خیال ہے، اگر میں تم سے کہوں کہ وادی میں ( پہاڑی کے پیچھے ) ایک لشکر ہے اور وہ تم پر حملہ کرنا چاہتا ہے تو کیا تم میری بات سچ مانو گے؟ سب نے کہا کہ ہاں، ہم آپ کی تصدیق کریں گے ہم نے ہمیشہ آپ کو سچا ہی پایا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر سنو، میں تمہیں اس سخت عذاب سے ڈراتا ہوں جو بالکل سامنے ہے۔ اس پر ابولہب بولا، تجھ پر سارے دن تباہی نازل ہو، کیا تو نے ہمیں اسی لیے اکٹھا کیا تھا۔ اسی واقعہ پر یہ آیت نازل ہوئی «تبت يدا أبي لهب وتب * ما أغنى عنه ماله وما كسب‏» ”ابولہب کے دونوں ہاتھ ٹوٹ گئے اور وہ برباد ہو گیا، نہ اس کا مال اس کے کام آیا اور نہ اس کی کمائی ہی اس کے آڑے آئی۔“' WHERE id = 4565;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن نصر نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے اعمش نے، کہا ہم سے ابوصالح نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ ارشاد فرماتا ہے کہ میں نے اپنے نیکوکار بندوں کے لیے وہ چیزیں تیار رکھی ہیں جنہیں کسی آنکھ نے نہ دیکھا اور کسی کان نے نہ سنا اور نہ کسی انسان کے دل میں ان کا کبھی گمان و خیال پیدا ہوا۔ اللہ کی ان نعمتوں سے واقفیت اور آگاہی تو الگ رہی ( ان کا کسی کو گمان و خیال بھی پیدا نہیں ہوا ) ۔ پھر نبی کریم صلی اللہ علیہ وسلم نے اس آیت کی تلاوت کی «فلا تعلم نفس ما أخفي لهم من قرة أعين جزاء بما كانوا يعملون‏» کہ ”سو کسی نفس مومن کو معلوم نہیں جو جو سامان آنکھوں کی ٹھنڈک کا ( جنت میں ) ان کے لیے چھپا کر رکھا گیا ہے، یہ بدلہ ہے ان کے نیک عملوں کا جو دنیا میں کرتے رہے۔“' WHERE id = 4575;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ان سے یحییٰ بن سعید قطان نے، ان سے حمید طویل نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ عمر رضی اللہ عنہ نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! آپ کے پاس اچھے برے ہر طرح کے لوگ آتے ہیں، کاش آپ ازواج مطہرات کو پردہ کا حکم دے دیں۔ اس کے بعد اللہ نے پردہ کا حکم اتارا۔' WHERE id = 4585;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے، کہا ہم سے عمرو بن دینار نے، کہا کہ میں نے عکرمہ سے سنا، وہ بیان کرتے تھے کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب اللہ تعالیٰ آسمان پر کسی بات کا فیصلہ کرتا ہے تو فرشتے اللہ تعالیٰ کے فیصلہ کو سن کر جھکتے ہوئے عاجزی کرتے ہوئے اپنے بازو پھڑپھڑاتے ہیں۔ اللہ کا فرمان انہیں اس طرح سنائی دیتا ہے جیسے صاف چکنے پتھر پر زنجیر چلانے سے آواز پیدا ہوتی ہے۔ پھر جب ان کے دلوں سے گھبراہٹ دور ہو جاتی ہے تو وہ آپس میں پوچھتے ہیں کہ تمہارے رب نے کیا فرمایا؟ وہ کہتے ہیں کہ حق بات کا حکم فرمایا اور وہ بہت اونچا، سب سے بڑا ہے پھر ان کی یہی گفتگو چوری چھپے سننے والے شیطان سن بھاگتے ہیں، شیطان آسمان کے نیچے یوں نیچے اوپر ہوتے ہیں، سفیان نے اس موقع پر ہتھیلی کو موڑ کر انگلیاں الگ الگ کر کے شیاطین کے جمع ہونے کی کیفیت بتائی کہ اس طرح شیطان ایک کے اوپر ایک رہتے ہیں۔ پھر وہ شیاطین کوئی ایک کلمہ سن لیتے ہیں اور اپنے نیچے والے کو بتاتے ہیں۔ اس طرح وہ کلمہ ساحر یا کاہن تک پہنچتا ہے۔ کبھی تو ایسا ہوتا ہے کہ اس سے پہلے کہ وہ یہ کلمہ اپنے سے نیچے والے کو بتائیں آگ کا گولا انہیں آ ڈبوچتا ہے اور کبھی ایسا ہوتا ہے کہ جب وہ بتا لیتے ہیں تو آگ کا انگارا ان پر پڑتا ہے، اس کے بعد کاہن اس میں سو جھوٹ ملا کر لوگوں سے بیان کرتا ہے ( ایک بات جب اس کاہن کی صحیح ہو جاتی ہے تو ان کے ماننے والوں کی طرف سے ) کہا جاتا ہے کہ کیا اسی طرح ہم سے فلاں دن کاہن نہیں کہا تھا، اسی ایک کلمہ کی وجہ سے جو آسمان پر شیاطین نے سنا تھا کاہنوں اور ساحروں کی بات کو لوگ سچا جاننے لگتے ہیں۔' WHERE id = 4595;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام بن یوسف نے خبر دی، انہیں ابن جریج نے خبر دی، ان سے یعلیٰ بن مسلم نے بیان کیا، انہیں سعید بن جبیر نے خبر دی اور انہیں ابن عباس رضی اللہ عنہما نے کہ مشرکین میں بعض نے قتل کا گناہ کیا تھا اور کثرت سے کیا تھا۔ اسی طرح زناکاری بھی کثرت سے کرتے رہے تھے۔ پھر وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں آئے اور عرض کیا کہ آپ جو کچھ کہتے ہیں اور جس کی طرف دعوت دیتے ہیں ( یعنی اسلام ) یقیناً اچھی چیز ہے، لیکن ہمیں یہ بتائیے کہ اب تک ہم نے جو گناہ کئے ہیں وہ اسلام لانے سے معاف ہوں گے یا نہیں؟ اس پر یہ آیت نازل ہوئی «والذين لا يدعون مع الله إلها آخر ولا يقتلون النفس التي حرم الله إلا بالحق ولا يزنون‏» ”اور وہ لوگ جو اللہ کے سوا اور کسی دوسرے معبود کو نہیں پکارتے اور کسی بھی جان کو قتل نہیں کرتے جس کا قتل کرنا اللہ نے حرام کیا ہے، ہاں مگر حق کے ساتھ“ اور یہ آیت نازل ہوئی «قل يا عبادي الذين أسرفوا على أنفسهم لا تقنطوا من رحمة الله‏» ”آپ کہہ دیں کہ اے میرے بندو! جو اپنے نفسوں پر زیادتیاں کر چکے ہو، اللہ کی رحمت سے ناامید مت ہو، بیشک اللہ سارے گناہوں کو معاف کر دے گا۔ بیشک اللہ وہ بڑا ہی بخشنے والا نہایت ہی مہربان ہے۔“' WHERE id = 4605;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، ان سے ابوحمزہ نے، ان سے اعمش نے، ان سے مسلم نے، ان سے مسروق نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ ( قیامت کی ) پانچ علامتیں گزر چکی ہیں «الدخان» دھواں، «الروم» غلبہ روم، «القمر» چاند کا ٹکڑے ہونا، «والبطشة» پکڑ اور «واللزام‏» ہلاکت اور قید۔' WHERE id = 4615;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن حمزہ نے بیان کیا، کہا کہ ہم کو حاتم نے بیان کیا، ان سے معاویہ نے بیان کیا، ان سے ان کے چچا ابوالحباب سعید بن یسار نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے سابقہ حدیث کی طرح۔ پھر ( ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ) رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اگر تمہارا جی چاہے تو آیت «فهل عسيتم» اگر تم کنارہ کش رہو پڑھ لو۔' WHERE id = 4625;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے شبابہ نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے بیان کیا، انہوں نے عقبہ بن صہبان سے سنا اور انہوں نے عبداللہ بن مغفل مزنی رضی اللہ عنہ سے، انہوں نے کہا کہ میں درخت کے نیچے بیعت میں موجود تھا، رسول اللہ صلی اللہ علیہ وسلم نے دو انگلیوں کے درمیان کنکری لے کر پھینکنے سے منع فرمایا۔' WHERE id = 4635;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، ان سے جریر نے، ان سے اسمٰعیل نے، ان سے قیس بن ابی حازم نے اور ان سے جریر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ ہم ایک رات نبی کریم صلی اللہ علیہ وسلم کے ساتھ بیٹھے ہوئے تھے چودہویں رات تھی۔ نبی کریم صلی اللہ علیہ وسلم نے چاند کی طرف دیکھا اور پھر فرمایا کہ یقیناً تم اپنے رب کو اسی طرح دیکھو گے جس طرح اس چاند کو دیکھ رہے ہو۔ اس کی رؤیت میں تم دھکم پیل نہیں کرو گے ( بلکہ بڑے اطمینان سے ایک دوسرے کو دھکا دیئے بغیر دیکھو گے ) اس لیے اگر تمہارے لیے ممکن ہو تو سورج نکلنے اور ڈوبنے سے پہلے نماز نہ چھوڑو۔ پھر آپ نے آیت «وسبح بحمد ربك قبل طلوع الشمس وقبل الغروب‏» ”اور اپنے رب کی حمد و تسبیح کرتے رہئیے آفتاب نکلنے سے پہلے اور چھپنے سے پہلے۔“ کی تلاوت کی۔' WHERE id = 4645;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا کہ میں نے عروہ سے سنا، انہوں نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا سے پوچھا تو انہوں نے کہا کہ کچھ لوگ منات بت کے نام پر احرام باندھتے جو مقام مشلل میں تھا، وہ صفا اور مروہ کے درمیان ( حج و عمرہ میں ) سعی نہیں کرتے تھے اس پر اللہ تعالیٰ نے آیت نازل کی «إن الصفا والمروة من شعائر الله‏» ”بیشک صفا اور مروہ اللہ کی نشانیوں میں سے ہیں“ چنانچہ رسول اللہ صلی اللہ علیہ وسلم نے ان کے درمیان طواف کیا اور مسلمانوں نے بھی طواف کیا۔ سفیان نے کہا کہ ”مناۃ“ مقام قدید پر مشلل میں تھا اور عبدالرحمٰن بن خالد نے بیان کیا کہ ان سے ابن شہاب نے، ان سے عروہ نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے کہا کہ یہ آیت انصار کے بارے میں نازل ہوئی تھی۔ اسلام سے پہلے انصار اور غسان کے لوگ منات کے نام پر احرام باندھتے تھے، پہلی حدیث کی طرح۔ اور معمر نے زہری سے بیان کیا، ان سے عروہ نے، ان سے عائشہ رضی اللہ عنہا نے کہ قبیلہ انصار کے کچھ لوگ منات کے نام کا احرام باندھتے تھے۔ منات ایک بت تھا جو مکہ اور مدینہ کے درمیان رکھا ہوا تھا ( اسلام لانے کے بعد ) ان لوگوں نے کہا کہ یا رسول اللہ! ہم منات کی تعظیم کے لیے صفا اور مروہ کے درمیان سعی نہیں کیا کرتے تھے۔' WHERE id = 4655;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے زہیر نے بیان کیا، ان سے ابواسحاق نے انہوں نے ایک شخص کو اسود سے پوچھتے سنا کہ سورۃ القمر میں آیت «فهل من مدكر‏» ہے یا «فهل من مذكر‏» ؟ انہوں نے کہا کہ میں نے ابن مسعود رضی اللہ عنہ سے سنا وہ «فهل من مدكر‏» پڑھتے تھے۔ انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو بھی «فهل من مدكر‏» پڑھتے سنا ہے ( دال مہملہ سے ) ۔' WHERE id = 4665;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا، کہا ہم سے سعید بن سلیمان نے بیان کیا، کہا ہم سے ہشیم نے بیان کیا، کہا ہم کو ابوبشر جعفر نے خبر دی، ان سے سعید بن جبیر نے بیان کیا کہ میں نے عبداللہ بن عباس رضی اللہ عنہما سے سورۃ التوبہ کے متعلق پوچھا تو انہوں نے کہا یہ سورۃ التوبہ کی ہے یا فضیحت کرنے والی ہے اس سورت میں برابر یہی اترتا رہا بعض لوگ ایسے ہیں اور بعض لوگ ایسے ہیں یہاں تک کہ لوگوں کو گمان ہوا یہ سورت کسی کا کچھ بھی نہیں چھوڑے گی بلکہ سب کے بھید کھول دے گی۔ بیان کیا کہ میں نے سورۃ الانفال کے متعلق پوچھا تو فرمایا کہ یہ جنگ بدر کے بارے میں نازل ہوئی تھی۔ بیان کیا کہ میں نے سورۃ الحشر کے متعلق پوچھا تو فرمایا کہ قبیلہ بنو نضیر کے یہود کے بارے میں نازل ہوئی تھی۔' WHERE id = 4675;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث نے، کہا ہم سے ایوب نے، ان سے حفصہ بنت سیرین نے اور ان سے ام عطیہ رضی اللہ عنہا نے بیان کیا کہ ہم نے رسول اللہ صلی اللہ علیہ وسلم سے بیعت کی تو آپ نے ہمارے سامنے اس آیت کی تلاوت کی «أن لا يشركن بالله شيئا‏» کے ساتھ کسی کو شریک نہ کریں گی اور ہمیں نوحہ ( یعنی میت پر زور زور سے رونا پیٹنا ) کرنے سے منع فرمایا۔ نبی کریم صلی اللہ علیہ وسلم کی اس ممانعت پر ایک عورت ( خود ام عطیہ رضی اللہ عنہا ) نے اپنا ہاتھ کھینچ لیا اور عرض کیا کہ فلاں عورت نے نوحہ میں میری مدد کی تھی، میں چاہتی ہوں کہ اس کا بدلہ چکا آؤں نبی کریم صلی اللہ علیہ وسلم نے اس کا کوئی جواب نہیں دیا چنانچہ وہ گئیں اور پھر دوبارہ آ کر نبی کریم صلی اللہ علیہ وسلم سے بیعت کی۔' WHERE id = 4685;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حکم نے بیان کیا، انہوں نے کہا کہ میں نے محمد بن کعب قرظی سے سنا، کہا کہ میں نے زید بن ارقم رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ جب عبداللہ بن ابی ابن سلول نے کہا کہ جو لوگ رسول اللہ صلی اللہ علیہ وسلم کے پاس ہیں ان پر خرچ نہ کرو یہ بھی کہا کہ اب اگر ہم مدینہ واپس گئے تو ہم سے عزت والا ذلیلوں کو نکال باہر کرے گا تو میں نے یہ خبر نبی کریم صلی اللہ علیہ وسلم تک پہنچائی۔ اس پر کفار نے مجھے ملامت کی اور عبداللہ بن ابی نے قسم کھا لی کہ اس نے یہ بات نہیں کہی تھی پھر میں گھر واپس آ گیا اور سو گیا۔ اس کے بعد مجھے نبی کریم صلی اللہ علیہ وسلم نے مجھے طلب فرمایا اور میں حاضر ہوا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے تمہاری تصدیق میں آیت نازل کر دی ہے اور یہ آیت اتری ہے «هم الذين يقولون لا تنفقوا‏» الخ آخر تک۔ اور ابن ابی زائدہ نے اعمش سے بیان کیا، ان سے عمرو نے، ان سے ابن ابی لیلیٰ نے اور ان سے زید بن ارقم رضی اللہ عنہما نے نبی کریم صلی اللہ علیہ وسلم سے اسی طرح نقل کیا۔' WHERE id = 4695;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام بن یوسف نے خبر دی، انہیں ابن جریج نے، انہیں عطاء نے، انہیں عبید بن عمیر اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم زینب بنت جحش رضی اللہ عنہا کے گھر میں شہد پیتے اور وہاں ٹھہرتے تھے پھر میں نے اور حفصہ رضی اللہ عنہا نے ایسے کیا کہ ہم میں سے جس کے پاس بھی نبی کریم صلی اللہ علیہ وسلم ( زینب کے یہاں سے شہد پی کر آنے کے بعد ) داخل ہوں تو وہ کہے کہ کیا آپ نے پیاز کھائی ہے۔ آپ کے منہ سے مغافیر کی بو آتی ہے۔ چنانچہ جب آپ صلی اللہ علیہ وسلم تشریف لائے تو منصوبہ بندی کے تحت یہی کہا گیا۔ نبی کریم صلی اللہ علیہ وسلم بدبو کو بہت ناپسند فرماتے تھے۔ اس لیے آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے مغافیر نہیں کھائی ہے البتہ زینب بنت جحش کے یہاں سے شہد پیا تھا لیکن اب اسے بھی ہرگز نہیں پیوں گا۔ میں نے اس کی قسم کھا لی ہے لیکن تم کسی سے اس کا ذکر نہ کرنا۔' WHERE id = 4705;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، ان سے علی بن مبارک نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے، انہوں نے ابوسلمہ بن عبدالرحمٰن سے پوچھا کہ قرآن مجید کی کون سی آیت سب سے پہلے نازل ہوئی تھی۔ انہوں نے کہا کہ «يا أيها المدثر‏» میں نے عرض کیا کہ لوگ تو کہتے ہیں کہ «اقرأ باسم ربك الذي خلق‏» سب سے پہلے نازل ہوئی۔ ابوسلمہ نے اس پر کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے پوچھا تھا اور جو بات ابھی تم نے مجھ سے کہی وہی میں نے بھی ان سے کہی تھی لیکن جابر رضی اللہ عنہ نے کہا تھا کہ میں تم سے وہی حدیث بیان کرتا ہوں جو ہم سے رسول اللہ صلی اللہ علیہ وسلم نے ارشاد فرمائی تھی۔ آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ میں غار حرا میں ایک مدت کے لیے خلوت نشیں تھا۔ جب میں وہ دن پورے کر کے پہاڑ سے اترا تو مجھے آواز دی گئی، میں نے اس آواز پر اپنے دائیں طرف دیکھا لیکن کوئی چیز نہیں دکھائی دی۔ پھر بائیں طرف دیکھا ادھر بھی کوئی چیز دکھائی نہیں دی، سامنے دیکھا ادھر بھی کوئی چیز نہیں دکھائی دی۔ پیچھے کی طرف دیکھا اور ادھر بھی کوئی چیز نہیں دکھائی دی۔ اب میں نے اپنا سر اوپر کی طرف اٹھایا تو مجھے ایک چیز دکھائی دی۔ پھر میں خدیجہ رضی اللہ عنہا کے پاس آیا اور ان سے کہا کہ مجھے کپڑا اوڑھا دو اور مجھ پر ٹھنڈا پانی ڈالو۔ فرمایا کہ پھر انہوں نے مجھے کپڑا اوڑھا دیا اور ٹھنڈا پانی مجھ پر بہایا۔ فرمایا کہ پھر یہ آیت نازل ہوئی «يا أيها المدثر * قم فأنذر * وربك فكبر‏» یعنی ”اے کپڑے میں لپٹنے والے! اٹھئیے پھر لوگوں کو عذاب الٰہی سے ڈرایئے اور اپنے پروردگار کی بڑائی بیان کیجئے۔“' WHERE id = 4715;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان نے خبر دی، کہا ہم سے عبدالرحمٰن بن عابس نے بیان کیا کہا میں نے ابن عباس رضی اللہ عنہما سے آیت «إنها ترمي بشرر كالقصر» یعنی ”وہ انگارے برسائے گی جیسے بڑے محل“ کے متعلق پوچھا اور انہوں نے کہا کہ ہم تین تین ہاتھ کی لکڑیاں اٹھا کر رکھتے تھے۔ ایسا ہم جاڑوں کے لیے کرتے تھے ( تاکہ وہ جلانے کے کام آئیں ) اور ان کا نام «قصر‏.‏» رکھتے تھے۔' WHERE id = 4726;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے اور انہیں عبداللہ بن زمعہ رضی اللہ عنہ نے خبر دی کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے اپنے ایک خطبہ میں صالح علیہ السلام کی اونٹنی کا ذکر فرمایا اور اس شخص کا بھی ذکر فرمایا جس نے اس کی کونچیں کاٹ ڈالی تھیں پھر آپ صلی اللہ علیہ وسلم نے ارشاد فرمایا «إذ انبعث أشقاها‏» یعنی اس اونٹنی کو مار ڈالنے کے لیے ایک مفسد بدبخت ( قدار نامی ) کو اپنی قوم میں ابوزمعہ کی طرح غالب اور طاقتور تھا اٹھا۔ نبی کریم صلی اللہ علیہ وسلم نے عورتوں کے حقوق کا بھی ذکر فرمایا کہ تم میں بعض اپنی بیوی کو غلام کی طرح کوڑے مارتے ہیں حالانکہ اسی دن کے ختم ہونے پر وہ اس سے ہمبستری بھی کرتے ہیں۔ پھر آپ نے انہیں ریاح خارج ہونے پر ہنسنے سے منع فرمایا اور فرمایا کہ ایک کام جو تم میں ہر شخص کرتا ہے اسی پر تم دوسروں پر کس طرح ہنستے ہو۔ ابومعاویہ نے بیان کیا کہ ہم سے ہشام بن عروہ بن زبیر نے، ان سے عبداللہ بن زمعہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ( اس حدیث میں ) یوں فرمایا ابوزمعہ کی طرح جو زبیر بن عوام کا چچا تھا۔' WHERE id = 4736;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا مجھے عدی بن ثابت نے خبر دی، انہوں نے کہا کہ میں نے براء بن عازب رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم ایک سفر میں تھے اور عشاء کی ایک رکعت میں آپ نے سورۃ والتین کی تلاوت فرمائی تھی۔ «تقويم‏» کے معنی پیدائش، بناوٹ کے ہیں۔' WHERE id = 4747;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے زید بن اسلم نے، ان سے ابوصالح سمان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ گھوڑا تین طرح کے لوگ تین قسم کے پالتے ہیں۔ ایک شخص کے لیے وہ اجر ہوتا ہے دوسرے کے لیے وہ معافی ہے، تیسرے کے لیے عذاب ہے۔ جس کے لیے وہ اجر و ثواب ہے وہ شخص ہے جو اسے اللہ کے راستہ میں جہاد کی نیت سے پالتا ہے۔ چراگاہ یا اس کے بجائے راوی نے یہ کہا باغ میں اس کی رسی کو دراز کر دیتا ہے اور وہ گھوڑا چراگاہ یا باغ میں اپنی رسی تڑا لے اور ایک دو کوڑے ( پھینکنے کی دوری ) تک اپنی حد سے آگے بڑھ گیا تو اس کے نشانات قدم اور اس کی لید بھی مالک کے لیے ثواب بن جاتی ہے اور اگر کسی نہر سے گزرتے ہوئے اس میں مالک کے ارادہ کے بغیر خود ہی اس نے پانی پی لیا تو یہ بھی مالک کے لیے باعث ثواب بن جاتا ہے۔ دوسرا شخص جس کے لیے اس کا گھوڑا باعث معافی، پردہ بنتا ہے۔ یہ وہ شخص ہے جس نے لوگوں سے بےپرواہ رہنے اور لوگوں ( کے سامنے سوال کرنے سے ) بچنے کے لیے اسے پالا اور اس گھوڑے کی گردن پر جو اللہ تعالیٰ کا حق ہے اور اس کی پیٹھ کو جو حق ہے اسے بھی وہ ادا کرتا رہتا ہے۔ تو گھوڑا اس کے لیے باعث معافی، پردہ بن جاتا ہے اور جو شخص گھوڑا اپنے دروازے پر فخر اور دکھاوے اور اسلام دشمنی کی غرض سے باندھتا ہے، وہ اس کے لیے وبال ہے۔ نبی کریم صلی اللہ علیہ وسلم سے گدھوں کے متعلق پوچھا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے اس کے متعلق مجھ پر خاص آیت سوا اس اکیلی عام اور جامع آیت کے نازل نہیں کی «فمن يعمل مثقال ذرة خيرا يره * ومن يعمل مثقال ذرة شرا يره‏» الخ یعنی ”جو کوئی ذرہ بھر نیکی کرے گا وہ اسے بھی لے گا دیکھ لے گا اور جو کوئی ذرہ بھر برائی کرے گا وہ اسے بھی دیکھ لے گا۔“' WHERE id = 4757;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو ابومعاویہ نے خبر دی، ان سے اعمش نے بیان کیا، ان سے عمرو بن مرہ نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ یعنی وہ ہلاک ہوا نہ اس کا مال اس کے کام آیا اور نہ جو کچھ اس نے کمایا وہ کام آیا۔ نبی کریم صلی اللہ علیہ وسلم بطحاء کی طرف تشریف لے گئے اور پہاڑی پر چڑھ کر پکارا۔ یا صباحاہ! قریش اس آواز پر آپ کے پاس جمع ہو گئے۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے پوچھا: تمہارا کیا خیال ہے اگر میں تمہیں بتاؤں کہ دشمن تم پر صبح کے وقت یا شام کے وقت حملہ کرنے والا ہے تو کیا تم میری تصدیق نہیں کرو گے؟ انہوں نے کہا کہ ہاں ضرور آپ کی تصدیق کریں گے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تو میں تمہیں سخت عذاب سے ڈراتا ہوں جو تمہارے سامنے آ رہا ہے۔ ابولہب بولا تم تباہ ہو جاؤ۔ کیا تم نے ہمیں اسی لیے جمع کیا تھا؟ اس پر اللہ تعالیٰ نے یہ آیت نازل کی «تبت يدا أبي لهب‏» آخر تک۔' WHERE id = 4767;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم سے شعیب نے بیان کیا، ان سے زہری نے اور انہیں انس بن مالک رضی اللہ عنہ نے خبر دی، انہوں نے بیان کیا کہ عثمان رضی اللہ عنہ نے زید بن ثابت، سعید بن عاص، عبداللہ بن زبیر، عبدالرحمٰن بن حارث بن ہشام رضی اللہ عنہم کو حکم دیا کہ قرآن مجید کو کتابی شکل میں لکھیں اور فرمایا کہ اگر قرآن کے کسی محاورے میں تمہارا زید بن ثابت رضی اللہ عنہ سے اختلاف ہو تو اس لفظ کو قریش کے محاورہ کے مطابق لکھو، کیونکہ قرآن ان ہی کے محاورے پر نازل ہوا ہے چنانچہ انہوں نے ایسا ہی کیا۔' WHERE id = 4778;
UPDATE hadiths SET urdu = 'ہم آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق نے بیان کیا، انہوں نے عبدالرحمٰن بن امیہ سے سنا اور انہوں نے ابن مسعود رضی اللہ عنہ سے سنا، انہوں نے کہا سورۃ بنی اسرائیل، سورۃ الکہف، سورۃ مریم، سورۃ طہٰ اور سورۃ انبیاء کے متعلق بتلایا کہ یہ پانچوں سورتیں اول درجہ کی فصیح سورتیں ہیں اور میری یاد کی ہوئی ہیں۔' WHERE id = 4788;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا ‘ کہا ہم سے عبداللہ بن مثنی نے بیان کیا ‘ کہا کہ مجھ سے ثابت بنانی اور ثمامہ نے بیان کیا اور ان سے انس نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی وفات تک قرآن مجید کو چار صحابیوں کے سوا اور کسی نے جمع نہیں کیا تھا۔ ابودرداء ‘ معاذ بن جبل ‘ زید بن ثابت اور ابوزید رضی اللہ عنہم۔ انس نے کہا کہ ابوزید کے وارث ہم ہوئے ہیں۔' WHERE id = 4798;
UPDATE hadiths SET urdu = 'اور ابومعمر (عبداللہ بن عمرو منقری) نے اتنا زیادہ کیا کہ ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے امام مالک بن انس نے، ان سے عبدالرحمٰن بن عبداللہ بن عبدالرحمٰن بن ابی صعصعہ نے، ان سے ان کے والد نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ مجھے میرے بھائی قتادہ بن نعمان رضی اللہ عنہ نے خبر دی کہ ایک صحابی نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں سحری کے وقت سے کھڑے «قل هو الله أحد‏» پڑھتے رہے۔ ان کے سوا اور کچھ نہیں پڑھتے تھے۔ پھر جب صبح ہوئی تو دوسرے صحابی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے ( باقی حصہ ) پچھلی حدیث کی طرح بیان کیا۔' WHERE id = 4808;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے زہری نے، ان سے ابوسلمہ بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے کوئی چیز توجہ سے نہیں سنی جتنی توجہ سے اپنے نبی ( صلی اللہ علیہ وسلم ) کو بہترین آواز کے ساتھ قرآن مجید پڑھتے سنا ہے۔ سفیان بن عیینہ نے کہا «يتغنى بالقرآن» سے مراد ہے کہ قرآن پر قناعت کرے۔' WHERE id = 4818;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، کہا کہ مجھے ابوایاس نے خبر دی، کہا کہ میں نے عبداللہ بن مغفل رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو فتح مکہ کے دن دیکھا کہ آپ سواری پر سورۃ الفتح کی تلاوت فرما رہے تھے۔' WHERE id = 4829;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر بن عبدالحمید نے بیان کیا، ان سے موسیٰ بن ابی عائشہ نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے اللہ تعالیٰ کے فرمان «لا تحرك به لسانك لتعجل به‏» ”آپ قرآن کو جلدی جلدی لینے کے لیے اس پر زبان کو نہ ہلایا کریں۔“ بیان کیا کہ جب جبرائیل علیہ السلام وحی لے کر نازل ہوتے تو رسول اللہ صلی اللہ علیہ وسلم اپنی زبان اور ہونٹ ہلایا کرتے تھے۔ اس کی وجہ سے آپ کے لیے وحی یاد کرنے میں بہت بار پڑتا تھا اور یہ آپ کے چہرے سے بھی ظاہر ہو جاتا تھا۔ اس لیے اللہ تعالیٰ نے یہ آیت جو سورۃ «لا أقسم بيوم القيامة‏» میں ہے، نازل کی کہ آپ قرآن کو جلدی جلدی لینے کے لیے اس پر زبان کو نہ ہلایا کریں یہ تو ہمارے ذمہ ہے اس کا جمع کرنا اور اس کا پڑھوانا تو جب ہم اسے پڑھنے لگیں تو آپ اس کے پیچھے پیچھے پڑھا کریں پھر آپ کی زبان سے اس کی تفسیر بیان کرا دینا بھی ہمارے ذمہ ہے۔“ راوی نے بیان کیا کہ پھر جب جبرائیل علیہ السلام آتے تو آپ سر جھکا لیتے اور جب واپس جاتے تو پڑھتے جیسا کہ اللہ نے آپ سے یاد کروانے کا وعدہ کیا تھا کہ تیرے دل میں جما دینا اس کو پڑھا دینا ہمارا کام ہے پھر آپ اس کے موافق پڑھتے۔' WHERE id = 4840;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن منصور نے بیان کیا، کہا ہم کو عبیداللہ بن موسیٰ نے خبر دی، انہیں شیبان نے، انہیں یحییٰ بن ابی کثیر نے، انہیں بنی زہرہ کے مولیٰ محمد بن عبدالرحمٰن نے، انہیں ابوسلمہ بن عبدالرحمٰن نے، یحییٰ نے کہا اور میں خیال کرتا ہوں شاید میں نے یہ حدیث خود ابوسلمہ سے سنی ہے۔ بلاواسطہ (محمد بن عبدالرحمٰن کے) خیر ابوسلمہ نے عبداللہ بن عمرو بن عاص رضی اللہ عنہما سے روایت کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا کہ ہر مہینے میں قرآن کا ایک ختم کیا کرو میں نے عرض کیا مجھ کو تو زیادہ پڑھنے کی طاقت ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اچھا سات راتوں میں ختم کیا کرو اس سے زیادہ مت پڑھ۔' WHERE id = 4851;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے حسان بن ابراہیم سے سنا، انہوں نے یونس بن یزید ایلی سے، ان سے زہری نے، کہا مجھ کو عروہ بن زبیر نے خبر دی اور انہوں نے عائشہ رضی اللہ عنہا سے اللہ تعالیٰ کے اس ارشاد «وإن خفتم أن لا تقسطوا في اليتامى فانكحوا ما طاب لكم من النساء مثنى وثلاث ورباع فإن خفتم أن لا تعدلوا فواحدة أو ما ملكت أيمانكم ذلك أدنى أن لا تعولوا‏» کے متعلق پوچھا ”اور اگر تمہیں اندیشہ ہو کہ تم یتیموں سے انصاف نہ کر سکو گے تو جو عورتیں تمہیں پسند ہوں ان سے نکاح کر لو۔ دو دو سے، خواہ تین تین سے، خواہ چار چار سے، لیکن اگر تمہیں اندیشہ ہو کہ تم انصاف نہیں کر سکو گے تو پھر ایک ہی پر بس کرو یا جو لونڈی تمہاری ملک میں ہو، اس صورت میں قوی امید ہے کہ تم ظلم و زیادتی نہ کر سکو گے۔“ عائشہ رضی اللہ عنہا نے کہا: بھانجے! آیت میں ایسی یتیم مالدار لڑکی کا ذکر ہے جو اپنے ولی کی پرورش میں ہو۔ وہ لڑکی کے مال اور اس کے حسن کی وجہ سے اس کی طرف مائل ہو اور اس سے معمولی مہر پر شادی کرنا چاہتا ہو تو ایسے شخص کو اس آیت میں ایسی لڑکی سے نکاح کرنے سے منع کیا گیا ہے۔ ہاں اگر اس کے ساتھ انصاف کر سکتا ہو اور پورا مہر ادا کرنے کا ارادہ رکھتا ہو تو اجازت ہے، ورنہ ایسے لوگوں سے کہا گیا ہے کہ اپنی پرورش میں یتیم لڑکیوں کے سوا اور دوسری لڑکیوں سے شادی کر لیں۔' WHERE id = 4861;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا مجھے سعید بن مسیب نے خبر دی اور انہوں نے سعد بن ابی وقاص رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے عثمان بن مظعون رضی اللہ عنہ کو عورت سے الگ رہنے کی اجازت نہیں دی تھی۔ اگر نبی کریم صلی اللہ علیہ وسلم انہیں اس کی اجازت دے دیتے تو ہم بھی اپنے آپ کو خصی بنا لیتے۔' WHERE id = 4871;
UPDATE hadiths SET urdu = 'ہم سے سعید بن تلید نے بیان کیا، کہا کہ مجھے عبداللہ بن وہب نے خبر دی، کہا کہ مجھے جریر بن حازم نے خبر دی، انہیں ایوب سختیانی نے، انہیں محمد بن سیرین نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا۔ ( دوسری سند ) ہم سے سلیمان بن حرب نے بیان کیا، ان سے حماد بن زید نے، ان سے ایوب سختیانی نے، ان سے محمد بن سیرین نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ ابراہیم علیہ السلام کی زبان سے تین مرتبہ کے سوا کبھی دین میں جھوٹ بات نہیں نکلی۔ ایک مرتبہ آپ ایک ظالم بادشاہ کی حکومت سے گزرے آپ کے ساتھ آپ کی بیوی سارہ علیہ السلام تھیں۔ پھر پورا واقعہ بیان کیا ( کہ بادشاہ کے سامنے ) آپ نے سارہ علیہ السلام کو اپنی بہن ( یعنی دینی بہن ) کہا۔ پھر اس بادشاہ نے سارہ علیہا السلام کو آجر ( ہاجرہ ) کو دے دیا۔ ( بی بی سارہ علیہا السلام نے ابراہیم علیہ السلام سے ) کہا کہ اللہ تعالیٰ نے کافر کے ہاتھ کو روک دیا اور آجر ( ہاجرہ ) کو میری خدمت کے لیے دلوا دیا۔ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ اے آسمان کے پانی کے بیٹو! یعنی اے عرب والو! یہی ہاجرہ علیہا السلام تمہاری ماں ہیں۔' WHERE id = 4881;
UPDATE hadiths SET urdu = 'ہم سے محمد بن منہال نے بیان کیا، انہوں نے کہا ہم سے یزید بن زریع نے بیان کیا، ان سے عمر بن محمد عسقلانی نے بیان کیا، ان سے ان کے والد اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے سامنے نحوست کا ذکر کیا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر نحوست کسی چیز میں ہو تو گھر، عورت اور گھوڑے میں ہو سکتی ہے۔' WHERE id = 4891;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے اسماعیل بن ابراہیم نے، کہا ہم کو ایوب سختیانی نے خبر دی، انہیں عبداللہ بن ابی ملیکہ نے، کہا کہ مجھ سے عبیداللہ بن ابی مریم نے بیان کیا، ان سے عقبہ بن حارث رضی اللہ عنہ نے (عبداللہ بن ابی ملیکہ نے) بیان کیا کہ میں نے یہ حدیث خود عقبہ سے بھی سنی ہے لیکن مجھے عبید کے واسطے سے سنی ہوئی حدیث زیادہ یاد ہے۔ عقبہ بن حارث نے بیان کیا کہ میں نے ایک عورت ( ام یحییٰ بن ابی اہاب ) سے نکاح کیا۔ پھر ایک کالی عورت آئی اور کہنے لگی کہ میں نے تم دونوں ( میاں بیوی ) کو دودھ پلایا ہے۔ میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کیا کہ میں نے فلانی بنت فلاں سے نکاح کیا ہے۔ اس کے بعد ہمارے یہاں ایک کالی عورت آئی اور مجھ سے کہنے لگی کہ میں نے تم دونوں کو دودھ پلایا ہے، حالانکہ وہ جھوٹی ہے ( آپ صلی اللہ علیہ وسلم کو عقبہ کا یہ کہنا کہ وہ جھوٹی ہے ناگوار گزرا ) آپ صلی اللہ علیہ وسلم نے اس پر اپنا چہرہ مبارک پھیر لیا۔ پھر میں آپ کے سامنے آیا اور عرض کیا وہ عورت جھوٹی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس بیوی سے اب کیسے نکاح رہ سکے گا جبکہ یہ عورت یوں کہتی ہے کہ اس نے تم دونوں کو دودھ پلایا ہے، اس عورت کو اپنے سے الگ کر دو۔“ ( حدیث کے راوی ) اسماعیل بن علیہ نے اپنی شہادت اور بیچ کی انگلی سے اشارہ کر کے بتایا کہ ایوب نے اس طرح اشارہ کر کے۔' WHERE id = 4901;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر محمد بن جعفر نے بیان کیا، کہا ہم سے شعبہ بن حجاج نے بیان کیا، ان سے ابوجمرہ نے بیان کیا، کہا میں نے ابن عباس رضی اللہ عنہما سے سنا، ان سے عورتوں کے ساتھ نکاح متعہ کرنے کے متعلق سوال کیا گیا تھا تو انہوں نے اس کی اجازت دی، پھر ان کے ایک غلام نے ان سے پوچھا کہ اس کی اجازت سخت مجبوری یا عورتوں کی کمی یا اسی جیسی صورتوں میں ہو گی؟ تو ابن عباس رضی اللہ عنہما نے کہا کہ ہاں۔ ( نوٹ: یہ حرمت سے قبل کی بات ہے بعد میں ہر حالت میں ہر شخص کے لیے متعہ حرام قرار دیا گیا جو قیامت تک کے لیے ہے ) ۔' WHERE id = 4912;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سعید نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، ان سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ آیت «وما يتلى عليكم في الكتاب في يتامى النساء اللاتي لا تؤتونهن ما كتب لهن وترغبون أن تنكحوهن‏» یعنی ”وہ ( آیات بھی ) جو تمہیں کتاب کے اندر ان یتیم لڑکوں کے بارے میں پڑھ کر سنائی جاتی ہیں جنہیں تم وہ نہیں دیتے ہو جو ان کے لیے مقرر ہو چکا ہے اور اس سے بیزار ہو کہ ان کا کسی سے نکاح کرو۔“ ایسی یتیم لڑکی کے بارے میں نازل ہوئی تھی جو کسی شخص کی پرورش میں ہو۔ ممکن ہے کہ اس کے مال و جائیداد میں بھی شریک ہو، وہی لڑکی کا زیادہ حقدار ہے لیکن وہ اس سے نکاح نہیں کرنا چاہتا البتہ اس کے مال کی وجہ سے اسے روکے رکھتا ہے اور کسی دوسرے مرد سے اس کی شادی نہیں ہونے دیتا کیونکہ وہ نہیں چاہتا کہ کوئی دوسرا اس کے مال میں حصہ دار بنے۔' WHERE id = 4923;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے عبدالرحمٰن بن قاسم نے، ان سے ان کے والد نے، ان سے عبدالرحمٰن اور مجمع نے جو دونوں یزید بن حارثہ کے بیٹے ہیں، ان سے خنساء بنت خذام انصاریہ رضی اللہ عنہا نے کہ ان کے والد نے ان کا نکاح کر دیا تھا، وہ ثیبہ تھیں، انہیں یہ نکاح منظور نہیں تھا، اس لیے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں، نبی کریم صلی اللہ علیہ وسلم نے اس نکاح کو فسخ کر دیا۔' WHERE id = 4933;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، ان سے سفیان نے ان سے ابوحازم نے اور ان سے صحابی سہل بن سعد رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک آدمی سے فرمایا کہ نکاح کر، خواہ لوہے کی ایک انگوٹھی پر ہی ہو۔' WHERE id = 4944;
UPDATE hadiths SET urdu = 'مجھ سے فروہ بن ابی المغراء نے بیان کیا، کہا ہم سے علی بن مسہر نے بیان کیا، ان سے ہشام بن عروہ نے، انس سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے شادی کی تھی۔ میری والدہ میرے پاس آئیں اور تنہا مجھے ایک گھر میں داخل کر دیا۔ پھر مجھے کسی چیز نے خوف نہیں دلایا سوائے رسول اللہ صلی اللہ علیہ وسلم کے کہ آپ اچانک ہی میرے پاس چاشت کے وقت آ گئے۔ آپ نے مجھ سے ملاپ فرمایا۔' WHERE id = 4954;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے زہیر نے بیان کیا، ان سے بیان بن بشر نے بیان کیا، انہوں نے کہا کہ میں نے انس رضی اللہ عنہ سے سنا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم ایک خاتون ( زینب بنت جحش رضی اللہ عنہا ) کو نکاح کر کے لائے تو مجھے بھیجا اور میں نے لوگوں کو ولیمہ کھانے کے لیے بلایا۔' WHERE id = 4964;
UPDATE hadiths SET urdu = 'ہم سے عبدالرحمٰن بن المبارک نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، کہا ہم سے عبدالعزیز بن صہیب نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے عورتوں اور بچوں کو کسی شادی سے آتے ہوئے دیکھا تو آپ صلی اللہ علیہ وسلم خوشی کے مارے جلدی سے کھڑے ہو گئے اور فرمایا: یا اللہ! ( تو گواہ رہ ) تم لوگ سب لوگوں سے زیادہ مجھ کو محبوب ہو۔' WHERE id = 4974;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو معمر نے خبر دی، انہیں ہمام بن منبہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر شوہر گھر پر موجود ہے تو کوئی عورت اس کی اجازت کے بغیر ( نفلی ) روزہ نہ رکھے۔' WHERE id = 4985;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، ان سے ابن جریج نے (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور مجھ سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں ابن جریج نے خبر دی، کہا کہ مجھے یحییٰ بن عبداللہ بن صیفی نے خبر دی، انہیں عکرمہ بن عبدالرحمٰن بن حارث نے خبر دی اور انہیں ام سلمہ رضی اللہ عنہا نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم نے ( ایک واقعہ کی وجہ سے ) قسم کھائی کہ اپنی بعض ازواج کے یہاں ایک مہینہ تک نہیں جائیں گے۔ پھر جب انتیس دن گزر گئے تو نبی کریم صلی اللہ علیہ وسلم ان کے پاس صبح کے وقت گئے یا شام کے وقت نبی کریم صلی اللہ علیہ وسلم سے عرض کیا گیا کہ آپ نے تو قسم کھائی تھی کہ ایک مہینہ تک نہیں آئیں گے؟ آپ نے فرمایا کہ مہینہ انتیس دن کا بھی ہوتا ہے۔' WHERE id = 4995;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن راشد نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے سفیان ثوری نے، کہا ہم سے ایوب اور خالد نے دونوں نے بیان کیا، ان سے ابوقلابہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ دستور یہ کہ جب کوئی شخص پہلے سے شادی شدہ بیوی کی موجودگی میں کسی کنواری عورت سے شادی کرے تو اس کے ساتھ سات دن تک قیام کرے اور پھر باری مقرر کرے اور جب کسی کنواری بیوی کی موجودگی میں پہلے سے شادی شدہ عورت سے نکاح کرے تو اس کے ساتھ تین دن تک قیام کرے اور پھر باری مقرر کرے۔ ابوقلابہ نے بیان کیا کہ اگر میں چاہوں تو کہہ سکتا ہوں کہ انس رضی اللہ عنہ نے یہ حدیث نبی کریم صلی اللہ علیہ وسلم سے مرفوعاً بیان کی ہے۔ اور عبدالرزاق نے بیان کیا، انہیں سفیان نے خبر دی، انہیں ایوب اور خالد نے کہا کہ اگر میں چاہوں تو کہہ سکتا ہوں کہ انس رضی اللہ عنہ نے یہ حدیث نبی کریم صلی اللہ علیہ وسلم سے مرفوعاً بیان کی ہے۔' WHERE id = 5006;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، کہا کہ مجھے میرے والد نے خبر دی اور ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے بیان کیا کہ زبیر رضی اللہ عنہ نے مجھ سے شادی کی تو ان کے پاس ایک اونٹ اور ان کے گھوڑے کے سوا روئے زمین پر کوئی مال، کوئی غلام، کوئی چیز نہیں تھی۔ میں ہی ان کا گھوڑا چراتی، پانی پلاتی، ان کا ڈول سیتی اور آٹا گوندھتی۔ میں اچھی طرح روٹی نہیں پکا سکتی تھی۔ انصار کی کچھ لڑکیاں میری روٹی پکا جاتی تھیں۔ یہ بڑی سچی اور باوفا عورتیں تھیں۔ زبیر رضی اللہ عنہ کی وہ زمین جو رسول اللہ صلی اللہ علیہ وسلم نے انہیں دی تھی، اس سے میں اپنے سر پر کھجور کی گٹھلیاں گھر لایا کرتی تھی۔ یہ زمین میرے گھر سے دو میل دور تھی۔ ایک روز میں آ رہی تھی اور گٹھلیاں میرے سر پر تھیں کہ راستے میں رسول اللہ صلی اللہ علیہ وسلم سے ملاقات ہو گئی۔ نبی کریم صلی اللہ علیہ وسلم کے ساتھ قبیلہ انصار کے کئی آدمی تھے۔ نبی کریم صلی اللہ علیہ وسلم نے مجھے بلایا پھر ( اپنے اونٹ کو بٹھانے کے لیے ) کہا اخ اخ۔ نبی کریم صلی اللہ علیہ وسلم چاہتے تھے کہ مجھے اپنی سواری پر اپنے پیچھے سوار کر لیں لیکن مجھے مردوں کے ساتھ چلنے میں شرم آئی اور زبیر رضی اللہ عنہ کی غیرت کا بھی خیال آیا۔ زبیر رضی اللہ عنہ بڑے ہی باغیرت تھے۔ نبی کریم صلی اللہ علیہ وسلم بھی سمجھ گئے کہ میں شرم محسوس کر رہی ہوں۔ اس لیے آپ آگے بڑھ گئے۔ پھر میں زبیر رضی اللہ عنہ کے پاس آئی اور ان سے واقعہ کا ذکر کیا کہ نبی کریم صلی اللہ علیہ وسلم سے میری ملاقات ہو گئی تھی۔ میرے سر پر گٹھلیاں تھیں اور نبی کریم صلی اللہ علیہ وسلم کے ساتھ آپ کے چند صحابہ بھی تھے۔ نبی کریم صلی اللہ علیہ وسلم نے اپنا اونٹ مجھے بٹھانے کے لیے بٹھایا لیکن مجھے اس سے شرم آئی اور تمہاری غیرت کا بھی خیال آیا۔ اس پر زبیر نے کہا کہ اللہ کی قسم! مجھ کو تو اس سے بڑا رنج ہوا کہ تو گٹھلیاں لانے کے لیے نکلے اگر تو نبی کریم صلی اللہ علیہ وسلم کے ساتھ سوار ہو جاتی تو اتنی غیرت کی بات نہ تھی ( کیونکہ اسماء رضی اللہ عنہا آپ کی سالی اور بھاوج دونوں ہوتی تھیں ) اس کے بعد میرے والد ابوبکر رضی اللہ عنہ نے ایک غلام میرے پاس بھیج دیا وہ گھوڑے کا سب کام کرنے لگا اور میں بےفکر ہو گئی گویا والد ماجد ابوبکر رضی اللہ عنہ نے ( غلام بھیج کر ) مجھ کو آزاد کر دیا۔' WHERE id = 5016;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے حدیث بیان کی، ان سے غندر نے حدیث بیان کی، ان سے شعبہ نے حدیث بیان کی، ان سے ہشام نے بیان کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ قبیلہ انصار کی ایک خاتون نبی کریم صلی اللہ علیہ وسلم کے پاس آئیں اور نبی کریم صلی اللہ علیہ وسلم نے اس سے لوگوں سے ایک طرف ہو کر تنہائی میں گفتگو کی اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم لوگ ( یعنی انصار ) مجھے سب لوگوں سے زیادہ عزیز ہو۔' WHERE id = 5026;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل مروزی نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو عاصم بن سلیمان نے خبر دی، انہیں عامر شعبی نے اور ان سے جابر بن عبداللہ انصاری رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اگر تم میں سے کوئی شخص زیادہ دنوں تک اپنے گھر سے دور ہو تو یکایک رات کو اپنے گھر میں نہ آ جائے۔' WHERE id = 5036;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے ولید بن مسلم نے بیان کیا، کہا ہم سے امام اوزاعی نے بیان کیا، کہا کہ میں نے زہری سے پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم کی کن بیوی نے نبی کریم صلی اللہ علیہ وسلم سے پناہ مانگی تھی؟ انہوں نے بیان کیا کہ مجھے عروہ بن زبیر نے خبر دی اور انہیں عائشہ رضی اللہ عنہا نے کہ جون کی بیٹی ( امیمہ یا اسماء ) جب نبی کریم صلی اللہ علیہ وسلم کے یہاں ( نکاح کے بعد ) لائی گئیں اور نبی کریم صلی اللہ علیہ وسلم ان کے پاس گئے تو اس نے یہ کہہ دیا کہ میں تم سے اللہ کی پناہ مانگتی ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ تم نے بہت بڑی چیز سے پناہ مانگی ہے، اپنے میکے چلی جاؤ۔ ابوعبداللہ امام بخاری رحمہ اللہ نے اس حدیث کو حجاج بن یوسف بن ابی منیع سے، اس نے بھی اپنے دادا ابومنیع ( عبیداللہ بن ابی زیاد ) سے، انہوں نے زہری سے، انہوں نے عروہ سے، انہوں نے عائشہ رضی اللہ عنہا سے روایت کیا ہے۔' WHERE id = 5046;
UPDATE hadiths SET urdu = 'مجھ سے حسن بن الصباح نے بیان کیا، انہوں نے ربیع بن نافع سے سنا کہ ہم سے معاویہ بن سلام نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے، ان سے یعلیٰ بن حکیم نے، ان سے سعید بن جبیر نے، انہوں نے انہیں خبر دی کہ انہوں نے ابن عباس رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ اگر کسی نے اپنی بیوی کو اپنے اوپر حرام کہا تو یہ کوئی چیز نہیں اور فرمایا کہ تمہارے لیے رسول اللہ صلی اللہ علیہ وسلم کی پیروی عمدہ پیروی ہے۔' WHERE id = 5058;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے ابن ابی ملیکہ نے اور ان سے مسور بن مخرمہ رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ بنی مغیرہ نے اس کی اجازت مانگی ہے کہ علی رضی اللہ عنہ سے وہ اپنی بیٹی کا نکاح کر لیں لیکن میں انہیں اس کی اجازت نہیں دوں گا۔' WHERE id = 5069;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے اور ابراہیم بن المنذر نے بیان کیا کہ مجھ سے عبداللہ بن وہب نے بیان کیا، ان سے یونس نے بیان کیا کہ ابن شہاب نے بیان کیا کہ مجھے عروہ بن زبیر نے خبر دی اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ مومن عورتیں جب ہجرت کر کے نبی کریم صلی اللہ علیہ وسلم کے پاس آتی تھیں تو نبی کریم صلی اللہ علیہ وسلم انہیں آزماتے تھے بوجہ اللہ تعالیٰ کے اس ارشاد کے «يا أيها الذين آمنوا إذا جاءكم المؤمنات مهاجرات فامتحنوهن‏» کہ ”اے وہ لوگو! جو ایمان لے آئے ہو، جب مومن عورتیں تمہارے پاس ہجرت کر کے آئیں تو انہیں آزماؤ“۔ آخر آیت تک۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر ان ( ہجرت کرنے والی ) مومن عورتوں میں سے جو اس شرط کا اقرار کر لیتی ( جس کا ذکر اسی سورۃ الممتحنہ میں ہے کہ ”اللہ کا کسی کو شریک نہ ٹھہراؤ گی“ ) تو وہ آزمائش میں پوری سمجھی جاتی تھی۔ چنانچہ جب وہ اس کا اپنی زبان سے اقرار کر لیتیں تو رسول اللہ صلی اللہ علیہ وسلم ان سے فرماتے کہ اب جاؤ میں نے تم سے عہد لے لیا ہے۔ ہرگز نہیں! واللہ! نبی کریم صلی اللہ علیہ وسلم کے ہاتھ نے ( بیعت لیتے وقت ) کسی عورت کا ہاتھ کبھی نہیں چھوا۔ نبی کریم صلی اللہ علیہ وسلم ان سے صرف زبان سے ( بیعت لیتے تھے ) ۔ واللہ! نبی کریم صلی اللہ علیہ وسلم نے عورتوں سے صرف انہیں چیزوں کا عہد لیا جن کا اللہ نے آپ کو حکم دیا تھا۔ بیعت لینے کے بعد آپ ان سے فرماتے کہ میں نے تم سے عہد لے لیا ہے۔ یہ آپ صرف زبان سے کہتے کہ میں نے تم سے بیعت لے لی۔' WHERE id = 5079;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے یحییٰ بن سعید انصاری نے اور انہوں نے انس بن مالک انصاری رضی اللہ عنہ سے سنا، بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ تمہیں بتاؤں کہ قبیلہ انصار کا سب سے بہتر گھرانہ کون سا ہے؟ صحابہ نے عرض کیا کہ ضرور بتائیے یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے فرمایا کہ بنو نجار کا۔ اس کے بعد ان کا مرتبہ ہے جو ان سے قریب ہیں یعنی بنو عبدالاشہل کا، ان کے بعد وہ ہیں جو ان سے قریب ہیں، بنی الحارث بن خزرج کا۔ اس کے بعد وہ ہیں جو ان سے قریب ہیں، بنو ساعدہ کا۔ پھر نبی کریم صلی اللہ علیہ وسلم نے اپنے ہاتھ سے اشارہ کیا اور اپنی مٹھی بند کی، پھر اسے اس طرح کھولا جیسے کوئی اپنے ہاتھ کی چیز کو پھینکتا ہے پھر فرمایا کہ انصار کے ہر گھرانہ میں خیر ہے۔' WHERE id = 5091;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا کہ مجھ سے لیث نے بیان کیا، ان سے یحییٰ بن سعید نے، ان سے عبدالرحمٰن بن قاسم نے، ان سے قاسم بن محمد نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کی مجلس میں لعان کا ذکر ہوا اور عاصم رضی اللہ عنہ نے اس سلسلہ میں کوئی بات کہی ( کہ میں اگر اپنی بیوی کے ساتھ کسی غیر مرد کو دیکھ لوں تو وہیں قتل کر دوں ) اور چلے گئے، پھر ان کی قوم کے ایک صحابی ( عویمر رضی اللہ عنہ ) ان کے پاس آئے یہ شکایت لے کر کہ انہوں نے اپنی بیوی کے ساتھ ایک غیر مرد کو پایا ہے۔ عاصم رضی اللہ عنہ نے کہا کہ مجھے آج یہ ابتلاء میری اسی بات کی وجہ سے ہوا ہے ( جو آپ نے نبی کریم صلی اللہ علیہ وسلم کے سامنے کہی تھی ) پھر وہ انہیں لے کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور نبی کریم صلی اللہ علیہ وسلم کو وہ واقعہ بتایا جس میں ملوث اس صحابی نے اپنی کو پایا تھا۔ یہ صاحب زرد رنگ، کم گوشت والے ( پتلے دبلے ) اور سیدھے بال والے تھے اور جس کے متعلق انہوں نے دعویٰ کیا تھا کہ اسے انہوں نے اپنی بیوی کے ساتھ ( تنہائی میں ) پایا، وہ گھٹے ہوئے جسم کا، گندمی اور بھرے گوشت والا تھا۔ پھر نبی کریم صلی اللہ علیہ وسلم نے دعا فرمائی کہ اے اللہ! اس معاملہ کو صاف کر دے۔ چنانچہ اس عورت نے بچہ اسی مرد کی شکل کا جنا جس کے متعلق شوہر نے دعویٰ کیا تھا کہ اسے انہوں نے اپنی بیوی کے ساتھ پایا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے میاں بیوی کے درمیان لعان کرایا۔ ایک شاگرد نے مجلس میں ابن عباس رضی اللہ عنہما سے پوچھا کیا یہی وہ عورت ہے جس کے متعلق نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ اگر میں کسی کو بلا شہادت کے سنگسار کر سکتا تو اس عورت کو سنگسار کرتا۔ ابن عباس رضی اللہ عنہما نے کہا کہ نہیں ( یہ جملہ نبی کریم صلی اللہ علیہ وسلم نے ) اس عورت کے متعلق فرمایا تھا جس کی بدکاری اسلام کے زمانہ میں کھل گئی تھی۔ ابوصالح اور عبداللہ بن یوسف نے اس حدیث میں بجائے «خدلا‏.‏» کے کسرہ کے ساتھ دال «خدلا‏.‏» روایت کیا ہے لیکن معنی وہی ہے۔' WHERE id = 5101;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے، ان سے مسور بن مخرمہ نے کہ سبیعہ اسلمیہ اپنے شوہر کی وفات کے بعد چند دنوں تک حالت نفاس میں رہیں۔ پھر نبی کریم صلی اللہ علیہ وسلم کے پاس آ کر انہوں نے نکاح کی اجازت مانگی تو نبی کریم صلی اللہ علیہ وسلم نے انہیں اجازت دی اور انہوں نے نکاح کیا۔' WHERE id = 5111;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے بشر نے بیان کیا، کہا ہم سے سلمہ بنت علقمہ نے بیان کیا، ان سے محمد بن سیرین نے کہ ام عطیہ رضی اللہ عنہا نے بیان کیا کہ ہمیں منع کیا گیا ہے کہ شوہر کے سوا کسی کا سوگ تین دن سے زیادہ منائیں۔' WHERE id = 5127;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، ان سے سعید بن جبیر نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے لعان کرنے والے میاں بیوی سے فرمایا کہ تمہارا حساب اللہ کے یہاں ہو گا۔ تم میں سے ایک تو یقیناً جھوٹا ہے۔ تمہارے یعنی ( شوہر کے ) لیے اسے ( بیوی کو ) حاصل کرنے کا اب کوئی راستہ نہیں ہے۔ شوہر نے عرض کیا: یا رسول اللہ! میرا مال؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اب وہ تمہارا مال نہیں رہا۔ اگر تم نے اس کے متعلق سچ کہا تھا تو وہ اس کے بدلہ میں ہے کہ تم نے اس کی شرمگاہ اپنے لیے حلال کی تھی اور اگر تم نے اس پر جھوٹی تہمت لگائی تھی تب تو اور زیادہ تجھ کو کچھ نہ ملنا چاہیئے۔' WHERE id = 5137;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، ان سے معمر بن راشد نے، ان سے ہمام بن عیینہ نے، کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر عورت اپنے شوہر کی کمائی میں سے، اس کے حکم کے بغیر ( دستور کے مطابق ) اللہ کے راستہ میں خرچ کر دے تو اسے بھی آدھا ثواب ملتا ہے۔' WHERE id = 5147;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، ان سے سفیان ثوری نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ہند نے عرض کیا: یا رسول اللہ! ابوسفیان بخیل ہیں۔ اگر میں ان کے مال سے اتنا ( ان سے پوچھے بغیر ) لے لیا کروں جو میرے اور میرے بچوں کو کافی ہو تو کیا اس میں کوئی گناہ ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ دستور کے مطابق لے لیا کرو۔' WHERE id = 5157;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو شعبہ نے خبر دی، انہیں اشعث نے، انہیں ان کے والد نے، انہیں مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جہاں تک ممکن ہوتا پاکی حاصل کرنے میں، جوتا پہننے اور کنگھا کرنے میں داہنی طرف سے ابتداء کرتے۔ اشعث اس حدیث کا راوی جب واسط شہر میں تھا تو اس نے اس حدیث میں یوں کہا تھا کہ ہر ایک کام میں نبی کریم صلی اللہ علیہ وسلم داہنی طرف سے ابتداء کرتے۔' WHERE id = 5167;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد نے بیان کیا، ان سے یحییٰ بن سعید انصاری نے، ان سے بشیر بن یسار نے، انہیں سوید بن نعمان رضی اللہ عنہ نے خبر دی کہ وہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ مقام صہبا میں تھے۔ وہ خیبر سے ایک منزل پر ہے۔ نماز کا وقت قریب تھا تو نبی کریم صلی اللہ علیہ وسلم نے کھانا طلب فرمایا لیکن ستو کے سوا اور کوئی چیز نہیں لائی گئی۔ آخر نبی کریم صلی اللہ علیہ وسلم نے اس کو پھانک لیا اور ہم نے بھی پھانکا پھر آپ صلی اللہ علیہ وسلم نے پانی طلب فرمایا اور کلی کی۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے نماز پڑھائی اور ہم نے بھی آپ کے ساتھ نماز پڑھی اور آپ نے ( اس نماز کے لیے نیا ) وضو نہیں کیا۔' WHERE id = 5177;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے ہشام بن یوسف نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں ابوامامہ بن سہل نے اور انہیں ابن عباس رضی اللہ عنہما نے کہ خالد بن ولید رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے لیے بھنا ہوا ساہنہ پیش کیا گیا تو آپ اسے کھانے کے لیے متوجہ ہوئے۔ اسی وقت آپ کو بتایا گیا کہ یہ ساہنہ ہے تو آپ صلی اللہ علیہ وسلم نے اپنا ہاتھ روک لیا۔ خالد رضی اللہ عنہ نے پوچھا کیا یہ حرام ہے؟ فرمایا کہ نہیں لیکن چونکہ یہ میرے ملک میں نہیں ہوتا اس لیے طبیعت اسے گوارا نہیں کرتی۔ پھر خالد رضی اللہ عنہ نے اسے کھایا اور نبی کریم صلی اللہ علیہ وسلم دیکھ رہے تھے۔ امام مالک نے ابن شہاب سے «ضب محنوذ‏.‏» ( یعنی بھنا ہوا ساہنہ «ضب مشوی» کی جگہ «محنوذ‏.‏» نقل کیا، دونوں لفظوں کا ایک معنی ہے ) ۔' WHERE id = 5187;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا ہم سے ابوغسان (محمد بن مطرف لیثی) نے بیان کیا، کہا کہ مجھ سے ابوحازم سلمہ بن دینار نے بیان کیا، انہوں نے سہل بن سعد ساعدی رضی اللہ عنہ سے پوچھا کیا تم نے نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں میدہ دیکھا تھا؟ انہوں نے کہا کہ نہیں، میں نے پوچھا کیا تم جَو کے آٹے کو چھانتے تھے؟ کہا نہیں، بلکہ ہم اسے صرف پھونک لیا کرتے تھے۔' WHERE id = 5197;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن منیر نے بیان کیا، انہوں نے ابوحاتم اشہل ابن حاتم سے سنا، ان سے ابن عون نے بیان کیا، ان سے شمامہ بن انس نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ آپ کے ایک غلام کے پاس گیا جو درزی تھے۔ انہوں نے نبی کریم صلی اللہ علیہ وسلم کے سامنے ایک پیالہ پیش کیا جس میں ثرید تھا۔ بیان کیا کہ پھر وہ اپنے کام میں لگ گئے۔ بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم اس میں سے کدو تلاش کرنے لگے کہا کہ پھر میں بھی اس میں سے کدو تلاش کر کر کے نبی کریم صلی اللہ علیہ وسلم کے سامنے رکھنے لگا۔ بیان کیا کہ اس کے بعد سے میں بھی کدو بہت پسند کرتا ہوں۔' WHERE id = 5207;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے، ان سے ربیعہ نے، انہوں نے قاسم بن محمد سے سنا، آپ نے بیان کیا کہ بریرہ رضی اللہ عنہا کے ساتھ شریعت کی تین سنتیں قائم ہوئیں۔ عائشہ رضی اللہ عنہا نے انہیں ( ان کے مالکوں سے ) خرید کر آزاد کرنا چاہا تو ان کے مالکوں نے کہا کہ ولاء کا تعلق ہم سے ہی قائم ہو گا۔ ( عائشہ رضی اللہ عنہا نے بیان کیا کہ ) میں نے اس کا ذکر رسول اللہ صلی اللہ علیہ وسلم سے کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر تم یہ شرط لگا بھی لو جب بھی ولاء اسی کے ساتھ قائم ہو گا جو آزاد کرے گا۔ پھر بیان کیا کہ بریرہ آزاد کی گئیں اور انہیں اختیار دیا گیا کہ اگر وہ چاہیں تو اپنے شوہر کے ساتھ رہیں یا ان سے الگ ہو جائیں اور تیسری بات یہ ہے کہ رسول اللہ صلی اللہ علیہ وسلم ایک دن عائشہ رضی اللہ عنہا کے گھر تشریف لائے، چولھے پر ہانڈی پک رہی تھی۔ آپ صلی اللہ علیہ وسلم نے دوپہر کا کھانا طلب فرمایا تو روٹی اور گھر میں موجود سالن پیش کیا گیا۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا میں نے گوشت ( پکتے ہوئے ) نہیں دیکھا ہے؟ عرض کیا کہ دیکھا ہے یا رسول اللہ! لیکن وہ گوشت تو بریرہ کو صدقہ میں ملا ہے، انہوں نے ہمیں ہدیہ کے طور پر دیا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان کے لیے وہ صدقہ ہے لیکن ہمارے لیے ہدیہ ہے۔' WHERE id = 5217;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، انہوں نے کہا کہ مجھ سے ابراہیم بن سعد نے بیان کیا، ان سے ان کے والد نے اور ان سے عبداللہ بن جعفر بن ابی طالب رضی اللہ عنہما نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو تازہ کھجور ککڑی کے ساتھ کھاتے دیکھا ہے۔' WHERE id = 5227;
UPDATE hadiths SET urdu = 'سے صلت بن محمد نے بیان کیا، کہا ہم سے حماد بن زید نے، ان سے جعد ابوعثمان نے ان سے انس رضی اللہ عنہ نے اور (اس کی روایت حماد نے) ہشام سے بھی کی، ان سے محمد نے اور ان سے انس رضی اللہ عنہ نے اور سنان ابوربیعہ سے (بھی کی) اور ان سے انس رضی اللہ عنہ نے کہ ان کی والدہ ام سلیم رضی اللہ عنہا نے ایک مد جَو لیا اور ان سے پیس کر اس کا «خطيفة» ( آٹے کو دودھ میں ملا کر پکاتے ہیں ) پکایا اور ان کے پاس جو گھی کا ڈبہ تھا اس میں اس پر سے گھی نچوڑا، پھر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ( بلانے کے لیے ) بھیجا۔ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں گیا تو آپ اپنے صحابہ کے ساتھ تشریف رکھتے تھے۔ میں نے آپ کو کھانا کھانے کے لیے بلایا۔ آپ نے دریافت فرمایا اور وہ لوگ بھی جو میرے ساتھ ہیں؟ چنانچہ میں واپس آیا اور کہا کہ نبی کریم صلی اللہ علیہ وسلم تو فرماتے ہیں کہ جو میرے ساتھ موجود ہیں وہ بھی چلیں گے۔ اس پر ابوطلحہ آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا: یا رسول اللہ! وہ تو ایک چیز ہے جو ام سلیم نے آپ کے لیے پکائی ہے۔ نبی کریم صلی اللہ علیہ وسلم تشریف لائے اور کھانا آپ کے پاس لایا گیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ دس آدمیوں کو میرے پاس اندر بلا لو۔ چنانچہ دس صحابہ داخل ہوئے اور کھانا پیٹ بھر کر کھایا پھر فرمایا دس آدمیوں کو میرے پاس اور بلا لو۔ یہ دس بھی اندر آئے اور پیٹ بھر کر کھایا پھر فرمایا اور دس آدمیوں کو بلا لو۔ اس طرح انہوں نے چالیس آدمیوں کا شمار کیا۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے کھانا کھایا پھر آپ کھڑے ہوئے تو میں دیکھنے لگا کہ کھانے میں سے کچھ بھی کم نہیں ہوا۔' WHERE id = 5238;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے محمد نے، وہ زیاد کے صاحبزادے ہیں، کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا، ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جب تم میں کسی شخص کا خادم اس کا کھانا لائے تو اگر وہ اسے اپنے ساتھ نہیں بٹھا سکتا تو کم از کم ایک یا دو لقمہ اس کھانے میں سے اسے کھلا دے ( کیونکہ ) اس نے ( پکاتے وقت ) اس کی گرمی اور تیاری کی مشقت برداشت کی ہے۔' WHERE id = 5248;
UPDATE hadiths SET urdu = 'ہم سے مطر بن فضل نے بیان کیا، کہا ہم سے یزید بن ہارون نے، انہیں عبداللہ بن عون نے خبر دی، انہیں انس بن سیرین نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ابوطلحہ رضی اللہ عنہ کا ایک لڑکا بیمار تھا۔ ابوطلحہ کہیں باہر گئے ہوئے تھے کہ بچہ کا انتقال ہو گیا۔ جب وہ ( تھکے ماندے ) واپس آئے تو پوچھا کہ بچہ کیسا ہے؟ ان کی بیوی ام سلیم رضی اللہ عنہا نے کہا کہ وہ پہلے سے زیادہ سکون کے ساتھ ہے پھر بیوی نے ان کے سامنے کھانا رکھا اور ابوطلحہ رضی اللہ عنہ نے کھانا کھایا۔ اس کے بعد انہوں نے ان کے ساتھ ہمبستری کی پھر جب فارغ ہوئے تو انہوں نے کہا کہ بچہ کو دفن کر دو۔ صبح ہوئی تو ابوطلحہ رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ کو واقعہ کی اطلاع دی۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ تم نے رات ہمبستری بھی کی تھی؟ انہوں نے عرض کیا کہ جی ہاں۔ نبی کریم صلی اللہ علیہ وسلم نے دعا کی ”اے اللہ! ان دونوں کو برکت عطا فرما۔“ پھر ان کے یہاں ایک بچہ پیدا ہوا تو مجھ سے ابوطلحہ رضی اللہ عنہ نے کہا کہ اسے حفاظت کے ساتھ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں لے جاؤ۔ چنانچہ بچہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں لائے اور ام سلیم رضی اللہ عنہا نے بچہ کے ساتھ کچھ کھجوریں بھیجیں، نبی کریم صلی اللہ علیہ وسلم نے بچہ کو لیا اور دریافت فرمایا کہ اس کے ساتھ کوئی چیز بھی ہے؟ لوگوں نے کہا کہ جی ہاں کھجوریں ہیں۔ آپ نے اسے لے کر چبایا اور پھر اسے اپنے منہ میں نکال کر بچہ کے منہ میں رکھ دیا اور اس سے بچہ کی تحنیک کی اور اس کا نام عبداللہ رکھا۔' WHERE id = 5258;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے عبدالعزیز بن مسلم نے بیان کیا، ان سے عبداللہ بن دینار نے بیان کیا، انہوں نے کہا کہ میں نے ابن عمر رضی اللہ عنہما سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس نے ایسا کتا پالا جو نہ مویشی کی حفاظت کے لیے ہے اور نہ شکار کرنے کے لیے تو روزانہ اس کی نیکیوں میں سے دو قیراط کی کمی ہو جاتی ہے۔' WHERE id = 5269;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے عمر بن عبیداللہ کے غلام ابوالنضر نے، ان سے ابوقتادہ رضی اللہ عنہ کے غلام نافع نے اور ان سے ابوقتادہ رضی اللہ عنہ نے کہ وہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھے وہ مکہ کے راستہ میں ایک جگہ پر اپنے بعض ساتھیوں کے ساتھ جو احرام باندھے ہوئے تھے پیچھے رہ گئے خود ابوقتادہ رضی اللہ عنہ احرام سے نہیں تھے اسی عرصہ میں انہوں نے ایک گورخر دیکھا اور ( اسے شکار کرنے کے ارادہ سے ) اپنے گھوڑے پر بیٹھ گئے۔ اس کے بعد اپنے ساتھیوں سے ( جو محرم تھے ) کوڑا مانگا لیکن انہوں نے دینے سے انکار کیا پھر اپنا نیزہ مانگا لیکن اسے بھی اٹھانے کے لیے وہ تیار نہیں ہوئے تو انہوں نے وہ خود اٹھایا اور گورخر پر حملہ کیا اور اسے شکار کر لیا پھر بعض نے اس کا گوشت کھایا اور بعض نے کھانے سے انکار کیا۔ اس کے بعد جب وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے تو اس کا حکم پوچھا آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ تو ایک کھانا تھا جو اللہ نے تمہارے لیے مہیا کیا تھا۔' WHERE id = 5279;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے ابوعوانہ نے، ان سے اسود بن قیس نے، ان سے جندب بن سفیان بجلی نے بیان کیا کہ ہم نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ایک مرتبہ قربانی کی۔ کچھ لوگوں نے عید کی نماز سے پہلے ہی قربانی کر لی تھی۔ جب نبی کریم صلی اللہ علیہ وسلم ( نماز پڑھ کر ) واپس تشریف لائے تو آپ صلی اللہ علیہ وسلم نے دیکھا کہ لوگوں نے اپنی قربانیاں نماز سے پہلے ہی ذبح کر لی ہیں پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ جس شخص نے نماز سے پہلے قربانی ذبح کر لی ہو، اسے چاہیئے کہ اس کی جگہ دوسری ذبح کرے اور جس نے نماز پڑھنے سے پہلے نہ ذبح کی ہو اسے چاہیئے کہ اللہ کے نام پر ذبح کرے۔' WHERE id = 5289;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، ان سے ہشام بن عروہ نے کہا کہ مجھے میری بیوی فاطمہ بنت منذر نے خبر دی ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے بیان کیا کہ ہم نے رسول اللہ صلی اللہ علیہ وسلم کے زمانے میں ایک گھوڑا نحر کیا اور اسے کھایا۔' WHERE id = 5299;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے عمرو بن دینار نے، ان سے محمد بن علی نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ جنگ خیبر میں رسول اللہ صلی اللہ علیہ وسلم نے گدھے کا گوشت کھانے کی ممانعت فرما دی تھی اور گھوڑے کا گوشت کھانے کی رخصت دی تھی۔' WHERE id = 5309;
UPDATE hadiths SET urdu = 'ہم سے خطاب بن عثمان نے بیان کیا، کہا ہم سے محمد بن حمیر نے بیان کیا، ان سے ثابت بن عجلان نے بیان کیا، انہوں نے سعید بن جبیر سے سنا، انہوں نے بیان کیا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا، انہوں نے بیان کہ نبی کریم صلی اللہ علیہ وسلم ایک مرے ہوئے بکرے کے پاس سے گزرے تو فرمایا کہ اس کے مالکوں کو کیا ہو گیا ہے اگر وہ اس کے چمڑے کو کام میں لاتے ( تو بہتر ہوتا ) ۔' WHERE id = 5320;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ہشام بن زید نے ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں اپنے بھائی ( عبداللہ بن ابی طلحہ نومولود ) کو لایا تاکہ آپ اس کی تحنیک فرما دیں۔ نبی کریم صلی اللہ علیہ وسلم اس وقت اونٹوں کے باڑے میں تشریف رکھتے تھے۔ میں نے دیکھا کہ آپ ایک بکری کو داغ رہے تھے ( شعبہ نے کہا کہ ) میں سمجھتا ہوں کہ ( ہشام نے ) کہا کہ اس کے کانوں کو داغ رہے تھے۔' WHERE id = 5330;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے کثیر بن فرقد نے، ان سے نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم ( قربانی ) ذبح اور نحر عیدگاہ میں کیا کرتے تھے۔' WHERE id = 5340;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے اسود بن قیس نے بیان کیا، کہا میں نے جندب بن سفیان بجلی رضی اللہ عنہ سے سنا کہ قربانی کے دن میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس نے نماز سے پہلے قربانی کر لی ہو وہ اس کی جگہ دوبارہ کرے اور جس نے قربانی ابھی نہ کی ہو وہ کرے۔' WHERE id = 5350;
UPDATE hadiths SET urdu = 'ابو عبید نے بیان کیا کہ پھر میں عثمان بن عفان رضی اللہ عنہ کے ساتھ ( ان کی خلافت کے زمانہ میں عیدگاہ میں ) حاضر تھا۔ اس دن جمعہ بھی تھا۔ آپ نے خطبہ سے پہلے نماز عید پڑھائی پھر خطبہ دیا اور فرمایا کہ اے لوگو! آج کے دن تمہارے لیے دو عیدیں جمع ہو گئیں ہیں۔ ( عید اور جمعہ ) پس اطراف کے رہنے والوں میں سے جو شخص پسند کرے جمعہ کا بھی انتظار کرے اور اگر کوئی واپس جانا چاہے ( نماز عید کے بعد ہی ) تو وہ واپس جا سکتا ہے، میں نے اسے اجازت دے دی ہے۔' WHERE id = 5360;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، انہوں نے کہا کہ مجھ سے مالک بن انس نے بیان کیا، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ میں ابوعبیدہ، ابوطلحہ اور ابی بن کعب رضی اللہ عنہم کو کچی اور پکی کھجور سے تیار کی ہوئی شراب پلا رہا تھا کہ ایک آنے والے نے آ کر بتایا کہ شراب حرام کر دی گئی ہے۔ اس وقت ابوطلحہ رضی اللہ عنہ نے کہا کہ انس اٹھو اور شراب کو بہا دو چنانچہ میں نے اسے بہا دیا۔' WHERE id = 5370;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن موسیٰ نے بیان کیا، کہا ہم سے محمد بن عبداللہ ابواحمد زبیری نے، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے منصور بن معتمر نے، ان سے سالم بن ابی الجعد نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے چند برتنوں میں نبیذ بھگونے کی ( جن میں شراب بنتی تھی ) ممانعت کر دی تھی پھر انصار نے عرض کیا کہ ہمارے پاس تو دوسرے برتن نہیں ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تو خیر پھر اجازت ہے۔ امام بخاری رحمہ اللہ کہتے ہیں مجھ سے خلیفہ بن خیاط نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے منصور بن معتمر نے اور ان سے سالم بن ابی الجعد نے پھر یہی حدیث روایت کی تھی۔' WHERE id = 5380;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ہشام دستوائی نے بیان کیا، کہا ہم کو یحییٰ بن ابی کثیر نے خبر دی، انہیں عبداللہ بن ابی قتادہ نے اور ان سے ان کے والد نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اس کی ممانعت کی تھی کہ پختہ اور گدرائی ہوئی کھجور، پختہ کھجور اور کشمش کو ملا کر نبیذ بنایا جائے۔ آپ صلی اللہ علیہ وسلم نے ہر ایک کو جدا جدا بھگونے کا حکم دیا۔' WHERE id = 5390;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم سے عبداللہ بن مبارک نے خبر دی، کہا ہم کو یونس نے خبر دی، ان سے زہری نے بیان کیا اور انہیں انس بن مالک رضی اللہ عنہ نے خبر دی کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم کو دودھ پیتے دیکھا اور نبی کریم صلی اللہ علیہ وسلم ان کے گھر تشریف لائے تھے ( بیان کیا کہ ) میں نے بکری کا دودھ نکالا اور اس میں کنویں کا تازہ پانی ملا کر ( نبی کریم صلی اللہ علیہ وسلم کو ) پیش کیا آپ نے پیالہ لے کر پیا۔ آپ کے بائیں طرف ابوبکر رضی اللہ عنہ تھے اور دائیں طرف ایک اعرابی تھا آپ نے اپنا باقی دودھ اعرابی کو دیا اور فرمایا کہ پہلے دائیں طرف سے، ہاں دائیں طرف والے کا حق ہے۔' WHERE id = 5400;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے معتمر نے، ان سے ان کے والد نے، کہ میں نے انس رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں کھڑا ہوا اپنے قبیلہ میں اپنے چچاؤں کو کھجور کی شراب پلا رہا تھا۔ میں ان میں سے سب سے چھوٹا تھا، اتنے میں کسی نے کہا کہ شراب حرام کر دی گئی ( ابوطلحہ رضی اللہ عنہ نے ) کہا کہ شراب پھینک دو۔ چنانچہ ہم نے پھینک دی۔ سلیمان نے کہا کہ میں نے انس رضی اللہ عنہ سے پوچھا اس وقت لوگ کس چیز کی شراب پیتے تھے کہا کہ پکی اور کچی کھجور کی۔ ابوبکر بن انس نے کہا کہ یہی ان کی شراب ہوتی تھی انس رضی اللہ عنہ نے اس کا انکار نہیں کیا، بکر بن عبداللہ مزنی یا قتادہ نے کہا اور مجھ سے بعض لوگوں نے بیان کیا کہ انہوں نے انس رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ”ان کی ان دنوں یہی ( فضیح ) ان کی شراب تھی۔“' WHERE id = 5410;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حکیم بن ابی لیلیٰ نے، انہوں نے بیان کیا کہ حذیفہ بن یمان رضی اللہ عنہ مدائن میں تھے۔ انہوں نے پانی مانگا تو ایک دیہاتی نے ان کو چاندی کے برتن میں پانی لا کر دیا، انہوں نے برتن کو اس پر پھینک مارا پھر کہا میں نے برتن صرف اس وجہ سے پھینکا ہے کہ اس شخص کو میں اس سے منع کر چکا تھا لیکن یہ باز نہ آیا اور رسول اللہ صلی اللہ علیہ وسلم نے ہمیں ریشم و دیبا کے پہننے سے اور سونے اور چاندی کے برتن میں کھانے پینے سے منع کیا تھا اور آپ صلی اللہ علیہ وسلم نے ارشاد فرمایا تھا کہ یہ چیزیں ان کفار کے لیے دنیا میں ہیں اور تمہیں آخرت میں ملیں گے۔' WHERE id = 5420;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، کہا کہ مجھ سے محمد بن فلیح نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا، ان سے بنی عامر بن لوی کے ایک مرد ہلال بن علی نے، ان سے عطاء بن یسار نے اور ان سے ابوہریرہ رضی اللہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ مومن کی مثال پودے کی پہلی نکلی ہوئی ہری شاخ جیسی ہے کہ جب بھی ہوا چلتی ہے اسے جھکا دیتی ہے پھر وہ سیدھا ہو کر مصیبت برداشت کرنے میں کامیاب ہو جاتا ہے اور بدکار کی مثال صنوبر کے درخت جیسی ہے کہ سخت ہوتا ہے اور سیدھا کھڑا رہتا ہے یہاں تک کہ اللہ تعالیٰ جب چاہتا ہے اسے اکھاڑ کر پھینک دیتا ہے۔' WHERE id = 5431;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، ان سے امام مالک نے، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم ہجرت کر کے مدینہ تشریف لائے تو ابوبکر رضی اللہ عنہ اور بلال رضی اللہ عنہ کو بخار ہو گیا۔ بیان کیا کہ پھر میں ان کے پاس ( عیادت کے لیے ) گئی اور پوچھا، محترم والد بزرگوار آپ کا مزاج کیسا ہے؟ بلال رضی اللہ عنہ سے بھی پوچھا کہ آپ کا کیا حال ہے؟ بیان کیا کہ جب ابوبکر رضی اللہ عنہ کو بخار ہوا تو وہ یہ شعر پڑھا کرتے تھے ”ہر شخص اپنے گھر والوں میں صبح کرتا ہے اور موت اس کے تسمے سے بھی زیادہ قریب ہے۔“ اور بلال رضی اللہ عنہ کو جب افاقہ ہوتا تو یہ شعر پڑھتے تھے ”کاش مجھے معلوم ہوتا کہ کیا پھر ایک رات وادی میں گزار سکوں گا اور میرے چاروں طرف اذخر اور جلیل ( مکہ مکرمہ کی گھاس ) کے جنگل ہوں گے اور کیا میں کبھی مجنہ ( مکہ سے چند میل کے فاصلہ پر ایک بازار ) کے پانی پر اتروں گا اور کیا پھر کبھی شامہ اور طفیل ( مکہ کے قریب دو پہاڑوں ) کو میں اپنے سامنے دیکھ سکوں گا۔“ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی اور آپ کو اس کی اطلاع دی آپ صلی اللہ علیہ وسلم نے دعا فرمائی کہ اے اللہ! ہمارے دل میں مدینہ کی محبت بھی اتنی ہی کر دے جتنی مکہ کی محبت ہے بلکہ اس سے بھی زیادہ اور اس کی آب و ہوا کو ہمارے موافق کر دے اور ہمارے لیے اس کے مد اور صاع میں برکت عطا فرما، اللہ اس کا بخار کہیں اور جگہ منتقل کر دے اسے مقام جحفہ میں بھیج دے۔' WHERE id = 5441;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عباس نے بیان کیا، کہا ہم سے عبدالرحمٰن نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے محمد نے جو منکدر کے بیٹے ہیں اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم میری عیادت کے لیے تشریف لائے آپ نہ کسی خچر پر سوار تھے نہ کسی گھوڑے پر۔ ( بلکہ آپ پیدل تشریف لائے تھے ) ۔' WHERE id = 5451;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی شیبہ نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام نے، ان سے عباد بن عبداللہ بن زبیر نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا سے سنا، انہوں نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم میرا سہارا لیے ہوئے تھے ( مرض الموت میں ) اور فرما رہے تھے «اللهم اغفر لي وارحمني وألحقني بالرفيق الأعلى» ”اے اللہ! میری مغفرت فرما مجھ پر رحم کر اور مجھ کو اچھے رفیقوں ( فرشتوں اور پیغمبروں ) کے ساتھ ملا دے۔“' WHERE id = 5461;
UPDATE hadiths SET urdu = 'ہم سے عیاش بن الولید نے بیان کیا، کہا ہم سے عبدالاعلیٰ نے، کہا ہم سے سعید نے، ان سے قتادہ نے، ان سے ابوالمتوکل نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ ایک صاحب نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا کہ میرا بھائی پیٹ کی تکلیف میں مبتلا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں شہد پلا پھر دوسری مرتبہ وہی صحابی حاضر ہوئے۔ آپ صلی اللہ علیہ وسلم نے اسے اس مرتبہ بھی شہد پلانے کے لیے کہا وہ پھر تیسری مرتبہ آیا اور عرض کیا کہ ( حکم کے مطابق ) میں نے عمل کیا ( لیکن شفاء نہیں ہوئی ) ۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ سچا ہے اور تمہارے بھائی کا پیٹ جھوٹا ہے، انہیں پھر شہد پلا۔ چنانچہ انہوں نے شہد پھر پلایا اور اسی سے وہ تندرست ہو گیا۔' WHERE id = 5471;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو حمید الطویل نے خبر دی اور انہیں انس رضی اللہ عنہ نے ان سے پچھنا لگوانے والے کی مزدوری کے بارے میں پوچھا گیا تھا۔ انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے پچھنا لگوایا تھا آپ کو ابوطیبہ ( نافع یا میسرہ ) نے پچھنا لگایا تھا آپ صلی اللہ علیہ وسلم نے انہیں دو صاع کھجور مزدوری میں دی تھی اور آپ نے ان کے مالکوں ( بنو حارثہ ) سے گفتگو کی تو انہوں نے ان سے وصول کئے جانے والے لگان میں کمی کر دی تھی اور نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ( خون کے دباؤ کا ) بہترین علاج جو تم کرتے ہو وہ پچھنا لگوانا ہے اور عمدہ دوا عود ہندی کا استعمال کرنا ہے اور فرمایا اپنے بچوں کو «عذرة» ( حلق کی بیماری ) میں ان کا تالو دبا کر تکلیف مت دو بلکہ «قسط» لگا دو اس سے ورم جاتا رہے گا۔' WHERE id = 5482;
UPDATE hadiths SET urdu = 'ہم سے بشر بن محمد نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو معمر اور یونس نے خبر دی، ان سے زہری نے بیان کیا کہ مجھ کو عبیداللہ بن عبداللہ بن عتبہ نے خبر دی اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ جب ( مرض الموت میں ) رسول اللہ صلی اللہ علیہ وسلم کے لیے چلنا پھرنا دشوار ہو گیا اور آپ کی تکلیف بڑھ گئی تو آپ نے بیماری کے دن میرے گھر میں گزارنے کی اجازت اپنی دوسری بیویوں سے مانگی جب اجازت مل گئی تو نبی کریم صلی اللہ علیہ وسلم دو اشخاص عباس رضی اللہ عنہ اور ایک صاحب کے درمیان ان کا سہارا لے کر باہر تشریف لائے، آپ کے مبارک قدم زمین پر گھسٹ رہے تھے۔ میں نے ابن عباس رضی اللہ عنہما سے اس کا ذکر کیا تو انہوں نے کہا تمہیں معلوم ہے وہ دوسرے صاحب کون تھے جن کا عائشہ رضی اللہ عنہا نے نام نہیں بتایا، میں نے کہا کہ نہیں کہا کہ وہ علی رضی اللہ عنہ تھے۔ عائشہ رضی اللہ عنہا نے کہا کہ ان کے حجرے میں داخل ہونے کے بعد نبی کریم صلی اللہ علیہ وسلم نے فرمایا جبکہ آپ کا مرض بڑھ گیا تھا کہ مجھ پر سات مشک ڈالو جو پانی سے لبریز ہوں۔ شاید میں لوگوں کو کچھ نصیحت کر سکوں۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم کو ہم نے ایک لگن میں بٹھایا جو نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ حفصہ رضی اللہ عنہ کا تھا اور آپ پر حکم کے مطابق مشکوں سے پانی ڈالنے لگے آخر آپ نے ہمیں اشارہ کیا کہ بس ہو چکا۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم صحابہ کے مجمع میں گئے، انہیں نماز پڑھائی اور انہیں خطاب فرمایا۔' WHERE id = 5495;
UPDATE hadiths SET urdu = 'ہم سے عبدالاعلیٰ بن حماد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے سعید نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ قبیلہ عکل اور عرینہ کے کچھ لوگ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور اسلام کے بارے میں گفتگو کی۔ انہوں نے کہا کہ اے اللہ کے نبی! ہم مویشی والے ہیں ہم لوگ اہل مدینہ کی طرح کاشتکار نہیں ہیں۔ مدینہ کی آب و ہوا انہیں موافق نہیں آئی تھی، چنانچہ نبی کریم صلی اللہ علیہ وسلم نے ان کے لیے چند اونٹوں اور ایک چرواہے کا حکم دیا اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ لوگ ان اونٹوں کے ساتھ باہر چلے جائیں اور ان کا دودھ اور پیشاب پئیں۔ وہ لوگ چلے گئے لیکن حرہ کے نزدیک پہنچ کر وہ اسلام سے مرتد ہو گئے اور نبی کریم صلی اللہ علیہ وسلم کے چرواہے کو قتل کر ڈالا اور اونٹوں کو لے کر بھاگ پڑے جب نبی کریم صلی اللہ علیہ وسلم کو اس کی خبر ملی تو آپ نے ان کی تلاش میں آدمی دوڑائے پھر آپ نے ان کے متعلق حکم دیا اور ان کی آنکھوں میں سلائی پھیر دی گئی، ان کے ہاتھ کاٹ دئیے گئے اور حرہ کے کنارے انہیں چھوڑ دیا گیا، وہ اسی حالت میں مر گئے۔' WHERE id = 5506;
UPDATE hadiths SET urdu = 'ہم سے سیدان بن مضارب ابو محمد باہلی نے بیان کیا، کہا ہم سے ابومعشر یوسف بن یزید البراء نے بیان کیا، کہا کہ مجھ سے عبیداللہ بن اخنس ابو مالک نے بیان کیا، ان سے ابن ابی ملیکہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ چند صحابہ ایک پانی سے گزرے جس کے پاس کے قبیلہ میں بچھو کا کاٹا ہوا ( لدیغ یا سلیم راوی کو ان دونوں الفاظ کے متعلق شبہ تھا ) ایک شخص تھا۔ قبیلہ کا ایک شخص ان کے پاس آیا اور کہا کیا آپ لوگوں میں کوئی دم جھاڑ کرنے والا ہے۔ ہمارے قبیلہ میں ایک شخص کو بچھو نے کاٹ لیا ہے چنانچہ صحابہ کی اس جماعت میں سے ایک صحابی اس شخص کے ساتھ گئے اور چند بکریوں کی شرط کے ساتھ اس شخص پر سورۃ فاتحہ پڑھی، اس سے وہ اچھا ہو گیا وہ صاحب شرط کے مطابق بکریاں اپنے ساتھیوں کے پاس لائے تو انہوں نے اسے قبول کر لینا پسند نہیں کیا اور کہا کہ اللہ کی کتاب پر تم نے اجرت لے لی۔ آخر جب سب لوگ مدینہ آئے تو عرض کیا کہ یا رسول اللہ! ان صاحب نے اللہ کی کتاب پر اجرت لے لی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جن چیزوں پر تم اجرت لے سکتے ہو ان میں سے زیادہ اس کی مستحق اللہ کی کتاب ہی ہے۔' WHERE id = 5516;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، کہا ہم سے سلیمان بن بلال نے بیان کیا، ان سے یحییٰ بن سعید انصاری نے بیان کیا کہ میں نے ابوسلمہ بن عبدالرحمٰن بن عوف سے سنا، کہا کہ میں نے ابوقتادہ رضی اللہ عنہ سے سنا، انہوں نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بیشک اچھا خواب اللہ کی طرف سے ہوتا ہے، اور حلم ( برا خواب جس میں گھبراہٹ ہو ) شیطان کی طرف سے ہوتا ہے اس لیے جب تم میں سے کوئی شخص کوئی ایسا خواب دیکھے جو برا ہو تو جاگتے ہی تین مرتبہ بائیں طرف تھو تھو کرے اور اس خواب کی برائی سے اللہ کی پناہ مانگے، اس طرح خواب کا اسے نقصان نہیں ہو گا اور ابوسلمہ نے کہا کہ پہلے بعض خواب مجھ پر پہاڑ سے بھی زیادہ بھاری ہوتا تھا جب سے میں نے یہ حدیث سنی اور اس پر عمل کرنے لگا، اب مجھے کوئی پرواہ نہیں ہوتی۔' WHERE id = 5526;
UPDATE hadiths SET urdu = 'ہم سے محمد بن حکم نے بیان کیا، انہوں نے کہا ہم سے نضر بن شمیل نے بیان کیا، انہوں نے کہا ہم کو اسرائیل نے خبر دی، انہوں نے کہا ہم کو ابوحصین (عثمان بن عاصم اسدی) نے خبر دی، انہیں ابوصالح ذکوان نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”چھوت لگ جانا بدشگونی یا الو یا صفر کی نحوست یہ کوئی چیز نہیں ہے۔“' WHERE id = 5536;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، انہوں نے کہا ہم کو ابواسامہ حماد بن اسامہ نے خبر دی، انہوں نے کہا ہم سے ہاشم بن ہاشم نے بیان کیا کہ میں نے عامر بن سعد سے سنا، انہوں نے سعد بن ابی وقاص رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ جس شخص نے صبح کے وقت سات عجوہ کھجوریں کھا لیں اس دن اسے نہ زہر نقصان پہنچا سکتا ہے اور نہ جادو۔' WHERE id = 5547;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے زہیر نے بیان کیا، کہا ہم سے موسیٰ بن عقبہ نے، ان سے سالم بن عبداللہ نے اور ان سے ان کے والد نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو شخص تکبر کی وجہ سے تہبند گھسیٹتا ہوا چلے گا تو اللہ پاک اس کی طرف قیامت کے دن نظر بھی نہیں کرے گا۔“ ابوبکر رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! میرے تہمد کا ایک حصہ کبھی لٹک جاتا ہے مگر یہ کہ خاص طور سے اس کا خیال رکھا کروں۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”تم ان لوگوں میں سے نہیں ہو جو ایسا تکبر سے کرتے ہیں۔“' WHERE id = 5559;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے حماد بن سلمہ نے بیان کیا، ان سے ایوب سختیانی نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ ایک صاحب نے عرض کیا: یا رسول اللہ! محرم کس طرح کا کپڑا پہنے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ محرم قمیص، پاجامہ، برنس ( ٹوپی یا سر پر پہننے کی کوئی چیز ) اور موزے نہیں پہنے گا البتہ اگر اسے چپل نہ ملیں تو موزوں ہی کو ٹخنوں تک کاٹ کر پہن لے وہ ہی جوتی کی طرح ہو جائیں گے۔' WHERE id = 5569;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے عمرو نے، ان سے جابر بن زید نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ( محرم کے بارے میں ) فرمایا ”جسے تہمد نہ ملے وہ پاجامہ پہنے اور جسے چپل نہ ملیں وہ موزے پہنیں۔“' WHERE id = 5579;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، انہوں نے کہا کہ مجھے ابوسلمہ بن عبدالرحمٰن بن عوف رضی اللہ عنہ نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے انہیں خبر دی کہ جب رسول اللہ صلی اللہ علیہ وسلم کی وفات ہوئی تو آپ کی نعش مبارک پر ایک سبز یمنی چادر ڈال دی گئی تھی۔' WHERE id = 5589;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم حنظلی نے بیان کیا، کہا ہم کو محمد بن بشر نے خبر دی، کہا ہم سے معمر نے بیان کیا، ان سے سعد بن ابی وقاص رضی اللہ عنہ نے بیان کیا کہ جنگ احد کے موقع پر میں نے نبی کریم صلی اللہ علیہ وسلم کے دائیں بائیں دو آدمیوں کو ( جو فرشتے تھے ) دیکھا وہ سفید کپڑے پہنے ہوئے تھے میں نے انہیں نہ اس سے پہلے دیکھا اور نہ اس کے بعد کبھی دیکھا۔' WHERE id = 5600;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے اسرائیل نے بیان کیا، ان سے ابواسحاق نے بیان کیا اور ان سے براء رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو ریشم کا ایک کپڑا ہدیہ میں پیش ہوا تو ہم اسے چھونے لگے اور اس کی ( نرمی و ملائمت پر ) حیرت زدہ ہو گئے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ کیا تمہیں اس پر حیرت ہے۔ ہم نے عرض کیا جی ہاں فرمایا، جنت میں سعد بن معاذ کے رومال اس سے بھی اچھے ہیں۔' WHERE id = 5610;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے عبدالوارث بن سعید نے بیان کیا، ان سے عبدالعزیز نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اس سے منع فرمایا کہ کوئی مرد زعفران کے رنگ کا استعمال کرے۔' WHERE id = 5620;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے، ان سے ابوالزناد نے، ان سے اعرج نے ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ تم میں کوئی شخص صرف ایک پاؤں میں جوتا پہن کر نہ چلے یا دونوں پاؤں ننگا رکھے یا دونوں میں جوتا پہنے۔' WHERE id = 5630;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن موسیٰ نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے عبیداللہ نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے سونے یا چاندی کی انگوٹھی بنوائی اور اس کا نگینہ ہتھیلی کی طرف رکھا اور اس پر «محمد رسول الله‏.‏» کے الفاظ کھدوائے پھر دوسرے لوگوں نے بھی اسی طرح کی انگوٹھیاں بنوا لیں۔ جب نبی کریم صلی اللہ علیہ وسلم نے دیکھا کہ کچھ دوسرے لوگوں نے بھی اس طرح کی انگوٹھیاں بنوا لی تو آپ نے اسے پھینک دیا اور فرمایا کہ اب میں اسے کبھی نہیں پہنوں گا۔ پھر آپ نے چاندی کی انگوٹھی بنوائی اور دوسرے لوگوں نے بھی چاندی کی انگوٹھیاں بنوا لیں۔ ابن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے بعد اس انگوٹھی کو ابوبکر رضی اللہ عنہ نے پہنا پھر عمر رضی اللہ عنہ اور پھر عثمان نے پہنا۔ آخر عثمان رضی اللہ عنہ کے عہد خلافت میں وہ انگوٹھی اریس کے کنویں میں گر گئی۔' WHERE id = 5640;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے جویریہ نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے پہلے ایک سونے کی انگوٹھی بنوائی اور پہننے میں آپ اس کا رنگ اندر کی طرف رکھتے تھے۔ آپ کی دیکھا دیکھی لوگوں نے بھی سونے کی انگوٹھیاں بنا لیں تو نبی کریم صلی اللہ علیہ وسلم منبر پر تشریف لائے اور اللہ کی حمد و ثنا کی اور فرمایا میں نے بھی سونے کی انگوٹھی بنوائی تھی۔ ( حرمت نازل ہونے کے بعد ) آپ صلی اللہ علیہ وسلم نے فرمایا کہ اب میں اسے نہیں پہنوں گا۔ پھر آپ نے وہ انگوٹھی پھینک دی اور لوگوں نے بھی اپنی سونے کی انگوٹھیوں کو پھینک دیا۔ جویریہ نے بیان کیا کہ مجھے یہی یاد ہے کہ نافع نے ”داہنے ہاتھ میں“ بیان کیا۔' WHERE id = 5650;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، کہا ہم سے ہشام دستوائی نے، ان سے یحییٰ بن ابی کثیر نے، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے مخنث مردوں پر اور مردوں کی چال چلن اختیار کرنے والی عورتوں پر لعنت بھیجی اور فرمایا کہ ان زنانہ بننے والے مردوں کو اپنے گھروں سے باہر نکال دو۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فلاں ہیجڑے کو نکالا تھا اور عمر رضی اللہ عنہ نے فلاں ہیجڑے کو نکالا تھا۔' WHERE id = 5660;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے عثمان بن عبداللہ بن وہب نے بیان کیا کہ میرے گھر والوں نے ام سلمہ رضی اللہ عنہا کے پاس پانی کا ایک پیالہ لے کر بھیجا ( راوی حدیث ) اسرائیل راوی نے تین انگلیاں بند کر لیں یعنی وہ اتنی چھوٹی پیالی تھی اس پیالی میں بالوں کا ایک گچھا تھا جس میں نبی کریم صلی اللہ علیہ وسلم کے بالوں میں سے کچھ بال تھے۔ عثمان نے کہا جب کسی شخص کو نظر لگ جاتی یا اور کوئی بیماری ہوتی تو وہ اپنا پانی کا برتن بی بی ام سلمہ رضی اللہ عنہا کے پاس بھیج دیتا۔ ( وہ اس میں نبی کریم صلی اللہ علیہ وسلم کے بال ڈبو دیتیں ) عثمان نے کہا کہ میں نے نلکی کو دیکھا ( جس میں موئے مبارک رکھے ہوئے تھے ) تو سرخ سرخ بال دکھائی دیئے۔' WHERE id = 5670;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے ہاتھ بھرے ہوئے تھے میں نے نبی کریم صلی اللہ علیہ وسلم کے بعد آپ جیسا ( خوبصورت کوئی آدمی ) نہیں دیکھا آپ کے سر کے بال میانہ تھے نہ گھونگھریالے اور نہ بالکل سیدھے لٹکے ہوئے۔' WHERE id = 5680;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن سلام نے بیان کیا، کہا کہ مجھے مخلد بن یزید نے خبر دی، کہا کہ مجھے ابن جریج نے خبر دی، کہا کہ مجھے عبیداللہ بن حفص نے خبر دی، انہیں عمرو بن نافع نے خبر دی، انہیں عبداللہ بن عمر رضی اللہ عنہما کے غلام نافع نے کہ انہوں نے ابن عمر رضی اللہ عنہما سے سنا، وہ بیان کرتے تھے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے آپ نے «قزع‏.‏» سے منع فرمایا، عبیداللہ کہتے ہیں کہ میں نے نافع سے پوچھا کہ «قزع‏.‏» کیا ہے؟ پھر عبیداللہ نے ہمیں اشارہ سے بتایا کہ نافع نے کہا کہ بچہ کا سر منڈاتے وقت کچھ یہاں چھوڑ دے اور کچھ بال وہاں چھوڑ دے۔ ( تو اسے «قزع‏.‏» کہتے ہیں ) اسے عبیداللہ نے پیشانی اور سر کے دونوں کناروں کی طرف اشارہ کر کے ہمیں اس کی صورت بتائی۔ عبیداللہ نے اس کی تفسیر یوں بیان کی یعنی پیشانی پر کچھ بال چھوڑ دیئے جائیں اور سر کے دونوں کونوں پر کچھ بال چھوڑ دیئے جائیں۔ پھر عبیداللہ سے پوچھا گیا کہ اس میں لڑکا اور لڑکی دونوں کا ایک ہی حکم ہے؟ فرمایا کہ مجھے معلوم نہیں۔ نافع نے صرف لڑکے کا لفظ کہا تھا۔ عبیداللہ نے بیان کیا کہ میں نے عمرو بن نافع سے دوبارہ اس کے متعلق پوچھا تو انہوں نے کہا کہ لڑکے کی کنپٹی یا گدی پر چوٹی کے بال اگر چھوڑ دیئے جائیں تو کوئی حرج نہیں ہے لیکن «قزع‏.‏» یہ ہے کہ پیشانی پر بال چھوڑ دیئے جائیں اور باقی سب منڈوائے جائیں اسی طرح سر کے اس جانب میں اور اس جانب میں۔' WHERE id = 5692;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ہشیم نے بیان کیا یا محمد بن یحییٰ دیلی نے، انہیں عثمان بن ہشیم نے (امام بخاری رحمہ اللہ کو شک ہے) ان سے ابن جریج نے انہوں نے کہا مجھ کو عمر بن عبداللہ بن عروہ بن شہر نے خبر دی، انہوں نے عروہ اور قاسم دونوں سے سنا، وہ دونوں ام المؤمنین عائشہ رضی اللہ عنہا سے نقل کرتے تھے کہ انہوں نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو حجۃ الوداع کے موقع پر احرام کھولنے اور احرام باندھنے کے وقت اپنے ہاتھ سے ذریرہ ( ایک قسم کی مرکب ) خوشبو لگائی تھی۔' WHERE id = 5702;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، ان سے عبدہ نے بیان کیا، ان سے عبیداللہ نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مصنوعی بال جوڑنے والی اور جڑوانے والی، گودنے والی اور گدوانے والی پر لعنت بھیجی ہے۔' WHERE id = 5712;
UPDATE hadiths SET urdu = 'ہم سے حمیدی عبداللہ بن زبیر نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے اعمش نے بیان کیا اور ان سے مسلم بن صبیحہ نے بیان کیا کہ ہم مسروق بن اجدع کے ساتھ یسار بن نمیر کے گھر میں تھے۔ مسروق نے ان کے گھر کے سائبان میں تصویریں دیکھیں تو کہا کہ میں نے عبداللہ بن مسعود رضی اللہ عنہ سے سنا ہے، انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ کے پاس قیامت کے دن تصویر بنانے والوں کو سخت سے سخت تر عذاب ہو گا۔“' WHERE id = 5723;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا کہ مجھ سے عبداللہ بن وہب نے، کہا کہ مجھ سے عمر بن محمد نے بیان کیا، ان سے سالم نے اور ان سے ان کے والد (ابن عمر رضی اللہ عنہما) نے بیان کیا کہ ایک وقت پر جبرائیل علیہ السلام نے نبی کریم صلی اللہ علیہ وسلم کے یہاں آنے کا وعدہ کیا لیکن آنے میں دیر ہوئی۔ اس وقت پر نہیں آئے تو نبی کریم صلی اللہ علیہ وسلم سخت پریشان ہوئے پھر آپ باہر نکلے تو جبرائیل علیہ السلام سے ملاقات ہوئی۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے شکایت کی تو انہوں نے کہا کہ ہم ( فرشتے ) کسی ایسے گھر میں نہیں جاتے جس میں مورت یا کتا ہو۔' WHERE id = 5733;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام نے بیان کیا، کہا ہم سے شعبہ نے، انہوں نے کہا کہ مجھے ولید بن عیزار نے خبر دی، کہا کہ میں نے ابوعمرو شیبانی سے سنا، کہا کہ ہمیں اس گھر والے نے خبر دی اور انہوں نے اپنے ہاتھ سے عبداللہ بن مسعود رضی اللہ عنہ کے گھر کی طرف اشارہ کیا، انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا اللہ تعالیٰ کے نزدیک کون سا عمل سب سے زیادہ پسند ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ وقت پر نماز پڑھنا۔ پوچھا کہ پھر کون سا؟ فرمایا کہ والدین کے ساتھ اچھا سلوک کرنا، پوچھا پھر کون سا؟ فرمایا کہ اللہ کے راستے میں جہاد کرنا۔ عبداللہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے ان کاموں کے متعلق بیان کیا اور اگر میں اسی طرح سوال کرتا رہتا تو آپ جواب دیتے رہتے۔' WHERE id = 5743;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے عبیداللہ بن عبداللہ نے اور انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی اور انہیں ابوسفیان رضی اللہ عنہ نے خبر دی کہ ہرقل نے انہیں بلا بھیجا تو انہوں نے اسے بتایا کہ وہ یعنی نبی کریم صلی اللہ علیہ وسلم ہمیں نماز، صدقہ، پاک دامنی اور صلہ رحمی کا حکم فرماتے ہیں۔' WHERE id = 5753;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عباس نے بیان کیا، انہوں نے کہا مجھ سے محمد بن جعفر نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے اسماعیل بن ابی خالد نے بیان کیا، ان سے قیس بن ابی حازم نے بیان کیا، ان سے عمرو بن العاص رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا کہ فلاں کی اولاد ( یعنی ابوسفیان بن حکم بن عاص یا ابولہب کی اولاد ) یہ عمرو بن عباس نے کہا کہ محمد بن جعفر کی کتاب میں اس وہم پر سفید جگہ خالی تھی ( یعنی تحریر نہ تھی ) میرے عزیز نہیں ہیں ( گو ان سے نسبی رشتہ ہے ) میرا ولی تو اللہ ہے اور میرے عزیز تو ولی ہیں جو مسلمانوں میں نیک اور پرہیزگار ہیں ( گو ان سے نسبی رشتہ بھی نہ ہو ) ۔ عنبسہ بن عبدالواحد نے بیان بن بشر سے، انہوں نے قیس سے، انہوں نے عمرو بن العاص سے اتنا بڑھایا ہے کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ نے فرمایا البتہ ان سے میرا رشتہ ناطہٰ ہے اگر وہ تر رکھیں گے تو میں بھی تر رکھوں گا یعنی وہ ناطہٰ جوڑیں گے تو میں بھی جوڑوں گا۔' WHERE id = 5763;
UPDATE hadiths SET urdu = 'ہم سے حکم بن نافع نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، کہا ہم کو سعید بن مسیب نے خبر دی کہ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ نے رحمت کے سو حصے بنائے اور اپنے پاس ان میں سے ننانوے حصے رکھے صرف ایک حصہ زمین پر اتارا اور اسی کی وجہ سے تم دیکھتے ہو کہ مخلوق ایک دوسرے پر رحم کرتی ہے، یہاں تک کہ گھوڑی بھی اپنے بچہ کو اپنے سم نہیں لگنے دیتی بلکہ سموں کو اٹھا لیتی ہے کہ کہیں اس سے اس کے بچہ کو تکلیف نہ پہنچے۔' WHERE id = 5773;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا کہ مجھے ابوسلمہ بن عبدالرحمٰن نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ایک نماز کے لیے کھڑے ہوئے اور ہم بھی نبی کریم صلی اللہ علیہ وسلم کے ساتھ کھڑے ہوئے۔ نماز پڑھتے ہی ایک دیہاتی نے کہا: اے اللہ! مجھ پر رحم کر اور محمد ( صلی اللہ علیہ وسلم ) پر اور ہمارے ساتھ کسی اور پر رحم نہ کر۔ جب نبی کریم صلی اللہ علیہ وسلم نے سلام پھیرا تو دیہاتی سے فرمایا کہ تم نے ایک وسیع چیز کو تنگ کر دیا آپ کی مراد اللہ کی رحمت سے تھی۔' WHERE id = 5783;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا کہ مجھے ابوعمران نے خبر دی، کہا کہ میں نے طلحہ سے سنا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! میری پڑوسنیں ہیں ( اگر ہدیہ ایک ہو تو ) میں ان میں سے کس کے پاس ہدیہ بھیجوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”جس کا دروازہ تم سے ( تمہارے دروازے سے ) زیادہ قریب ہو۔“' WHERE id = 5793;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عیسیٰ نے بیان کیا، کہا ہم سے محمد بن سواء نے بیان کیا، کہا ہم سے روح ابن قاسم نے بیان کیا، ان سے محمد بن منکدر نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم سے ایک شخص نے اندر آنے کی اجازت چاہی۔ نبی کریم صلی اللہ علیہ وسلم نے اسے دیکھ کر فرمایا کہ برا ہے فلاں قبیلہ کا بھائی۔ یا ( آپ صلی اللہ علیہ وسلم نے فرمایا ) کہ برا ہے فلاں قبیلہ کا بیٹا۔ پھر جب وہ نبی کریم صلی اللہ علیہ وسلم کے پاس آ بیٹھا تو آپ اس کے ساتھ بہت خوش خلقی کے ساتھ پیش آئے۔ وہ شخص جب چلا گیا تو عائشہ رضی اللہ عنہا نے آپ سے عرض کیا: یا رسول اللہ! جب آپ نے اسے دیکھا تھا تو اس کے متعلق یہ کلمات فرمائے تھے، جب آپ اس سے ملے تو بہت ہی خندہ پیشانی سے ملے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اے عائشہ! تم نے مجھے بدگو کب پایا۔ اللہ کے یہاں قیامت کے دن وہ لوگ بدترین ہوں گے جن کے شر کے ڈر سے لوگ اس سے ملنا چھوڑ دیں۔' WHERE id = 5804;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عبداللہ بن زمعہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے کسی کی ریح خارج ہونے پر ہنسنے سے منع فرمایا اور آپ نے یہ بھی فرمایا کہ تم میں سے کس طرح ایک شخص اپنی بیوی کو زور سے مارتا ہے جیسے اونٹ، حالانکہ اس کی پوری امید ہے کہ شام میں اسے وہ گلے لگائے گا۔ اور ثوری، وہیب اور ابومعاویہ نے ہشام سے بیان کیا کہ ( جانور کی طرح ) کے بجائے لفظ غلام کی طرح کا استعمال کیا۔' WHERE id = 5814;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ بلخی نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، ان سے اعمش نے بیان کیا، انہوں نے مجاہد سے سنا، وہ طاؤس سے بیان کرتے تھے اور وہ ابن عباس رضی اللہ عنہما سے، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم دو قبروں کے پاس سے گزرے اور فرمایا کہ ان دونوں مردوں کو عذاب ہو رہا ہے اور یہ کسی بڑے گناہ کی وجہ سے عذاب میں گرفتار نہیں ہیں بلکہ یہ ( ایک قبر کا مردہ ) اپنے پیشاب کی چھینٹوں سے نہیں بچتا تھا ( یا پیشاب کرتے وقت پردہ نہیں کرتا تھا ) اور یہ ( دوسری قبر والا مردہ ) چغل خور تھا، پھر آپ صلی اللہ علیہ وسلم نے ایک ہری شاخ منگائی اور اسے دو ٹکڑوں میں توڑ کر دونوں قبروں پر گاڑ دیا اس کے بعد فرمایا کہ جب تک یہ شاخیں سوکھ نہ جائیں اس وقت تک شاید ان دونوں کا عذاب ہلکا رہے۔' WHERE id = 5824;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے موسیٰ بن عقبہ نے بیان کیا، ان سے سالم نے اور ان سے ان کے والد عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم کو ازار لٹکانے کے بارے میں جو کچھ فرمانا تھا جب آپ نے فرمایا تو ابوبکر رضی اللہ عنہ نے عرض کیا کہ یا رسول اللہ! میرا تہمد ایک طرف سے لٹکنے لگتا ہے، تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم ان تکبر کرنے والوں میں سے نہیں ہو۔' WHERE id = 5834;
UPDATE hadiths SET urdu = 'اور محمد بن عیسیٰ نے بیان کیا کہ ہم سے ہشیم نے بیان کیا، کہا ہم کو حمید طویل نے خبر دی، کہا ہم سے انس بن مالک نے کہ رسول اللہ صلی اللہ علیہ وسلم کے اخلاق فاضلہ کا یہ حال تھا کہ ایک لونڈی مدینہ کی لونڈیوں میں سے آپ کا ہاتھ پکڑ لیتی اور اپنے کسی بھی کام کے لیے جہاں چاہتی آپ کو لے جاتی تھی۔' WHERE id = 5844;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا ہم سے ابراہیم نے بیان کیا، ان سے صالح بن کیسان نے، ان سے ابن شہاب نے، ان سے عبدالحمید بن عبدالرحمٰن بن زید بن خطاب نے، ان سے محمد بن سعد نے اور ان سے ان کے والد نے بیان کیا کہ عمر بن خطاب رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہونے کی اجازت چاہی۔ اس وقت نبی کریم صلی اللہ علیہ وسلم کے پاس آپ کی کئی بیویاں جو قریش سے تعلق رکھتی تھیں آپ سے خرچ دینے کے لیے تقاضا کر رہی تھیں اور اونچی آواز میں باتیں کر رہی تھیں۔ جب عمر رضی اللہ عنہ نے اجازت چاہی تو وہ جلدی سے بھاگ کر پردے کے پیچھے چلی گئیں۔ پھر نبی کریم صلی اللہ علیہ وسلم نے ان کو اجازت دی اور وہ داخل ہوئے۔ نبی کریم صلی اللہ علیہ وسلم اس وقت ہنس رہے تھے، عمر رضی اللہ عنہ نے عرض کیا: اللہ آپ کو خوش رکھے، یا رسول اللہ! میرے ماں باپ آپ پر قربان ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ان پر مجھے حیرت ہوئی، جو ابھی میرے پاس تقاضا کر رہی تھیں، جب انہوں نے تمہاری آواز سنی تو فوراً بھاگ کر پردے کے پیچھے چلی گئیں۔ عمر رضی اللہ عنہ نے اس پر عرض کیا: یا رسول اللہ! آپ اس کے زیادہ مستحق ہیں کہ آپ سے ڈرا جائے، پھر عورتوں کو مخاطب کر کے انہوں نے کہا، اپنی جانوں کی دشمن! مجھ سے تو تم ڈرتی ہو او اللہ کے رسول سے نہیں ڈرتیں۔ انہوں نے عرض کیا: آپ نبی کریم صلی اللہ علیہ وسلم سے زیادہ سخت ہیں۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا: ہاں اے ابن خطاب! اس ذات کی قسم جس کے ہاتھ میں میری جان ہے، اگر شیطان بھی تمہیں راستے پر آتا ہوا دیکھے گا تو تمہارا راستہ چھوڑ کر دوسرے راستے پر چلا جائے گا۔' WHERE id = 5855;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے جریر نے بیان کیا، انہوں نے کہا ہم سے ابورجاء نے بیان کیا، ان سے سمرہ بن جندب رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میرے پاس گذشتہ رات خواب میں دو آدمی آئے انہوں نے کہا کہ جسے آپ نے دیکھا کہ اس کا جبڑا چیرا جا رہا تھا وہ بڑا ہی جھوٹا تھا، جو ایک بات کو لیتا اور ساری دنیا میں پھیلا دیتا تھا، قیامت تک اس کو یہی سزا ملتی رہے گی۔“' WHERE id = 5865;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبادہ نے بیان کیا، کہا ہم کو یزید نے خبر دی، کہا ہم کو سلیم نے خبر دی، کہا ہم سے عمرو بن دینار نے بیان کیا، ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ معاذ بن جبل رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ نماز پڑھتے، پھر اپنی قوم میں آتے اور انہیں نماز پڑھاتے۔ انہوں نے ( ایک مرتبہ ) نماز میں سورۃ البقرہ پڑھی۔ اس پر ایک صاحب جماعت سے الگ ہو گئے اور ہلکی نماز پڑھی۔ جب اس کے متعلق معاذ کو معلوم ہوا تو کہا وہ منافق ہے۔ معاذ کی یہ بات جب ان کو معلوم ہوئی تو وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا: یا رسول اللہ! ہم لوگ محنت کا کام کرتے ہیں اور اپنی اونٹنیوں کو خود پانی پلاتے ہیں معاذ نے کل رات ہمیں نماز پڑھائی اور سورۃ البقرہ پڑھنی شروع کر دی۔ اس لیے میں نماز توڑ کر الگ ہو گیا، اس پر وہ کہتے ہیں کہ میں منافق ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اے معاذ! تم لوگوں کو فتنہ میں مبتلا کرتے ہو، تین مرتبہ آپ صلی اللہ علیہ وسلم نے یہ فرمایا ( جب امام ہو تو ) سورۃ «اقرأ»،‏‏‏‏ «والشمس وضحاها‏» اور «سبح اسم ربك الأعلى‏» جیسی سورتیں پڑھا کرو۔' WHERE id = 5875;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن یوسف نے بیان کیا، کہا ہم کو ابوبکر نے خبر دی جو ابن عیاش ہیں، انہیں ابوحصین نے، انہیں ابوصالح نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ ایک شخص نے نبی کریم صلی اللہ علیہ وسلم سے عرض کیا کہ مجھے آپ کوئی نصیحت فرما دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ غصہ نہ ہوا کر۔ انہوں نے کئی مرتبہ یہ سوال کیا اور نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ غصہ نہ ہوا کر۔' WHERE id = 5885;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے مالک نے، ان سے ابن شہاب نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب بھی رسول اللہ صلی اللہ علیہ وسلم کو دو چیزوں میں سے ایک کو اختیار کرنے کا اختیار دیا گیا تو آپ نے ہمیشہ ان میں آسان چیزوں کو اختیار فرمایا، بشرطیکہ اس میں گناہ کا کوئی پہلو نہ ہوتا۔ اگر اس میں گناہ کا کوئی پہلو ہوتا تو نبی کریم صلی اللہ علیہ وسلم اس سے سب سے زیادہ دور رہتے اور نبی کریم صلی اللہ علیہ وسلم نے اپنی ذات کے لیے کسی سے بدلہ نہیں لیا، البتہ اگر کوئی شخص اللہ کی حرمت و حد کو توڑتا تو نبی کریم صلی اللہ علیہ وسلم ان سے تو محض اللہ کی رضا مندی کے لیے بدلہ لیتے۔' WHERE id = 5895;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا کہ ہم سے ابن مہندی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے ابوحصین نے، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو شخص اللہ اور آخرت کے دن پر ایمان رکھتا ہو، اس پر لازم ہے کہ اپنے پڑوسی کو تکلیف نہ دے، جو شخص اللہ اور آخرت کے دن پر ایمان رکھتا ہو، اس پر لازم ہے کہ اپنے مہمان کی عزت کرے اور جو شخص اللہ اور آخرت کے دن پر ایمان رکھتا ہو، اس پر لازم ہے کہ بھلی بات کہے ورنہ چپ رہے۔“' WHERE id = 5905;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے حاتم بن اسماعیل نے، ان سے برید ابن ابی عبید نے اور ان سے سلمہ بن اکوع رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ جنگ خیبر میں گئے اور ہم نے رات میں سفر کیا، اتنے میں مسلمانوں کے آدمی نے عامر بن اکوع رضی للہ عنہ سے کہا کہ اپنے کچھ شعر اشعار سناؤ۔ راوی نے بیان کیا کہ عامر شاعر تھے۔ وہ لوگوں کو اپنی حدی سنانے لگے۔ ”اے اللہ! اگر تو نہ ہوتا تو ہم ہدایت نہ پاتے نہ ہم صدقہ دے سکتے اور نہ نماز پڑھ سکتے۔ ہم تجھ پر فدا ہوں، ہم نے جو کچھ پہلے گناہ کئے ان کو تو معاف کر دے اور جب ( دشمن سے ) ہمارا سامنا ہو تو ہمیں ثابت قدم رکھ اور ہم پر سکون نازل فرما۔ جب ہمیں جنگ کے لیے بلایا جاتا ہے، تو ہم موجود ہو جاتے ہیں اور دشمن نے بھی پکار کر ہم سے نجات چاہی ہے۔“ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ یہ کون اونٹوں کو ہانک رہا ہے جو حدی گا رہا ہے؟ صحابہ نے عرض کیا کہ عامر بن اکوع ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ پاک اس پر رحم کرے۔ ایک صحابی یعنی عمر رضی اللہ عنہ نے کہا: یا رسول اللہ! اب تو عامر شہید ہوئے۔ کاش اور چند روز آپ ہم کو عامر سے فائدہ اٹھانے دیتے۔ راوی نے بیان کیا کہ پھر ہم خیبر آئے اور اس کو گھیر لیا اس گھراؤ میں ہم شدید فاقوں میں مبتلا ہوئے، پھر اللہ تعالیٰ نے خیبر والوں پر ہم کو فتح عطا فرمائی جس دن ان پر فتح ہوئی اس کی شام کو لوگوں نے جگہ جگہ آگ جلائی۔ نبی کریم صلی اللہ علیہ وسلم نے پوچھا کہ یہ آگ کیسی ہے، کس کام کے لیے تم لوگوں نے یہ آگ جلائی ہے؟ صحابہ نے عرض کیا کہ گوشت پکانے کے لیے۔ اس پر آپ نے دریافت فرمایا کس چیز کے گوشت کے لیے؟ صحابہ نے کہا کہ بستی کے پالتو گدھوں کا گوشت پکانے کے لیے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ گوشت کو برتنوں میں سے پھینک دو اور برتنوں کو توڑ دو۔ ایک صحابی نے عرض کیا: یا رسول اللہ! ہم گوشت تو پھینک دیں، مگر برتن توڑنے کے بجائے اگر دھو لیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اچھا یوں ہی کر لو۔ جب لوگوں نے جنگ کی صف بندی کر لی تو عامر ( ابن اکوع شاعر ) نے اپنی تلوار سے ایک یہودی پر وار کیا، ان کی تلوار چھوٹی تھی اس کی نوک پلٹ کر خود ان کے گھٹنوں پر لگی اور اس کی وجہ سے ان کی شہادت ہو گئی۔ جب لوگ واپس آنے لگے تو سلمہ ( عامر کے بھائی ) نے بیان کیا کہ مجھے نبی کریم صلی اللہ علیہ وسلم نے دیکھا کہ میرے چہرے کا رنگ بدلا ہوا ہے۔ دریافت فرمایا کہ کیا بات ہے؟ میں نے عرض کیا: یا رسول اللہ! پر میرے ماں اور باپ فدا ہوں، لوگ کہہ رہے ہیں کہ عامر کے اعمال برباد ہو گئے۔ ( کیونکہ ان کی موت خود ان کی تلوار سے ہوئی ہے ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا یہ کس نے کہا؟ میں نے عرض کیا: فلاں، فلاں، فلاں اور اسید بن حضیر انصاری نے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس نے یہ بات کہی اس نے جھوٹ کہا ہے انہیں تو دوہرا اجر ملے گا۔ نبی کریم صلی اللہ علیہ وسلم نے اپنی دو انگلیوں کو ملا کر اشارہ کیا کہ وہ عابد بھی تھا اور مجاہد بھی ( تو عبادت اور جہاد دونوں کا ثواب اس نے پایا ) عامر کی طرح تو بہت کم بہادر عرب میں پیدا ہوئے ہیں ( وہ ایسا بہادر اور نیک آدمی تھا ) ۔' WHERE id = 5916;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، کہا ہم سے امام مالک نے، ان سے عمر بن عبیداللہ کے غلام ابوالنضر نے، ان سے ام ہانی بنت ابی طالب کے غلام ابو مرہ نے خبر دی کہ انہوں نے ام ہانی بنت ابی طالب سے سنا۔ انہوں نے بیان کیا کہ فتح مکہ کے موقع پر میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی۔ میں نے دیکھا کہ آپ غسل کر رہے ہیں اور آپ کی صاحبزادی فاطمہ رضی اللہ عنہا نے پردہ کر دیا ہے۔ میں نے سلام کیا تو نبی کریم صلی اللہ علیہ وسلم نے دریافت کیا کہ یہ کون ہیں؟ میں نے کہا کہ ام ہانی بنت ابی طالب ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، ام ہانی! مرحبا ہو۔ جب آپ غسل کر چکے تو کھڑے ہو کر آٹھ رکعات پڑھیں۔ آپ اس وقت ایک کپڑے میں جسم مبارک کو لپیٹے ہوئے تھے۔ جب نماز سے فارغ ہو گئے تو میں نے عرض کیا: یا رسول اللہ! میرے بھائی ( علی بن ابی طالب رضی اللہ عنہ ) کا خیال ہے کہ وہ ایک ایسے شخص کو قتل کریں گے جسے میں نے امان دے رکھی ہے۔ یعنی فلاں بن ہبیرہ کو۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ام ہانی جسے تم نے امان دی اسے ہم نے بھی امان دی۔ ام ہانی نے بیان کیا کہ یہ نماز چاشت کی تھی۔' WHERE id = 5926;
UPDATE hadiths SET urdu = 'ہم سے بشر بن خالد نے بیان کیا، انہوں نے کہا ہم سے محمد بن جعفر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے سلیمان نے، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”انسان اس کے ساتھ ہے جس سے وہ محبت رکھتا ہے۔“' WHERE id = 5936;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، وہ یونس سے روایت کرتے ہیں، وہ زہری سے، وہ ابوامامہ بن سہل سے، وہ اپنے باپ سے، وہ نبی کریم صلی اللہ علیہ وسلم سے، آپ صلی اللہ علیہ وسلم نے فرمایا ”تم میں سے کوئی ہرگز یوں نہ کہے کہ میرا نفس پلید ہو گیا لیکن یوں کہہ سکتا ہے کہ میرا دل خراب یا پریشان ہو گیا۔“ اس حدیث کو عقیل نے بھی ابن شہاب سے روایت کیا ہے۔' WHERE id = 5946;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نصر نے بیان کیا، انہوں نے نے کہا ہم سے عبدالرزاق نے بیان کیا، انہوں نے کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں سعید بن مسیب نے اور انہیں ان کے والد مسیب رضی اللہ عنہ نے کہ ان کے والد ( حزن بن ابی وہب ) نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے تو نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ تمہارا نام کیا ہے؟ انہوں نے بتایا کہ «حزن» ( بمعنی سختی ) ۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم «سهل» ( بمعنی نرمی ) ہو، پھر انہوں نے کہا کہ میرا نام میرے والد رکھ گئے ہیں اسے میں نہیں بدلوں گا۔ ابن مسیب رحمہ اللہ بیان کرتے تھے کہ چنانچہ ہمارے خاندان میں بعد تک ہمیشہ سختی اور مصیبت کا دور رہا۔' WHERE id = 5956;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے خبر دی، انہوں نے کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے زہری نے بیان کیا، ان سے سعید نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم نے سر مبارک رکوع سے اٹھایا تو یہ دعا کی «اللهم أنج الوليد بن الوليد وسلمة بن هشام،‏‏‏‏ وعياش بن أبي ربيعة،‏‏‏‏ والمستضعفين بمكة» ”اے اللہ! ولید بن ولید، سلمہ بن ہشام، عیاش بن ابی ربیعہ اور مکہ میں دیگر موجود کمزور مسلمانوں کو نجات دیدے۔“ «اللهم اشدد وطأتك على مضر،‏‏‏‏ اللهم اجعلها عليهم سنين كسني يوسف» ”اے اللہ! قبیلہ مضر کے کفاروں کو سخت پکڑ، اے اللہ! ان پر یوسف علیہ السلام کے زمانہ جیسا قحط نازل فرما۔“' WHERE id = 5966;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے حماد نے بیان کیا، ان سے ثابت بنانی نے بیان کیا، ان سے انس و ایوب نے، ان سے ابوقلابہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم ایک سفر میں تھے، انجشہ نامی غلام عورتوں کی سواریوں کو حدی پڑھتا لے کر چل رہا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے اس سے فرمایا ”انجشہ! شیشوں کو آہستہ لے چل۔“ ابوقلابہ نے بیان کیا کہ مراد عورتیں تھیں۔' WHERE id = 5976;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے، انہوں نے عقبہ بن صہبان ازدی سے سنا، وہ عبداللہ بن مغفل مزنی سے نقل کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے کنکری پھینکنے سے منع کیا تھا اور فرمایا تھا کہ وہ نہ شکار مار سکتی ہے اور نہ دشمن کو کوئی نقصان پہنچا سکتی ہے، البتہ آنکھ پھوڑ سکتی ہے اور دانت توڑ سکتی ہے۔' WHERE id = 5986;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا، انہوں نے کہا ہم سے ہمارے والد نے بیان کیا، انہوں نے کہا ہم سے اعمش نے بیان کیا، انہوں نے کہا کہ مجھ سے شقیق نے بیان کیا اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ جب ہم ( ابتداء اسلام میں ) نبی کریم صلی اللہ علیہ وسلم کے ساتھ نماز پڑھتے تو کہتے ”سلام ہو اللہ پر اس کے بندوں سے پہلے، سلام ہو جبرائیل پر، سلام ہو میکائیل پر، سلام ہو فلاں پر، پھر ( ایک مرتبہ ) جب نبی کریم صلی اللہ علیہ وسلم نماز سے فارغ ہوئے تو ہماری طرف متوجہ ہو کر فرمایا کہ اللہ ہی سلام ہے۔ اس لیے جب تم میں سے کوئی نماز میں بیٹھے تو «التحيات لله،‏‏‏‏ والصلوات والطيبات السلام عليك أيها النبي ورحمة الله وبركاته،‏‏‏‏ السلام علينا وعلى عباد الله الصالحين‏.‏» الخ پڑھا کرے۔ کیونکہ جب وہ یہ دعا پڑھے گا تو آسمان و زمین کے ہر صالح بندے کو اس کی یہ دعا پہنچے گی۔ «أشهد أن لا إله إلا الله وأشهد أن محمدا عبده ورسوله‏.‏» اس کے بعد اسے اختیار ہے جو دعا چاہے پڑھے۔' WHERE id = 5996;
UPDATE hadiths SET urdu = 'ہم سے اسحاق نے بیان کیا، کہا ہم کو یعقوب نے خبر دی، مجھ سے میرے والد نے بیان کیا، ان سے صالح نے، ان سے ابن شہاب نے بیان کیا، کہا کہ مجھے عروہ بن زبیر نے خبر دی اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ عمر بن خطاب رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم سے کہا کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم ازواج مطہرات کا پردہ کرائیں۔ بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایسا نہیں کیا اور ازواج مطہرات رفع حاجت کے لیے صرف رات ہی کے وقت نکلتی تھیں ( اس وقت گھروں میں بیت الخلاء نہیں تھے ) ایک مرتبہ سودہ بنت زمعہ رضی اللہ عنہا باہر گئی ہوئی تھیں۔ ان کا قد لمبا تھا۔ عمر بن خطاب رضی اللہ عنہ نے انہیں دیکھا۔ اس وقت وہ مجلس میں بیٹھے ہوئے تھے۔ انہوں نے کہا سودہ میں نے آپ کو پہچان لیا یہ انہوں نے اس لیے کہا کیونکہ وہ پردہ کے حکم نازل ہونے کے بڑے متمنی تھے۔ بیان کیا کہ پھر اللہ تعالیٰ نے پردہ کی آیت نازل کی۔' WHERE id = 6006;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے محمد بن منکدر نے کہا کہ میں نے جابر رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں اس قرض کے بارے میں حاضر ہوا جو میرے والد پر تھا۔ میں نے دروازہ کھٹکھٹایا۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کون ہیں؟ میں نے کہا ”میں“ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں، میں“ جیسے آپ نے اس جواب کو ناپسند فرمایا۔' WHERE id = 6016;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل ابوالحسن نے بیان کیا انہوں نے کہا ہم کو عبداللہ نے خبر دی انہوں نے کہا ہم کو یونس نے خبر دی اور ان سے زہری نے بیان کیا انہیں عبیداللہ بن عبداللہ بن عتبہ نے خبر دی انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی اور انہیں ابوسفیان بن حرب رضی اللہ عنہ نے خبر دی کہ ہرقل نے قریش کے چند افراد کے ساتھ انہیں بھی بلا بھیجا یہ لوگ شام تجارت کی غرض سے گئے تھے سب لوگ ہرقل کے پاس آئے پھر انہوں نے واقعہ بیان کیا کہ پھر ہرقل نے رسول اللہ صلی اللہ علیہ وسلم کا خط منگوایا اور وہ پڑھا گیا خط میں یہ لکھا ہوا تھا۔ بسم اللہ الرحمن الرحیم، محمد کی طرف سے جو اللہ کا بندہ اور اس کا رسول ہے ( صلی اللہ علیہ وسلم ) ۔ ہرقل عظیم روم کی طرف، سلام ہو ان پر جنہوں نے ہدایت کی اتباع کی۔ امابعد' WHERE id = 6026;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے عبداللہ عمری نے، ان سے نافع اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے اس سے منع فرمایا تھا کہ کسی شخص کو اس کی جگہ سے اٹھایا جائے تاکہ دوسرا اس کی جگہ پر بیٹھے، البتہ ( آنے والے کو مجلس میں ) جگہ دے دیا کرو اور فراخی کر دیا کرو اور ابن عمر رضی اللہ عنہما ناپسند کرتے تھے کہ کوئی شخص مجلس میں سے کسی کو اٹھا کر خود اس کی جگہ بیٹھ جائے۔' WHERE id = 6036;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے عبدالعزیز بن حازم نے بیان کیا، ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ علی رضی اللہ عنہ کو کوئی نام ابوتراب سے زیادہ محبوب نہیں تھا۔ جب ان کو اس نام سے بلایا جاتا تو وہ خوش ہوتے تھے۔ ایک مرتبہ رسول اللہ صلی اللہ علیہ وسلم ، فاطمہ علیہا السلام کے گھر تشریف لائے تو علی رضی اللہ عنہ کو گھر میں نہیں پایا تو فرمایا کہ بیٹی تمہارے چچا کے لڑکے ( اور شوہر ) کہاں گئے ہیں؟ انہوں نے کہا میرے اور ان کے درمیان کچھ تلخ کلامی ہو گئی تھی وہ مجھ پر غصہ ہو کر باہر چلے گئے اور میرے یہاں ( گھر میں ) قیلولہ نہیں کیا۔ نبی کریم صلی اللہ علیہ وسلم نے ایک شخص سے کہا کہ دیکھو وہ کہاں ہیں۔ وہ صحابی واپس آئے اور عرض کیا: یا رسول اللہ! وہ تو مسجد میں سوئے ہوئے ہیں۔ نبی کریم صلی اللہ علیہ وسلم مسجد میں تشریف لائے تو علی رضی اللہ عنہ لیٹے ہوئے تھے اور چادر آپ کے پہلو سے گر گئی تھی اور گرد آلود ہو گئی تھی نبی کریم صلی اللہ علیہ وسلم اس سے مٹی صاف کرنے لگے اور فرمانے لگے، ابوتراب! ( مٹی والے ) اٹھو، ابوتراب! اٹھو۔' WHERE id = 6046;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، انہوں نے کہا ہم سے ابواسامہ نے بیان کیا، ہم سے برید بن عبداللہ نے بیان کیا، ان سے ابوبردہ نے بیان کیا اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ مدینہ منورہ میں ایک گھر رات کے وقت جل گیا۔ نبی کریم صلی اللہ علیہ وسلم سے اس کے متعلق کہا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ آگ تمہاری دشمن ہے اس لیے جب سونے لگو تو اسے بجھا دیا کرو۔' WHERE id = 6058;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ہر نبی کو ایک دعا حاصل ہوتی ہے ( جو قبول کی جاتی ہے ) اور میں چاہتا ہوں کہ میں اپنی دعا کو آخرت میں اپنی امت کی شفاعت کے لیے محفوظ رکھوں۔“' WHERE id = 6068;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے عبدالملک بن عمیر نے، ان سے ربعی نے اور ان سے حذیفہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جب رات میں بستر پر لیٹتے تو اپنا ہاتھ اپنے رخسار کے نیچے رکھتے اور یہ کہتے «اللهم باسمك أموت وأحيا» ”اے اللہ! تیرے نام کے ساتھ مرتا ہوں اور زندہ ہوتا ہوں۔“ اور جب آپ بیدار ہوتے تو کہتے «الحمد لله الذي أحيانا بعد ما أماتنا وإليه النشور‏ ‏‏.‏» ”تمام تعریفیں اس اللہ کے لیے ہیں جس نے ہمیں زندہ کیا اس کے بعد کہ ہمیں موت ( مراد نیند ہے ) دے دی تھی اور تیری ہی طرف جانا ہے۔“' WHERE id = 6078;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عبدالملک بن عمیر نے، ان سے ربعی بن حراش نے اور ان سے حذیفہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جب سونے کا ارادہ کرتے تو کہتے «باسمك اللهم أموت وأحيا» ”تیرے نام کے ساتھ، اے اللہ! میں مرتا اور تیرے ہی نام سے جیتا ہوں۔“ اور جب بیدار ہوتے تو یہ دعا پڑھتے «الحمد لله الذي أحيانا بعد ما أماتنا،‏‏‏‏ وإليه النشور» ”تمام تعریفیں اس اللہ کے لیے ہیں جس نے ہمیں موت کے بعد زندگی بخشی اور اسی کی طرف ہم کو لوٹنا ہے۔“' WHERE id = 6088;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ربیع نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے کہا کہ میں نے انس رضی اللہ عنہ سے سنا، کہا کہ ام سلیم رضی اللہ عنہا نے رسول اللہ صلی اللہ علیہ وسلم سے کہا کہ انس آپ کا خادم ہے اس کے حق میں دعا فرمائیے۔ نبی کریم صلی اللہ علیہ وسلم نے دعا فرمائی «اللهم أكثر ماله وولده،‏‏‏‏ وبارك له فيما أعطيته» ”یا اللہ! اس کے مال و اولاد کو زیادہ کر اور جو کچھ تو نے اسے دیا ہے، اس میں اسے برکت عطا فرمائیو۔“' WHERE id = 6098;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی الاسود نے بیان کیا، کہا ہم سے حرمی بن عمارہ نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ میری والدہ ( ام سلیم رضی اللہ عنہ ) نے کہا: یا رسول اللہ! انس رضی اللہ عنہ آپ کا خادم ہے اس کے لیے دعا فرما دیں۔ نبی کریم صلی اللہ علیہ وسلم نے دعا کی کہ اے اللہ! اس کے مال و اولاد کو زیادہ کر اور جو کچھ تو نے اسے دیا ہے اس میں برکت عطا فرما۔' WHERE id = 6108;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے صالح بن کیسان نے، ان سے ابن شہاب نے بیان کیا، انہیں محمود بن ربیع رضی اللہ عنہ نے خبر دی یہ محمود وہ بزرگ ہیں جن کے منہ میں رسول اللہ صلی اللہ علیہ وسلم نے جس وقت وہ بچے تھے، انہیں کے کنوئیں سے پانی لے کر کلی کر لی تھی۔' WHERE id = 6118;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے، کہا ہم سے موسیٰ بن عقبہ نے بیان کیا، کہا کہ میں نے ام خالد بنت خالد بن سعید رضی اللہ عنہما سے سنا (موسیٰ نے) بیان کیا کہ میں نے کسی سے نہیں سنا کہ ان کی بیان کی ہوئی حدیث سے مختلف کسی نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہو، انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا کہ آپ قبر کے عذاب سے اللہ کی پناہ مانگتے تھے۔' WHERE id = 6128;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، کہا ہم کو حسین بن علی جعفی نے خبر دی، انہیں زائدہ بن قدامہ نے، انہیں عبدالملک بن عمیر نے، انہیں مصعب بن سعد نے اور ان سے ان کے والد نے بیان کیا کہ ان کلمات کے ذریعہ اللہ کی پناہ مانگو جن کے ذریعہ نبی کریم صلی اللہ علیہ وسلم پناہ مانگتے تھے «اللهم إني أعوذ بك من الجبن،‏‏‏‏ وأعوذ بك من البخل،‏‏‏‏ وأعوذ بك من أن أرد إلى أرذل العمر،‏‏‏‏ وأعوذ بك من فتنة الدنيا،‏‏‏‏ وعذاب القبر» ”اے اللہ! میں تیری پناہ مانگتا ہوں بزدلی سے، تیری پناہ مانگتا ہوں بخل سے، اس سے کہ ناکارہ عمر کو پہنچوں، تیری پناہ مانگتا ہوں دنیا کی آزمائش سے اور قبر کے عذاب سے۔“' WHERE id = 6138;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے عمرو نے اور ان سے جابر رضی اللہ عنہ نے بیان کیاکہ میرے والد شہید ہوئے تو انہوں نے سات یا نو لڑکیاں چھوڑی تھیں ( راوی کو تعداد میں شبہ تھا ) پھر میں نے ایک عورت سے شادی کی تو رسول اللہ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ جابر کیا تم نے شادی کر لی ہے؟ میں نے کہا جی ہاں۔ فرمایا کنواری سے یا بیوہ سے؟ میں نے کہا بیاہی سے۔ فرمایا، کسی لڑکی ( کنواری ) سے کیوں نہ کی۔ تم اس کے ساتھ کھیلتے اور وہ تمہارے ساتھ کھیلتی یا ( آپ صلی اللہ علیہ وسلم نے فرمایا کہ ) تم اسے ہنساتے اور وہ تمہیں ہنساتی۔ میں نے عرض کی، میرے والد ( عبداللہ ) شہید ہوئے اور سات یا نو لڑکیاں چھوڑی ہیں۔ اس لیے میں نے پسند نہیں کیا کہ میں ان کے پاس انہی جیسی لڑکی لاؤں۔ چنانچہ میں نے ایسی عورت سے شادی کی جو ان کی نگرانی کر سکے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تمہیں برکت عطا فرمائے۔ ابن عیینہ اور محمد بن مسلمہ نے عمرو سے روایت میں ”اللہ تمہیں برکت عطا فرمائے“ کے الفاظ نہیں کہے۔' WHERE id = 6149;
UPDATE hadiths SET urdu = 'ہم سے علی نے بیان کیا، ان سے سفیان نے کہا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ طفیل بن عمرو رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا: یا رسول اللہ! قبیلہ دوس نے نافرمانی اور سرکشی کی ہے، آپ ان کے لیے بددعا کیجئے۔ لوگوں نے سمجھا کہ نبی کریم صلی اللہ علیہ وسلم ان کے لیے بددعا ہی کریں گے لیکن نبی کریم صلی اللہ علیہ وسلم نے دعا کی کہ ”اے اللہ! قبیلہ دوس کو ہدایت دے اور انہیں ( میرے پاس ) بھیج دے۔“' WHERE id = 6159;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے یزید بن عبداللہ نے، ان سے ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اس شخص کی مثال جو اپنے رب کو یاد کرتا ہے اور اس کی مثال جو اپنے رب کو یاد نہیں کرتا زندہ اور مردہ جیسی ہے۔“' WHERE id = 6169;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، کہا ہم کو یحییٰ قطان نے خبر دی، ان سے سفیان ثوری نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا، ان سے منذر بن یعلیٰ نے، ان سے ربیع بن خثیم نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے چوکھٹا خط کھینچا۔ پھر اس کے درمیان ایک خط کھینچا جو چوکھٹے کے درمیان میں تھا۔ اس کے بعد درمیان والے خط کے اس حصے میں جو چوکھٹے کے درمیان میں تھا چھوٹے چھوٹے بہت سے خطوط کھینچے اور پھر فرمایا کہ یہ انسان ہے اور یہ اس کی موت ہے جو اسے گھیرے ہوئے ہے اور یہ جو ( بیچ کا ) خط باہر نکلا ہوا ہے وہ اس کی امید ہے اور چھوٹے چھوٹے خطوط اس کی دنیاوی مشکلات ہیں۔ پس انسان جب ایک ( مشکل ) سے بچ کر نکلتا ہے تو دوسری میں پھنس جاتا ہے اور دوسری سے نکلتا ہے تو تیسری میں پھنس جاتا ہے۔' WHERE id = 6179;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے زید بن اسلم نے، ان سے عطا بن یسار نے اور ان سے ابوسعید رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں تمہارے متعلق سب سے زیادہ اس سے خوف کھاتا ہوں کہ جب اللہ تعالیٰ زمین کی برکتیں تمہارے لیے نکال دے گا۔ پوچھا گیا زمین کی برکتیں کیا ہیں؟ فرمایا کہ دنیا کی چمک دمک، اس پر ایک صحابی نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا کیا بھلائی سے برائی پیدا ہو سکتی ہے؟ نبی کریم صلی اللہ علیہ وسلم اس پر خاموش ہو گئے اور ہم نے خیال کیا کہ شاید آپ پر وحی نازل ہو رہی ہے۔ اس کے بعد اپنی پیشانی کو صاف کرنے لگے اور دریافت فرمایا، پوچھنے والے کہاں ہیں؟ پوچھنے والے نے کہا کہ حاضر ہوں۔ ابو سعید خدری رضی اللہ عنہ نے کہا کہ جب اس سوال کا حل ہمارے سامنے آ گیا تو ہم نے ان صاحب کی تعریف کی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بھلائی سے تو صرف بھلائی ہی پیدا ہوتی ہے لیکن یہ مال سرسبز اور خوشگوار ( گھاس کی طرح ) ہے اور جو چیز بھی ربیع کے موسم میں اگتی ہیں وہ حرص کے ساتھ کھانے والوں کو ہلاک کر دیتی ہیں یا ہلاکت کے قریب پہنچا دیتی ہیں۔ سوائے اس جانور کے جو پیٹ بھر کے کھائے کہ جب اس نے کھا لیا اور اس کی دونوں کوکھ بھر گئیں تو اس نے سورج کی طرف منہ کر کے جگالی کر لی اور پھر پاخانہ پیشاب کر دیا اور اس کے بعد پھر لوٹ کے کھا لیا اور یہ مال بھی بہت شیریں ہے جس نے اسے حق کے ساتھ لیا اور حق میں خرچ کیا تو وہ بہترین ذریعہ ہے اور جس نے اسے ناجائز طریقہ سے حاصل کیا تو وہ اس شخص جیسا ہے جو کھاتا ہے لیکن آسودہ نہیں ہوتا۔' WHERE id = 6189;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن سلام نے بیان کیا، انہوں نے کہا ہم کو مخلد نے خبر دی، انہوں نے کہا ہم کو ابن جریج نے خبر دی، انہوں نے کہا کہ میں نے عطاء سے سنا، انہوں نے کہا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا، کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اگر انسان کے پاس مال ( بھیڑ بکری ) کی پوری وادی ہو تو وہ چاہے گا کہ اسے ویسی ہی ایک اور مل جائے اور انسان کی آنکھ مٹی کے سوا اور کوئی چیز نہیں بھر سکتی اور جو اللہ سے توبہ کرتا ہے، وہ اس کی توبہ قبول کرتا ہے۔“ ابن عباس رضی اللہ عنہما نے کہا کہ مجھے معلوم نہیں یہ قرآن میں سے ہے یا نہیں۔ بیان کیا کہ میں نے ابن زبیر رضی اللہ عنہما کو یہ منبر پر کہتے سنا تھا۔' WHERE id = 6199;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے عبدالعزیز بن ابی حازم نے بیان کیا، ان سے ان کے والد نے اور ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ ایک شخص رسول اللہ صلی اللہ علیہ وسلم کے سامنے سے گزرا تو نبی کریم صلی اللہ علیہ وسلم نے ایک دوسرے شخص ابوذرغفاری رضی اللہ عنہ سے جو آپ کے قریب بیٹھے ہوئے تھے، پوچھا کہ اس شخص ( گزرے والے ) کے متعلق تم کیا کہتے ہو؟ انہوں نے کہا کہ یہ معزز لوگوں میں سے ہے اور اللہ کی قسم! یہ اس قابل ہے کہ اگر یہ پیغام نکاح بھیجے تو اس سے نکاح کر دیا جائے۔ اگر یہ سفارش کرے تو ان کی سفارش قبول کر لی جائے۔ بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم یہ سن کر خاموش ہو گئے۔ اس کے بعد ایک دوسرے صاحب گزرے۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے ان کے متعلق بھی پوچھا کہ ان کے بارے میں تمہاری کیا رائے ہے؟ انہوں نے کہا، یا رسول اللہ! یہ صاحب مسلمانوں کے غریب طبقہ سے ہیں اور یہ ایسے ہیں کہ اگر یہ نکاح کا پیغام بھیجیں تو ان کا نکاح نہ کیا جائے، اگر یہ کسی کی سفارش کریں تو ان کی سفارش قبول نہ کی جائے اور اگر کچھ کہیں تو ان کی بات نہ سنی جائے۔ نبی کریم صلی اللہ علیہ وسلم نے اس کے بعد فرمایا کہ اللہ کے نزدیک یہ پچھلا محتاج شخص اگلے مالدار شخص سے، گو ویسے آدمی زمین بھر کر ہوں، بہتر ہے۔' WHERE id = 6209;
UPDATE hadiths SET urdu = 'ہم سے ہدبہ بن خالد نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا کہا کہ ہم انس بن مالک رضی اللہ عنہ کی خدمت میں حاضر ہوتے، ان کا نان بائی وہیں موجود ہوتا ( جو روٹیاں پکا پکا کر دیتا جاتا ) انس رضی اللہ عنہ لوگوں سے کہتے کہ کھاؤ، میں نے کبھی نبی کریم صلی اللہ علیہ وسلم کو پتلی روٹی کھاتے نہیں دیکھا اور نہ نبی کریم صلی اللہ علیہ وسلم نے کبھی اپنی آنکھ سے سموچی بھنی ہوئی بکری دیکھی۔ یہاں تک کہ آپ کا انتقال ہو گیا۔' WHERE id = 6219;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے محمد بن زبرقان نے، کہا ہم سے موسیٰ بن عقبہ نے، ان سے ابوسلمہ بن عبدالرحمٰن نے، ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”دیکھو جو نیک کام کرو ٹھیک طور سے کرو اور حد سے نہ بڑھ جاؤ بلکہ اس کے قریب رہو ( میانہ روی اختیار کرو ) اور خوش رہو اور یاد رکھو کہ کوئی بھی اپنے عمل کی وجہ سے جنت میں نہیں جائے گا۔ صحابہ نے عرض کیا: اور آپ بھی نہیں یا رسول اللہ! فرمایا اور میں بھی نہیں۔ سوا اس کے کہ اللہ اپنی مغفرت و رحمت کے سایہ میں مجھے ڈھانک لے۔ مدینی نے بیان کیا کہ میرا خیال ہے کہ موسیٰ بن عقبہ نے یہ حدیث ابوسلمہ سے ابوالنصر کے واسطے سے سنی ہے، ابوسلمہ نے عائشہ رضی اللہ عنہا سے۔ اور عفان بن مسلم نے بیان کیا کہ ہم سے وہیب نے بیان کیا، ان سے موسیٰ بن عقبہ نے بیان کیا، کہا کہ میں نے ابوسلمہ رضی اللہ عنہ سے سنا اور انہوں نے عائشہ رضی اللہ عنہا سے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا ”درستی کے ساتھ عمل کرو اور خوش رہو۔“ اور مجاہد نے بیان کیا کہ «سدادا سديدا» ہر دو کے معنیٰ صدق کے ہیں۔' WHERE id = 6229;
UPDATE hadiths SET urdu = 'مجھ سے ابرہیم بن حمزہ نے بیان کیا، کہا مجھ سے ابن ابی حازم نے بیان کیا، ان سے یزید بن عبداللہ نے، ان سے محمد بن ابراہیم نے، ان سے عیسیٰ بن طلحہ تیمی نے اور ان سے ابوہریرہ رضی اللہ عنہ نے، انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا ”بندہ ایک بات زبان سے نکالتا ہے اور اس کے متعلق سوچتا نہیں ( کتنی کفر اور بےادبی کی بات ہے ) جس کی وجہ سے وہ دوزخ کے گڑھے میں اتنی دور گر پڑتا ہے جتنا مغرب سے مشرق دور ہے۔“' WHERE id = 6239;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”دوزخ خواہشات نفسانی سے ڈھک دی گئی ہے اور جنت مشکلات اور دشواریوں سے ڈھکی ہوئی ہے۔“' WHERE id = 6249;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان ثوری نے خبر دی، کہا ہم سے اعمش نے بیان کیا، کہا ان سے زید بن وہب نے، کہا ہم سے حذیفہ رضی اللہ عنہ نے بیان کیا کہ ہم سے رسول اللہ صلی اللہ علیہ وسلم نے دو حدیثیں ارشاد فرمائیں۔ ایک کا ظہور تو میں دیکھ چکا ہوں اور دوسری کا منتظر ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے ہم سے فرمایا کہ امانت لوگوں کے دلوں کی گہرائیوں میں اترتی ہے۔ پھر قرآن شریف سے، پھر حدیث شریف سے اس کی مضبوطی ہوتی جاتی ہے اور نبی کریم صلی اللہ علیہ وسلم نے ہم سے اس کے اٹھ جانے کے متعلق ارشاد فرمایا کہ آدمی ایک نیند سوئے گا اور ( اسی میں ) امانت اس کے دل سے ختم ہو گی اور اس بےایمانی کا ہلکا نشان پڑ جائے گا۔ پھر ایک اور نیند لے گا اب اس کا نشان چھالے کی طرح ہو جائے گا جیسے تو پاؤں پر ایک چنگاری لڑھکائے تو ظاہر میں ایک چھالا پھول آتا ہے اس کو پھولا دیکھتا ہے، پر اندر کچھ نہیں ہوتا۔ پھر حال یہ ہو جائے گا کہ صبح اٹھ کر لوگ خرید و فروخت کریں گے اور کوئی شخص امانت دار نہیں ہو گا، کہا جائے گا کہ بنی فلاں میں ایک امانت دار شخص ہے۔ کسی شخص کے متعلق کہا جائے گا کہ کتنا عقلمند ہے، کتنا بلند حوصلہ ہے اور کتنا بہادر ہے۔ حالانکہ اس کے دل میں رائی برابر بھی ایمان ( امانت ) نہیں ہو گا۔“ ( حذیفہ رضی اللہ عنہ کہتے ہیں ) میں نے ایک ایسا وقت بھی گزارا ہے کہ میں اس کی پروا نہیں کرتا تھا کہ کس سے خرید و فروخت کرتا ہوں۔ اگر وہ مسلمان ہوتا تو اس کو اسلام ( بےایمانی سے ) روکتا تھا۔ اگر وہ نصرانی ہوتا تو اس کا مددگار اسے روکتا تھا لیکن اب میں فلاں اور فلاں کے سوا کسی سے خرید و فروخت ہی نہیں کرتا۔' WHERE id = 6259;
UPDATE hadiths SET urdu = 'ہم سے حجاج نے بیان کیا، کہا ہم سے ہمام نے، کہا ہم سے قتادہ نے ان سے انس رضی اللہ عنہ نے اور ان سے عبادہ بن صامت رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جو شخص اللہ سے ملنے کو محبوب رکھتا ہے، اللہ بھی اس سے ملنے کو محبوب رکھتا ہے اور جو اللہ سے ملنے کو پسند نہیں کرتا ہے اللہ بھی اس سے ملنے کو پسند نہیں کرتا۔“ اور عائشہ رضی اللہ عنہا یا نبی کریم صلی اللہ علیہ وسلم کی بعض ازواج نے عرض کیا کہ مرنا تو ہم بھی نہیں پسند کرتے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کے ملنے سے موت مراد نہیں ہے بلکہ بات یہ ہے کہ ایماندار آدمی کو جب موت آتی ہے تو اسے اللہ کی خوشنودی اور اس کے یہاں اس کی عزت کی خوشخبری دی جاتی ہے۔ اس وقت مومن کو کوئی چیز اس سے زیادہ عزیز نہیں ہوتی جو اس کے آگے ( اللہ سے ملاقات اور اس کی رضا اور جنت کے حصول کے لیے ) ہوتی ہے، اس لیے وہ اللہ سے ملاقات کا خواہشمند ہو جاتا ہے اور اللہ بھی اس کی ملاقات کو پسند کرتا ہے اور جب کافر کی موت کا وقت قریب آتا ہے تو اسے اللہ کے عذاب اور اس کی سزا کی بشارت دی جاتی ہے، اس وقت کوئی چیز اس کے دل میں اس سے زیادہ ناگوار نہیں ہوتی جو اس کے آگے ہوتی ہے۔ وہ اللہ سے جا ملنے کو ناپسند کرنے لگتا ہے، پس اللہ بھی اس سے ملنے کو ناپسند کرتا ہے۔ ابودواؤد طیالسی اور عمرو بن مرزوق نے اس حدیث کو شعبہ سے مختصراً روایت کیا ہے اور سعید بن ابی عروبہ نے بیان کیا، ان سے قتادہ نے، ان سے زرارہ بن ابی اوفی نے، ان سے سعد نے اور ان سے عائشہ رضی اللہ عنہا نے نبی کریم صلی اللہ علیہ وسلم سے روایت کیا۔' WHERE id = 6269;
UPDATE hadiths SET urdu = 'مجھ سے عبدالعزیز بن عبداللہ نے بیان کیا، انہوں نے کہا کہ مجھ سے ابراہیم بن سعد نے بیان کیا، ان سے ابوسلمہ بن عبدالرحمٰن نے اور عبدالرحمٰن الاعرج نے بیان کیا، ان دونوں نے بیان کیا کہ ابوہریرہ رضی اللہ عنہ نے فرمایا کہ دو آدمیوں نے آپس میں گالی گلوچ کی۔ جن میں سے ایک مسلمان تھا اور دوسرا یہودی تھا۔ مسلمان نے کہا کہ اس پروردگار کی قسم جس نے محمد صلی اللہ علیہ وسلم کو تمام جہان پر برگزیدہ کیا۔ یہودی نے کہا کہ اس پروردگار کی قسم جس نے موسیٰ علیہ السلام کو تمام جہان پر برگزیدہ کیا۔ راوی نے بیان کیا کہ مسلمان یہودی کی بات سن کر خفا ہو گیا اور اس کے منہ پر ایک طمانچہ رسید کیا۔ وہ یہودی رسول اللہ صلی اللہ علیہ وسلم کے پاس گیا اور نبی کریم صلی اللہ علیہ وسلم سے اپنا اور مسلمان کا سارا واقعہ بیان کیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”دیکھو موسیٰ علیہ السلام پر مجھ کو فضیلت مت دو کیونکہ قیامت کے دن ایسا ہو گا کہ صور پھونکتے ہی تمام لوگ بیہوش ہو جائیں گے اور میں سب سے پہلا شخص ہوں گا جسے ہوش آئے گا۔ میں کیا دیکھوں گا کہ موسیٰ علیہ السلام عرش الٰہی کا کونہ تھامے ہوئے ہیں۔ مجھے نہیں معلوم کی موسیٰ علیہ السلام بھی ان لوگوں میں ہوں گے جو بیہوش ہوئے تھے اور پھر مجھ سے پہلے ہی ہوش میں آ گئے تھے یا ان میں سے ہوں گے جنہیں اللہ تعالیٰ نے اس سے مستثنیٰ کر دیا۔“' WHERE id = 6279;
UPDATE hadiths SET urdu = 'ہم سے قیس بن حفص نے بیان کیا، کہا ہم سے خالد بن حارث نے بیان کیا، کہا ہم سے حاتم بن ابی صغیرہ نے بیان کیا، ان سے عبداللہ بن ابی ملکیہ نے بیان کیا، کہا کہ مجھ سے قاسم بن محمد بن ابی بکر نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تم ننگے پاؤں، ننگے جسم، بلا ختنہ کے اٹھائے جاؤ گے۔“ عائشہ رضی اللہ عنہا فرماتی ہیں کہ اس پر میں نے پوچھا: یا رسول اللہ! تو کیا مرد عورتیں ایک دوسرے کو دیکھتے ہوں گے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس وقت معاملہ اس سے کہیں زیادہ سخت ہو گا، اس کا خیال بھی کوئی نہیں کر سکے گا۔' WHERE id = 6289;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن منصور نے بیان کیا، کہا ہم سے روح بن عبادہ نے بیان کیا، کہا ہم سے حاتم بن ابوصغیرہ نے بیان کیا، کہا ہم سے عبداللہ بن ابی ملیکہ نے بیان کیا، کہا مجھ سے قاسم بن محمد نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس شخص سے بھی قیامت کے دن حساب لیا گیا پس وہ ہلاک ہوا۔ میں نے عرض کیا: یا رسول اللہ! کیا اللہ تعالیٰ نے خود نہیں فرمایا ہے «فأما من أوتي كتابه بيمينه * فسوف يحاسب حسابا يسيرا‏» کہ ”پس جس کا نامہ اعمال اس کے دائیں ہاتھ میں دیا گیا تو عنقریب اس سے ایک آسان حساب لیا جائے گا۔“ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ تو صرف پیشی ہو گی۔ ( اللہ رب العزت کے کہنے کا مطلب یہ ہے کہ ) قیامت کے دن جس کے بھی حساب میں کھود کرید کی گئی اس کو عذاب یقینی ہو گا۔' WHERE id = 6299;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے اسماعیل بن ابراہیم نے بیان کیا، کہا ہم سے سلیمان تیمی نے بیان کیا، انہیں ابوعثمان نہدی نے، انہیں اسامہ بن زید رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں جنت کے دروازے پر کھڑا ہوا تو وہاں اکثر داخل ہونے والے محتاج لوگ تھے اور محنت مزدوری کرنے والے تھے اور مالدار لوگ ایک طرف روکے گئے ہیں، ان کا حساب لینے کے لیے باقی ہے اور جو لوگ دوزخی تھے وہ تو دوزخ کے لیے بھیج دئیے گئے اور میں نے جہنم کے دروازے پر کھڑے ہو کر دیکھا تو اس میں اکثر داخل ہونے والی عورتیں تھیں۔“' WHERE id = 6309;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر محمد بن جعفر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابوعمران جونی نے بیان کیا، کہا میں نے انس بن مالک رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ قیامت کے دن دوزخ کے سب سے کم عذاب پانے والے سے پوچھے گا اگر تمہیں روئے زمین کی ساری چیزیں میسر ہوں تو کیا تم ان کو فدیہ میں ( اس عذاب سے نجات پانے کے لیے ) دے دو گے، وہ کہے گا کہ ہاں، اللہ تعالیٰ فرمائے گا کہ میں نے تم سے اس سے بھی سہل چیز کا اس وقت مطالبہ کیا تھا جب تم آدم علیہ السلام کی پیٹھ میں تھے کہ میرے ساتھ کسی کو شریک نہ کرنا لیکن تم نے ( توحید کا ) انکار کیا اور نہ مانا آخر شرک ہی کیا۔“' WHERE id = 6319;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے حمید نے اور ان سے انس رضی اللہ عنہ نے کہ حارثہ بن سراقہ بن حارث رضی اللہ عنہ کی والدہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں۔ حارثہ بدر کی لڑائی میں ایک نامعلوم تیر لگ جانے کی وجہ سے شہید ہو گئے تھے اور انہوں نے کہا: یا رسول اللہ! آپ کو معلوم ہے کہ حارثہ سے مجھے کتنی محبت تھی، اگر وہ جنت میں ہے تو اس پر میں نہیں روؤں گی، ورنہ آپ دیکھیں گے کہ میں کیا کرتی ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ بیوقوف ہوئی ہو، کیا کوئی جنت ایک ہی ہے، جنتیں تو بہت سی ہیں اور حارثہ ”فردوس اعلیٰ“ ( جنت کے اونچے درجے ) میں ہے۔' WHERE id = 6329;
UPDATE hadiths SET urdu = 'مجھ سے عمرو بن محمد نے بیان کیا، انہوں نے کہا ہم سے ہشیم نے بیان کیا، انہوں نے کہا ہم کو ابوبشر اور عطاء بن سائب نے خبر دی، انہیں سعید بن جبیر نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ کوثر سے مراد بہت زیادہ بھلائی ( خیر کثیر ) ہے جو اللہ تعالیٰ نے نبی کریم صلی اللہ علیہ وسلم کو دی ہے۔ ابوبشر نے بیان کیا کہ میں نے سعید بن جبیر سے کہا کہ بعض لوگوں کا خیال ہے کہ کوثر جنت میں ایک نہر ہے تو انہوں نے کہا کہ جو نہر جنت میں ہے وہ بھی اس خیر ( بھلائی ) کا ایک حصہ ہے جو اللہ تعالیٰ نے نبی کریم صلی اللہ علیہ وسلم کو دی ہے۔' WHERE id = 6339;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن المنذر نے بیان کیا، انہوں نے کہا کہ ہم سے انس بن عیاض نے بیان کیا، ان سے عبیداللہ نے بیان کیا، ان سے خبیب بن عبدالرحمٰن نے، ان سے حفص بن عاصم نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میرے گھر اور میرے منبر کے درمیان کی جگہ کا جنت کے باغوں میں سے ایک باغ ہے اور میرا منبر میرے حوض پر ہے۔' WHERE id = 6349;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، ان سے یونس نے بیان کیا، ان سے ابن شہاب نے بیان کیا، انہوں نے کہا کہ مجھے عطا بن یزید نے خبر دی، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم سے مشرکین کی اولاد کے متعلق پوچھا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ خوب جانتا ہے کہ وہ کیا عمل کرتے۔' WHERE id = 6359;
UPDATE hadiths SET urdu = 'مجھ سے ابوالحسن محمد بن مقاتل نے بیان کیا، انہوں نے کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہوں نے کہا ہم کو خالد حذاء نے خبر دی، انہیں ابوعثمان نہدی نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ایک غزوہ میں تھے اور جب بھی ہم کسی بلندی پر چڑھتے یا کسی نشیبی علاقہ میں اترتے تو تکبیر بلند آواز سے کہتے۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم ہمارے قریب آئے اور فرمایا ”اے لوگو! اپنے آپ پر رحم کرو، کیونکہ تم کسی بہرے یا غیر موجود کو نہیں پکارتے بلکہ تم اس ذات کو پکارتے ہو جو بہت زیادہ سننے والا بڑا دیکھنے والا ہے۔“ پھر فرمایا: اے عبداللہ بن قیس! ( ابوموسیٰ اشعری رضی اللہ عنہ ) کیا میں تمہیں ایک کلمہ نہ سکھا دوں جو جنت کے خزانوں میں سے ہے۔ ( وہ کلمہ ہے ) «لا حول ولا قوة إلا بالله» یعنی طاقت و قوت اللہ کے سوا اور کسی کے پاس نہیں۔' WHERE id = 6370;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، انہوں نے کہا کہ ہم کو جریر نے خبر دی جو ابن حازم ہیں، انہیں ابواسحاق نے، ان سے براء بن عازب رضی اللہ عنہ نے کہا کہ میں نے غزوہ خندق کے دن رسول اللہ صلی اللہ علیہ وسلم کو دیکھا کہ آپ ہمارے ساتھ مٹی اٹھا رہے تھے اور یہ کہتے جاتے تھے۔ ”واللہ، اگر اللہ نہ ہوتا تو ہم ہدایت نہ پا سکتے۔ نہ روزہ رکھ سکتے اور نہ نماز پڑھ سکتے۔ پس اے اللہ! ہم پر سکینت نازل فرما۔ اور جب سامنا ہو تو ہمیں ثابت قدم رکھ۔ اور مشرکین نے ہم پر زیادتی کی ہے۔ جب وہ کسی فتنہ کا ارادہ کرتے ہیں تو ہم انکار کرتے ہیں۔“' WHERE id = 6380;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، انہیں سعید بن مسیب نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب کسریٰ ( بادشاہ ایران ) ہلاک ہو جائے گا تو اس کے بعد کوئی کسریٰ نہیں پیدا ہو گا اور جب قیصر ( بادشاہ روم ) ہلاک ہو جائے گا تو اس کے بعد کوئی قیصر نہیں پیدا ہو گا اور اس ذات کی قسم جس کے ہاتھ میں میری جان ہے تم ان کے خزانے اللہ کے راستے میں خرچ کرو گے۔“' WHERE id = 6390;
UPDATE hadiths SET urdu = 'مجھ سے احمد بن عثمان نے بیان کیا، انہوں نے کہا ہم سے شریح بن مسلمہ نے بیان کیا، انہوں نے کہا ہم سے ابراہیم نے بیان کیا، ان سے ان کے والد نے بیان کیا، ان سے ابواسحاق نے، کہا کہ میں نے عمرو بن میمون سے سنا، کہا کہ مجھ سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ ایک موقع پر رسول اللہ صلی اللہ علیہ وسلم جب یمنی چمڑے کے خیمہ سے پشت لگائے ہوئے بیٹھے تھے تو آپ نے اپنے صحابہ سے فرمایا کیا تم اس پر خوش ہو کہ تم اہل جنت کے ایک چوتھائی رہو؟ انہوں نے عرض کیا، کیوں نہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کیا تم اس پر خوش نہیں ہو کہ تم اہل جنت کے ایک تہائی حصہ پاؤ۔ صحابہ نے عرض کیا کیوں نہیں۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا، پس اس ذات کی قسم جس کے ہاتھ میں میری جان ہے! مجھے امید ہے کہ جنت میں آدھے تم ہی ہو گے۔' WHERE id = 6401;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسعد نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، انہوں نے ایوب سے روایت کیا، انہوں نے ابوقلابہ سے، انہوں نے ثابت بن ضحاک سے، انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جو اسلام کے سوا کسی اور مذہب پر قسم کھائے پس وہ ایسا ہی ہے جیسی کہ اس نے قسم کھائی ہے اور جو شخص اپنے نفس کو کسی چیز سے ہلاک کرے وہ دوزخ میں اسی چیز سے عذاب دیا جاتا رہے گا اور مومن پر لعنت بھیجنا اس کو قتل کرنے کے برابر ہے اور جس نے کسی مومن پر کفر کا الزام لگایا پس وہ بھی اس کے قتل کرنے کے برابر ہے۔“' WHERE id = 6411;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، کہا ہم سے مسعر بن کدام نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، کہا ہم سے زرارہ بن اوفی نے بیان کیا، ان سے ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے کہ اللہ تعالیٰ نے میری امت کی ان غلطیوں کو معاف کیا ہے جن کا صرف دل میں وسوسہ گزرے یا دل میں اس کے کرنے کی خواہش پیدا ہو، مگر اس کے مطابق عمل نہ ہو اور نہ بات کی ہو۔' WHERE id = 6422;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے، ان سے اسود بن قیس نے کہا کہ میں نے جندب رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں اس وقت تک موجود تھا جب رسول اللہ صلی اللہ علیہ وسلم نے عید کی نماز پڑھائی پھر خطبہ دیا اور فرمایا کہ جس نے نماز سے پہلے ذبح کر لیا ہو اسے چاہئے کہ اس کی جگہ دوسرا جانور ذبح کرے اور جس نے ابھی ذبح نہ کیا ہو اسے چاہئے کہ اللہ کا نام لے کر جانور ذبح کرے۔' WHERE id = 6432;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو اسماعیل بن ابی خالد نے خبر دی، انہیں شعبی نے، انہیں عکرمہ نے اور انہیں ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کی بیوی صاحبہ سودہ رضی اللہ عنہا نے بیان کیا کہ ان کی ایک بکری مر گئی تو اس کے چمڑے کو ہم نے دباغت دے دیا۔ پھر ہم اس کی مشک میں نبیذ بناتے رہے یہاں تک کہ وہ پرانی ہو گئی۔' WHERE id = 6443;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے طلحہ بن عبدالملک نے، ان سے قاسم نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے اس کی نذر مانی ہو کہ اللہ کی اطاعت کرے گا تو اسے اطاعت کرنی چاہئے لیکن جس نے اللہ کی معصیت کی نذر مانی ہو اسے نہ کرنی چاہئے۔“' WHERE id = 6453;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے یزید بن ذریع نے بیان کیا، ان سے یونس نے، ان سے زیادہ بن جبیر نے بیان کیا کہ میں ابن عمر رضی اللہ عنہما کے ساتھ تھا ایک شخص نے ان سے پوچھا کہ میں نے نذر مانی ہے کہ ہر منگل یا بدھ کے دن روزہ رکھوں گا۔ اتفاق سے اسی دن کی بقر عید پڑ گئی ہے؟ ابن عمر رضی اللہ عنہما نے کہا کہ اللہ تعالیٰ نے نذر پوری کرنے کا حکم دیا ہے اور ہمیں بقر عید کے دن روزہ رکھنے کی ممانعت کی گئی ہے۔ اس شخص نے دوبارہ اپنا سوال دہرایا تو آپ نے پھر اس سے صرف اتنی ہی بات کہی اس پر کوئی زیادتی نہیں کی۔' WHERE id = 6463;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم کو حماد بن زید نے خبر دی، انہیں عمرو بن دینار نے اور ان سے جابر رضی اللہ عنہ نے کہ قبیلہ انصار کے ایک صاحب نے اپنے غلام کو مدبر بنا لیا اور ان کے پاس اس غلام کے سوا اور کوئی مال نہیں تھا۔ جب اس کی اطلاع نبی کریم صلی اللہ علیہ وسلم کو ملی تو آپ نے دریافت فرمایا کہ مجھ سے اس غلام کو کون خریدتا ہے۔ نعیم بن نحام رضی اللہ عنہ نے آٹھ سو درہم میں نبی کریم صلی اللہ علیہ وسلم سے اسے خرید لیا۔ میں نے جابر رضی اللہ عنہ کو یہ کہتے سنا کہ وہ ایک قبطی غلام تھا اور پہلے سال مر گیا۔ نبی کریم صلی اللہ علیہ وسلم نے اسے نیلام فرما کر اس رقم سے اسے مکمل آزاد کرا دیا۔' WHERE id = 6473;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے بیان کیا کہ مجھے مالک بن اوس بن حدثان نے خبر دی کہ محمد بن جبیر بن مطعم نے مجھ سے مالک بن اوس کی اس حدیث کا ایک حصہ ذکر کیا تھا۔ پھر میں خود مالک بن اوس کے پاس گیا اور ان سے یہ حدیث پوچھی تو انہوں نے بیان کیا کہ میں عمر رضی اللہ عنہ کی خدمت میں حاضر ہوا پھر ان کے حاجب یرفاء نے جا کر ان سے کہا کہ عثمان، عبدالرحمٰن بن زبیر اور سعد آپ کے پاس آنا چاہتے ہیں؟ انہوں نے کہا کہ اچھا آنے دو۔ چنانچہ انہیں اندر آنے کی اجازت دے دی۔ پھر کہا، کیا آپ علی و عباس رضی اللہ عنہما کو بھی آنے کی اجازت دیں گے؟ کہا کہ ہاں آنے دو۔ چنانچہ عباس رضی اللہ عنہ نے کہا کہ امیرالمؤمنین میرے اور علی رضی اللہ عنہ کے درمیان فیصلہ کر دیجئیے۔ عمر رضی اللہ عنہ نے کہا میں تمہیں اللہ کی قسم دیتا ہوں جس کے حکم سے آسمان و زمین قائم ہیں کیا تمہیں معلوم ہے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا کہ ہماری وراثت تقسیم نہیں ہوتی جو کچھ ہم چھوڑیں وہ سب راہ اللہ صدقہ ہے؟ اس سے مراد نبی کریم صلی اللہ علیہ وسلم کی خود اپنی ہی ذات تھی۔ جملہ حاضرین بولے کہ جی ہاں، نبی کریم صلی اللہ علیہ وسلم نے یہ ارشاد فرمایا تھا۔ پھر عمر، علی اور عباس رضی اللہ عنہما کی طرف متوجہ ہوئے اور پوچھا، کیا تمہیں معلوم ہے کہ نبی کریم صلی اللہ علیہ وسلم نے یہ فرمایا تھا؟ انہوں نے بھی تصدیق کی کہ نبی کریم صلی اللہ علیہ وسلم نے یہ ارشاد فرمایا تھا۔ عمر رضی اللہ عنہ نے فرمایا پھر میں اب آپ لوگوں سے اس معاملہ میں گفتگو کروں گا۔ اللہ تعالیٰ نے اس فے کے معاملہ میں نبی کریم صلی اللہ علیہ وسلم کے لیے کچھ حصے مخصوص کر دئیے جو آپ کے سوا کسی اور کو نہیں ملتا تھا۔ چنانچہ اللہ تعالیٰ نے فرمایا تھا «ما أفاء الله على رسوله‏» سے ارشاد «قدير‏» تک۔ یہ تو خاص نبی کریم صلی اللہ علیہ وسلم کا حصہ تھا۔ اللہ کی قسم! نبی کریم صلی اللہ علیہ وسلم نے اسے تمہارے لیے ہی مخصوص کیا تھا اور تمہارے سوا کسی کو اس پر ترجیح نہیں دی تھی، تمہیں کو اس میں سے دیتے تھے اور تقسیم کرتے تھے۔ آخر اس میں سے یہ مال باقی رہ گیا اور نبی کریم صلی اللہ علیہ وسلم اس میں سے اپنے گھر والوں کے لیے سال بھر کا خرچہ لیتے تھے، اس کے بعد جو کچھ باقی بچتا اسے ان مصارف میں خرچ کرتے جو اللہ کے مقرر کردہ ہیں۔ نبی کریم صلی اللہ علیہ وسلم کا یہ طرز عمل آپ کی زندگی بھر رہا۔ میں آپ کو اللہ کی قسم دے کر کہتا ہوں، کیا آپ لوگوں کو معلوم ہے؟ لوگوں نے کہا کہ جی ہاں۔ پھر آپ نے علی اور عباس رضی اللہ عنہما سے پوچھا، میں اللہ کی قسم دے کر پوچھتا ہوں کیا آپ لوگوں کو یہ معلوم ہے؟ انہوں نے بھی کہا کہ جی ہاں۔ پھر نبی کریم صلی اللہ علیہ وسلم کی وفات ہو گئی اور ابوبکر رضی اللہ عنہ نے کہا کہ اب میں نبی کریم صلی اللہ علیہ وسلم کا نائب ہوں چنانچہ انہوں نے اس پر قبضہ میں رکھ کر اس طرز عمل کو جاری رکھا جو نبی کریم صلی اللہ علیہ وسلم کا اس میں تھا۔ اللہ تعالیٰ نے ابوبکر رضی اللہ عنہ کو بھی وفات دی تو میں نے کہا کہ میں نبی کریم صلی اللہ علیہ وسلم کے نائب کا نائب ہوں۔ میں بھی دو سال سے اس پر قابض ہوں اور اس مال میں وہی کرتا ہوں جو رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ نے کیا۔ پھر آپ دونوں میرے پاس آئے ہو۔ آپ دونوں کی بات ایک ہے اور معاملہ بھی ایک ہی ہے۔ آپ ( عباس رضی اللہ عنہ ) میرے پاس اپنے بھتیجے کی میراث سے اپنا حصہ لینے آئے ہو اور آپ ( علی رضی اللہ عنہ ) اپنی بیوی کا حصہ لینے آئے ہو جو ان کے والد کی طرف سے انہیں ملتا۔ میں کہتا ہوں کہ اگر آپ دونوں چاہتے ہیں تو میں اسے آپ کو دے سکتا ہوں لیکن آپ لوگ اس کے سوا کوئی اور فیصلہ چاہتے ہیں تو اس ذات کی قسم جس کے حکم سے آسمان و زمین قائم ہیں، میں اس مال میں اس کے سوا اور کوئی فیصلہ نہیں کر سکتا، قیامت تک، اگر آپ اس کے مطابق عمل نہیں کر سکتے تو وہ جائیداد مجھے واپس کر دیجئیے میں اس کا بھی بندوبست کر لوں گا۔' WHERE id = 6484;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، انہوں نے کہا ہم سے عبدالوارث نے بیان کیا، انہوں نے کہا ہم سے ایوب نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے جو یہ فرمایا ہے کہ اگر میں اس امت کے کسی آدمی کو خلیل بناتا تو ان کو ( ابوبکر رضی اللہ عنہ کو ) کو خلیل بناتا، لیکن اسلام کا تعلق ہی سب سے بہتر ہے تو اس میں نبی کریم صلی اللہ علیہ وسلم نے دادا کو باپ کے درجہ میں رکھا ہے۔' WHERE id = 6494;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن قزعہ نے بیان کیا، کہا ہم سے مالک نے بیان کیا، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ ایک شخص نے اپنی بیوی سے نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں لعان کیا اور اس کے بچہ کو اپنا بچہ ماننے سے انکار کر دیا تو نبی کریم صلی اللہ علیہ وسلم نے دونوں کے درمیان جدائی کرا دی اور بچہ عورت کو دے دیا۔' WHERE id = 6504;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، کہا ہم کو جریر نے خبر دی، انہیں منصور نے، انہیں ابراہیم نے، انہیں اسود نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے بریرہ کو خریدنا چاہا تو ان کے مالکوں نے شرط لگائی کہ ولاء ان کے ساتھ قائم ہو گی۔ میں نے اس کا تذکرہ نبی کریم صلی اللہ علیہ وسلم سے کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ انہیں آزاد کر دو، ولاء قیمت ادا کرنے والے ہی کے ساتھ قائم ہوتی ہے۔ بیان کیا کہ پھر میں نے آزاد کر دیا۔ پھر انہیں نبی کریم صلی اللہ علیہ وسلم نے بلایا اور ان کے شوہر کے معاملہ میں اختیار دیا۔ انہوں نے کہا کہ اگر مجھے یہ یہ چیزیں بھی وہ دیدے تو میں اس کے ساتھ رات گزارنے کے لیے تیار نہیں۔ چنانچہ اس نے شوہر سے علیحدگی کو پسند کیا۔' WHERE id = 6514;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم میرے یہاں ایک مرتبہ بہت خوش خوش تشریف لائے۔ آپ صلی اللہ علیہ وسلم کا چہرہ چمک رہا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم نے نہیں دیکھا، مجزز ( ایک قیافہ شناس ) نے ابھی ابھی زید بن حارثہ اور اسامہ بن زید رضی اللہ عنہما کے ( صرف پاؤں دیکھے ) اور کہا کہ یہ پاؤں ایک دوسرے سے تعلق رکھتے ہیں۔“' WHERE id = 6525;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ مجھ سے لیث نے بیان کیا، کہا کہ مجھ سے خالد بن یزید نے بیان کیا، ان سے سعید بن ابی ہلال نے، ان سے زید بن اسلم نے، ان سے ان کے والد نے اور ان سے عمر بن خطاب رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں ایک شخص، جس کا نام عبداللہ تھا اور «حمار» کے لقب سے پکارے جاتے تھے، وہ نبی کریم صلی اللہ علیہ وسلم کو ہنساتے تھے اور نبی کریم صلی اللہ علیہ وسلم نے انہیں شراب پینے پر مارا تھا تو انہیں ایک دن لایا گیا اور نبی کریم صلی اللہ علیہ وسلم نے ان کے لیے حکم دیا اور انہیں مارا گیا۔ حاضرین میں ایک صاحب نے کہا: اللہ اس پر لعنت کرے! کتنی مرتبہ کہا جا چکا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس پر لعنت نہ کرو واللہ میں نے اس کے متعلق یہی جانا ہے کہ یہ اللہ اور اس کے رسول سے محبت کرتا ہے۔' WHERE id = 6535;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، ان سے ابن وہب نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے، ان سے عروہ بن زبیر نے، ان سے عمرہ نے اور ان سے ام المؤمنین عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”چور کا ہاتھ ایک چوتھائی دینار پر کاٹ لیا جائے گا۔“' WHERE id = 6545;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، کہا کہ مجھ سے ابن وہب نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک عورت کا ہاتھ کٹوایا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ وہ عورت بعد میں بھی آتی تھی اور میں اس کی ضرورتیں نبی کریم صلی اللہ علیہ وسلم کے سامنے رکھتی تھی , اس عورت نے توبہ کر لی تھی اور حسن توبہ کا ثبوت دیا تھا۔' WHERE id = 6555;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے ذکوان نے بیان کیا، اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”زنا کرنے والا جب زنا کرتا ہے تو وہ مومن نہیں رہتا، وہ چور جب چوری کرتا ہے تو وہ مومن نہیں رہتا، شرابی جب شراب پیتا ہے تو وہ مومن نہیں رہتا۔ پھر ان سب آدمیوں کے لیے توبہ کا دروازہ بہرحال کھلا ہوا ہے۔“' WHERE id = 6565;
UPDATE hadiths SET urdu = 'اور لیث نے بیان کیا، ان سے عمرو بن الحارث نے، ان سے عبدالرحمٰن بن القاسم نے، ان سے محمد بن جعفر بن زبیر نے، ان سے عباد بن عبداللہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ایک صاحب نبی کریم صلی اللہ علیہ وسلم کے پاس مسجد میں آئے اور عرض کیا میں تو دوزخ کا مستحق ہو گیا۔ نبی کریم صلی اللہ علیہ وسلم نے پوچھا کیا بات ہوئی؟ کہا کہ میں نے اپنی بیوی سے رمضان میں جماع کر لیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے کہا کہ پھر صدقہ کر۔ انہوں نے کہا کہ میرے پاس کچھ بھی نہیں۔ پھر وہ بیٹھ گیا اور اس کے بعد ایک صاحب گدھا ہانکتے لائے جس پر کھانے کی چیز رکھی تھی۔ عبدالرحمٰن نے بیان کیا کہ مجھے معلوم نہیں کہ وہ کیا چیز تھی۔ ( دوسری روایت میں یوں ہے کہ کھجور لدی ہوئی تھی ) اسے نبی کریم صلی اللہ علیہ وسلم کے پاس لایا جا رہا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے پوچھا کہ آگ میں جلنے والے صاحب کہاں ہیں؟ وہ صاحب بولے کہ میں حاضر ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے لے اور صدقہ کر دے۔ انہوں نے پوچھا کیا اپنے سے زیادہ محتاج کو دوں؟ میرے گھر والوں کے لیے تو خود کوئی کھانے کی چیز نہیں ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر تم ہی کھا لو۔ عبداللہ امام بخاری رحمہ اللہ نے کہا کہ پہلی حدیث زیادہ واضح ہے جس میں «أطعم أهلك» کے الفاظ ہیں۔' WHERE id = 6576;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا مجھ سے امام مالک نے بیان کیا، ان سے عبدالرحمٰن بن القاسم نے بیان کیا، ان سے ان کے والد (قاسم بن محمد) نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ابوبکر رضی اللہ عنہ نے کہا تمہاری وجہ سے نبی کریم صلی اللہ علیہ وسلم اور سب لوگوں کو رکنا پڑا جبکہ یہاں پانی بھی نہیں ہے۔ چنانچہ وہ مجھ پر سخت ناراض ہوئے اور اپنے ہاتھ سے میری کوکھ میں مکا مارنے لگے مگر میں نے اپنے جسم میں کسی قسم کی حرکت اس لیے نہیں ہونے دی کہ نبی کریم صلی اللہ علیہ وسلم آرام فرما رہے تھے۔ پھر اللہ تعالیٰ نے تیمم کی آیت نازل کی۔' WHERE id = 6592;
UPDATE hadiths SET urdu = 'ہم سے علی نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے زہری نے بیان کیا اور ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ میں نے دو لعان کرنے والے میاں بیوی کو دیکھا تھا۔ اس وقت میری عمر پندرہ سال تھی۔ نبی کریم صلی اللہ علیہ وسلم نے دونوں کے درمیان جدائی کرا دی تھی۔ شوہر نے کہا تھا کہ اگر اب بھی میں ( اپنی بیوی کو ) اپنے ساتھ رکھوں تو اس کا مطلب یہ ہے کہ میں جھوٹا ہوں۔ سفیان نے بیان کیا کہ میں نے زہری سے یہ روایت محفوظ رکھی ہے کہ ”اگر اس عورت کے ایسا بچہ پیدا ہوا تو شوہر سچا ہے اور اگر اس کے ایسا ایسا بچہ پیدا ہوا جیسے چھپکلی ہوتی ہے تو شوہر جھوٹا ہے۔“ اور میں نے زہری سے سنا، انہوں نے بیان کیا کہ اس عورت نے اس آدمی کے ہم شکل بچہ جنا جو میری طرح کا تھا۔' WHERE id = 6602;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہیں واقد بن عبداللہ نے خبر دی، انہوں نے کہا مجھ کو میرے والد نے اور انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میرے بعد کافر نہ بن جانا کہ تم میں سے بعض بعض کی گردن مارنے لگ جاؤ۔“' WHERE id = 6614;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا، کہا ہم سے میرے والد نے بیان کیا، انہوں نے کہا ہم سے اعمش نے بیان کیا، ان سے عبداللہ بن مرہ نے بیان کیا، ان سے مسروق نے بیان کیا اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کسی مسلمان کا خون جو کلمہ لا الہٰ الا اللہ محمد رسول اللہ کا ماننے والا ہو حلال نہیں ہے البتہ تین صورتوں میں جائز ہے۔ جان کے بدلہ جان لینے والا، شادی شدہ ہو کر زنا کرنے والا اور اسلام سے نکل جانے والا ( مرتد ) جماعت کو چھوڑ دینے والا۔“' WHERE id = 6624;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے حمید نے کہ ایک صاحب نبی کریم صلی اللہ علیہ وسلم کے گھر میں جھانک رہے تھے تو نبی کریم صلی اللہ علیہ وسلم نے ان کی طرف تیر کا پھل بڑھایا تھا۔ میں نے پوچھا کہ یہ حدیث تم سے کس نے بیان کی ہے؟ تو انہوں نے بیان کیا انس بن مالک رضی اللہ عنہ نے۔' WHERE id = 6634;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے ابوبشر اسماعیل بن ابراہیم الاسدی نے بیان کیا، کہا ہم سے حجاج بن ابی عثمان نے بیان کیا، ان سے آل ابوقلابہ کے غلام ابورجاء نے بیان کیا اس نے کہا کہ مجھ سے ابوقلابہ نے بیان کیا کہ عمر بن عبدالعزیز نے ایک دن دربار عام کیا اور سب کو اجازت دی۔ لوگ داخل ہوئے تو انہوں نے پوچھا: قسامہ کے بارے میں تمہارا کیا خیال ہے؟ کسی نے کہا کہ قسامہ کے ذریعہ قصاص لینا حق ہے اور خلفاء نے اس کے ذریعہ قصاص لیا ہے۔ اس پر انہوں نے مجھ سے پوچھا: ابوقلابہ! تمہاری کیا رائے ہے؟ اور مجھے عوام کے ساتھ لا کھڑا کر دیا۔ میں نے عرض کیا: یا امیرالمؤمنین! آپ کے پاس عرب کے سردار اور شریف لوگ رہتے ہیں آپ کی کیا رائے ہو گی اگر ان میں سے پچاس آدمی کسی دمشقی کے شادی شدہ شخص کے بارے میں زنا کی گواہی دیں جبکہ ان لوگوں نے اس شخص کو دیکھا بھی نہ ہو کیا آپ ان کی گواہی پر اس شخص کو رجم کر دیں گے۔ امیرالمؤمنین نے فرمایا کہ نہیں۔ پھر میں نے کہا کہ آپ کا کیا خیال ہے اگر انہیں ( اشراف عرب ) میں سے پچاس افراد حمص کے کسی شخص کے متعلق چوری کی گواہی دے دیں اس کو بغیر دیکھے تو کیا آپ اس کا ہاتھ کاٹ دیں گے؟ فرمایا کہ نہیں۔ پھر میں نے کہا، پس اللہ کی قسم کہ رسول اللہ صلی اللہ علیہ وسلم نے کبھی کسی کو تین حالتوں کے سوا قتل نہیں کرایا۔ ایک وہ شخص جس نے کسی کو ظلماً قتل کیا ہو اور اس کے بدلے میں قتل کیا گیا ہو۔ دوسرا وہ شخص جس نے شادی کے بعد زنا کیا ہو۔ تیسرا وہ شخص جس نے اللہ اور اس کے رسول سے جنگ کی ہو اور اسلام سے پھر گیا ہو۔ لوگوں نے اس پر کہا، کیا انس بن مالک رضی اللہ عنہ نے یہ حدیث نہیں بیان کی ہے کہ نبی کریم صلی اللہ علیہ وسلم نے چوری کے معاملہ میں ہاتھ پیر کاٹ دئیے تھے اور آنکھوں میں سلائی پھروائی تھی اور پھر انہیں دھوپ میں ڈلوا دیا تھا۔ میں نے کہا کہ میں آپ لوگوں کو انس بن مالک رضی اللہ عنہ کی حدیث سناتا ہوں۔ مجھ سے انس رضی اللہ عنہ نے بیان کیا کہ قبیلہ عکل کے آٹھ افراد نبی کریم صلی اللہ علیہ وسلم کے پاس آئے اور آپ سے اسلام پر بیعت کی، پھر مدینہ منورہ کی آب و ہوا انہیں ناموافق ہوئی اور وہ بیمار پڑ گئے تو انہوں نے نبی کریم صلی اللہ علیہ وسلم سے اس کی شکایت کی۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ پھر کیوں نہیں تم ہمارے چرواہے کے ساتھ اس کے اونٹوں میں چلے جاتے اور اونٹوں کا دودھ اور ان کا پیشاب پیتے۔ انہوں نے عرض کیا کیوں نہیں۔ چنانچہ وہ نکل گئے اور اونٹوں کا دودھ اور پیشاب پیا اور صحت مند ہو گئے۔ پھر انہوں نے نبی کریم صلی اللہ علیہ وسلم کے چرواہے کو قتل کر دیا اور اونٹ ہنکا لے گئے۔ اس کی اطلاع جب نبی کریم صلی اللہ علیہ وسلم کو پہنچی تو آپ نے ان کی تلاش میں آدمی بھیجے، پھر وہ پکڑے گئے اور لائے گئے۔ نبی کریم صلی اللہ علیہ وسلم نے حکم دیا اور ان کے بھی ہاتھ اور پاؤں کاٹ دئیے گئے اور ان کی آنکھوں میں سلائی پھیر دی گئی پھر انہیں دھوپ میں ڈلوا دیا اور آخر وہ مر گئے۔ میں نے کہا کہ ان کے عمل سے بڑھ کر اور کیا جرم ہو سکتا ہے اسلام سے پھر گئے اور قتل کیا اور چوری کی۔ عنبہ بن سعید نے کہا میں نے آج جیسی بات کبھی نہیں سنی تھی۔ میں نے کہا: عنبہ! کیا تم میری حدیث رد کرتے ہو؟ انہوں نے کہا کہ نہیں آپ نے یہ حدیث واقعہ کے مطابق بیان کر دی ہے۔ واللہ! اہل شام کے ساتھ اس وقت تک خیر و بھلائی رہے گی جب تک یہ شیخ ( ابوقلابہ ) ان میں موجود رہیں گے۔ میں نے کہا کہ اس قسامہ کے سلسلہ میں نبی کریم صلی اللہ علیہ وسلم کی ایک سنت ہے۔ انصار کے کچھ لوگ آپ کے پاس آئے اور نبی کریم صلی اللہ علیہ وسلم سے بات کی پھر ان میں سے ایک صاحب ان کے سامنے ہی نکلے ( خیبر کے ارادہ سے ) اور وہاں قتل کر دئیے گئے۔ اس کے بعد دوسرے صحابہ بھی گئے اور دیکھا کہ ان کے ساتھ خون میں تڑپ رہے ہیں۔ ان لوگوں نے واپس آ کر آپ صلی اللہ علیہ وسلم کو اس کی اطلاع دی اور کہا: یا رسول اللہ! ہمارے ساتھ گفتگو کر رہے تھے اور اچانک وہ ہمیں ( خیبر میں ) خون میں تڑپتے ملے۔ پھر نبی کریم صلی اللہ علیہ وسلم نکلے اور پوچھا کہ تمہارا کس پر شبہ ہے کہ انہوں نے ان کو قتل کیا ہے۔ صحابہ نے کہا کہ ہم سمجھتے ہیں کہ یہودیوں نے ہی قتل کیا ہے پھر آپ نے یہودیوں کو بلا بھیجا اور ان سے پوچھا کیا تم نے انہیں قتل کیا ہے؟ انہوں نے انکار کر دیا تو آپ نے فرمایا، کیا تم مان جاؤ گے اگر پچاس یہودی اس کی قسم لیں کہ انہوں نے مقتول کو قتل نہیں کیا ہے۔ صحابہ نے عرض کیا: یہ لوگ ذرا بھی پرواہ نہیں کریں گے کہ ہم سب کو قتل کرنے کے بعد پھر قسم کھا لیں ( کہ قتل انہوں نے نہیں کیا ہے ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا تو پھر تم میں سے پچاس آدمی قسم کھا لیں اور خون بہا کے مستحق ہو جائیں۔ صحابہ نے عرض کیا: ہم بھی قسم کھانے کے لیے تیار نہیں ہیں۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے انہیں اپنے پاس سے خون بہا دیا ( ابوقلابہ نے کہا کہ ) میں نے کہا کہ زمانہ جاہلیت میں قبیلہ ہذیل کے لوگوں نے اپنے ایک آدمی کو اپنے میں سے نکال دیا تھا پھر وہ شخص بطحاء میں یمن کے ایک شخص کے گھر رات کو آیا۔ اتنے میں ان میں سے کوئی شخص بیدار ہو گیا اور اس نے اس پر تلوار سے حملہ کر کے قتل کر دیا۔ اس کے بعد ہذیل کے لوگ آئے اور انہوں نے یمنی کو ( جس نے قتل کیا تھا ) پکڑا کہ عمر رضی اللہ عنہ کے پاس لے گئے حج کے زمانہ میں اور کہا کہ اس نے ہمارے آدمی کو قتل کر دیا ہے۔ یمنی نے کہا کہ انہوں نے اسے اپنی برادری سے نکال دیا تھا۔ عمر رضی اللہ عنہ نے فرمایا کہ اب ہذیل کے پچاس آدمی اس کی قسم کھائیں کہ انہوں نے اسے نکالا نہیں تھا۔ بیان کیا کہ پھر ان میں سے انچاس آدمیوں نے قسم کھائی پھر انہیں کے قبیلہ کا ایک شخص شام سے آیا تو انہوں نے اس سے بھی مطالبہ کیا کہ وہ قسم کھائے لیکن اس نے اپنی قسم کے بدلہ میں ایک ہزار درہم دے کر اپنا پیچھا قسم سے چھڑا لیا۔ ہذلیوں نے اس کی جگہ ایک دوسرے آدمی کو تیار کر لیا پھر وہ مقتول کے بھائی کے پاس گیا اور اپنا ہاتھ اس کے ہاتھ سے ملایا۔ انہوں نے بیان کیا کہ پھر ہم پچاس جنہوں نے قسم کھائی تھی روانہ ہوئے۔ جب مقام نخلہ پر پہنچے تو بارش نے انہیں آیا۔ سب لوگ پہاڑ کے ایک غار میں گھس گئے اور غار ان پچاسوں کے اوپر گر پڑا۔ جنہوں نے قسم کھائی تھی اور سب کے سب مر گئے۔ البتہ دونوں ہاتھ ملانے والے بچ گئے۔ لیکن ان کے پیچھے سے ایک پتھر لڑھک کر گرا اور اس سے مقتول کے بھائی کی ٹانگ ٹوٹ گئی اس کے بعد وہ ایک سال اور زندہ رہا پھر مر گیا۔ میں نے کہا کہ عبدالملک بن مروان نے قسامہ پر ایک شخص سے قصاص لی تھی پھر اسے اپنے کئے ہوئے پر ندامت ہوئی اور اس نے ان پچاسوں کے متعلق جنہوں نے قسم کھائی تھی حکم دیا اور ان کے نام رجسٹر سے کاٹ دئیے گئے پھر انہوں نے شام بھیج دیا۔' WHERE id = 6645;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، انہوں نے کہا ہم سے ابن شہاب نے بیان کیا، ان سے سعید بن مسیب اور ابوسلمہ بن عبدالرحمٰن نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”چوپائے اگر کسی کو زخمی کر دیں تو ان کا خون بہا نہیں، کنویں میں گرنے کا کوئی خون بہا نہیں، کان میں دبنے کا کوئی خون بہا نہیں اور دفینہ میں پانچواں حصہ ہے۔“' WHERE id = 6657;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان محمد بن فضل سدوسی نے بیان کیا، کہا ہم سے حماد بن زید نے، انہوں نے ایوب سختیانی سے، انہوں نے عکرمہ سے، انہوں نے کہا علی رضی اللہ عنہ کے پاس کچھ بےدین لوگ لائے گئے۔ آپ نے ان کو جلوا دیا۔ یہ خبر ابن عباس رضی اللہ عنہما کو پہنچی تو انہوں نے کہا اگر میں حاکم ہوتا تو ان کو کبھی نہ جلواتا ( دوسری طرح سے سزا دیتا ) کیونکہ نبی کریم صلی اللہ علیہ وسلم نے آگ میں جلانے سے منع فرمایا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ آگ اللہ کا عذاب ہے تم اللہ کے عذاب سے کسی کو مت عذاب دو میں ان کو قتل کروا ڈالتا کیونکہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ہے جو شخص اپنا دین بدل ڈالے اسلام سے پھر جائے اس کو قتل کر ڈالو۔' WHERE id = 6667;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے عبدالواحد بن زیادہ نے، کہا ہم سے سلمان شیبانی نے، کہا ہم سے یسیر بن عمرو نے بیان کیا کہ میں نے سہل بن حنیف ( بدری صحابی ) رضی اللہ عنہ سے پوچھا کیا تم نے نبی کریم صلی اللہ علیہ وسلم کو خوارج کے سلسلے میں کچھ فرماتے ہوئے سنا ہے، انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو یہ کہتے ہوئے سنا ہے اور آپ نے عراق کی طرف ہاتھ سے اشارہ فرمایا تھا کہ ادھر سے ایک جماعت نکلے گی یہ لوگ قرآن مجید پڑھیں گے لیکن قرآن مجید ان کے حلقوں سے نیچے نہیں اترے گا۔ وہ اسلام سے اس طرح باہر ہو جائیں گے جیسے تیر شکار کے جانور سے باہر نکل جاتا ہے۔' WHERE id = 6678;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، ان سے سعید مقبری نے بیان کیا، ان سے ان کے والد نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ہم مسجد میں تھے کہ رسول اللہ صلی اللہ علیہ وسلم ہمارے پاس تشریف لائے اور فرمایا کہ یہودیوں کے پاس چلو۔ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ روانہ ہوئے اور جب ہم بیت المدراس کے پاس پہنچے تو نبی کریم صلی اللہ علیہ وسلم نے انہیں آواز دی اے قوم یہود! اسلام لاؤ تم محفوظ ہو جاؤ گے۔ یہودیوں نے کہا: ابوالقاسم! آپ نے پہنچا دیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میرا بھی یہی مقصد ہے پھر آپ صلی اللہ علیہ وسلم نے دوبارہ یہی فرمایا اور یہودیوں نے کہا کہ ابوالقاسم آپ نے پہنچا دیا نبی کریم صلی اللہ علیہ وسلم نے تیسری مرتبہ یہی فرمایا۔ اور پھر فرمایا تمہیں معلوم ہونا چاہئے کہ زمین اللہ اور اس کے رسول کی ہے اور میں تمہیں جلا وطن کرتا ہوں۔ پس تم میں سے جس کے پاس مال ہو اسے چاہئے کہ جلا وطن ہونے سے پہلے اسے بیچ دے ورنہ جان لو کہ زمین اللہ اور اس کے رسول کی ہے۔' WHERE id = 6688;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، ان سے معمر نے، ان سے ہمام نے، ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ تم میں سے کسی ایسے شخص کی نماز قبول نہیں کرتا جسے وضو کی ضرورت ہو یہاں تک کہ وہ وضو کر لے۔“' WHERE id = 6698;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے عبداللہ بن دینار نے، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا، کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ہر دھوکہ دینے والے کے لیے قیامت کے دن ایک جھنڈا ہو گا جس کے ذریعہ وہ پہچانا جائے گا۔“' WHERE id = 6709;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا ‘ انہوں نے کہا ہم سے ہشام بن یوسف نے بیان کیا ‘ انہوں نے کہا ہم کو معمر نے خبر دی ‘ انہیں زہری نے ‘ انہیں ابوسلمہ نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے شفعہ کا حکم ہر اس چیز میں دیا تھا جو تقسیم نہ ہو سکتی ہو۔ پس جب حد بندی ہو جائے اور راستے الگ الگ کر دئیے جائیں تو پھر شفعہ نہیں۔ اور بعض لوگ کہتے ہیں کہ شفعہ کا حق پڑوسی کو بھی ہوتا ہے پھر خود ہی اپنی بات کو غلط قرار دیا اور کہا کہ اگر کسی نے کوئی گھر خریدا اور اسے خطرہ ہے کہ اس کا پڑوسی حق شفعہ کی بنا پر اس سے گھر لے لے گا تو اس نے اس کے سو حصے کر کے ایک حصہ اس میں سے پہلے خرید لیا اور باقی حصے بعد میں خریدے تو ایسی صورت میں پہلے حصے میں تو پڑوسی کو شفعہ کا حق ہو گا۔ گھر کے باقی حصوں میں اسے یہ حق نہیں ہو گا اور اس کے لیے جائز ہے کہ یہ حیلہ کرے۔' WHERE id = 6719;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے عبداللہ بن یحییٰ بن ابی کثیر نے بیان کیا اور ان کی تعریف کی کہ میں نے ان سے یمامہ میں ملاقات کی تھی، ان سے ان کے والد نے، ان سے ابوسلمہ رضی اللہ عنہ اور ان سے ابوقتادہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اچھا خواب اللہ کی طرف سے ہوتا ہے اور برا خواب شیطان کی طرف سے پس اگر کوئی برا خواب دیکھے تو اسے اس سے اللہ کی پناہ مانگنی چاہئیے اور بائیں طرف تھوکنا چاہئیے یہ خواب اسے کوئی نقصان نہیں پہنچا سکے گا“ اور عبداللہ بن یحییٰ سے ان کے والد نے اور ان سے عبداللہ بن ابی قتادہ نے بیان کیا اور ان سے ان کے والد نے نبی کریم صلی اللہ علیہ وسلم سے اسی طرح بیان کیا۔' WHERE id = 6729;
UPDATE hadiths SET urdu = 'ہم سے خالد بن خلی نے بیان کیا، انہوں نے کہا ہم سے محمد بن حرب نے بیان کیا، انہوں نے کہا مجھ سے زبیدی نے بیان کیا، ان سے زہری نے بیان کیا، ان سے ابوسلمہ رضی اللہ عنہ نے اور ان سے ابوقتادہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے مجھے دیکھا اس نے حق دیکھا۔“ اس روایت کی متابعت یونس نے اور زہری کے بھتیجے نے کی۔' WHERE id = 6739;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، ان سے یعقوب بن ابراہیم نے بیان کیا، کہا ان سے میرے والد ابراہیم بن سعد نے بیان کیا، ان سے صالح نے، ان سے ابن شہاب نے، ان سے حمزہ بن عبداللہ بن عمر نے بیان کیا اور انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، میں سویا ہوا تھا کہ میرے پاس دودھ کا ایک پیالہ لایا گیا اور میں نے اس میں سے پیا، یہاں تک کہ میں نے سیرابی کا اثر اپنے اطراف میں نمایاں دیکھا۔ پھر میں نے اس کا بچا ہوا عمر بن خطاب رضی اللہ عنہ کو دیا جو صحابہ وہاں موجود تھے، انہوں نے پوچھا کہ یا رسول اللہ! آپ نے اس کی تعبیر کیا کی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ علم مراد ہے۔' WHERE id = 6749;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم بن کثیر نے بیان کیا، کہا ہم سے شعیب بن حرب نے بیان کیا، کہا ہم سے صخر بن جویریہ نے بیان کیا، کہا ہم سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ” ( خواب میں ) میں ایک کنویں سے پانی کھینچ رہا تھا کہ ابوبکر اور عمر بھی آ گئے۔ اب ابوبکر نے ڈول لے لیا اور ایک یا دو ڈول پانی کھینچا۔ ان کے کھینچنے میں کمزوری تھی۔ اللہ تعالیٰ ان کی مغفرت کرے آمین۔ اس کے بعد عمر بن خطاب نے اسے ابوبکر کے ہاتھ سے لے لیا اور وہ ڈول ان کے ہاتھ میں بڑا ڈول بن گیا۔ میں نے عمر جیسا پانی کھینچنے میں کسی کو ماہر نہیں دیکھا۔ انہوں نے خوب پانی نکالا یہاں تک کہ لوگوں نے اونٹوں کے لیے پانی سے حوض بھر لیے۔“' WHERE id = 6760;
UPDATE hadiths SET urdu = 'مجھ سے سعید بن محمد نے بیان کیا، انہوں نے کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے ہمارے والد نے بیان کیا، ان سے صالح نے، ان سے ابوعبیدہ بن نشیط نے بیان کیا، ان سے عبیداللہ بن عبداللہ نے بیان کیا کہ میں نے عبداللہ بن عباس رضی اللہ عنہما سے نبی کریم صلی اللہ علیہ وسلم کے اس خواب کے متعلق پوچھا جو انہوں نے بیان کیا تھا۔' WHERE id = 6772;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ربیع نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے عبدربہ بن سعید نے بیان کیا، انہوں نے کہا کہ میں نے ابوسلمہ سے سنا، انہوں نے کہا کہ میں ( برے ) خواب دیکھتا تھا اور اس کی وجہ سے بیمار پڑ جاتا تھا۔ آخر میں نے قتادہ رضی اللہ عنہ سے سنا انہوں نے بیان کیا کہ میں بھی خواب دیکھتا اور میں بھی بیمار پڑ جاتا۔ آخر میں نے نبی کریم صلی اللہ علیہ وسلم کو یہ فرماتے سنا کہ اچھے خواب اللہ کی طرف سے ہوتے ہیں پس جب کوئی اچھے خواب دیکھے تو اس کا ذکر صرف اسی سے کرے جو اسے عزیز ہو اور جب برا خواب دیکھے تو اللہ کی اس کے شر سے پناہ مانگے اور شیطان کے شر سے اور تین مرتبہ تھوتھو کر دے اور اس کا کسی سے ذکر نہ کرے پس وہ اسے ہرگز کوئی نقصان نہ پہنچا سکے گا۔' WHERE id = 6782;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے عمرو بن یحییٰ بن سعید نے بیان کیا، انہوں نے کہا کہ مجھے میرے دادا سعید نے خبر دی، کہا کہ میں ابوہریرہ رضی اللہ عنہ کے پاس مدینہ منورہ میں نبی کریم صلی اللہ علیہ وسلم کی مسجد میں بیٹھا تھا اور ہمارے ساتھ مروان بھی تھا۔ ابوہریرہ رضی اللہ عنہ نے کہا کہ میں نے صادق و مصدوق سے سنا ہے آپ صلی اللہ علیہ وسلم نے فرمایا کہ میری امت کی تباہی قریش کے چند لڑکوں کے ہاتھ سے ہو گی۔ مروان نے اس پر کہا ان پر اللہ کی لعنت ہو۔ ابوہریرہ رضی اللہ عنہ نے کہا کہ اگر میں ان کے خاندان کے نام لے کر بتلانا چاہوں تو بتلا سکتا ہوں۔ پھر جب بنی مروان شام کی حکومت پر قابض ہو گئے تو میں اپنے دادا کے ساتھ ان کی طرف جاتا تھا۔ جب وہاں انہوں نے نوجوان لڑکوں کو دیکھا تو کہا کہ شاید یہ انہی میں سے ہوں۔ ہم نے کہا کہ آپ کو زیادہ علم ہے۔' WHERE id = 6795;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہیں امام مالک نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس نے ہم مسلمانوں پر ہتھیار اٹھایا وہ ہم سے نہیں ہے۔“' WHERE id = 6806;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا ہم سے علی بن مدرک نے بیان کیا، کہا میں نے ابوزرعہ بن عمرو بن جریر سے سنا، ان سے ان کے دادا جریر رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھ سے حجۃ الوداع کے موقع پر فرمایا کہ لوگوں کو خاموش کر دو۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا ”میرے بعد کافر نہ ہو جانا کہ تم ایک دوسرے کی گردن مارنے لگ جاؤ۔“' WHERE id = 6816;
UPDATE hadiths SET urdu = 'اور عباس النرسی نے بیان کیا، ان سے یزید بن زریع نے بیان کیا، ان سے سعید نے بیان کیا، ان سے قتادہ نے بیان کیا اور ان سے انس رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے یہی حدیث بیان کی اور انس رضی اللہ عنہ نے کہا ہر شخص کپڑے میں اپنا سر لپیٹے ہوئے رو رہا تھا اور فتنے سے اللہ کی پناہ مانگ رہا تھا یا یوں کہہ رہا تھا کہ میں اللہ سے فتنہ کی برائی سے پناہ مانگتا ہوں۔' WHERE id = 6826;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن آدم نے بیان کیا، انہوں نے کہا ہم سے ابوبکر بن عیاش نے بیان کیا، انہوں نے کہا ہم سے ابوحصین نے بیان کیا، انہوں نے کہا ہم سے ابومریم عبداللہ بن زیاد الاسدی نے بیان کیا کہ ہم سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن آدم نے بیان کیا، انہوں نے کہا ہم سے ابوبکر بن عیاش نے بیان کیا، انہوں نے کہا ہم سے ابوحصین نے بیان کیا، انہوں نے کہا ہم سے ابومریم عبداللہ بن زیاد الاسدی نے بیان کیا کہ جب طلحہ، زبیر اور عائشہ رضی اللہ عنہم بصرہ کی طرف روانہ ہوئے تو علی رضی اللہ عنہ نے عمار بن یاسر اور حسن بن علی رضی اللہ عنہما کو بھیجا۔ یہ دونوں بزرگ ہمارے پاس کوفہ آئے اور منبر پر چڑھے۔ حسن بن علی رضی اللہ عنہما منبر کے اوپر سب سے اونچی جگہ تھے اور عمار بن یاسر رضی اللہ عنہما ان سے نیچے تھے۔ پھر ہم ان کے پاس جمع ہو گئے اور میں نے عمار رضی اللہ عنہ کو یہ کہتے سنا کہ عائشہ رضی اللہ عنہا بصرہ گئی ہیں اور اللہ کی قسم وہ دنیا و آخرت میں تمہارے نبی کریم صلی اللہ علیہ وسلم کی پاک بیوی ہیں لیکن اللہ تبارک و تعالیٰ نے تمہیں آزمایا ہے تاکہ جان لے کہ تم اس اللہ کی اطاعت کرتے ہو یا عائشہ رضی اللہ عنہا کی۔' WHERE id = 6836;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، ان سے سعید بن مسیب نے بیان کیا اور انہیں ابوہریرہ رضی اللہ عنہ نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ قیامت قائم نہیں ہو گی یہاں تک کہ قبیلہ دوس کی عورتوں کا ذوالخلصہ کا ( طواف کرتے ہوئے ) چوتڑ سے چوتڑ چھلے اور ذوالخلصہ قبیلہ دوس کا بت تھا جس کو وہ زمانہ جاہلیت میں پوجا کرتے تھے۔' WHERE id = 6848;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے محمد بن بشر نے بیان کیا، کہا ہم سے مسعر نے بیان کیا، ان سے سعد بن ابراہیم نے بیان کیا، ان سے ان کے والد نے اور ان سے ابوبکرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”مدینہ پر مسیح دجال کا رعب نہیں پڑے گا۔ اس وقت اس کے سات دروازے ہوں گے اور ہر دروازے پر پہرہ دار دو فرشتے ہوں گے۔“ علی بن عبداللہ نے کہا کہ محمد بن اسحاق نے صالح بن ابراہیم سے روایت کیا، ان سے ان کے والد ابراہیم بن عبدالرحمٰن بن عوف نے بیان کیا کہ میں بصرہ گیا تو مجھ سے ابوبکرہ رضی اللہ عنہ نے یہی حدیث بیان کی۔' WHERE id = 6858;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے وہیب بن خالد نے بیان کیا، ان سے عبداللہ بن طاؤس نے بیان کیا، ان سے ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ” «سد» یعنی یاجوج ماجوج کی دیوار اتنی کھل گئی ہے۔“ وہیب نے نوے کا اشارہ کر کے بتلایا۔' WHERE id = 6868;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے جریر بن حازم نے بیان کیا، ان سے حسن نے اور ان سے عبدالرحمٰن بن سمرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اے عبدالرحمٰن! حکومت کے طالب نہ بننا کیونکہ اگر تمہیں مانگنے کے بعد حکومت ملی تو تم اس کے حوالے کر دئیے جاؤ گے اور وہ تمہیں بلا مانگے ملی تو اس میں تمہاری ( اللہ کی طرف سے ) مدد کی جائے گی اور اگر تم نے قسم کھا لی ہو پھر اس کے سوا دوسری چیز میں بھلائی دیکھو تو اپنی قسم کا کفارہ ادا کر دو اور وہ کام کرو جس میں بھلائی ہو۔“' WHERE id = 6878;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے قرہ نے، ان سے حمید بن ہلال نے، ان سے ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے انہیں بھیجا تھا اور ان کے ساتھ معاذ رضی اللہ عنہ کو بھی بھیجا تھا۔' WHERE id = 6888;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، انہیں ابن جریج نے خبر دی، انہیں ابن شہاب نے خبر دی، انہیں بنی ساعدہ کے ایک فرد سہل رضی اللہ عنہ نے خبر دی کہ قبیلہ انصار کا ایک شخص نبی کریم صلی اللہ علیہ وسلم کے پاس آیا اور عرض کیا آپ کا اس بارے میں کیا خیال ہے اگر کوئی مرد اپنی بیوی کے ساتھ دوسرے مرد کو دیکھے، کیا اسے قتل کر سکتا ہے؟ پھر دونوں ( میاں بیوی ) میں میری موجودگی میں لعان کرایا گیا۔' WHERE id = 6898;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہا ہم سے عاصم بن محمد بن زید بن عبداللہ بن عمر نے، اور ان سے ان کے والد نے کہ کچھ لوگوں نے ابن عمر رضی اللہ عنہما سے کہا کہ ہم اپنے حاکموں کے پاس جاتے ہیں اور ان کے حق میں وہ باتیں کہتے ہیں کہ باہر آنے کے بعد ہم اس کے خلاف کہتے ہیں۔ ابن عمر رضی اللہ عنہما نے کہا کہ ہم اسے نفاق کہتے تھے۔' WHERE id = 6909;
UPDATE hadiths SET urdu = 'ہم سے محمود نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کہا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے انہیں سالم نے اور انہیں ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے خالد رضی اللہ عنہ کو بھیجا۔ (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور مجھ سے نعیم بن حماد نے بیان کیا کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں سالم نے، انہیں ان کے والد نے کہ نبی کریم صلی اللہ علیہ وسلم نے خالد بن ولید رضی اللہ عنہ کو بنی جذیمہ کی طرف بھیجا ( جب انہیں اسلام کی دعوت دی ) تو وہ «أسلمنا‏.‏» ( ہم اسلام لائے ) کہہ کر اچھی طرح اظہار اسلام نہ کر سکے بلکہ کہنے لگے کہ «صبأنا صبأنا» ( ہم اپنے دین سے پھر گئے، ہم اپنے دین سے پھر گئے ) اس پر خالد رضی اللہ عنہ انہیں قتل اور قید کرنے لگے اور ہم میں سے ہر شخص کو اس کے حصہ کا قیدی دیا اور ہمیں حکم دیا کہ ہر شخص اپنے قیدی کو قتل کر دے۔ اس پر میں نے کہا کہ واللہ! میں اپنے قیدی کو قتل نہیں کروں گا اور نہ میرے ساتھیوں میں کوئی اپنے قیدی کو قتل کرے گا۔ پھر ہم نے اس کا ذکر نبی کریم صلی اللہ علیہ وسلم سے کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اے اللہ! میں اس سے برات ظاہر کرتا ہوں جو خالد بن ولید نے کیا، دو مرتبہ۔' WHERE id = 6919;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے سفیان نے، ان سے عبداللہ بن دینار نے بیان کیا کہا کہ میں اس وقت عبداللہ بن عمر رضی اللہ عنہما کے پاس موجود تھا جب سب لوگ عبدالملک بن مروان سے بیعت کے لیے جمع ہو گئے۔ بیان کیا کہ انہوں نے عبدالملک کو لکھا کہ ”میں سننے اور اطاعت کرنے کا اقرار کرتا ہوں عبداللہ عبدالملک امیرالمؤمنین کے لیے اللہ کے دین اور اس کے رسول کی سنت کے مطابق جتنی بھی مجھ میں قوت ہو گی اور یہ کہ میرے لڑکے بھی اس کا اقرار کرتے ہیں۔“' WHERE id = 6931;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، ان سے ایوب نے، ان سے حفصہ نے اور ان سے ام عطیہ رضی اللہ عنہا نے کہ ہم نے رسول اللہ صلی اللہ علیہ وسلم سے بیعت کی تو آپ نے میرے سامنے سورۃ الممتحنہ کی یہ آیت پڑھی «أن لا يشركن بالله شيئا‏» یہ کہ ”وہ اللہ کے ساتھ کسی کو شریک نہ ٹھہرائیں گی“ آخر تک۔ اور ہمیں آپ صلی اللہ علیہ وسلم نے نوحہ سے منع کیا پھر ہم میں سے ایک عورت نے اپنا ہاتھ کھینچ لیا اور کہا کہ فلاں عورت نے کسی نوحہ میں میری مدد کی تھی ( میرے ساتھ مل کر نوحہ کیا تھا ) اور میں اسے اس کا بدلہ دینا چاہتی ہوں۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے کچھ نہیں کہا، پھر وہ گئیں اور واپس آئیں ( میرے ساتھ بیعت کرنے والی عورتوں میں سے ) کسی عورت نے اس بیعت کو پورا نہیں کیا، سوا ام سلیم اور ام العلاء اور معاذ رضی اللہ عنہم کی بیوی ابوسبرہ کی بیٹی کے یا ابوسبرہ کی بیٹی اور معاذ کی بیوی کے اور سب عورتوں نے احکام بیعت کو پورے طور پر ادا نہ کر کے بیعت کو نہیں نبھایا۔ غفر اللہ لھن اجمعین۔' WHERE id = 6943;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو مالک نے خبر دی، انہیں ابوالزناد نے، انہیں اعرج نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اس ذات کی قسم جس کے ہاتھ میں میری جان ہے، میری آرزو ہے کہ میں اللہ کے راستے میں جنگ کروں اور قتل کیا جاؤں پھر زندہ کیا جاؤں، پھر قتل کیا جاؤں، پھر زندہ کیا جاؤں، پھر قتل کیا جاؤں، ابوہریرہ رضی اللہ عنہ ان الفاظ کو تین مرتبہ دہراتے تھے کہ میں اللہ کو گواہ کر کے کہتا ہوں۔“' WHERE id = 6954;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا ہم سے معاویہ بن عمرو نے بیان کیا، انہوں نے کہا ہم سے ابواسحاق نے بیان کیا، ان سے موسیٰ بن عقبہ نے بیان کیا، ان سے عمر بن عبیداللہ کے غلام سالم ابوالنضر نے بیان کیا، جو اپنے آقا کے کاتب تھے بیان کیا کہ عبداللہ بن ابی اوفی رضی اللہ عنہما نے انہیں لکھا اور میں نے اسے پڑھا تو اس میں یہ مضمون تھا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ہے کہ دشمن سے مڈبھیڑ ہونے کی تمنا نہ کرو اور اللہ سے عافیت کی دعا مانگا کرو۔' WHERE id = 6964;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ قطان نے، ان سے سلیمان تیمی نے، ان سے ابوعثمان نہدی نے، ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کسی شخص کو بلال رضی اللہ عنہ کی اذان سحری کھانے سے نہ روکے کیونکہ وہ صرف اس لیے اذان دیتے ہیں یا نداء کرتے ہیں تاکہ جو نماز کے لیے بیدار ہیں وہ واپس آ جائیں اور جو سوئے ہوئے ہیں وہ بیدار ہو جائیں اور فجر وہ نہیں ہے جو اس طرح لمبی دھار ہوتی ہے۔ یحییٰ نے اس کے اظہار کے لیے اپنے دونوں ہاتھ ملائے اور کہا یہاں تک کہ وہ اس طرح ظاہر ہو جائے اور اس کے اظہار کے لیے انہوں نے اپنی دونوں شہادت کی انگلیوں کو پھیلا کر بتلایا۔“' WHERE id = 6974;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے زبید نے، ان سے سعد بن عبیدہ نے، ان سے ابوعبدالرحمٰن نے اور ان سے علی رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک لشکر بھیجا اور اس کا امیر ایک صاحب عبداللہ بن حذافہ سہمی کو بنایا، پھر ( اس نے کیا کیا کہ ) آگ جلوائی اور ( لشکریوں سے ) کہا کہ اس میں داخل ہو جاؤ۔ جس پر بعض لوگوں نے داخل ہونا چاہا لیکن کچھ لوگوں نے کہا کہ ہم آگ ہی سے بھاگ کر آئے ہیں۔ پھر اس کا ذکر نبی کریم صلی اللہ علیہ وسلم سے کیا تو آپ صلی اللہ علیہ وسلم نے ان سے فرمایا کہ جنہوں نے آگ میں داخل ہونے کا ارادہ کیا تھا کہ اگر تم اس میں داخل ہو جاتے تو اس میں قیامت تک رہتے۔ اور دوسرے لوگوں سے کہا کہ اللہ تعالیٰ کی نافرمانی میں کسی کی اطاعت حلال نہیں ہے اطاعت صرف نیک کاموں میں ہے۔' WHERE id = 6984;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل بن خالد نے، ان سے ابن شہاب نے اور انہیں انس بن مالک رضی اللہ عنہ نے خبر دی کہ انہوں نے عمر رضی اللہ عنہ سے وہ خطبہ سنا جو انہوں نے وفات نبوی کے دوسرے دن پڑھا تھا، جس دن مسلمانوں نے ابوبکر رضی اللہ عنہ سے بیعت کی تھی۔ عمر رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم کے منبر پر چڑھے اور ابوبکر رضی اللہ عنہ سے پہلے خطبہ پڑھا پھر کہا: امابعد! اللہ تعالیٰ نے اپنے رسول کے لیے وہ چیز ( آخرت ) پسند کی جو اس کے پاس تھی اس کے بجائے جو تمہارے پاس تھی یعنی دنیا اور یہ کتاب اللہ موجود ہے جس کے ذریعہ اللہ تعالیٰ نے تمہارے رسول کو دین و سیدھا راستہ بتلایا پس اسے تم تھامے رہو تو ہدایت یاب رہو گے۔ یعنی اس راستے پر رہو گے جو اللہ نے اپنے پیغمبر کو بتلایا تھا۔' WHERE id = 6995;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبادہ نے بیان کیا، کہا ہم کو یزید بن ہارون نے خبر دی، کہا ہم سے سلیم بن حیان نے بیان کیا اور یزید بن ہارون نے ان کی تعریف کی، کہا ہم سے سعید بن میناء نے بیان کیا، انہوں نے کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ فرشتے نبی کریم صلی اللہ علیہ وسلم کے پاس آئے ( جبرائیل و میکائیل ) اور آپ سوئے ہوئے تھے۔ ایک نے کہا کہ یہ سوئے ہوئے ہیں، دوسرے نے کہا کہ ان کی آنکھیں سو رہی ہیں لیکن ان کا دل بیدار ہے۔ انہوں نے کہا کہ تمہارے ان صاحب ( نبی کریم صلی اللہ علیہ وسلم ) کی ایک مثال ہے پس ان کی مثال بیان کرو۔ تو ان میں سے ایک کہا کہ یہ سو رہے ہیں، دوسرے نے کہا کہ آنکھ سو رہی ہے اور دل بیدار ہے۔ انہوں نے کہا کہ ان کی مثال اس شخص جیسی ہے جس نے ایک گھر بنایا اور وہاں کھانے کی دعوت کی اور بلانے والے کو بھیجا، پس جس نے بلانے والے کی دعوت قبول کر لی وہ گھر میں داخل ہو گیا اور دستر خوان سے کھایا اور جس نے بلانے والے کی دعوت قبول نہیں کی وہ گھر میں داخل نہیں ہوا اور دستر خوان سے کھانا نہیں کھایا، پھر انہوں نے کہا کہ اس کی ان کے لیے تفسیر کر دو تاکہ یہ سمجھ جائیں۔ بعض نے کہا کہ یہ تو سوئے ہوئے ہیں لیکن بعض نے کہا کہ آنکھیں گو سو رہی ہیں لیکن دل بیدار ہے۔ پھر انہوں نے کہا کہ گھر تو جنت ہے اور بلانے والے محمد صلی اللہ علیہ وسلم ہیں، پس جو ان کی اطاعت کرے گا وہ اللہ کی اطاعت کرے گا اور جو ان کی نافرمانی کرے گا وہ اللہ کی نافرمانی کرے گا اور محمد صلی اللہ علیہ وسلم اچھے اور برے لوگوں کے درمیانی فرق کرنے والے ہیں۔ محمد بن عبادہ کے ساتھ اس حدیث کو قتیبہ بن سعید نے بھی لیث سے روایت کیا، انہوں نے خالد بن یزید مصری سے، انہوں نے سعید بن ابی ہلال سے، انہوں نے جابر سے کہ نبی کریم صلی اللہ علیہ وسلم ہم پر بیدار ہوئے، پھر یہی حدیث نقل کی اسے ترمذی نے وصل کیا۔' WHERE id = 7006;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا , کہا ہم سے حماد بن زید نے بیان کیا , ان سے ثابت نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ ہم عمر رضی اللہ عنہ کے پاس تھے تو آپ نے فرمایا کہ ہمیں تکلف اختیار کرنے سے منع کیا گیا ہے۔' WHERE id = 7017;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا مجھ سے امام مالک نے بیان کیا، ان سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے بیان کیا اور ان سے ام المؤمنین عائشہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی بیماری میں فرمایا ابوبکر سے کہو کہ لوگوں کو نماز پڑھائیں عائشہ نے کہا کہ میں نے جواباً عرض کیا کہ ابوبکر رضی اللہ عنہ اگر آپ صلی اللہ علیہ وسلم کی جگہ کھڑے ہوں گے تو رونے کی شدت کی وجہ سے اپنی آواز لوگوں کو نہیں سنا سکیں گے اس لیے آپ عمر رضی اللہ عنہ کو حکم دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ابوبکر سے کہو کہ لوگوں کو نماز پڑھائیں۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے حفصہ رضی اللہ عنہا سے کہا کہ تم کہو کہ ابوبکر رضی اللہ عنہ آپ کی جگہ کھڑے ہوں گے تو شدت بکاء کی وجہ سے لوگوں کو سنا نہیں سکیں گے، اس لیے آپ صلی اللہ علیہ وسلم عمر رضی اللہ عنہ کو نماز پڑھانے کا حکم دیں۔ حفصہ رضی اللہ عنہا نے ایسا ہی کیا۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بلاشبہ تم یوسف پیغمبر کی ساتھ والیاں ہو؟ ابوبکر سے کہو کہ لوگوں کو نماز پڑھائیں۔ بعد میں حفصہ رضی اللہ عنہا نے عائشہ رضی اللہ عنہا سے کہا کہ میں نے تم سے کبھی کچھ بھلائی نہیں دیکھی۔' WHERE id = 7027;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم پر یہ آیت نازل ہوئی «قل هو القادر على أن يبعث عليكم عذابا من فوقكم‏» کہ ”کہو کہ وہ اس پر قادر ہے کہ تم پر تمہارے اوپر سے عذاب بھیجے۔“ تو نبی کریم صلی اللہ علیہ وسلم نے کہا کہ میں تیرے با عظمت و بزرگ منہ کی پناہ مانگتا ہوں۔ «أو من تحت أرجلكم‏» ”یا تمہارے پاؤں کے نیچے سے“ ( عذاب بھیجے ) تو اس پر پھر نبی کریم صلی اللہ علیہ وسلم نے کہا کہ میں تیرے مبارک منہ کی پناہ مانگتا ہوں، پھر جب یہ آیت نازل ہوئی «أو يلبسكم شيعا ويذيق بعضكم بأس بعض‏» کہ ”یا تمہیں فرقوں میں تقسیم کر دے اور تم میں سے بعض کو بعض کا خوف چکھائے“ تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ دونوں آسان و سہل ہیں۔' WHERE id = 7037;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان ثوری نے خبر دی، ان سے عبدالرحمٰن بن عابس نے بیان کیا، کہا کہ ابن عباس رضی اللہ عنہما سے پوچھا گیا کہ کیا آپ نبی کریم صلی اللہ علیہ وسلم کے ساتھ عید میں گئے ہیں؟ کہا کہ ہاں میں اس وقت کم سن تھا۔ اگر نبی کریم صلی اللہ علیہ وسلم سے مجھ کو اتنا نزدیک کا رشتہ نہ ہوتا اور کم سن نہ ہوتا تو آپ کے ساتھ کبھی نہیں رہ سکتا تھا۔ نبی کریم صلی اللہ علیہ وسلم گھر سے نکل کر اس نشان کے پاس آئے جو کثیر بن صلت کے مکان کے پاس ہے اور وہاں آپ نے نماز عید پڑھائی پھر خطبہ دیا۔ انہوں نے اذان اور اقامت کا ذکر نہیں کیا، پھر آپ نے صدقہ دینے کا حکم دیا تو عورتیں اپنے کانوں اور گردنوں کی طرف ہاتھ بڑھانے لگیں زیوروں کا صدقہ دینے کے لیے، اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے بلال رضی اللہ عنہ کو حکم فرمایا، وہ آئے اور صدقہ میں ملی ہوئی چیزوں کو لے کر نبی کریم صلی اللہ علیہ وسلم کے پاس واپس گئے۔' WHERE id = 7048;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، ان سے لیث نے، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے (دوسری سند) اور مجھ سے اسحاق نے بیان کیا، انہوں نے کہا ہم کو عیسیٰ اور ابن ادریس نے خبر دی اور ابن ابی غنیہ نے خبر دی، انہیں ابوحیان نے، انہیں شعبی نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے عمر رضی اللہ عنہ کو نبی کریم صلی اللہ علیہ وسلم کے منبر پر ( خطبہ دیتے ) سنا۔' WHERE id = 7059;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا ہم سے ابوصالح (ذکوان) نے بیان کیا، ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”قیامت کے دن نوح علیہ السلام کو لایا جائے گا اور ان سے پوچھا جائے گا، کیا تم نے اللہ کا پیغام پہنچا دیا تھا؟ وہ عرض کریں گے کہ ہاں، اے رب! پھر ان کی امت سے پوچھا جائے گا کہ کیا انہوں نے تمہیں اللہ کا پیغام پہنچا دیا تھا؟ وہ کہیں گے کہ ہمارے پاس کوئی ڈرانے والا نہیں آیا۔ اللہ تعالیٰ نوح علیہ السلام سے پوچھے گا، تمہارے گواہ کون ہیں؟ نوح علیہ السلام عرض کریں گے کہ محمد صلی اللہ علیہ وسلم اور ان کی امت پھر تمہیں لایا جائے گا اور تم لوگ ان کے حق میں شہادت دو گے، پھر رسول اللہ صلی اللہ علیہ وسلم نے یہ آیت پڑھی «‏‏‏‏وكذلك جعلناكم أمة وسطا‏» ”اور اسی طرح ہم نے تمہیں درمیانی امت بنایا۔“ کہا کہ «وسط» بمعنی «عدل» ( میانہ رو ) ہے، تاکہ تم لوگوں کے لیے گواہ بنو اور رسول تم پر گواہ بنے۔ اسحاق بن منصور سے جعفر بن عون نے روایت کیا، کہا ہم سے اعمش نے بیان کیا، ان سے ابوصالح نے، ان سے ابو سعید خدری رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے یہی حدیث بیان فرمائی۔' WHERE id = 7070;
UPDATE hadiths SET urdu = 'ابوالیمان امام بخاری رحمہ اللہ کے شیخ نے بیان کیا کہ ہم کو شعیب نے خبر دی، انہیں زہری نے، انہیں حمید بن عبدالرحمٰن نے خبر دی، انہوں نے معاویہ رضی اللہ عنہ سے سنا وہ مدینے میں قریش کی ایک جماعت سے حدیث بیان کر رہے تھے۔ معاویہ رضی اللہ عنہ نے کعب احبار کا ذکر کیا اور فرمایا جتنے لوگ اہل کتاب سے احادیث نقل کرتے ہیں ان سب میں کعب احبار بہت سچے تھے اور باوجود اس کے کبھی کبھی ان کی بات جھوٹ نکلتی تھی، یہ مطلب نہیں ہے کہ کعب احبار جھوٹ بولتے تھے۔' WHERE id = 7081;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نبیل نے بیان کیا، انہوں نے کہا ہم سے زکریا بن اسحاق نے بیان کیا، ان سے یحییٰ بن عبداللہ بن صیفی نے بیان کیا، ان سے ابومعبد نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے معاذ بن جبل رضی اللہ عنہ کو یمن بھیجا۔' WHERE id = 7091;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا ہم سے زہیر نے بیان کیا، کہا ہم سے مغیرہ نے بیان کیا، انہوں نے کہا ہم سے شقیق بن سلمہ نے بیان کیا اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ ہم ( ابتداء اسلام میں ) رسول اللہ صلی اللہ علیہ وسلم کے پیچھے نماز پڑھتے تھے اور کہتے تھے «السلام على الله‏.‏» تو نبی کریم صلی اللہ علیہ وسلم نے ہم سے فرمایا کہ اللہ تو خود ہی «السلام‏.‏» ہے، البتہ اس طرح کہا کرو «التحيات لله والصلوات والطيبات،‏‏‏‏ ‏‏‏‏ السلام عليك أيها النبي ورحمة الله وبركاته،‏‏‏‏ ‏‏‏‏ السلام علينا وعلى عباد الله الصالحين،‏‏‏‏ ‏‏‏‏ أشهد أن لا إله إلا الله وأشهد أن محمدا عبده ورسوله» ۔' WHERE id = 7101;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا مجھ سے امام مالک نے بیان کیا، ان سے سعید بن ابی سعید مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جو شخص اپنے بستر پر جائے تو اسے چاہئے کہ اسے اپنے کپڑے کے کنارے سے تین مرتبہ صاف کر لے اور یہ دعا پڑھے «باسمك رب وضعت جنبي وبك أرفعه،‏‏‏‏ ‏‏‏‏ إن أمسكت نفسي فاغفر لها،‏‏‏‏ ‏‏‏‏ وإن أرسلتها فاحفظها بما تحفظ به عبادك الصالحين» ”اے میرے رب! تیرا نام لے کر میں اپنی کروٹ رکھتا ہوں اور تیرے نام ہی کے ساتھ اسے اٹھاؤں گا۔ اگر تو نے میری جان کو باقی رکھا تو اسے معاف کرنا اور اگر اسے ( اپنی طرف سوتے ہی میں ) اٹھا لیا تو اس کی حفاظت اس طرح کرنا جس طرح تو اپنے نیکوکار بندوں کی حفاظت کرتا ہے۔“ اس روایت کی متابعت یحییٰ اور بشر بن الفضل نے عبیداللہ سے کی ہے، ان سے سعید نے اور ان سے ابوہریرہ رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے۔ اور زہیر، ابوضمرہ اور اسماعیل بن زکریا نے عبیداللہ سے یہ اضافہ کیا کہ ان سے سعید نے، ان سے ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا اور اس کی روایت ابن عجلان نے کی، ان سے سعید نے، ان سے ابوہریرہ رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے۔ اس کی متابعت محمد بن عبدالرحمٰن الداوردی اور اسامہ بن حفص نے کی۔' WHERE id = 7112;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، انہوں نے کہا مجھ سے میرے والد نے بیان کیا، انہوں نے کہا ہم سے اعمش نے بیان کیا، ان سے شقیق نے اور ان سے عبداللہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کوئی بھی اللہ سے زیادہ غیرت مند نہیں اور اسی لیے اس نے فواحش کو حرام قرار دیا ہے اور اللہ سے زیادہ کوئی تعریف پسند کرنے والا نہیں۔“' WHERE id = 7122;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، انہوں نے کہا مجھ سے میرے والد نے بیان کیا، انہوں نے کہا ہم سے اعمش نے بیان کیا، انہوں نے ابراہیم سے سنا، کہا کہ میں نے علقمہ سے سنا، انہوں نے بیان کیا کہ عبداللہ رضی اللہ عنہ نے کہا کہ اہل کتاب میں سے ایک شخص نبی کریم صلی اللہ علیہ وسلم کے پاس آیا اور کہا کہ اے ابوالقاسم! اللہ آسمانوں کو ایک انگلی پر روک لے گا، زمین کو ایک انگلی پر روک لے گا، درخت اور مٹی کو ایک انگلی پر روک لے گا اور تمام مخلوقات کو ایک انگلی پر روک لے گا اور پھر فرمائے گا کہ میں ”بادشاہ ہوں، میں بادشاہ ہوں“ میں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھا کہ آپ اس پر ہنس دئیے، یہاں تک کہ آپ کے دانت مبارک دکھائی دینے لگے، پھر یہ آیت پڑھی «وما قدروا الله حق قدره‏» ۔' WHERE id = 7133;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے ابراہیم نے، انہوں نے کہا ہم سے ابن شہاب نے بیان کیا، ان سے عبید بن سباق نے بیان کیا اور ان سے زید بن ثابت رضی اللہ عنہ نے بیان کیا۔ اور لیث نے بیان کیا، ان سے عبدالرحمٰن بن خالد نے بیان کیا، ان سے ابن شہاب نے، ان سے ابن سباق نے اور ان سے زید بن ثابت رضی اللہ عنہ نے بیان کیا کہ ابوبکر رضی اللہ عنہ نے مجھے بلا بھیجا، پھر میں نے قرآن کی تلاش کی اور سورۃ التوبہ کی آخری آیت ابوخزیمہ انصاری رضی اللہ عنہ کے پاس پائی۔ یہ آیات مجھے کسی اور کے پاس نہیں ملی تھیں «لقد جاءكم رسول من أنفسكم‏» سورۃ برات کے آخر تک۔ ہم سے یحییٰ بن بکیر نے بیان کیا، ان سے لیث نے بیان کیا اور ان سے یونس نے یہی بیان کیا کہ ابوخزیمہ انصاری رضی اللہ عنہ کے پاس سورۃ توبہ کی آخری آیات پائیں۔' WHERE id = 7143;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ابن شہاب نے، ان سے عطاء بن یزید لیثی نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ لوگوں نے پوچھا: یا رسول اللہ! کیا ہم قیامت کے دن اپنے رب کو دیکھیں گے؟ نبی کریم صلی اللہ علیہ وسلم نے پوچھا، کیا چودھویں رات کا چاند دیکھنے میں کوئی دشواری ہوتی ہے؟ لوگوں نے عرض کیا نہیں یا رسول اللہ! پھر آپ نے پوچھا کیا جب بادل نہ ہوں تو تمہیں سورج کو دیکھنے میں کوئی دشواری ہوتی ہے؟ لوگوں نے کہا نہیں یا رسول اللہ! نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر تم اسی طرح اللہ تعالیٰ کو دیکھو گے قیامت کے دن اللہ تعالیٰ لوگوں کو جمع کرے گا اور فرمائے گا کہ تم میں جو کوئی جس چیز کی پوجا پاٹ کیا کرتا تھا وہ اس کے پیچھے لگ جائے۔ چنانچہ جو سورج کی پوجا کرتا تھا وہ سورج کے پیچھے ہو جائے گا، جو چاند کی پوجا کرتا تھا وہ چاند کے پیچھے ہو جائے گا اور جو بتوں کی پوجا کرتا تھا وہ بتوں کے پیچھے لگ جائے گا ( اسی طرح قبروں، تعزیوں کے پجاری قبروں، تعزیوں کے پیچھے لگ جائیں گے ) پھر یہ امت باقی رہ جائے گی اس میں بڑے درجہ کے شفاعت کرنے والے بھی ہوں گے یا منافق بھی ہوں گے ابراہیم کو ان لفظوں میں شک تھا۔ پھر اللہ ان کے پاس آئے گا اور فرمائے گا کہ میں تمہارا رب ہوں، وہ جواب دیں گے کہ ہم یہیں رہیں گے۔ یہاں تک کہ ہمارا رب آ جائے، جب ہمارا رب آ جائے گا تو ہم اسے پہچان لیں گے۔ چنانچہ اللہ تعالیٰ ان کے پاس اس صورت میں آئے گا جسے وہ پہچانتے ہوں گے اور فرمائے گا کہ میں تمہارا رب ہوں، وہ اقرار کریں گے کہ تو ہمارا رب ہے۔ چنانچہ وہ اس کے پیچھے ہو جائیں گے اور دوزخ کی پیٹھ پر پل صراط نصب کر دیا جائے گا اور میں اور میری امت سب سے پہلے اس کو پار کرنے والے ہوں گے اور اس دن صرف انبیاء بات کر سکیں گے اور انبیاء کی زبان پر یہ ہو گا۔ اے اللہ! مجھ کو محفوظ رکھ، مجھ کو محفوظ رکھ۔ اور دوزخ میں درخت سعدان کے کانٹوں کی طرح آنکڑے ہوں گے۔ کیا تم نے سعدان دیکھا ہے؟ لوگوں نے جواب دیا کہ جی ہاں، یا رسول اللہ! تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ وہ سعدان کے کانٹوں ہی کی طرح ہوں گے البتہ وہ اتنے بڑے ہوں گے کہ اس کا طول و عرض اللہ کے سوا اور کسی کو معلوم نہ ہو گا۔ وہ لوگوں کو ان کے اعمال کے بدلے میں اچک لیں گے تو ان میں سے کچھ وہ ہوں گے جو تباہ ہونے والے ہوں گے اور اپنے عمل بد کی وجہ سے وہ دوزخ میں گر جائیں گے یا اپنے عمل کے ساتھ بندھے ہوں گے اور ان میں بعض ٹکڑے کر دئیے جائیں گے یا بدلہ دئیے جائیں گے یا اسی جیسے الفاظ بیان کئے۔ پھر اللہ تعالیٰ تجلی فرمائے گا اور جب بندوں کے درمیان فیصلہ کر کے فارغ ہو گا اور دوزخیوں میں سے جسے اپنی رحمت سے باہر نکالنا چاہے گا تو فرشتوں کو حکم دے گا کہ جو اللہ کے ساتھ کسی کو شریک نہیں ٹھہراتے تھے انہیں دوزخ سے باہر نکالیں، یہ وہ لوگ ہوں گے جن پر اللہ تعالیٰ رحم کرنا چاہے گا۔ ان میں سے جنہوں نے کلمہ لا الہٰ الا اللہ کا اقرار کیا تھا۔ چنانچہ فرشتے انہیں سجدوں کے نشان سے دوزخ میں پہچانیں گے۔ دوزخ ابن آدم کا ہر عضو جلا کر بھسم کر دے گی سوا سجدہ کے نشان کے، کیونکہ اللہ تعالیٰ نے دوزخ پر حرام کیا ہے کہ وہ سجدوں کے نشان کو جلائے ( یا اللہ! ہم گنہگاروں کو دوزخ سے محفوظ رکھیو ہم کو تیری رحمت سے یہی امید ہے ) چنانچہ یہ لوگ دوزخ سے اس حال میں نکالے جائیں گے کہ یہ جل بھن چکے ہوں گے۔ پھر ان پر آب حیات ڈالا جائے گا اور یہ اس کے نیچے سے اس طرح اگ کر نکلیں گے جس طرح سیلاب کے کوڑے کرکٹ سے سبزہ اگ آتا ہے۔ پھر اللہ تعالیٰ بندوں کے درمیان فیصلہ سے فارغ ہو گا۔ ایک شخص باقی رہ جائے گا جس کا چہرہ دوزخ کی طرف ہو گا، وہ ان دوزخیوں میں سب سے آخری انسان ہو گا جسے جنت میں داخل ہونا ہے۔ وہ کہے گا: اے رب! میرا منہ دوزخ سے پھیر دے کیونکہ مجھے اس کی گرم ہوا نے پریشان کر رکھا ہے اور اس کی تیزی نے جھلسا ڈالا ہے۔ پھر اللہ تعالیٰ سے وہ اس وقت تک دعا کرتا رہے گا جب تک اللہ چاہے گا۔ پھر اللہ تعالیٰ فرمائے گا کیا اگر میں تیرا یہ سوال پورا کر دوں گا تو تو مجھ سے کچھ اور مانگے گا؟ وہ کہے گا نہیں، تیری عزت کی قسم! اس کے سوا اور کوئی چیز نہیں مانگوں گا اور وہ شخص اللہ رب العزت سے بڑے عہد و پیمان کرے گا۔ چنانچہ اللہ اس کا منہ دوزخ کی طرف سے پھیر دے گا۔ پھر جب وہ جنت کی طرف رخ کرے گا اور اسے دیکھے گا تو اتنی دیر خاموش رہے گا جتنی دیر اللہ تعالیٰ اسے خاموش رہنے دینا چاہے گا۔ پھر وہ کہے گا: اے رب! مجھے صرف جنت کے دروازے تک پہنچا دے۔ اللہ تعالیٰ فرمائے گا کیا تو نے وعدہ نہیں کیا تھا کہ جو کچھ میں نے دیا ہے اس کے سوا اور کچھ کبھی تو نہیں مانگے گا؟ افسوس ابن آدم تو کتنا وعدہ خلاف ہے۔ پھر وہ کہے گا: اے رب! اور اللہ سے دعا کرے گا۔ آخر اللہ تعالیٰ پوچھے گا کیا اگر میں نے تیرا یہ سوال پورا کر دیا تو اس کے سوا کچھ اور مانگے گا؟ وہ کہے گا تیری عزت کی قسم! اس کے سوا اور کچھ نہیں مانگوں گا اور جتنے اللہ چاہے گا وہ شخص وعدہ کرے گا۔ چنانچہ اسے جنت کے دروازے تک پہنچا دے گا۔ پھر جب وہ جنت کے دروازے پر کھڑا ہو جائے گا تو جنت اسے سامنے نظر آئے گی اور دیکھے گا کہ اس کے اندر کس قدر خیریت اور مسرت ہے۔ اس کے بعد اللہ تعالیٰ جتنی دیر چاہے گا وہ شخص خاموش رہے گا۔ پھر کہے گا: اے رب! مجھے جنت میں پہنچا دے۔ اللہ تعالیٰ اس پر کہے گا کیا تو نے وعدہ نہیں کیا تھا کہ جو کچھ میں نے تجھے دے دیا ہے اس کے سوا تو اور کچھ نہیں مانگے گا۔ اللہ تعالیٰ فرمائے گا افسوس! ابن آدم تو کتنا وعدہ خلاف ہے۔ وہ کہے گا: اے رب! مجھے اپنی مخلوق میں سب سے بڑھ کر بدبخت نہ بنا۔ چنانچہ وہ مسلسل دعا کرتا رہے گا یہاں تک کہ اللہ تعالیٰ اس کی دعاؤں پر ہنس دے گا، جب ہنس دے گا تو اس کے متعلق کہے گا کہ اسے جنت میں داخل کر دو۔ جنت میں اسے داخل کر دے گا تو اس سے فرمائے گا کہ اپنی آرزوئیں بیان کر، وہ اپنی تمام آرزوئیں بیان کر دے گا۔ یہاں تک کہ اللہ تعالیٰ اسے یاد دلائے گا۔ وہ کہے گا کہ فلاں چیز، فلاں چیز، یہاں تک کہ اس کی آرزوئیں ختم ہو جائیں گی تو اللہ تعالیٰ فرمائے گا کہ یہ آرزوئیں اور انہی جیسی تمہیں ملیں گی۔ ( «اللھم ارزقنا آمین»)' WHERE id = 7154;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے عبدالواحد بن زیاد نے بیان کیا، کہا ہم سے عاصم احول نے بیان کیا، ان سے ابوعثمان نہدی نے اور ان سے اسامہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کی ایک صاحبزادی ( زینب رضی اللہ عنہا ) کا لڑکا جاں کنی کے عالم میں تھا تو انہوں نے نبی کریم صلی اللہ علیہ وسلم کو بلا بھیجا۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں کہلایا کہ اللہ ہی کا وہ ہے جو وہ لیتا ہے اور وہ بھی جسے وہ دیتا ہے اور سب کے لیے ایک مدت مقرر ہے، پس صبر کرو اور اسے ثواب کا کام سمجھو۔ لیکن انہوں نے پھر دوبارہ بلا بھیجا اور قسم دلائی۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم اٹھے اور میں بھی آپ کے ساتھ چلا۔ معاذ بن جبل، ابی بن کعب اور عبادہ بن صامت رضی اللہ عنہم بھی ساتھ تھے۔ جب ہم صاحبزادی کے گھر میں داخل ہوئے تو لوگوں نے بچے کو نبی کریم صلی اللہ علیہ وسلم کو گود میں دے دیا۔ اس وقت بچہ کا سانس اکھڑ رہا تھا۔ ایسا معلوم ہوتا تھا جیسا پرانی مشک۔ نبی کریم صلی اللہ علیہ وسلم یہ دیکھ کر رو دئیے تو سعد بن عبادہ رضی اللہ عنہ نے عرض کیا، آپ روتے ہیں! نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ اپنے بندوں میں رحم کرنے والوں پر ہی رحم کھاتا ہے۔' WHERE id = 7164;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے اعمش نے، ان سے ابووائل نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے کہ ایک شخص نبی کریم صلی اللہ علیہ وسلم کے پاس آیا اور کہا کہ کوئی شخص حمیت کی وجہ سے لڑتا ہے، کوئی بہادری کی وجہ سے لڑتا ہے اور کوئی دکھاوے کے لیے لڑتا ہے۔ تو ان میں سے کون اللہ کے راستے میں ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو اس لیے لڑتا ہے کہ اللہ کا کلمہ ہی بلند رہے۔' WHERE id = 7174;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ المسندی نے بیان کیا، انہوں نے کہا ہم سے ہشام بن یوسف نے بیان کیا، انہوں نے کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں ابوادریس نے اور ان سے عبادہ بن صامت رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے ایک جماعت کے ساتھ بیعت کی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں تم سے اس بات پر بیعت لیتا ہوں کہ تم اللہ کے ساتھ کسی کو شریک نہیں ٹھہراؤ گے، اسراف نہیں کرو گے، زنا نہیں کرو گے، اپنی اولاد کو قتل نہیں کرو گے اور من گھڑت بہتان کسی پر نہیں لگاؤ گے اور نیک کاموں میں میری نافرمانی نہیں کرو گے۔ پس تم میں سے جو کوئی اس عہد کو پورا کرے گا اس کا اجر اللہ پر ہے اور جس نے کہیں لغزش کی اور اسے دنیا میں ہی پکڑ لیا گیا تو یہ حد اس کے لیے کفارہ اور پاکی بن جائے گی اور جس کی اللہ نے پردہ پوشی کی تو پھر اللہ پر ہے جسے چاہے عذاب دے اور جسے چاہے اس کا گناہ بخش دے۔' WHERE id = 7184;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا ہم سے ابوحفص عمرو نے بیان کیا، ان سے اوزاعی نے بیان کیا ان سے ابن شہاب نے بیان کیا، ان سے عبیداللہ بن عبداللہ بن عقبہ بن مسعود نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ وہ اور حر بن قیس بن حصین الفزاری، موسیٰ علیہ السلام کے ساتھی کے بارے میں اختلاف کر رہے تھے کہ کیا وہ خضر علیہ السلام ہی تھے۔ اتنے میں ابی بن کعب رضی اللہ عنہ کا ادھر سے گزر ہوا اور ابن عباس رضی اللہ عنہما نے انہیں بلایا اور ان سے کہا کہ میں اور میرا یہ ساتھی اس بارے میں شک میں ہیں کہ موسیٰ علیہ السلام کے وہ صاحب کون تھے جن سے ملاقات کے لیے موسیٰ علیہ السلام نے راستہ پوچھا تھا۔ کیا آپ نے رسول اللہ صلی اللہ علیہ وسلم سے اس سلسلہ میں کوئی حدیث سنی ہے انہوں نے کہا کہ ہاں۔ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ موسیٰ علیہ السلام بنی اسرائیل کے ایک مجمع میں تھے کہ ایک شخص نے آ کر پوچھا کیا آپ کسی ایسے شخص کو جانتے ہیں جو آپ سے زیادہ علم رکھتا ہو؟ موسیٰ علیہ السلام نے کہا کہ نہیں۔ چنانچہ آپ پر وحی نازل ہوئی کہ کیوں نہیں ہمارا بندہ خضر ہے۔ موسیٰ علیہ السلام نے ان سے ملاقات کا راستہ معلوم کیا اور اللہ تعالیٰ نے اس کے لیے مچھلی کو نشان قرار دیا اور آپ سے کہا گیا کہ جب تم مچھلی کو گم پاؤ تو لوٹ جانا کہ وہیں ان سے ملاقات ہو گی۔ چنانچہ موسیٰ علیہ السلام مچھلی کا نشان دریا میں ڈھونڈنے لگے اور آپ کے ساتھی نے آپ کو بتایا کہ آپ کو معلوم ہے۔ جب ہم نے چٹان پر ڈیرہ ڈالا تھا تو وہیں میں مچھلی بھول گیا اور مجھے شیطان نے اسے بھلا دیا۔ موسیٰ علیہ السلام نے کہا کہ یہ جگہ وہی ہے جس کی تلاش میں ہم سرگرداں ہیں پس وہ دونوں اپنے قدموں کے نشانوں پر واپس لوٹے اور انہوں نے خضر علیہ السلام کو پا لیا ان ہی دونوں کا یہ قصہ ہے جو اللہ نے بیان فرمایا۔' WHERE id = 7194;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے ابوالاحوص نے بیان کیا، انہوں نے کہا ہم سے ابواسحاق ہمدانی نے بیان کیا، ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اے فلان! جب تم اپنے بستر پر جاؤ تو یہ دعا کرو «‏‏‏‏اللهم أسلمت نفسي إليك،‏‏‏‏ ووجهت وجهي إليك وفوضت أمري إليك،‏‏‏‏ وألجأت ظهري إليك،‏‏‏‏ رغبة ورهبة إليك،‏‏‏‏ لا ملجأ ولا منجا منك إلا إليك،‏‏‏‏ آمنت بكتابك الذي أنزلت،‏‏‏‏ وبنبيك الذي أرسلت‏.‏» ”اے اللہ! میں نے اپنی جان تیرے سپرد کر دی اور اپنا رخ تیری طرف موڑ دیا اور اپنا معاملہ تیرے سپرد کر دیا اور تیری پناہ لی، تیری طرف رغبت کی وجہ سے اور تجھ سے ڈر کر۔ تیرے سوا کوئی پناہ اور نجات کی جگہ نہیں، میں تیری کتاب پر ایمان لایا جو تو نے نازل کی اور تیرے نبی پر ایمان لایا جو تو نے بھیجے۔ پس اگر تم آج رات مر گئے تو فطرت پر مرو گے اور صبح کو زندہ اٹھے تو ثواب ملے گا۔“' WHERE id = 7204;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن عمر نمیری نے بیان کیا، انہوں نے کہا ہم سے یونس بن یزید ایلی نے بیان کیا، کہا کہ میں نے زہری سے سنا، انہوں نے کہا کہ میں نے عروہ بن زبیر ‘ سعید بن مسیب، علقمہ بن وقاص اور عبیداللہ بن عبداللہ رضی اللہ عنہم سے سنا، نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا کے بارے میں جب تہمت لگانے والوں نے ان پر تہمت لگائی تھی اور اللہ نے اس سے انہیں بَری قرار دیا تھا۔ ان سب نے بیان کیا اور ہر ایک نے مجھ سے عائشہ رضی اللہ عنہا کی بیان کی ہوئی بات کا ایک حصہ بیان کیا۔ ام المؤمنین نے کہا: اللہ کی قسم! مجھے یہ خیال نہیں تھا کہ اللہ تعالیٰ میری پاکی بیان کرنے کے لیے وحی نازل کرے گا جس کی تلاوت ہو گی۔ میرے دل میں میرا درجہ اس سے بہت کم تھا کہ اللہ میرے بارے میں ( قرآن مجید میں ) وحی نازل کرے گا جس کی تلاوت ہو گی، البتہ مجھے امید تھی کہ رسول اللہ صلی اللہ علیہ وسلم کوئی خواب دیکھیں گے جس کے ذریعہ اللہ میری برات کر دے گا، لیکن اللہ تعالیٰ نے یہ آیات «إن الذين جاءوا بالإفك‏» نازل کی ہیں، دس آیات۔' WHERE id = 7215;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے حماد بن زید نے بیان کیا، ان سے سعید بن ہلال العنزی نے بیان کیا، انہوں نے کہا کہ بصرہ کے کچھ لوگ ہمارے پاس جمع ہو گئے۔ پھر ہم انس بن مالک رضی اللہ عنہ کے پاس گئے اور اپنے ساتھ ثابت رضی اللہ عنہ کو بھی لے گئے تاکہ وہ ہمارے لیے شفاعت کی حدیث پوچھیں۔ انس رضی اللہ عنہ اپنے محل میں تھے اور جب ہم پہنچے تو وہ چاشت کی نماز پڑھ رہے تھے۔ ہم نے ملاقات کی اجازت چاہی اور ہمیں اجازت مل گئی۔ اس وقت وہ اپنے بستر پر بیٹھے تھے۔ ہم نے ثابت سے کہا تھا کہ حدیث شفاعت سے پہلے ان سے اور کچھ نہ پوچھنا۔ چنانچہ انہوں نے کہا: اے ابوحمزہ! یہ آپ کے بھائی بصرہ سے آئے ہیں اور آپ سے شفاعت کی حدیث پوچھنا چاہتے ہیں۔ انہوں نے کہا کہ ہم سے محمد صلی اللہ علیہ وسلم نے بیان کیا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ قیامت کا دن جب آئے گا تو لوگ ٹھاٹھیں مارتے ہوئے سمندر کی طرح ظاہر ہوں گے۔ پھر وہ آدم علیہ السلام کے پاس آئیں گے اور ان سے کہیں گے کہ ہماری اپنے رب کے پاس شفاعت کیجئے۔ وہ کہیں گے کہ میں اس قابل نہیں ہوں تم ابراہیم علیہ السلام کے پاس جاؤ، وہ اللہ کے خلیل ہیں۔ لوگ ابراہیم علیہ السلام کے پاس آئیں گے وہ بھی کہیں گے کہ میں اس قابل نہیں ہوں، ہاں تم موسیٰ علیہ السلام کے پاس جاؤ کہ وہ اللہ سے شرف ہم کلامی پانے والے ہیں۔ لوگ موسیٰ علیہ السلام کے پاس آئیں گے اور وہ بھی کہیں گے کہ میں اس قابل نہیں ہوں، البتہ تم عیسیٰ علیہ السلام کے پاس جاؤ کہ وہ اللہ کی روح اور اس کا کلمہ ہیں۔ چنانچہ لوگ عیسیٰ علیہ السلام کے پاس آئیں گے وہ بھی کہیں گے کہ میں اس قابل نہیں ہوں، ہاں تم محمد صلی اللہ علیہ وسلم کے پاس جاؤ۔ لوگ میرے پاس آئیں گے اور میں کہوں گا کہ میں شفاعت کے لیے ہوں اور پھر میں اپنے رب سے اجازت چاہوں گا اور مجھے اجازت دی جائے گی اور اللہ تعالیٰ تعریفوں کے الفاظ مجھے الہام کرے گا جن کے ذریعہ میں اللہ کی حمد بیان کروں گا جو اس وقت مجھے یاد نہیں ہیں۔ چنانچہ جب میں یہ تعریفیں بیان کروں گا اللہ کے حضور میں سجدہ کرنے والا ہو جاؤں گا تو مجھ سے کہا جائے گا: اے محمد! اپنا سر اٹھاؤ، جو کہو وہ سنا جائے گا، جو مانگو گے وہ دیا جائے گا، جو شفاعت کرو گے قبول کی جائے گی۔ پھر میں کہوں گا: اے رب! میری امت، میری امت، کہا جائے گا کہ جاؤ اور ان لوگوں کو دوزخ سے نکال لو جن کے دل میں ذرہ یا رائی برابر بھی ایمان ہو۔ چنانچہ میں جاؤں گا اور ایسا ہی کروں گا۔ پھر میں لوٹوں گا اور یہی تعریفیں پھر کروں گا اور اللہ کے لیے سجدہ میں چلا جاؤں گا مجھ سے کہا جائے گا۔ اپنا سر اٹھاؤ کہو، آپ کی سنی جائے گی، میں کہوں گا: اے رب! میری امت، میری امت۔ اللہ تعالیٰ فرمائے گا: جاؤ اور جس کے دل میں ایک رائی کے دانہ کے کم سے کم تر حصہ کے برابر بھی ایمان ہو اسے بھی جہنم سے نکال لو۔ پھر میں جاؤں گا اور نکالوں گا۔ پھر جب ہم انس رضی اللہ عنہ کے پاس سے نکلے تو میں نے اپنے بعض ساتھیوں سے کہا کہ ہمیں امام حسن بصری کے پاس بھی چلنا چاہئیے، وہ اس وقت ابوخلیفہ کے مکان میں تھے اور ان سے وہ حدیث بیان کرنا چاہئیے جو انس رضی اللہ عنہ نے ہم سے بیان کی ہے۔ چنانچہ ہم ان کے پاس آئے اور انہیں سلام کیا۔ پھر انہوں نے ہمیں اجازت دی اور ہم نے ان سے کہا: اے ابوسعید! ہم آپ کے پاس آپ کے بھائی انس بن مالک رضی اللہ عنہ کے یہاں سے آئے ہیں اور انہوں نے ہم سے جو شفاعت کے متعلق حدیث بیان کی، اس جیسی حدیث ہم نے نہیں سنی، انہوں نے کہا کہ بیان کرو۔ ہم نے ان سے حدیث بیان کی جب اس مقام تک پہنچے تو انہوں نے کہا کہ اور بیان کرو، ہم نے کہا کہ اس سے زیادہ انہوں نے نہیں بیان کی۔ انہوں نے کہا کہ انس رضی اللہ عنہ جب صحت مند تھے، بیس سال اب سے پہلے تو انہوں نے مجھ سے یہ حدیث بیان کی تھی۔ مجھے معلوم نہیں کہ وہ باقی بھول گئے یا اس لیے بیان کرنا ناپسند کیا کہ کہیں لوگ بھروسہ نہ کر بیٹھیں۔ ہم نے کہا ابوسعید! پھر ہم سے وہ حدیث بیان کیجئے۔ آپ اس پر ہنسے اور فرمایا: انسان بڑا جلد باز پیدا کیا گیا ہے۔ میں نے اس کا ذکر ہی اس لیے کیا ہے کہ تم سے بیان کرنا چاہتا ہوں۔ انس رضی اللہ عنہ نے مجھ سے اسی طرح حدیث بیان کی جس طرح تم سے بیان کی ( اور اس میں یہ لفظ اور بڑھائے ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر میں چوتھی مرتبہ لوٹوں گا اور وہی تعریفیں کروں گا اور اللہ کے لیے سجدہ میں چلا جاؤں گا۔ اللہ فرمائے گا: اے محمد! اپنا سر اٹھاؤ، جو کہو گے سنا جائے گا، جو مانگو کے دیا جائے گا، جو شفاعت کرو کے قبول کی جائے گی۔ میں کہوں گا: اے رب! مجھے ان کے بارے میں بھی اجازت دیجئیے جنہوں نے لا الہٰ الا اللہ کہا ہے۔ اللہ تعالیٰ فرمائے گا میری عزت، میرے جلال، میری کبریائی، میری بڑائی کی قسم! اس میں سے ( میں ) انہیں بھی نکالوں گا جنہوں نے کلمہ لا الہٰ الا اللہ کہا ہے۔' WHERE id = 7225;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے منصور نے، ان سے ابووائل نے، ان سے عمرو بن شرجیل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا کہ کون سا گناہ اللہ کے یہاں سب سے بڑا ہے؟ فرمایا یہ کہ تم اللہ کے ساتھ کسی کو شریک ٹھہراؤ حالانکہ اسی نے تمہیں پیدا کیا ہے۔ میں نے کہا یہ تو بہت بڑا گناہ ہے۔ میں نے عرض کیا: پھر کون سا؟ فرمایا یہ کہ تم اپنے بچے کو اس خطرہ کی وجہ سے قتل کر دو کہ وہ تمہارے ساتھ کھائے گا۔ میں نے عرض کیا کہ پھر کون؟ فرمایا یہ کہ تم اپنے پڑوسی کی بیوی سے زنا کرو۔' WHERE id = 7235;
UPDATE hadiths SET urdu = 'ہم سے فضل بن یعقوب نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن جعفر الرقی نے بیان کیا، ان سے معتمر بن سلیمان نے بیان کیا، ان سے سعید بن عبیداللہ ثقفی نے بیان کیا، ان سے بکر بن عبداللہ مزنی اور زیاد بن جبیر بن حیہ نے بیان کیا، ان سے مغیرہ بن شعبہ رضی اللہ عنہ نے (ایران کی فوج کے سامنے) کہا کہ ہمارے نبی صلی اللہ علیہ وسلم نے ہمیں اپنے رب کے پیغامات میں سے یہ پیغام پہنچایا کہ ہم میں سے جو ( فی سبیل اللہ ) قتل کیا جائے گا وہ جنت میں جائے گا۔' WHERE id = 7245;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا ہم سے عثمان بن عمر نے بیان کیا، انہیں علی بن مبارک نے خبر دی، انہیں یحییٰ بن ابی کثیر نے، انہیں ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ اہل کتاب توریت کو عبرانی میں پڑھتے اور مسلمانوں کے لیے اس کی تفسیر عربی میں کرتے تھے۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم نہ اہل کتاب کی تصدیق کرو اور نہ اس کی تکذیب، بلکہ کہو کہ ہم اللہ اور اس کی تمام نازل کی ہوئی کتابوں پر ایمان لائے۔ الآیہ۔' WHERE id = 7257;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے منصور اور اعمش نے، انہوں نے سعد بن عبیدہ سے سنا، انہوں نے ابوعبدالرحمٰن اسلمیٰ سے اور انہوں نے علی رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم ایک جنازہ میں تھے پھر آپ نے ایک لکڑی لی اور اس سے زمین کریدنے لگے۔ پھر فرمایا تم میں کوئی ایسا نہیں جس کا ٹھکانہ جہنم میں یا جنت میں لکھا نہ جا چکا ہو۔ صحابہ نے کہا: پھر ہم اسی پر بھروسہ نہ کر لیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہر شخص کے لیے اس عمل میں آسانی پیدا کر دی گئی جس کے لیے وہ پیدا کیا گیا ہے۔ پھر آپ صلی اللہ علیہ وسلم نے یہ آیت پڑھی «فأما من أعطى واتقى‏» کہ ”جس شخص نے بخشش کی اور تقویٰ اختیار کیا“ آخر آیت تک۔' WHERE id = 7267;
